import { motion, AnimatePresence } from 'framer-motion';
import { Shield, ChevronRight } from 'lucide-react';

export function SafaricomTab({
  stkForm,
  setStkForm,
  safaricomLoading,
  safaricomResult,
  handleSafaricomAction,
  setSafaricomResult
}: {
  stkForm: any;
  setStkForm: any;
  safaricomLoading: boolean;
  safaricomResult: any;
  handleSafaricomAction: (action: string, params: any) => void;
  setSafaricomResult: (val: any) => void;
}) {
  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
       <div className="p-10 rounded-[32px] bg-[#1a1a1a] border border-white/5 shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-20 transition-opacity">
             <Shield className="w-24 h-24 text-[#F5C200]" />
          </div>
          <h3 className="text-2xl font-black text-white tracking-tight mb-8 uppercase">Payment Gateway</h3>
          <div className="space-y-6">
             <div className="space-y-1">
               <label className="text-[10px] font-black text-gray-600 uppercase tracking-widest ml-1">Test MSISDN</label>
               <input 
                 placeholder="254700000000"
                 value={stkForm.phoneNumber}
                 onChange={e => setStkForm((p: any) => ({ ...p, phoneNumber: e.target.value }))}
                 className="w-full px-6 py-4 bg-[#0f0f0f] border border-white/5 rounded-2xl text-sm font-bold focus:outline-none focus:border-[#F5C200]/30 transition-all placeholder:text-gray-800 text-white"
               />
             </div>
             <div className="grid grid-cols-2 gap-6">
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-600 uppercase tracking-widest ml-1">Volume</label>
                 <input 
                   type="number"
                   value={stkForm.amount}
                   onChange={e => setStkForm((p: any) => ({ ...p, amount: e.target.value }))}
                   className="w-full px-6 py-4 bg-[#0f0f0f] border border-white/5 rounded-2xl text-sm font-bold focus:outline-none focus:border-[#F5C200]/30 transition-all text-white"
                 />
               </div>
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-600 uppercase tracking-widest ml-1">Referential</label>
                 <input 
                   value={stkForm.accountRef}
                   onChange={e => setStkForm((p: any) => ({ ...p, accountRef: e.target.value }))}
                   className="w-full px-6 py-4 bg-[#0f0f0f] border border-white/5 rounded-2xl text-sm font-bold focus:outline-none focus:border-[#F5C200]/30 transition-all text-white"
                 />
               </div>
             </div>
             <button 
               onClick={() => handleSafaricomAction('stkpush', { ...stkForm, transactionDesc: 'Ops Audit' })}
               disabled={safaricomLoading || !stkForm.phoneNumber}
               className="w-full py-4 bg-[#F5C200] hover:bg-[#F5C200]/90 text-black rounded-2xl font-black uppercase tracking-widest text-xs transition-all disabled:opacity-50 shadow-xl shadow-[#F5C200]/20 active:scale-95"
             >
               {safaricomLoading ? 'Initiating...' : 'Fire STK Push'}
             </button>
          </div>
       </div>

       <div className="space-y-6">
          <div className="p-8 rounded-[32px] bg-[#1a1a1a] border border-white/5 shadow-2xl">
             <h4 className="text-[10px] font-black text-gray-600 uppercase tracking-widest mb-6">Ops Utilities</h4>
             <div className="space-y-4">
                <button onClick={() => handleSafaricomAction('balance', {})} className="w-full text-left p-6 rounded-[24px] bg-[#0f0f0f] border border-white/5 hover:bg-white/5 transition-all group flex items-center justify-between">
                   <div>
                      <div className="font-bold text-white text-sm">Query Wallet Balance</div>
                      <div className="text-[10px] font-black text-gray-700 uppercase tracking-widest mt-1">Verify current float reserves</div>
                   </div>
                   <ChevronRight className="w-5 h-5 text-gray-700 group-hover:text-[#F5C200] group-hover:translate-x-1 transition-all" />
                </button>
             </div>
          </div>

          <AnimatePresence>
             {safaricomResult && (
               <motion.div 
                 initial={{ opacity: 0, scale: 0.98 }} 
                 animate={{ opacity: 1, scale: 1 }} 
                 className="p-8 rounded-[32px] bg-black border border-white/5 shadow-2xl relative"
               >
                  <button onClick={() => setSafaricomResult(null)} className="absolute top-4 right-4 text-xs font-black text-emerald-500 uppercase tracking-widest">Close Output</button>
                  <pre className="text-[10px] font-mono text-[#F5C200]/80 overflow-auto max-h-64 custom-scrollbar">{JSON.stringify(safaricomResult, null, 2)}</pre>
               </motion.div>
             )}
          </AnimatePresence>
       </div>
    </div>
  );
}

import { motion } from 'framer-motion';
import { Pagination } from '../Pagination';
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function TransactionsTab({
  transactions,
  txPage,
  txTotalPages,
  setTxPage
}: {
  transactions: any[];
  txPage: number;
  txTotalPages: number;
  setTxPage: (val: number) => void;
}) {
  return (
    <div className="space-y-6">
       <div className="rounded-[32px] border border-white/5 bg-[#1a1a1a] shadow-2xl overflow-hidden">
          <table className="w-full text-left">
             <thead>
               <tr className="bg-white/[0.02] border-b border-white/5">
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Identity</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Volume</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Category</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">State</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Chronology</th>
               </tr>
             </thead>
             <tbody>
               {transactions.map((tx, i) => (
                 <motion.tr 
                   key={tx.id}
                   initial={{ opacity: 0 }}
                   animate={{ opacity: 1 }}
                   transition={{ delay: i * 0.02 }}
                   className="border-b border-white/[0.02] group hover:bg-white/[0.01] transition-colors"
                 >
                   <td className="py-5 px-8">
                     <div className="font-bold text-sm text-white group-hover:text-[#F5C200] transition-colors">{tx.user?.name || 'Anonymous'}</div>
                     <div className="text-[10px] font-black text-gray-600 uppercase tracking-tighter mt-0.5">{tx.user?.email}</div>
                   </td>
                   <td className="py-5 px-8 text-sm font-black text-[#F5C200] tabular-nums">KES {(tx.amount/100).toLocaleString()}</td>
                   <td className="py-5 px-8 text-[10px] font-black text-gray-500 uppercase tracking-widest">{tx.type}</td>
                   <td className="py-5 px-8">
                     <span className={cn(
                       "px-2 py-0.5 rounded-lg text-[9px] font-black tracking-widest border uppercase",
                       tx.status === 'completed' ? "bg-emerald-500/10 text-emerald-500 border-emerald-500/20" :
                       tx.status === 'pending' ? "bg-amber-500/10 text-amber-500 border-amber-500/20" :
                       "bg-emerald-500/10 text-emerald-500 border-emerald-500/20"
                     )}>
                       {tx.status}
                     </span>
                   </td>
                   <td className="py-5 px-8 text-[10px] font-black text-gray-700 uppercase tracking-widest">
                     {new Date(tx.createdAt).toLocaleDateString()}
                   </td>
                 </motion.tr>
               ))}
             </tbody>
          </table>
       </div>
       <Pagination page={txPage} totalPages={txTotalPages} onPageChange={setTxPage} />
    </div>
  );
}

import { motion } from 'framer-motion';
import { Search, FileCheck2, Edit2, Zap } from 'lucide-react';
import { Pagination } from '../Pagination';
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

const TIER_COLOR: Record<string, string> = {
  basic: 'bg-sky-500/10 text-sky-400 border-sky-500/20',
  pro: 'bg-[#F5C200]/10 text-[#F5C200] border-[#F5C200]/20',
  enterprise: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  none: 'bg-white/5 text-gray-500 border-white/10',
};

export function UsersTab({
  userSearch,
  setUserSearch,
  setUsersPage,
  usersTotal,
  users,
  usersPage,
  usersTotalPages,
  setEditingUser,
  setEditForm,
  fetchUserCertificates,
  setAssigningUser,
}: {
  userSearch: string;
  setUserSearch: (val: string) => void;
  setUsersPage: (val: number) => void;
  usersTotal: number;
  users: any[];
  usersPage: number;
  usersTotalPages: number;
  setEditingUser: (val: any) => void;
  setEditForm: (val: any) => void;
  fetchUserCertificates: (val: any) => void;
  setAssigningUser: (val: any) => void;
}) {
  return (
    <div className="space-y-6">
       <div className="flex items-center justify-between p-6 rounded-[24px] bg-[#1a1a1a] border border-white/5 shadow-2xl">
          <div className="flex items-center gap-6">
             <div className="relative">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-600" />
               <input 
                 type="text" 
                 placeholder="Search users..." 
                 value={userSearch}
                 onChange={e => { setUserSearch(e.target.value); setUsersPage(1); }}
                 className="w-80 pl-12 pr-4 py-2.5 bg-[#0f0f0f] border border-white/5 rounded-xl text-sm focus:outline-none focus:border-[#F5C200]/30 transition-all font-bold placeholder:text-gray-700 text-white"
               />
             </div>
             <div className="flex items-center gap-2">
               <div className="w-1.5 h-1.5 rounded-full bg-[#F5C200]" />
               <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">{usersTotal} Total Members</span>
             </div>
          </div>
       </div>

       <div className="rounded-[32px] border border-white/5 bg-[#1a1a1a] shadow-2xl overflow-hidden">
          <table className="w-full text-left">
             <thead>
               <tr className="bg-white/[0.02] border-b border-white/5">
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Member</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Privileges</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Subscription</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Expiry</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Credits</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600 text-right">Actions</th>
               </tr>
             </thead>
             <tbody>
               {users.map((u, i) => (
                 <motion.tr 
                   key={u.id}
                   initial={{ opacity: 0 }}
                   animate={{ opacity: 1 }}
                   transition={{ delay: i * 0.02 }}
                   className="border-b border-white/[0.02] group hover:bg-white/[0.01] transition-colors"
                 >
                   <td className="py-5 px-8">
                     <div className="font-bold text-sm text-white group-hover:text-[#F5C200] transition-colors">{u.name || 'Anonymous'}</div>
                     <div className="text-[10px] font-black text-gray-600 uppercase tracking-tighter mt-0.5">{u.email}</div>
                   </td>
                   <td className="py-5 px-8">
                     <span className={cn(
                       "px-2 py-0.5 rounded-lg text-[9px] font-black tracking-widest border uppercase",
                       u.role === 'admin' ? "bg-emerald-500/10 text-emerald-500 border-emerald-500/20" :
                       (u.role === 'premium' || u.role === 'cyber') ? "bg-[#F5C200]/10 text-[#F5C200] border-[#F5C200]/20" :
                       "bg-white/5 text-gray-500 border-white/10"
                     )}>
                       {u.role === 'cyber' ? 'premium' : u.role}
                     </span>
                   </td>
                   <td className="py-5 px-8">
                     <div className="flex flex-col gap-1">
                       <span className={cn(
                         "inline-flex w-fit px-2 py-0.5 rounded-lg text-[9px] font-black tracking-widest border uppercase",
                         TIER_COLOR[u.subscriptionTier?.toLowerCase()] || TIER_COLOR['none']
                       )}>
                         {u.subscriptionTier?.replace('_', ' ') || 'NONE'}
                       </span>
                       <span className={cn(
                         "text-[9px] font-black uppercase tracking-widest",
                         u.subscriptionStatus === 'active' ? "text-[#F5C200]" : "text-gray-700"
                       )}>{u.subscriptionStatus || 'INACTIVE'}</span>
                     </div>
                   </td>
                   <td className="py-5 px-8">
                     {u.subscriptionEnd && new Date(u.subscriptionEnd) > new Date() ? (
                       <div className="flex flex-col">
                         <span className="text-[10px] font-black text-gray-400 tabular-nums">
                           {new Date(u.subscriptionEnd).toLocaleDateString('en-KE', { day: '2-digit', month: 'short', year: '2-digit' })}
                         </span>
                         <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Active</span>
                       </div>
                     ) : (
                       <span className="text-[9px] font-black text-gray-700 uppercase tracking-widest">—</span>
                     )}
                   </td>
                   <td className="py-5 px-8 text-xs font-black text-gray-500 tabular-nums">{u.credits}</td>
                   <td className="py-5 px-8">
                     <div className="flex items-center justify-end gap-2">
                       {/* Quick Assign Limit */}
                       <button 
                         onClick={() => setAssigningUser(u)}
                         className="p-2.5 rounded-xl border border-sky-500/20 hover:bg-sky-500/10 text-gray-600 hover:text-sky-400 transition-all group/btn"
                         title="Quick Assign Tier"
                       >
                         <Zap className="w-4 h-4 transition-transform group-hover/btn:scale-110" />
                       </button>
                       <button 
                         onClick={() => fetchUserCertificates(u)}
                         className="p-2.5 rounded-xl border border-white/5 hover:bg-white/5 text-gray-600 hover:text-white transition-all group/btn"
                         title="View Certificates"
                       >
                         <FileCheck2 className="w-4 h-4 transition-transform group-hover/btn:scale-110" />
                       </button>
                       <button 
                         onClick={() => {
                           setEditingUser(u);
                           setEditForm({
                             role: u.role,
                             subscriptionTier: u.subscriptionTier,
                             subscriptionStatus: u.subscriptionStatus,
                             credits: u.credits,
                             subscriptionEnd: u.subscriptionEnd ? new Date(u.subscriptionEnd).toISOString().split('T')[0] : '',
                             pdfPremiumEnd: u.pdfPremiumEnd ? new Date(u.pdfPremiumEnd).toISOString().split('T')[0] : ''
                           });
                         }}
                         className="p-2.5 rounded-xl border border-white/5 hover:bg-[#F5C200]/10 hover:border-[#F5C200]/30 text-gray-600 hover:text-[#F5C200] transition-all group/btn"
                         title="Edit Profile"
                       >
                         <Edit2 className="w-4 h-4 transition-transform group-hover/btn:scale-110" />
                       </button>
                     </div>
                   </td>
                 </motion.tr>
               ))}
             </tbody>
          </table>
       </div>
       <Pagination page={usersPage} totalPages={usersTotalPages} onPageChange={setUsersPage} />
    </div>
  );
}

import { motion } from 'framer-motion';
import { Search, Shield } from 'lucide-react';
import { Pagination } from '../Pagination';

export function VerificationsTab({
  vfSearch,
  setVfSearch,
  setVfPage,
  verifications,
  vfPage,
  vfTotalPages
}: {
  vfSearch: string;
  setVfSearch: (val: string) => void;
  setVfPage: (val: number) => void;
  verifications: any[];
  vfPage: number;
  vfTotalPages: number;
}) {
  return (
    <div className="space-y-6">
       <div className="flex items-center justify-between p-6 rounded-[24px] bg-[#1a1a1a] border border-white/5 shadow-2xl">
          <div className="flex items-center gap-6">
             <div className="relative">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-600" />
               <input 
                 type="text" 
                 placeholder="Search PINs or Names..." 
                 value={vfSearch}
                 onChange={e => { setVfSearch(e.target.value); setVfPage(1); }}
                 className="w-80 pl-12 pr-4 py-2.5 bg-[#0f0f0f] border border-white/5 rounded-xl text-sm focus:outline-none focus:border-[#F5C200]/30 transition-all font-bold placeholder:text-gray-700 text-white"
               />
             </div>
             <div className="flex items-center gap-2">
               <div className="w-1.5 h-1.5 rounded-full bg-[#F5C200]" />
               <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Deep Verification Protocol</span>
             </div>
          </div>
       </div>

       <div className="rounded-[32px] border border-white/5 bg-[#1a1a1a] shadow-2xl overflow-hidden">
          <table className="w-full text-left">
             <thead>
               <tr className="bg-white/[0.02] border-b border-white/5">
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Taxpayer</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">KRA PIN</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Initiator</th>
                 <th className="py-5 px-8 text-[10px] font-black uppercase tracking-widest text-gray-600">Chronology</th>
               </tr>
             </thead>
             <tbody>
               {verifications.map((vf, i) => (
                 <motion.tr 
                   key={vf.id}
                   initial={{ opacity: 0 }}
                   animate={{ opacity: 1 }}
                   transition={{ delay: i * 0.02 }}
                   className="border-b border-white/[0.02] group hover:bg-white/[0.01] transition-colors"
                 >
                   <td className="py-5 px-8">
                     <div className="font-bold text-sm text-white group-hover:text-[#F5C200] transition-colors">{vf.taxpayerName || 'Direct ID Pull'}</div>
                     <span className="text-[9px] font-black text-[#F5C200]/60 uppercase tracking-widest">Verified</span>
                   </td>
                   <td className="py-5 px-8 text-sm font-black text-gray-400 tabular-nums uppercase">{vf.kraPin}</td>
                   <td className="py-5 px-8">
                     <div className="text-[10px] font-black text-white uppercase tracking-tighter">{vf.user?.name || 'Anonymous'}</div>
                     <div className="text-[9px] font-bold text-gray-600 uppercase tracking-tighter">{vf.user?.email}</div>
                   </td>
                   <td className="py-5 px-8 text-[10px] font-black text-gray-700 uppercase tracking-widest">
                     {new Date(vf.createdAt).toLocaleString()}
                   </td>
                 </motion.tr>
               ))}
               {verifications.length === 0 && (
                 <tr>
                   <td colSpan={4} className="py-20 text-center">
                      <Shield className="w-12 h-12 text-gray-800 mx-auto mb-4 opacity-20" />
                      <p className="text-gray-600 font-black uppercase tracking-widest text-xs">No verification records found</p>
                   </td>
                 </tr>
               )}
             </tbody>
          </table>
       </div>
       <Pagination page={vfPage} totalPages={vfTotalPages} onPageChange={setVfPage} />
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Activity, DollarSign, Users, TrendingUp, BarChart3, Globe } from 'lucide-react';
import { AdminSidebar } from '../_components/AdminSidebar';
import { AdminHeader } from '../_components/AdminHeader';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

export default function ExecutiveDashboard() {
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    fetch('/api/admin/stats')
      .then(res => res.json())
      .then(data => {
        setStats(data);
        setLoading(false);
      });
  }, []);

  const refreshData = () => {
    setLoading(true);
    fetch('/api/admin/stats').then(res => res.json()).then(data => {
      setStats(data);
      setLoading(false);
    });
  };

  // Using real dailyRevenueTrend from API or fallback to mock for visualization during cold starts
  const chartData = stats?.dailyRevenueTrend || [
    { date: 'Mon', revenue: 0 },
    { date: 'Tue', revenue: 0 },
    { date: 'Wed', revenue: 0 },
    { date: 'Thu', revenue: 0 },
    { date: 'Fri', revenue: 0 },
    { date: 'Sat', revenue: 0 },
    { date: 'Sun', revenue: 0 },
  ];

  const totalRevenue = stats?.totalRevenue || 0;
  const activeBase = stats?.totalUsers || 0;

  return (
    <div className="min-h-screen bg-black text-white selection:bg-[#F5C200]/30 overflow-x-hidden font-sans">
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none z-0">
        <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-[#F5C200]/10 blur-[150px] rounded-full translate-x-1/2 -translate-y-1/2" />
      </div>

      <AdminSidebar />

      <main className="lg:pl-72 min-h-screen transition-all duration-500 pb-20 relative z-10">
        <AdminHeader 
          title="Executive Command" 
          subtitle="Top-Level Performance Overview"
          onRefresh={refreshData}
          isSyncing={loading}
        />

        <div className="px-6 lg:px-10 py-10 max-w-[1600px] mx-auto relative">
          {loading ? (
             <div className="flex flex-col items-center justify-center min-h-[60vh] gap-6">
               <div className="relative">
                  <div className="w-16 h-16 border-2 border-white/5 rounded-full animate-spin border-t-[#F5C200]" />
               </div>
               <p className="text-[10px] font-black text-gray-500 uppercase tracking-[0.4em]">Initializing Executive Systems...</p>
            </div>
          ) : (
             <motion.div 
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               transition={{ duration: 0.4 }}
               className="space-y-8"
             >
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  <div className="p-6 rounded-[24px] bg-[#0f0f0f] border border-white/5 relative overflow-hidden group hover:border-[#F5C200]/30 transition-all">
                    <div className="absolute top-0 right-0 p-6 opacity-[0.02] group-hover:opacity-[0.05] transition-opacity"><DollarSign className="w-24 h-24 text-[#F5C200]" /></div>
                    <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2 mb-2">
                       <div className="w-2 h-2 rounded-sm bg-[#F5C200]" /> Total Platform Revenue
                    </div>
                    <h3 className="text-4xl font-black text-white tracking-tighter uppercase whitespace-nowrap">KES {totalRevenue.toLocaleString()}</h3>
                    <p className="text-xs font-bold text-emerald-500 mt-2">All-time realized</p>
                  </div>

                  <div className="p-6 rounded-[24px] bg-[#0f0f0f] border border-white/5 relative overflow-hidden group hover:border-[#F5C200]/30 transition-all">
                    <div className="absolute top-0 right-0 p-6 opacity-[0.02] group-hover:opacity-[0.05] transition-opacity"><BarChart3 className="w-24 h-24 text-[#F5C200]" /></div>
                    <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2 mb-2">
