    },
    { value: 'edit-annotate', label: t('home.categories.editAnnotate') },
    { value: 'convert-to-pdf', label: t('home.categories.convertToPdf') },
    { value: 'convert-from-pdf', label: t('home.categories.convertFromPdf') },
    { value: 'organize-manage', label: t('home.categories.organizeManage') },
    { value: 'optimize-repair', label: t('home.categories.optimizeRepair') },
    { value: 'secure-pdf', label: t('home.categories.securePdf') },
  ];

  const handleClearSearch = useCallback(() => {
    setSearchQuery('');
  }, []);

  const handleClearFilters = useCallback(() => {
    setSearchQuery('');
    setSelectedCategory('all');
  }, []);

  return (
    <div className="w-full">
      <div className="w-full">
        {/* Page Header */}
        <section className="relative pt-10 sm:pt-16 pb-12 sm:pb-20 overflow-hidden">
          {/* Animated Background Blobs (Subtle) */}
          <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none -z-10">
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-[hsl(var(--color-primary)/0.05)] rounded-full mix-blend-multiply filter blur-3xl opacity-50" />
            <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-[hsl(var(--color-accent)/0.05)] rounded-full mix-blend-multiply filter blur-3xl opacity-50" />
          </div>

          <div className="container mx-auto px-4 relative z-10">
            <div className="max-w-3xl mx-auto text-center">
              <h1 className="text-2xl sm:text-4xl md:text-6xl lg:text-7xl font-bold text-white mb-4 sm:mb-6 leading-tight">
                <span className="bg-clip-text text-transparent bg-gradient-to-br from-[var(--color-brand-red)] to-[var(--color-brand-yellow)]">{t('toolsPage.title')}</span>
              </h1>
              <p className="text-base sm:text-xl text-[#E8D5D5] max-w-[550px] mx-auto mb-8 sm:mb-10 leading-relaxed font-sans">
                {t('toolsPage.subtitle', { count: allTools.length })}
              </p>

              {/* Search Bar */}
              <div className="relative max-w-2xl mx-auto">
                <div className="relative group">
                  <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-5 w-5 text-[var(--color-brand-red)] group-focus-within:text-[var(--color-brand-red)] transition-colors z-10" aria-hidden="true" />
                  <input
                    type="search"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder={t('tools.search.placeholder')}
                    className="w-full pl-14 pr-12 py-4 text-lg rounded-full border border-white/10 bg-[#0a0a0a] text-white placeholder:text-[#E8D5D5]/50 shadow-md focus:outline-none focus:ring-4 focus:ring-[var(--color-brand-red)]/15 focus:border-[var(--color-brand-red)] transition-all glass-panel"
