                    aria-pressed={selectedCategory === cat.value}
                    className={`
                      px-4 py-2 rounded-full text-sm font-bold transition-all duration-200 flex items-center gap-1.5
                      ${selectedCategory === cat.value
                        ? cat.value === 'favorites'
