              )}
            </div>

            {/* Results Count */}
            <div className="mb-6 px-2">
              <p className="text-sm font-bold text-[#E8D5D5]/70">
                {selectedCategory === 'favorites'
                  ? `${filteredTools.length} ${t('tools.favorite.title').toLowerCase()}`
