                    {t('toolsPage.allTools')}
                  </Button>
                </div>
              </Card>
            ) : (
              // No results
              <Card className="p-16 text-center glass-panel border-dashed border-2 border-white/10 rounded-3xl bg-[#0a0a0a]">
