import { getAuth } from '@clerk/nextjs/server';
import prisma from '@/lib/prisma';

export async function POST(req: Request) {
  const { userId: clerkId } = getAuth(req as any);

  if (!clerkId) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const { name, email, subject, message } = await req.json();

    if (!message || message.length < 10) {
      return NextResponse.json({ error: 'Message must be at least 10 characters long' }, { status: 400 });
    }

    // Find the internal database user ID
    const dbUser = await prisma.user.findUnique({
      where: { clerkId },
      select: { id: true }
    });

    if (!dbUser) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    // Save the message to DB
    const contactMessage = await prisma.contactMessage.create({
      data: {
        userId: dbUser.id,
        name,
        email,
        subject,
        message,
        status: 'pending'
      }
    });

    console.log(`[CONTACT FORM] New submission saved [ID: ${contactMessage.id}]:
      From: ${name} (${email})
      User ID: ${clerkId}
      Subject: ${subject}
    `);

    return NextResponse.json({ 
      success: true, 
      message: 'Message sent successfully. Our team will contact you soon.',
      id: contactMessage.id
    });
  } catch (error) {
    console.error('Contact API Error:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { fileNilReturn, NilReturnData } from '@/lib/kra-client';
import { checkUsageLimit, incrementUsage } from '@/lib/pdf/usage';

export async function POST(req: Request) {
    try {
        // Rate limiting disabled - Always allowed

        const body: NilReturnData = await req.json();

        // Basic validation
        if (!body.TaxpayerPIN || !body.ObligationCode || !body.Month || !body.Year) {
            return NextResponse.json({ errorMessage: 'Missing required fields' }, { status: 400 });
        }

        const result = await fileNilReturn(body);

        // Increment usage on success
        try { await incrementUsage('KRA'); } catch (e) { console.warn('[NIL-RETURN] incrementUsage failed:', e); }

        return NextResponse.json(result);
    } catch (error: unknown) {
        console.error('[NIL-RETURN] Route Error:', error);
        if (error instanceof Error) {
            return NextResponse.json({ errorMessage: error.message }, { status: 500 });
        }
        return NextResponse.json({ errorMessage: 'Unknown error occurred' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { auth } from '@clerk/nextjs/server';
import prisma from '@/lib/prisma';
import { TIERS, isValidTier } from '@/lib/pricing';

export async function POST(req: Request) {
  try {
    const { userId } = await auth();
    if (!userId) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { tier } = await req.json();

    if (!tier || !isValidTier(tier)) {
      return NextResponse.json({ error: 'Invalid tier' }, { status: 400 });
    }

    const amount = TIERS[tier].price;

    const user = await prisma.user.findUnique({
      where: { clerkId: userId },
    });

    if (!user) {
      return NextResponse.json({ error: 'User not found in database. Please sync your account.' }, { status: 404 });
    }

    // Create pending transaction
    const transaction = await prisma.transaction.create({
      data: {
        userId: user.id,
        amount: amount * 100, // Store in subunits (cents/kobo)
        type: 'paystack',
        status: 'pending',
        tier,
      },
    });

    const host = req.headers.get('origin') || `https://${req.headers.get('host')}`;
    const callback_url = `${host}/api/payments/paystack/callback`;

    // Initiate Paystack Transaction
    const paystackRes = await fetch('https://api.paystack.co/transaction/initialize', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.PAYSTACK_SECRET_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        email: user.email,
        amount: amount * 100, // Paystack requires subunits
        currency: 'KES',
        reference: transaction.id,
        callback_url,
        metadata: {
          tier,
          transactionId: transaction.id,
          tierName: TIERS[tier].name,
          durationMs: TIERS[tier].durationMs,
          filings: TIERS[tier].filings,
        }
      }),
    });

    const paystackData = await paystackRes.json();

    if (paystackRes.ok && paystackData.status) {
      await prisma.transaction.update({
        where: { id: transaction.id },
        data: { paymentReference: paystackData.data.reference },
      });

      return NextResponse.json({ 
        success: true, 
        authorization_url: paystackData.data.authorization_url,
        reference: paystackData.data.reference,
        transactionId: transaction.id,
        amount: amount * 100,
      });
    } else {
      console.error('Paystack Checkout Error:', paystackData);
      await prisma.transaction.update({
        where: { id: transaction.id },
        data: { status: 'failed', failureReason: paystackData.message || 'Initialization failed' },
      });
      return NextResponse.json({ error: paystackData.message || 'Paystack initialization failed' }, { status: 500 });
    }

  } catch (error: any) {
    console.error('Paystack Checkout Error:', error);
    return NextResponse.json({ 
      error: 'An unexpected error occurred during checkout',
      details: error.message
    }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import crypto from 'crypto';
import prisma from '@/lib/prisma';
import { TIERS, isValidTier } from '@/lib/pricing';

/**
 * Computes subscriptionEnd = now + durationMs for the given tier.
 * Returns the full user updateData object for prisma.user.update.
 */
function buildSubscriptionUpdate(tier: string): Record<string, unknown> {
  if (!isValidTier(tier)) return {};

  const { durationMs, filings } = TIERS[tier];
  const now = new Date();
  const subscriptionEnd = new Date(now.getTime() + durationMs);

  return {
    role: 'premium',
    subscriptionStatus: 'active',
    subscriptionTier: tier,
    subscriptionEnd,
    // Clear legacy pdfPremiumEnd
    pdfPremiumEnd: null,
  };
}

export async function POST(req: Request) {
  try {
    const rawBody = await req.text();
    const signature = req.headers.get('x-paystack-signature');

    if (!signature) {
      return NextResponse.json({ error: 'Missing signature' }, { status: 400 });
    }

    const hash = crypto.createHmac('sha512', process.env.PAYSTACK_SECRET_KEY as string)
      .update(rawBody)
      .digest('hex');

    if (hash !== signature) {
      return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
    }

    const event = JSON.parse(rawBody);

    if (event.event === 'charge.success') {
      const { reference, status, metadata } = event.data;

      const transaction = await prisma.transaction.findFirst({
        where: { id: metadata.transactionId },
        include: { user: true },
      });

      if (!transaction) {
        console.warn('Paystack Webhook: Transaction not found:', metadata.transactionId);
        return NextResponse.json({ success: true });
      }

      if (transaction.status === 'completed') {
        return NextResponse.json({ success: true });
      }

      if (status === 'success') {
        await prisma.transaction.update({
          where: { id: transaction.id },
          data: { status: 'completed', paymentReference: reference },
        });

        const tier = transaction.tier;
        const updateData = buildSubscriptionUpdate(tier ?? '');

        if (Object.keys(updateData).length > 0 && transaction.userId) {
          await prisma.user.update({
            where: { id: transaction.userId },
            data: updateData,
          });
          const tierInfo = isValidTier(tier ?? '') ? TIERS[tier as keyof typeof TIERS] : null;
          console.log(`✅ ${tierInfo?.name ?? tier} access (${tierInfo?.label}) granted to user ${transaction.userId} via Paystack Webhook`);
        }
      } else {
        await prisma.transaction.update({
          where: { id: transaction.id },
          data: { status: 'failed', failureReason: `Paystack webhook event: ${event.event}` },
        });
      }
    }

    return NextResponse.json({ success: true });

  } catch (error) {
    console.error('Paystack Webhook processing error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

