import { NextRequest, NextResponse } from 'next/server';
import { getAuth } from '@clerk/nextjs/server';
import prisma from '@/lib/prisma';
import { rateLimit } from '@/lib/rate-limit';

export async function GET(req: NextRequest) {
  const limited = rateLimit(req);
  if (limited) return limited;

  const { userId: clerkId } = getAuth(req as any);

  if (!clerkId) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const notifications = await prisma.userNotification.findMany({
      where: {
        user: { clerkId }
      },
      orderBy: { createdAt: 'desc' },
      take: 20
    });

    return NextResponse.json(notifications);
  } catch (error) {
    console.error('[User Notifications GET]', error);
    return NextResponse.json({ error: 'Failed to fetch notifications' }, { status: 500 });
  }
}

export async function PATCH(req: NextRequest) {
  const limited = rateLimit(req);
  if (limited) return limited;

  const { userId: clerkId } = getAuth(req as any);

  if (!clerkId) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const { id } = await req.json();

    if (!id) {
        // Mark all as read
        await prisma.userNotification.updateMany({
            where: { user: { clerkId }, isRead: false },
            data: { isRead: true }
        });
        return NextResponse.json({ success: true });
    }

    const notification = await prisma.userNotification.update({
      where: { id },
      data: { isRead: true },
    });

    return NextResponse.json({ success: true, notification });
  } catch (error) {
    console.error('[User Notifications PATCH]', error);
    return NextResponse.json({ error: 'Failed to update notification' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import Stripe from 'stripe';
import { headers } from 'next/headers';
import prisma from '@/lib/prisma';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  // @ts-expect-error - Ignore the strict apiVersion literal check
  apiVersion: '2023-10-16',
});

const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;

export async function POST(req: Request) {
  const body = await req.text();
  const headersList = await headers();
  const signature = headersList.get('stripe-signature') as string;

  let event: Stripe.Event;

  try {
    if (!webhookSecret) {
        console.warn('⚠️ Stripe Webhook Secret is not set. Verification skipped (not recommended for production).');
        event = JSON.parse(body);
    } else {
        event = stripe.webhooks.constructEvent(body, signature, webhookSecret);
    }
  } catch (err: any) {
    console.error(`❌ Webhook Error: ${err.message}`);
    return NextResponse.json({ error: `Webhook Error: ${err.message}` }, { status: 400 });
  }

  // Handle the event
  try {
    switch (event.type) {
      case 'invoice.paid':
        const invoice = event.data.object as any; // Cast as any to bypass direct property check on complex Stripe object
        const subscriptionId = typeof invoice.subscription === 'string' 
          ? invoice.subscription 
          : invoice.subscription?.id;

        if (!subscriptionId) {
          console.error('No subscriptionId found in invoice');
          break;
        }

        // Retrieve full subscription to get metadata
        const subscription = await stripe.subscriptions.retrieve(subscriptionId);
        const metadata = subscription.metadata as { userId?: string; tier?: string };
        const { userId, tier } = metadata;

        if (!userId) {
          console.error('No userId found in subscription metadata');
          break;
        }

        const now = new Date();
        const periodEnd = new Date(invoice.lines.data[0].period.end * 1000);

        if (tier === 'daily') {
          // Add 24 hours of premium PDF access
          const pdfEnd = new Date(now.getTime() + 24 * 60 * 60 * 1000);
          await prisma.user.update({
            where: { clerkId: userId },
            data: {
              pdfPremiumEnd: pdfEnd,
            }
          });
          console.log(`✅ Daily PDF access granted to user ${userId}`);
        } else if (tier === 'weekly' || tier === 'monthly') {
          // Cyber Pro access
          await prisma.user.update({
            where: { clerkId: userId },
            data: {
              role: 'cyber',
              subscriptionStatus: 'active',
              subscriptionEnd: periodEnd,
            }
          });
          console.log(`✅ Cyber Pro (${tier}) access granted to user ${userId}`);
        }
        break;

      case 'customer.subscription.deleted':
        const deletedSub = event.data.object as Stripe.Subscription;
        const subUserId = deletedSub.metadata.userId;

        if (subUserId) {
          await prisma.user.update({
            where: { clerkId: subUserId },
            data: {
              subscriptionStatus: 'expired'
            }
          });
          console.log(`ℹ️ Subscription expired for user ${subUserId}`);
        }
        break;

      default:
        console.log(`Unhandled event type ${event.type}`);
    }

    return NextResponse.json({ received: true });
  } catch (error) {
    console.error('Error processing webhook:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

'use client';

import { useAuth } from '@clerk/nextjs';
import { useEffect } from 'react';

export function UserActivityTracker() {
  const { isSignedIn, userId } = useAuth();

  useEffect(() => {
    if (!isSignedIn || !userId) return;

    const trackActivity = async () => {
      try {
        await fetch('/api/user/heartbeat', { 
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          // Use keepalive to ensure it finishes even if page is closed/moved
          keepalive: true
        });
      } catch (e) {
        // Silent fail
      }
    };

    // Track immediately on mount/sign-in
    trackActivity();

    // Track every 5 minutes while active
    const interval = setInterval(trackActivity, 5 * 60 * 1000);

    return () => clearInterval(interval);
  }, [isSignedIn, userId]);

  return null;
}

/**
 * GuidedTour Component
 * Requirements: 10.5
 * 
 * Provides a guided tour for first-time users with step-by-step tooltips
 */

'use client';

import React, { useEffect, useState, useRef } from 'react';
import { X, ChevronLeft, ChevronRight, HelpCircle } from 'lucide-react';
import { useGuidedTour, type TourStep } from '@/lib/hooks/useGuidedTour';
import { Button } from '@/components/ui/Button';

export interface GuidedTourProps {
  steps: TourStep[];
  translations: {
    startTour: string;
    next: string;
    prev: string;
    finish: string;
    skip: string;
    stepOf: string;
    welcomeTitle: string;
    welcomeMessage: string;
  };
  autoStart?: boolean;
}

interface TooltipPosition {
  top: number;
  left: number;
  placement: 'top' | 'bottom' | 'left' | 'right';
}

export const GuidedTour: React.FC<GuidedTourProps> = ({
  steps,
  translations,
  autoStart = false,
}) => {
  const {
    isActive,
    currentStep,
    currentStepData,
    totalSteps,
    isFirstVisit,
    startTour,
    nextStep,
    prevStep,
    endTour,
    dismissTour,
  } = useGuidedTour(steps);

  const [tooltipPosition, setTooltipPosition] = useState<TooltipPosition | null>(null);
  const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
  const tooltipRef = useRef<HTMLDivElement>(null);
  const [showWelcome, setShowWelcome] = useState(isFirstVisit && autoStart);
  useEffect(() => {
    if (isFirstVisit && autoStart) {
      setTimeout(() => setShowWelcome(true), 0);
    }
  }, [isFirstVisit, autoStart]);

  // Calculate tooltip position when step changes
  useEffect(() => {
    if (!isActive || !currentStepData) {
      setTimeout(() => {
        setTooltipPosition(current => current !== null ? null : current);
        setTargetRect(current => current !== null ? null : current);
      }, 0);
      return;
    }

    const calculatePosition = () => {
      const target = document.querySelector(currentStepData.target);
      if (!target) {
        setTooltipPosition(null);
        setTargetRect(null);
        return;
      }

      const rect = target.getBoundingClientRect();
      setTargetRect(rect);

      const padding = currentStepData.highlightPadding || 8;
      const tooltipWidth = 320;
      const tooltipHeight = 200;
      const margin = 12;

      let placement = currentStepData.placement || 'bottom';
      let top = 0;
      let left = 0;

      // Calculate position based on placement
      switch (placement) {
        case 'top':
          top = rect.top - tooltipHeight - margin;
          left = rect.left + rect.width / 2 - tooltipWidth / 2;
          break;
        case 'bottom':
          top = rect.bottom + margin;
          left = rect.left + rect.width / 2 - tooltipWidth / 2;
          break;
        case 'left':
          top = rect.top + rect.height / 2 - tooltipHeight / 2;
          left = rect.left - tooltipWidth - margin;
          break;
        case 'right':
          top = rect.top + rect.height / 2 - tooltipHeight / 2;
          left = rect.right + margin;
          break;
      }

      // Adjust if tooltip goes off screen
      if (left < margin) left = margin;
      if (left + tooltipWidth > window.innerWidth - margin) {
        left = window.innerWidth - tooltipWidth - margin;
      }
      if (top < margin) {
        top = rect.bottom + margin;
        placement = 'bottom';
      }
      if (top + tooltipHeight > window.innerHeight - margin) {
        top = rect.top - tooltipHeight - margin;
        placement = 'top';
      }

      setTooltipPosition({ top, left, placement });

      // Scroll target into view if needed
      target.scrollIntoView({ behavior: 'smooth', block: 'center' });
    };

    calculatePosition();
    window.addEventListener('resize', calculatePosition);
    window.addEventListener('scroll', calculatePosition);

    return () => {
      window.removeEventListener('resize', calculatePosition);
      window.removeEventListener('scroll', calculatePosition);
    };
  }, [isActive, currentStepData, currentStep]);

  const handleStartTour = () => {
    setShowWelcome(false);
    startTour();
  };

  const handleSkipWelcome = () => {
    setShowWelcome(false);
    dismissTour();
  };

  // Welcome dialog for first-time users
  if (showWelcome) {
    return (
      <>
        {/* Backdrop */}
        <div className="fixed inset-0 bg-black/50 z-[9998]" />

        {/* Welcome Dialog */}
        <div className="fixed inset-0 flex items-center justify-center z-[9999] p-4">
          <div className="bg-[hsl(var(--color-background))] rounded-[var(--radius-lg)] shadow-xl max-w-md w-full p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 rounded-full bg-[hsl(var(--color-primary))]/10">
                <HelpCircle className="h-6 w-6 text-[hsl(var(--color-primary))]" />
              </div>
              <h2 className="text-xl font-semibold text-[hsl(var(--color-foreground))]">
                {translations.welcomeTitle}
              </h2>
            </div>
            <p className="text-[hsl(var(--color-muted-foreground))] mb-6">
              {translations.welcomeMessage}
            </p>
            <div className="flex gap-3 justify-end">
              <Button variant="ghost" onClick={handleSkipWelcome}>
                {translations.skip}
              </Button>
              <Button variant="primary" onClick={handleStartTour}>
                {translations.startTour}
              </Button>
            </div>
          </div>
        </div>
      </>
    );
  }

  if (!isActive || !currentStepData || !tooltipPosition) {
    return null;
  }

  const isLastStep = currentStep === totalSteps - 1;
  const isFirstStep = currentStep === 0;

  return (
    <>
      {/* Backdrop with spotlight */}
      <div className="fixed inset-0 z-[9998] pointer-events-none">
        <svg className="w-full h-full">
          <defs>
            <mask id="spotlight-mask">
              <rect x="0" y="0" width="100%" height="100%" fill="white" />
              {targetRect && (
                <rect
                  x={targetRect.left - 8}
                  y={targetRect.top - 8}
                  width={targetRect.width + 16}
                  height={targetRect.height + 16}
                  rx="8"
                  fill="black"
                />
              )}
            </mask>
          </defs>
          <rect
            x="0"
            y="0"
            width="100%"
            height="100%"
            fill="rgba(0, 0, 0, 0.5)"
            mask="url(#spotlight-mask)"
          />
        </svg>
      </div>

      {/* Highlight border around target */}
      {targetRect && (
        <div
          className="fixed z-[9999] pointer-events-none border-2 border-[hsl(var(--color-primary))] rounded-[var(--radius-md)] transition-all duration-300"
          style={{
            top: targetRect.top - 8,
            left: targetRect.left - 8,
            width: targetRect.width + 16,
            height: targetRect.height + 16,
          }}
        />
      )}

      {/* Tooltip */}
      <div
        ref={tooltipRef}
        className="fixed z-[10000] w-80 bg-[hsl(var(--color-background))] rounded-[var(--radius-lg)] shadow-xl border border-[hsl(var(--color-border))] transition-all duration-300"
        style={{
          top: tooltipPosition.top,
          left: tooltipPosition.left,
        }}
      >
        {/* Close button */}
        <button
          onClick={endTour}
          className="absolute top-2 right-2 p-1 text-[hsl(var(--color-muted-foreground))] hover:text-[hsl(var(--color-foreground))] transition-colors"
          aria-label="Close tour"
        >
          <X className="h-4 w-4" aria-hidden="true" />
        </button>

        {/* Content */}
        <div className="p-4">
          <h3 className="font-semibold text-[hsl(var(--color-foreground))] mb-2 pr-6">
            {currentStepData.title}
          </h3>
          <p className="text-sm text-[hsl(var(--color-muted-foreground))] mb-4">
            {currentStepData.content}
          </p>

          {/* Progress and navigation */}
          <div className="flex items-center justify-between">
            <span className="text-xs text-[hsl(var(--color-muted-foreground))]">
              {currentStep + 1} {translations.stepOf} {totalSteps}
            </span>
            <div className="flex gap-2">
              {!isFirstStep && (
                <Button variant="ghost" size="sm" onClick={prevStep}>
                  <ChevronLeft className="h-4 w-4 mr-1" />
                  {translations.prev}
                </Button>
              )}
              <Button variant="primary" size="sm" onClick={nextStep}>
                {isLastStep ? translations.finish : translations.next}
                {!isLastStep && <ChevronRight className="h-4 w-4 ml-1" />}
              </Button>
            </div>
          </div>
        </div>

        {/* Progress dots */}
        <div 
          className="flex justify-center gap-1 pb-3"
          role="tablist"
          aria-label="Tour progress"
        >
          {steps.map((step, index) => (
            <button
              key={index}
              type="button"
              role="tab"
              aria-selected={index === currentStep}
              aria-label={`Step ${index + 1}: ${step.title}`}
              tabIndex={index === currentStep ? 0 : -1}
              onClick={() => {
                // Navigate to specific step
                if (index < currentStep) {
                  for (let i = currentStep; i > index; i--) {
                    prevStep();
                  }
                } else if (index > currentStep) {
                  for (let i = currentStep; i < index; i++) {
                    nextStep();
                  }
                }
              }}
              onKeyDown={(e) => {
                if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
                  e.preventDefault();
                  if (currentStep < totalSteps - 1) {
                    nextStep();
                  }
                } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
                  e.preventDefault();
                  if (currentStep > 0) {
                    prevStep();
                  }
                } else if (e.key === 'Home') {
                  e.preventDefault();
                  for (let i = currentStep; i > 0; i--) {
                    prevStep();
                  }
                } else if (e.key === 'End') {
                  e.preventDefault();
                  for (let i = currentStep; i < totalSteps - 1; i++) {
                    nextStep();
                  }
                }
              }}
              className={`w-2 h-2 rounded-full transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-[hsl(var(--color-ring))] focus-visible:ring-offset-1 ${
                index === currentStep
                  ? 'bg-[hsl(var(--color-primary))]'
                  : 'bg-[hsl(var(--color-muted))] hover:bg-[hsl(var(--color-muted-foreground))]'
              }`}
            />
          ))}
        </div>
      </div>
    </>
  );
};

export default GuidedTour;

/**
 * LiveRegion Component
 * Requirements: 9.4
 * 
 * Provides screen reader announcements for dynamic content changes
 */

'use client';

import React, { useEffect, useState, useRef, createContext, useContext, useCallback } from 'react';

export type LiveRegionPoliteness = 'polite' | 'assertive' | 'off';

export interface LiveRegionProps {
  /** The message to announce */
  message: string;
  /** Politeness level for the announcement */
  politeness?: LiveRegionPoliteness;
  /** Clear the message after announcement */
  clearOnAnnounce?: boolean;
  /** Delay before clearing (ms) */
  clearDelay?: number;
}

/**
 * LiveRegion component for screen reader announcements
 * Uses ARIA live regions to announce dynamic content changes
 */
export const LiveRegion: React.FC<LiveRegionProps> = ({
  message,
  politeness = 'polite',
  clearOnAnnounce = true,
  clearDelay = 1000,
}) => {
  const [announcement, setAnnouncement] = useState(message);
  const [prevMessage, setPrevMessage] = useState(message);
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  if (message !== prevMessage) {
    setPrevMessage(message);
    setAnnouncement(message);
  }

  useEffect(() => {
    if (announcement && clearOnAnnounce) {
      // Clear any existing timeout
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }

      // Clear after delay if configured
      timeoutRef.current = setTimeout(() => {
        setAnnouncement('');
      }, clearDelay);
    }

    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, [announcement, clearOnAnnounce, clearDelay]);

  return (
    <div
      role="status"
      aria-live={politeness}
      aria-atomic="true"
      className="sr-only"
    >
      {announcement}
    </div>
  );
};

/**
 * Context for global announcements
 */
interface AnnouncementContextValue {
  announce: (message: string, politeness?: LiveRegionPoliteness) => void;
}

const AnnouncementContext = createContext<AnnouncementContextValue | null>(null);

/**
 * Provider for global screen reader announcements
 */
export const AnnouncementProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [politeMessage, setPoliteMessage] = useState('');
  const [assertiveMessage, setAssertiveMessage] = useState('');

  const announce = useCallback((message: string, politeness: LiveRegionPoliteness = 'polite') => {
    if (politeness === 'assertive') {
      setAssertiveMessage(message);
      // Clear after a short delay to allow re-announcement of same message
      setTimeout(() => setAssertiveMessage(''), 100);
    } else {
      setPoliteMessage(message);
      setTimeout(() => setPoliteMessage(''), 100);
    }
  }, []);

  return (
    <AnnouncementContext.Provider value={{ announce }}>
      {children}
      {/* Polite live region */}
      <div
        role="status"
        aria-live="polite"
        aria-atomic="true"
        className="sr-only"
      >
        {politeMessage}
      </div>
      {/* Assertive live region */}
      <div
        role="alert"
        aria-live="assertive"
        aria-atomic="true"
        className="sr-only"
      >
        {assertiveMessage}
      </div>
    </AnnouncementContext.Provider>
  );
};

/**
 * Hook to access the announcement function
 */
export function useAnnouncement() {
  const context = useContext(AnnouncementContext);
  if (!context) {
    // Return a no-op function if not within provider
    return {
      announce: (message: string, politeness?: LiveRegionPoliteness) => {
        console.warn('useAnnouncement: AnnouncementProvider not found');
      },
    };
  }
  return context;
}

/**
 * Hook for announcing status changes
 */
export function useStatusAnnouncement() {
  const { announce } = useAnnouncement();

  const announceStatus = useCallback((status: string) => {
    announce(status, 'polite');
  }, [announce]);

  const announceError = useCallback((error: string) => {
    announce(error, 'assertive');
  }, [announce]);

  const announceSuccess = useCallback((message: string) => {
    announce(message, 'polite');
  }, [announce]);

  const announceLoading = useCallback((message: string = 'Loading, please wait') => {
    announce(message, 'polite');
  }, [announce]);

  return {
    announceStatus,
    announceError,
    announceSuccess,
    announceLoading,
  };
}

