'use client';

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { useTranslations } from 'next-intl';
import { Globe, ChevronDown, Check } from 'lucide-react';
import { type Locale, locales, localeConfig, getLocalizedPath } from '@/lib/i18n/config';
import { Button } from '@/components/ui/Button';

export interface LanguageSelectorProps {
  currentLocale: Locale;
}

// Storage key for language preference
const LANGUAGE_PREFERENCE_KEY = 'pdfcraft-language-preference';

/**
 * Save language preference to localStorage
 */
export function saveLanguagePreference(locale: Locale): void {
  if (typeof window !== 'undefined') {
    localStorage.setItem(LANGUAGE_PREFERENCE_KEY, locale);
  }
}

/**
 * Get language preference from localStorage
 */
export function getLanguagePreference(): Locale | null {
  if (typeof window !== 'undefined') {
    const stored = localStorage.getItem(LANGUAGE_PREFERENCE_KEY);
    if (stored && locales.includes(stored as Locale)) {
      return stored as Locale;
    }
  }
  return null;
}

export const LanguageSelector: React.FC<LanguageSelectorProps> = ({ currentLocale }) => {
  const t = useTranslations('common.buttons');
  const router = useRouter();
  const pathname = usePathname();
  const [isOpen, setIsOpen] = useState(false);
  const [focusedIndex, setFocusedIndex] = useState<number>(-1);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const optionRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const currentConfig = localeConfig[currentLocale];

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
        setFocusedIndex(-1);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Close dropdown on escape key
  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        setIsOpen(false);
        setFocusedIndex(-1);
      }
    };

    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, []);

  // Focus option when focusedIndex changes
  useEffect(() => {
    if (focusedIndex >= 0 && optionRefs.current[focusedIndex]) {
      optionRefs.current[focusedIndex]?.focus();
    }
  }, [focusedIndex]);

  const handleToggle = useCallback(() => {
    setIsOpen((prev) => {
      if (!prev) {
        // Find current locale index when opening
        const currentIndex = locales.indexOf(currentLocale);
        setFocusedIndex(currentIndex >= 0 ? currentIndex : 0);
      } else {
        setFocusedIndex(-1);
      }
      return !prev;
    });
  }, [currentLocale]);

  const handleButtonKeyDown = useCallback((event: React.KeyboardEvent) => {
    if (event.key === 'ArrowDown') {
      event.preventDefault();
      if (!isOpen) {
        setIsOpen(true);
      }
      const currentIndex = locales.indexOf(currentLocale);
      setFocusedIndex(currentIndex >= 0 ? currentIndex : 0);
    }
  }, [isOpen, currentLocale]);

  const handleLanguageSelect = useCallback((locale: Locale) => {
    // Save preference to localStorage
    saveLanguagePreference(locale);

    // Navigate to the new locale path
    const newPath = getLocalizedPath(pathname, locale);
    router.push(newPath);

    setIsOpen(false);
    setFocusedIndex(-1);
  }, [pathname, router]);

  const handleOptionKeyDown = useCallback((event: React.KeyboardEvent, locale: Locale, index: number) => {
    switch (event.key) {
      case 'Enter':
      case ' ':
        event.preventDefault();
        handleLanguageSelect(locale);
        break;
      case 'ArrowDown':
        event.preventDefault();
        setFocusedIndex((prev) => (prev < locales.length - 1 ? prev + 1 : 0));
        break;
      case 'ArrowUp':
        event.preventDefault();
        setFocusedIndex((prev) => (prev > 0 ? prev - 1 : locales.length - 1));
        break;
      case 'Home':
        event.preventDefault();
        setFocusedIndex(0);
        break;
      case 'End':
        event.preventDefault();
        setFocusedIndex(locales.length - 1);
        break;
      case 'Escape':
        event.preventDefault();
        setIsOpen(false);
        setFocusedIndex(-1);
        break;
      case 'Tab':
        setIsOpen(false);
        setFocusedIndex(-1);
        break;
    }
  }, [handleLanguageSelect]);

  return (
    <div className="relative" ref={dropdownRef}>
      <Button
        variant="ghost"
        size="sm"
        onClick={handleToggle}
        onKeyDown={handleButtonKeyDown}
        aria-expanded={isOpen}
        aria-haspopup="listbox"
        aria-label={t('selectLanguage')}
        className="flex items-center gap-1.5"
      >
        <Globe className="h-4 w-4" aria-hidden="true" />
        <span className="hidden sm:inline text-sm">{currentConfig.nativeName}</span>
        <ChevronDown 
          className={`h-3 w-3 transition-transform ${isOpen ? 'rotate-180' : ''}`}
          aria-hidden="true"
        />
      </Button>

      {/* Dropdown */}
      {isOpen && (
        <div
          className="absolute top-full right-0 mt-1 w-48 py-1 bg-[hsl(var(--color-background))] border border-[hsl(var(--color-border))] rounded-[var(--radius-lg)] shadow-lg z-50"
          role="listbox"
          aria-label={t('selectLanguage')}
          aria-activedescendant={focusedIndex >= 0 ? `language-option-${locales[focusedIndex]}` : undefined}
        >
          {locales.map((locale, index) => {
            const config = localeConfig[locale];
            const isSelected = locale === currentLocale;

            return (
              <button
                key={locale}
                id={`language-option-${locale}`}
                ref={(el) => { optionRefs.current[index] = el; }}
                onClick={() => handleLanguageSelect(locale)}
                onKeyDown={(e) => handleOptionKeyDown(e, locale, index)}
                className={`
                  flex items-center justify-between w-full px-3 py-2 text-sm text-left
                  transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-[hsl(var(--color-ring))]
                  ${isSelected 
                    ? 'bg-[hsl(var(--color-primary)/0.1)] text-[hsl(var(--color-primary))]' 
                    : 'text-[hsl(var(--color-foreground))] hover:bg-[hsl(var(--color-muted))] focus:bg-[hsl(var(--color-muted))]'
                  }
                `}
                role="option"
                aria-selected={isSelected}
                tabIndex={focusedIndex === index ? 0 : -1}
                dir={config.direction}
              >
                <span className="flex items-center gap-2">
                  <span>{config.nativeName}</span>
                  <span className="text-xs text-[hsl(var(--color-muted-foreground))]">
                    ({config.name})
                  </span>
                </span>
                {isSelected && (
                  <Check className="h-4 w-4" aria-hidden="true" />
                )}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default LanguageSelector;

'use client';

import React, { useState, useRef, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useTranslations } from 'next-intl';
import { ChevronDown } from 'lucide-react';
import { type Locale } from '@/lib/i18n/config';
import { type ToolCategory } from '@/types/tool';

export interface NavigationProps {
  locale: Locale;
  currentPath: string;
}

interface CategoryItem {
  id: ToolCategory;
  labelKey: string;
  href: string;
}

export const Navigation: React.FC<NavigationProps> = ({ locale, currentPath }) => {
  const t = useTranslations('home.categories');
  const tCommon = useTranslations('common');
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [focusedIndex, setFocusedIndex] = useState<number>(-1);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const menuItemRefs = useRef<(HTMLAnchorElement | null)[]>([]);

  const categories: CategoryItem[] = [
    { id: 'edit-annotate', labelKey: 'editAnnotate', href: `/${locale}/tools?category=edit-annotate` },
    { id: 'convert-to-pdf', labelKey: 'convertToPdf', href: `/${locale}/tools?category=convert-to-pdf` },
    { id: 'convert-from-pdf', labelKey: 'convertFromPdf', href: `/${locale}/tools?category=convert-from-pdf` },
    { id: 'organize-manage', labelKey: 'organizeManage', href: `/${locale}/tools?category=organize-manage` },
    { id: 'optimize-repair', labelKey: 'optimizeRepair', href: `/${locale}/tools?category=optimize-repair` },
    { id: 'secure-pdf', labelKey: 'securePdf', href: `/${locale}/tools?category=secure-pdf` },
  ];

  const mainNavItems = [
    { href: `/${locale}`, label: tCommon('navigation.home') },
    { href: `/${locale}/tools`, label: tCommon('navigation.tools'), hasDropdown: true },
    { href: `/${locale}/about`, label: tCommon('navigation.about') },
    { href: `/${locale}/faq`, label: tCommon('navigation.faq') },
  ];

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpenDropdown(null);
        setFocusedIndex(-1);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Close dropdown on escape key
  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        setOpenDropdown(null);
        setFocusedIndex(-1);
      }
    };

    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, []);

  // Focus menu item when focusedIndex changes
  useEffect(() => {
    if (focusedIndex >= 0 && menuItemRefs.current[focusedIndex]) {
      menuItemRefs.current[focusedIndex]?.focus();
    }
  }, [focusedIndex]);

  const handleDropdownToggle = useCallback((itemHref: string) => {
    setOpenDropdown((prev) => {
      if (prev === itemHref) {
        setFocusedIndex(-1);
        return null;
      }
      setFocusedIndex(0);
      return itemHref;
    });
  }, []);

  const handleKeyDown = useCallback((event: React.KeyboardEvent, itemHref: string) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      handleDropdownToggle(itemHref);
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      if (openDropdown !== itemHref) {
        setOpenDropdown(itemHref);
      }
      setFocusedIndex(0);
    }
  }, [handleDropdownToggle, openDropdown]);

  const handleMenuKeyDown = useCallback((event: React.KeyboardEvent, index: number) => {
    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault();
        setFocusedIndex((prev) => (prev < categories.length - 1 ? prev + 1 : 0));
        break;
      case 'ArrowUp':
        event.preventDefault();
        setFocusedIndex((prev) => (prev > 0 ? prev - 1 : categories.length - 1));
        break;
      case 'Home':
        event.preventDefault();
        setFocusedIndex(0);
        break;
      case 'End':
        event.preventDefault();
        setFocusedIndex(categories.length - 1);
        break;
      case 'Escape':
        event.preventDefault();
        setOpenDropdown(null);
        setFocusedIndex(-1);
        break;
      case 'Tab':
        setOpenDropdown(null);
        setFocusedIndex(-1);
        break;
    }
  }, [categories.length]);

  const isActive = (href: string) => {
    if (href === `/${locale}`) {
      return currentPath === `/${locale}` || currentPath === `/${locale}/`;
    }
    return currentPath.startsWith(href);
  };

  return (
    <nav 
      className="hidden md:flex items-center gap-1"
      role="navigation"
      aria-label="Main navigation"
      ref={dropdownRef}
    >
      {mainNavItems.map((item) => (
        <div key={item.href} className="relative">
          {item.hasDropdown ? (
            <>
              <button
                onClick={() => handleDropdownToggle(item.href)}
                onKeyDown={(e) => handleKeyDown(e, item.href)}
                className={`
                  flex items-center gap-1 px-3 py-2 text-sm font-medium rounded-[var(--radius-md)]
                  transition-colors
                  ${isActive(item.href) 
                    ? 'text-[hsl(var(--color-primary))] bg-[hsl(var(--color-primary)/0.1)]' 
                    : 'text-[hsl(var(--color-foreground))] hover:text-[hsl(var(--color-primary))] hover:bg-[hsl(var(--color-muted))]'
                  }
                `}
                aria-expanded={openDropdown === item.href}
                aria-haspopup="true"
                aria-controls={`dropdown-${item.href}`}
              >
                {item.label}
                <ChevronDown 
                  className={`h-4 w-4 transition-transform ${openDropdown === item.href ? 'rotate-180' : ''}`}
                  aria-hidden="true"
                />
              </button>

              {/* Dropdown Menu */}
              {openDropdown === item.href && (
                <div
                  id={`dropdown-${item.href}`}
                  className="absolute top-full left-0 mt-1 w-56 py-2 bg-[hsl(var(--color-background))] border border-[hsl(var(--color-border))] rounded-[var(--radius-lg)] shadow-lg z-50"
                  role="menu"
                  aria-orientation="vertical"
                >
                  {categories.map((category, index) => (
                    <Link
                      key={category.id}
                      ref={(el) => { menuItemRefs.current[index] = el; }}
                      href={category.href}
                      className="block px-4 py-2 text-sm text-[hsl(var(--color-foreground))] hover:bg-[hsl(var(--color-muted))] hover:text-[hsl(var(--color-primary))] focus:bg-[hsl(var(--color-muted))] focus:text-[hsl(var(--color-primary))] focus:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-[hsl(var(--color-ring))] transition-colors"
                      role="menuitem"
                      tabIndex={focusedIndex === index ? 0 : -1}
                      onClick={() => {
                        setOpenDropdown(null);
                        setFocusedIndex(-1);
                      }}
                      onKeyDown={(e) => handleMenuKeyDown(e, index)}
                    >
                      {t(category.labelKey)}
                    </Link>
                  ))}
                </div>
              )}
            </>
          ) : (
            <Link
              href={item.href}
              className={`
                px-3 py-2 text-sm font-medium rounded-[var(--radius-md)]
                transition-colors
                ${isActive(item.href) 
                  ? 'text-[hsl(var(--color-primary))] bg-[hsl(var(--color-primary)/0.1)]' 
                  : 'text-[hsl(var(--color-foreground))] hover:text-[hsl(var(--color-primary))] hover:bg-[hsl(var(--color-muted))]'
                }
              `}
              aria-current={isActive(item.href) ? 'page' : undefined}
            >
              {item.label}
            </Link>
          )}
        </div>
      ))}
    </nav>
  );
};

