'use client';

import { useState, useEffect, useRef } from 'react';
import { Timer, Zap } from 'lucide-react';

export function SubscriptionBanner() {
  const [status, setStatus] = useState<any>(null);
  const [subscriptionTimeLeft, setSubscriptionTimeLeft] = useState<string | null>(null);
  const [refreshTimeLeft, setRefreshTimeLeft] = useState<string | null>(null);

  useEffect(() => {
    async function fetchStatus() {
      try {
        const res = await fetch('/api/user/status', {
          credentials: 'include',
          headers: {
            Accept: 'application/json',
          },
        });
        if (res.ok) {
          const data = await res.json();
          setStatus(data);
        }
      } catch (e) {
        console.error('Failed to fetch user status:', e);
      }
    }
    fetchStatus();
    const interval = setInterval(fetchStatus, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, []);

  // Helper to format time distance
  const formatDistance = (distance: number) => {
    if (distance <= 0) return 'Expired';
    const days = Math.floor(distance / 86400000);
    const hours = Math.floor((distance % 86400000) / 3600000);
    const minutes = Math.floor((distance % 3600000) / 60000);
    const seconds = Math.floor((distance % 60000) / 1000);
    if (days > 0) return `${days}d ${hours}h ${String(minutes).padStart(2,'0')}m`;
    return `${String(hours).padStart(2,'0')}:${String(minutes).padStart(2,'0')}:${String(seconds).padStart(2,'0')}`;
  };

  // Timer for Subscription duration
  useEffect(() => {
    if (!status?.subscriptionEnd) {
      setTimeout(() => setSubscriptionTimeLeft(null), 0);
      return;
    }
    const subscriptionEnd = new Date(status.subscriptionEnd).getTime();

    const updateTimer = () => {
      setSubscriptionTimeLeft(formatDistance(subscriptionEnd - Date.now()));
    };

    setTimeout(updateTimer, 0);
    const timer = setInterval(updateTimer, 1000);
    return () => clearInterval(timer);
  }, [status?.subscriptionEnd]);

  // Timer for Credit Refresh (Midnight)
  useEffect(() => {
    if (!status?.usage?.nextRefresh) return;

    const refreshEnd = new Date(status.usage.nextRefresh).getTime();

    function updateRefreshTimer() {
      const now = new Date().getTime();
      const distance = refreshEnd - now;

      if (distance < 0) {
        setRefreshTimeLeft('Refreshing...');
        return;
      }

      const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((distance % (1000 * 60)) / 1000);

      setRefreshTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
    }

    setTimeout(updateRefreshTimer, 0);
    const timer = setInterval(updateRefreshTimer, 1000);
    return () => clearInterval(timer);
  }, [status]);

  if (!status) return null;

  return (
    <div className="bg-[#F5C200] text-black py-1 px-4 flex flex-wrap items-center justify-center gap-x-6 gap-y-1 text-[10px] font-black uppercase tracking-widest overflow-hidden relative group border-b border-black/10 z-[70]">
      <div className="absolute inset-0 bg-white/10 -translate-x-full group-hover:translate-x-full transition-transform duration-1000 ease-in-out" />

      {/* Credits Section */}
      <div className="flex items-center gap-2 relative z-10">
        <Zap className="w-3 h-3 text-current" />
        <span>Remaining Filings: <span className="tabular-nums">
          {status.usage?.remaining >= 15 ? 'Unlimited' : status.usage?.remaining ?? 0}
        </span></span>
      </div>

      {/* Subscription Duration Countdown */}
      {subscriptionTimeLeft && (
        <div className="flex items-center gap-2 relative z-10 border-l border-black/20 pl-6">
          <Timer className="w-3 h-3 animate-pulse" />
          <span className="tabular-nums font-mono">{subscriptionTimeLeft}</span>
        </div>
      )}

      {/* Admin Toggle */}
      {status.role === 'admin' && (
        <div className="flex items-center gap-2 relative z-10 border-l border-black/20 pl-6 text-red-600 font-black">
          <span>ADMIN ACCESS</span>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { useUser } from '@clerk/nextjs';
import { Zap, Clock, ShieldCheck, Star, RefreshCcw } from 'lucide-react';
import Link from 'next/link';

interface UserStatus {
  isPremiumUser: boolean;
  hasPdfPremium: boolean;
  subscriptionTier: string;
  subscriptionStatus: string;
  subscriptionEnd: string | null;
  usage: {
    remaining: number;
    limit: number;
    nextRefresh: string;
  };
}

export const UserCreditsIndicator = () => {
  const { isLoaded, isSignedIn } = useUser();
  const [status, setStatus] = useState<UserStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [timeLeft, setTimeLeft] = useState<string>('');

  const fetchStatus = useCallback(async () => {
    if (!isSignedIn) return;
    try {
      const res = await fetch('/api/user/status', {
        cache: 'no-store',
        credentials: 'include',
        headers: {
          Accept: 'application/json',
        },
      });
      if (res.ok) {
        const data = await res.json();
        setStatus(data);
      }
    } catch (err) {
      console.error('Failed to fetch user status:', err);
    } finally {
      setLoading(false);
    }
  }, [isSignedIn]);

  useEffect(() => {
    fetchStatus();
    // Poll every 2 minutes
    const interval = setInterval(fetchStatus, 120000);
    return () => clearInterval(interval);
  }, [fetchStatus]);

  // Timer logic
  useEffect(() => {
    if (!status) return;

    const timer = setInterval(() => {
      const target = status.isPremiumUser && status.subscriptionEnd 
        ? new Date(status.subscriptionEnd) 
        : new Date(status.usage.nextRefresh);

      const now = new Date();
      const diff = target.getTime() - now.getTime();

      if (diff <= 0) {
        setTimeLeft('00:00:00');
        return;
      }

      const hours = Math.floor(diff / (1000 * 60 * 60));
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((diff % (1000 * 60)) / 1000);

      const pad = (n: number) => n.toString().padStart(2, '0');

      if (hours > 24) {
        const days = Math.floor(hours / 24);
        setTimeLeft(`${days}d ${pad(hours % 24)}h`);
      } else {
        setTimeLeft(`${pad(hours)}:${pad(minutes)}:${pad(seconds)}`);
      }
    }, 1000);

    return () => clearInterval(timer);
  }, [status]);

  if (!isLoaded || !isSignedIn) return null;
  if (loading && !status) return (
    <div className="h-9 w-24 bg-black/5 animate-pulse rounded-full border border-black/10" />
  );
  if (!status) return null;

  return (
    <div className="flex items-center gap-2 group">
      {status.isPremiumUser ? (
        <div className="flex flex-col items-end mr-1">
          <Link 
            href="/pricing"
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-[#1F6F5B] text-white font-black text-[10px] shadow-sm hover:shadow-md transition-all uppercase tracking-widest italic"
          >
            <Star size={10} className="fill-[#F2E600] text-[#F2E600]" />
            <span>Premium</span>
          </Link>
          <span className="text-[10px] text-[#2E8B75] font-mono mt-0.5 flex items-center gap-1">
             <Clock size={8} /> {timeLeft} left
          </span>
        </div>
      ) : (
        <div className="flex flex-col items-end mr-1">
          <Link 
            href="/pricing"
            className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-[#E5E7EB] border border-[#D1D5DB] hover:bg-[#D1D5DB] transition-all text-xs font-medium"
          >
            <Zap size={12} className={status.usage.remaining > 0 ? "text-[#1F6F5B] fill-[#1F6F5B]/20" : "text-[#D1D5DB]"} />
            <span className="text-[#2B2B2B]">
              {status.usage.limit >= 999999 ? '∞' : `${status.usage.remaining} / ${status.usage.limit}`}
            </span>
            <span className="text-[10px] text-[#2E8B75] border-l border-[#D1D5DB] pl-2 font-mono uppercase tracking-tighter">
              {status.usage.limit >= 999999 ? 'Unlimited' : 'Credits'}
            </span>
          </Link>
          <span className="text-[9px] text-[#2E8B75] font-mono mt-0.5 flex items-center gap-1 group-hover:text-[#1F6F5B] transition-colors">
            {status.usage.limit >= 999999 ? 'Enterprise Tier' : `Resets in ${timeLeft}`}
          </span>
        </div>
      )}
    </div>
  );
};

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Bell, CheckCircle2, Clock, Trash2, X, MessageSquare, ExternalLink } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface UserNotification {
    id: string;
    message: string;
    isRead: boolean;
    createdAt: string;
}

export const UserNotificationBell = () => {
    const [notifications, setNotifications] = useState<UserNotification[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const unreadCount = notifications.filter(n => !n.isRead).length;

    const fetchNotifications = useCallback(async () => {
        try {
            const res = await fetch('/api/user/notifications', {
                credentials: 'include',
                headers: {
                    Accept: 'application/json',
                },
            });
            if (res.ok) {
                setNotifications(await res.json());
            }
        } catch (e) {
            console.error('Failed to fetch notifications:', e);
        }
    }, []);


    useEffect(() => {
        // Initial fetch
        const init = async () => {
            await fetchNotifications();
        };
        init();

        // Poll every 2 minutes
        const interval = setInterval(fetchNotifications, 2 * 60 * 1000);
        return () => clearInterval(interval);
    }, [fetchNotifications]);


    const markAsRead = async (id?: string) => {
        try {
            const res = await fetch('/api/user/notifications', {
                method: 'PATCH',
                credentials: 'include',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ id }),
            });
            if (res.ok) {
                if (id) {
                    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
                } else {
                    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
                }
            }
        } catch (e) {
            console.error('Failed to mark as read:', e);
        }
    };

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    return (
        <div className="relative" ref={dropdownRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="relative p-2 rounded-xl text-foreground hover:text-primary hover:bg-muted transition-all outline-none"
                aria-label="Notifications"
            >
                <Bell className="w-5 h-5" />
                {unreadCount > 0 && (
                    <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-primary text-primary-foreground text-[8px] font-black rounded-full flex items-center justify-center border-2 border-background shadow-[0_0_10px_rgba(31,111,91,0.3)]">
                        {unreadCount > 9 ? '9+' : unreadCount}
                    </span>
                )}
            </button>

            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: 10 }}
                        className="absolute right-0 mt-3 w-[360px] max-w-[calc(100vw-2rem)] bg-card border border-border rounded-[32px] shadow-[0_24px_48px_-12px_rgba(0,0,0,0.5)] overflow-hidden z-[100]"
                    >
                        <div className="p-6 border-b border-border bg-muted/20 flex items-center justify-between">
                            <h3 className="text-xs font-black text-foreground uppercase tracking-widest flex items-center gap-2">
                                <Bell size={14} className="text-primary" />
                                Notifications
                            </h3>
                            {unreadCount > 0 && (
                                <button 
                                    onClick={() => markAsRead()}
                                    className="text-[9px] font-black text-[var(--color-brand-red)] uppercase tracking-widest hover:brightness-125 transition-all"
                                >
                                    Clear All
                                </button>
                            )}
                        </div>

                        <div className="max-h-[400px] overflow-y-auto custom-scrollbar p-2">
                            {notifications.length > 0 ? (
                                notifications.map((n) => (
                                    <div
                                        key={n.id}
                                        onClick={() => !n.isRead && markAsRead(n.id)}
                                        className={`p-4 rounded-2xl transition-all cursor-pointer group relative ${
                                            n.isRead ? 'opacity-40 grayscale' : 'bg-muted/50 border border-border hover:border-primary/30 hover:bg-muted'
                                        }`}
                                    >
                                        <div className="flex gap-4">
                                            <div className="mt-1">
                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${n.isRead ? 'bg-white/5 text-gray-500' : 'bg-green-500/10 text-green-500'}`}>
                                                    <CheckCircle2 size={16} />
                                                </div>
                                            </div>
                                            <div className="flex-1 space-y-1">
                                                <p className="text-xs font-bold text-foreground leading-relaxed">
                                                    {n.message}
                                                </p>
                                                <div className="flex items-center gap-2 text-[10px] text-muted-foreground font-black uppercase tracking-widest">
                                                    <Clock size={10} />
                                                    {new Date(n.createdAt).toLocaleDateString()}
                                                </div>
                                            </div>
                                            {!n.isRead && (
                                                <div className="absolute top-4 right-4 w-1.5 h-1.5 rounded-full bg-[var(--color-brand-red)]" />
                                            )}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="py-12 text-center space-y-4">
                                    <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto border border-white/5 border-dashed">
                                        <MessageSquare className="w-8 h-8 text-gray-700" />
                                    </div>
                                    <p className="text-[10px] font-black text-gray-600 uppercase tracking-widest">
                                        No new signals detected
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="p-4 border-t border-black/5 bg-black/[0.01] text-center">
                            <button 
                                onClick={() => setIsOpen(false)}
                                className="text-[10px] font-black text-[#2E8B75] uppercase tracking-widest hover:text-[#1F6F5B] transition-all"
                            >
                                Close Signals
                            </button>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

