        Accept: 'application/json',
      },
    })
      .then(res => res.json())
      .then(data => { setUserStatus(data); setStatusLoading(false); })
      .catch((err) => {
        console.error('[CHECKOUT] status fetch failed', err);
        setStatusLoading(false);
      });
  }, []);

  // Plan Details 
