/**
 * Node Settings Panel Component
 */
export function NodeSettingsPanel({ node, onClose, onUpdateSettings }: NodeSettingsPanelProps) {
    const t = useTranslations('tools');
    const tWorkflow = useTranslations('workflow');
    const tCommon = useTranslations('common');
    const tRoot = useTranslations(); // Root level translations for tool-specific settings
    const messages = useMessages(); // Get raw messages for nested key lookup
    const locale = useLocale() as Locale;

    const [settings, setSettings] = useState<Record<string, unknown>>({});

    const toolSettingsConfigs = getToolSettingsConfig();

    const config = node?.data.toolId
        ? toolSettingsConfigs[node.data.toolId]
        : null;

    const getToolTitle = (): string => {
        if (!node) return '';
        const content = getToolContent(locale, node.data.toolId);
        return content?.title || node.data.label;
    };

    const getTranslation = (key: string, fallback?: string): string => {
        // If the key doesn't contain a dot, it might be a literal value (like 'A4', 'PNG', 'Letter')
        // These are not translation keys, just direct values to display
        if (!key.includes('.')) {
            // Return the key directly as it's likely a literal value
            return fallback || key;
        }

        // Handle common namespace keys
        if (key.startsWith('common.')) {
            const commonKey = key.replace('common.', '');
            try {
                const result = tCommon(commonKey);
                if (result && typeof result === 'string' && !result.startsWith('MISSING') && result !== commonKey) {
                    return result;
                }
            } catch {
                // Continue
            }
        }

        // Try tools namespace with explicit path navigation for nested keys
        try {
            // For keys like "watermark.optionsTitle", try to access nested structure
            const parts = key.split('.');
            if (parts.length > 1) {
                // Try to get the raw object and navigate using messages from useMessages()
                try {
                    // Access the tools namespace from messages
                    const toolsMessages = messages?.tools as Record<string, unknown> | undefined;
                    if (toolsMessages && typeof toolsMessages === 'object') {
                        let value: unknown = toolsMessages;
                        for (const part of parts) {
                            value = (value as Record<string, unknown>)?.[part];
                        }
                        if (value && typeof value === 'string') {
                            return value;
                        }
                    }
                } catch {
                    // Continue to simple lookup
                }
            }

            // Try simple lookup - with existence check to avoid console errors
            try {
                // Check if the key exists in the current namespace (tools)
                const toolsMessages = messages?.tools as Record<string, unknown> | undefined;
                let exists = false;
                if (toolsMessages && typeof toolsMessages === 'object') {
                    let current: any = toolsMessages;
                    const parts = key.split('.');
                    for (const part of parts) {
                        if (current && typeof current === 'object' && part in current) {
                            current = current[part];
                            exists = true;
                        } else {
                            exists = false;
                            break;
                        }
                    }
                }

                if (exists) {
                    const result = t(key);
                    if (result && typeof result === 'string' && result !== key && !result.startsWith('MISSING')) {
                        return result;
                    }
                }
            } catch {
                // Continue to root level
            }
        } catch {
            // Continue to root level
        }

        // Try root level translations
        try {
            // Existence check for rootResult
            let exists = false;
            if (messages && typeof messages === 'object') {
                let current: any = messages;
                const parts = key.split('.');
                for (const part of parts) {
                    if (current && typeof current === 'object' && part in current) {
                        current = current[part];
                        exists = true;
                    } else {
                        exists = false;
                        break;
                    }
                }
            }

            if (exists) {
                const rootResult = tRoot(key);
                if (rootResult && typeof rootResult === 'string' && rootResult !== key && !rootResult.startsWith('MISSING')) {
                    return rootResult;
                }
            }
        } catch {
            // Continue to fallback
        }

        // Return fallback or extract last part of key as readable label
        const extracted = key.split('.').pop()?.replace(/([A-Z])/g, ' $1').trim() || key;
        return fallback || extracted;
    };

    useEffect(() => {
        if (node && config) {
            const initialSettings: Record<string, unknown> = {};
            config.fields.forEach(field => {
                initialSettings[field.key] = node.data.settings?.[field.key] ?? field.defaultValue;
            });
            setSettings(initialSettings);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [node?.id, node?.data.toolId]);

    const handleFieldChange = (key: string, value: unknown) => {
        setSettings(prev => ({ ...prev, [key]: value }));
    };

    const handleApply = () => {
        if (node) {
            onUpdateSettings(node.id, settings);
            onClose();
        }
    };

    const handleReset = () => {
        if (config) {
            const defaultSettings: Record<string, unknown> = {};
            config.fields.forEach(field => {
                defaultSettings[field.key] = field.defaultValue;
            });
            setSettings(defaultSettings);
        }
    };

    if (!node) return null;

    return (
        <div className="fixed right-0 top-0 h-full w-80 bg-[hsl(var(--color-background))] border-l border-[hsl(var(--color-border))] shadow-xl z-[100] flex flex-col animate-in slide-in-from-right duration-200">
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-[hsl(var(--color-border))] bg-[hsl(var(--color-muted)/0.3)]">
                <div className="flex items-center gap-2">
                    <Settings className="w-5 h-5 text-[hsl(var(--color-primary))]" />
                    <h3 className="font-medium text-[hsl(var(--color-foreground))] truncate max-w-[180px]">
                        {getToolTitle()}
                    </h3>
                </div>
                <button
                    onClick={onClose}
                    className="p-1.5 rounded-md hover:bg-[hsl(var(--color-muted))] transition-colors"
                >
                    <X className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-4">
                {!config || config.fields.length === 0 ? (
                    <div className="text-center py-8">
                        <Settings className="w-12 h-12 mx-auto text-[hsl(var(--color-muted-foreground))] opacity-50" />
                        <p className="mt-3 text-sm text-[hsl(var(--color-muted-foreground))]">
                            {tWorkflow('noSettings') || 'No configurable settings for this tool'}
                        </p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
                            {getTranslation(config.titleKey, 'Settings')}
                        </p>

                        {config.fields.map(field => {
                            // Check showWhen condition
                            if (field.showWhen) {
                                const depValue = settings[field.showWhen.field];
                                if (depValue !== field.showWhen.value) return null;
                            }

                            return (
                            <div key={field.key} className="space-y-1.5">
                                <label className="block text-sm font-medium text-[hsl(var(--color-foreground))]">
                                    {getTranslation(field.labelKey)}
                                </label>

                                {field.descriptionKey && (
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                                        {getTranslation(field.descriptionKey)}
                                    </p>
                                )}

                                {field.type === 'text' && (
                                    <input
                                        type="text"
                                        value={(settings[field.key] as string) || ''}
                                        onChange={(e) => handleFieldChange(field.key, e.target.value)}
                                        placeholder={field.placeholderKey ? getTranslation(field.placeholderKey) : undefined}
                                        className="w-full px-3 py-2 text-sm rounded-md border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))] placeholder:text-[hsl(var(--color-muted-foreground))]"
                                    />
                                )}

                                {field.type === 'number' && (
                                    <input
                                        type="number"
                                        value={(settings[field.key] as number) ?? field.defaultValue}
                                        onChange={(e) => handleFieldChange(field.key, Number(e.target.value))}
                                        min={field.min}
                                        max={field.max}
                                        placeholder={field.placeholderKey ? getTranslation(field.placeholderKey) : undefined}
                                        className="w-full px-3 py-2 text-sm rounded-md border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))] placeholder:text-[hsl(var(--color-muted-foreground))]"
                                    />
                                )}

                                {field.type === 'select' && (
                                    <>
                                    <select
                                        value={(settings[field.key] as string) || ''}
                                        onChange={(e) => handleFieldChange(field.key, e.target.value)}
                                        className="w-full px-3 py-2 text-sm rounded-md border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
                                    >
                                        {field.options?.map(opt => (
                                            <option key={opt.value} value={opt.value}>
                                                {getTranslation(opt.labelKey, opt.labelKey)}
                                            </option>
                                        ))}
                                    </select>
                                    {(() => {
                                        const selectedOpt = field.options?.find(o => o.value === (settings[field.key] as string));
                                        return selectedOpt?.descriptionKey ? (
                                            <p className="text-xs text-[hsl(var(--color-muted-foreground))] mt-1">
                                                {getTranslation(selectedOpt.descriptionKey)}
                                            </p>
                                        ) : null;
                                    })()}
                                    </>
                                )}

                                {field.type === 'checkbox' && (
                                    <label className="flex items-center gap-2 cursor-pointer">
                                        <input
                                            type="checkbox"
                                            checked={(settings[field.key] as boolean) || false}
                                            onChange={(e) => handleFieldChange(field.key, e.target.checked)}
                                            className="w-4 h-4 rounded border-[hsl(var(--color-border))] text-[hsl(var(--color-primary))] focus:ring-[hsl(var(--color-primary))]"
                                        />
                                    </label>
                                )}

                                {field.type === 'range' && (
                                    <div className="space-y-1">
                                        <input
                                            type="range"
                                            value={(settings[field.key] as number) ?? field.defaultValue}
                                            onChange={(e) => handleFieldChange(field.key, Number(e.target.value))}
                                            min={field.min}
                                            max={field.max}
                                            step={field.step}
                                            className="w-full h-2 rounded-lg appearance-none cursor-pointer bg-[hsl(var(--color-muted))]"
                                        />
                                        <div className="flex justify-between text-xs text-[hsl(var(--color-muted-foreground))]">
                                            <span>{field.min}</span>
                                            <span className="font-medium text-[hsl(var(--color-foreground))]">
                                                {field.key.includes('opacity') || field.key.includes('quality')
                                                    ? `${Math.round((settings[field.key] as number || 0) * 100)}%`
                                                    : settings[field.key] as number
                                                }
                                            </span>
                                            <span>{field.max}</span>
                                        </div>
                                    </div>
                                )}

                                {field.type === 'color' && (
                                    <div className="flex items-center gap-2">
                                        <input
                                            type="color"
                                            value={(settings[field.key] as string) || '#000000'}
                                            onChange={(e) => handleFieldChange(field.key, e.target.value)}
                                            className="w-10 h-10 rounded border border-[hsl(var(--color-border))] cursor-pointer"
                                        />
                                        <input
                                            type="text"
                                            value={(settings[field.key] as string) || ''}
                                            onChange={(e) => handleFieldChange(field.key, e.target.value)}
                                            className="flex-1 px-3 py-2 text-sm rounded-md border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
                                        />
                                    </div>
                                )}

                                {field.type === 'file' && (
                                    <div className="space-y-1">
                                        <input
                                            type="file"
                                            accept={field.accept}
                                            onChange={(e) => {
                                                const file = e.target.files?.[0] || null;
                                                handleFieldChange(field.key, file);
                                            }}
                                            className="w-full text-sm file:mr-3 file:py-1.5 file:px-3 file:rounded-md file:border-0 file:text-sm file:font-medium file:bg-[hsl(var(--color-primary))] file:text-[hsl(var(--color-primary-foreground))] hover:file:opacity-90 cursor-pointer"
                                        />
                                        {settings[field.key] instanceof File && (
                                            <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                                                {(settings[field.key] as File).name}
                                            </p>
                                        )}
                                    </div>
                                )}

                                {field.type === 'password' && (
                                    <input
                                        type="password"
                                        value={(settings[field.key] as string) || ''}
                                        onChange={(e) => handleFieldChange(field.key, e.target.value)}
                                        placeholder={field.placeholderKey ? getTranslation(field.placeholderKey) : undefined}
                                        className="w-full px-3 py-2 text-sm rounded-md border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))] placeholder:text-[hsl(var(--color-muted-foreground))]"
                                    />
                                )}
                            </div>
                            );
                        })}
                    </div>
                )}
            </div>

            {/* Footer */}
            {config && config.fields.length > 0 && (
                <div className="flex items-center justify-between gap-3 px-4 py-3 border-t border-[hsl(var(--color-border))] bg-[hsl(var(--color-muted)/0.3)]">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={handleReset}
                    >
                        <RotateCcw className="w-4 h-4 mr-2" />
                        {tWorkflow('reset') || 'Reset'}
                    </Button>
                    <div className="flex gap-2">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={onClose}
                        >
                            {tWorkflow('cancel') || 'Cancel'}
                        </Button>
                        <Button
                            variant="primary"
                            size="sm"
                            onClick={handleApply}
                        >
                            {tWorkflow('apply') || 'Apply'}
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default NodeSettingsPanel;

'use client';

import React, { useState, useMemo } from 'react';
import { useTranslations, useLocale } from 'next-intl';
import { PDF_TOOLS as tools } from '@/config/pdf-tools';
import { getToolContent } from '@/config/pdf-tool-content';
import { ToolNodeData } from '@/types/workflow';
import * as LucideIcons from 'lucide-react';
import { Search, ChevronDown, ChevronRight, GripVertical, PanelLeftClose, PanelLeftOpen } from 'lucide-react';
import { Locale } from '@/lib/i18n/config';

interface ToolSidebarProps {
    onDragStart: (event: React.DragEvent, nodeData: ToolNodeData) => void;
    isCollapsed?: boolean;
    onToggleCollapse?: () => void;
}

interface CategoryGroup {
    id: string;
    name: string;
    icon: string;
    tools: typeof tools;
}

/**
 * Tool Sidebar for the workflow editor
 * Displays available tools grouped by category
 */
export function ToolSidebar({ onDragStart, isCollapsed = false, onToggleCollapse }: ToolSidebarProps) {
    const tWorkflow = useTranslations('workflow');
    const locale = useLocale() as Locale;

    const [searchQuery, setSearchQuery] = useState('');
    const [expandedCategories, setExpandedCategories] = useState<Set<string>>(
        new Set(['organize-manage', 'convert-to-pdf'])
    );

    // Format tool ID to human readable name
    const formatToolId = (id: string): string => {
        return id
            .split('-')
            .map(word => word.charAt(0).toUpperCase() + word.slice(1))
            .join(' ');
    };

    // Helper function to get tool name with fallback using getToolContent
    const getToolName = (toolId: string): string => {
        const content = getToolContent(locale, toolId);
        if (content && content.title) {
            return content.title;
        }
        return formatToolId(toolId);
    };

    // Group tools by category
    const categories: CategoryGroup[] = (() => {
        const categoryMap: Record<string, typeof tools> = {};

        // Tools that require interactive UI and should be excluded from workflow
        const interactiveToolsBlacklist = new Set([
            'pdf-multi-tool',    // Interactive multi-tool
            'edit-pdf',          // Canvas editor required
            'sign-pdf',          // Signature drawing required
            'crop-pdf',          // Visual crop selection required
            'bookmark',          // Bookmark editing required
            'add-stamps',        // Position interaction required
            'form-filler',       // Form field interaction required
            'form-creator',      // Form design required
            'rotate-custom',     // Per-page rotation settings required
            'view-metadata',     // Read-only viewer tool
            'compare-pdfs',      // Visual comparison interface required
            'add-attachments',   // File selection for attachments required
            'edit-attachments',  // Attachment management interaction required
            'page-dimensions',   // Analysis only, no PDF output
            'validate-signature', // Read-only signature verification, no PDF output
            'pdf-to-docx',       // Workflow executor not yet implemented
            'pdf-to-pptx',       // Workflow executor not yet implemented
            'pdf-to-excel',      // Workflow executor not yet implemented
        ]);

        tools
            .filter(tool => !interactiveToolsBlacklist.has(tool.id))
            .forEach(tool => {
                if (!categoryMap[tool.category]) {
                    categoryMap[tool.category] = [];
                }
                categoryMap[tool.category].push(tool);
            });

        const categoryOrder = [
            'organize-manage',
            'edit-annotate',
            'convert-to-pdf',
            'convert-from-pdf',
            'optimize-repair',
            'secure-pdf',
        ];

        const categoryNames: Record<string, string> = {
            'organize-manage': 'Organize & Manage',
            'edit-annotate': 'Edit & Annotate',
            'convert-to-pdf': 'Convert to PDF',
            'convert-from-pdf': 'Convert from PDF',
            'optimize-repair': 'Optimize & Repair',
            'secure-pdf': 'Security & Privacy',
        };

        const categoryIcons: Record<string, string> = {
            'organize-manage': 'files',
            'edit-annotate': 'pencil',
            'convert-to-pdf': 'file-up',
            'convert-from-pdf': 'file-down',
            'optimize-repair': 'zap',
            'secure-pdf': 'shield',
        };

        return categoryOrder
            .filter(cat => categoryMap[cat])
            .map(cat => ({
                id: cat,
                name: categoryNames[cat],
                icon: categoryIcons[cat],
                tools: categoryMap[cat],
            }));
    })();

    // Filter tools based on search query
    const filteredCategories = (() => {
        if (!searchQuery.trim()) return categories;

        const query = searchQuery.toLowerCase();
        return categories
            .map(cat => ({
                ...cat,
                tools: cat.tools.filter(tool => {
                    const translatedName = getToolName(tool.id);
                    return (
                        tool.id.toLowerCase().includes(query) ||
                        translatedName.toLowerCase().includes(query)
                    );
                }),
            }))
            .filter(cat => cat.tools.length > 0);
    }, [categories, searchQuery]);

    const toggleCategory = (categoryId: string) => {
        setExpandedCategories(prev => {
            const next = new Set(prev);
            if (next.has(categoryId)) {
                next.delete(categoryId);
            } else {
                next.add(categoryId);
            }
            return next;
        });
    };

    const handleDragStart = (e: React.DragEvent, tool: typeof tools[0]) => {
        const nodeData: ToolNodeData = {
            toolId: tool.id,
            label: getToolName(tool.id),
            icon: tool.icon,
            category: tool.category,
            acceptedFormats: tool.acceptedFormats,
            outputFormat: tool.outputFormat,
            status: 'idle',
            progress: 0,
        };
        onDragStart(e, nodeData);
    };

    // Get icon component dynamically
    const getIcon = (iconName: string) => {
        const pascalName = iconName
            .split('-')
            .map(word => word.charAt(0).toUpperCase() + word.slice(1))
            .join('');
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        return (LucideIcons as any)[pascalName] || LucideIcons.FileText;
    };

    // Collapsed view
    if (isCollapsed) {
        return (
            <div className="w-12 h-full bg-[hsl(var(--color-background))] border-r border-[hsl(var(--color-border))] flex flex-col items-center py-2">
                <button
                    onClick={onToggleCollapse}
                    className="p-2 rounded-lg hover:bg-[hsl(var(--color-muted))] transition-colors mb-2"
                    title={tWorkflow('toolbox') || 'Toolbox'}
                >
                    <PanelLeftOpen className="w-5 h-5 text-[hsl(var(--color-primary))]" />
                </button>
                <div className="w-8 h-px bg-[hsl(var(--color-border))] mb-2" />
                {/* Show category icons when collapsed */}
                {categories.slice(0, 6).map(category => {
                    const CategoryIcon = getIcon(category.icon);
                    return (
                        <button
                            key={category.id}
                            onClick={onToggleCollapse}
                            className="p-2 rounded-lg hover:bg-[hsl(var(--color-muted))] transition-colors mb-1"
                            title={category.name}
                        >
                            <CategoryIcon className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                        </button>
                    );
                })}
            </div>
        );
    }

    return (
        <div className="w-72 h-full bg-[hsl(var(--color-background))] border-r border-[hsl(var(--color-border))] flex flex-col">
            {/* Header */}
            <div className="p-4 border-b border-[hsl(var(--color-border))] flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold text-[hsl(var(--color-foreground))]">
                        {tWorkflow('toolbox') || 'Tool Box'}
                    </h2>
                    <p className="text-xs text-[hsl(var(--color-muted-foreground))] mt-1">
                        {tWorkflow('dragToAdd') || 'Drag tools to add to workflow'}
                    </p>
                </div>
                <button
                    onClick={onToggleCollapse}
                    className="p-1.5 rounded-lg hover:bg-[hsl(var(--color-muted))] transition-colors"
                    title="Collapse sidebar"
                >
                    <PanelLeftClose className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                </button>
            </div>

            {/* Search */}
            <div className="p-3 border-b border-[hsl(var(--color-border))]">
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                    <input
                        type="text"
                        placeholder={tWorkflow('searchTools') || 'Search tools...'}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-9 pr-3 py-2 text-sm rounded-lg border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))] placeholder:text-[hsl(var(--color-muted-foreground))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
                    />
                </div>
            </div>

            {/* Tools List */}
            <div className="flex-1 overflow-y-auto">
                {filteredCategories.map(category => {
                    const isExpanded = expandedCategories.has(category.id);
                    const CategoryIcon = getIcon(category.icon);

                    return (
                        <div key={category.id} className="border-b border-[hsl(var(--color-border))]">
                            {/* Category Header */}
                            <button
                                onClick={() => toggleCategory(category.id)}
                                className="w-full flex items-center gap-2 px-4 py-3 text-left hover:bg-[hsl(var(--color-muted)/0.5)] transition-colors"
                            >
                                {isExpanded ? (
                                    <ChevronDown className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                                ) : (
                                    <ChevronRight className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                                )}
                                <CategoryIcon className="w-4 h-4 text-[hsl(var(--color-primary))]" />
                                <span className="text-sm font-medium text-[hsl(var(--color-foreground))]">
                                    {category.name}
                                </span>
                                <span className="ml-auto text-xs text-[hsl(var(--color-muted-foreground))]">
                                    {category.tools.length}
                                </span>
                            </button>

                            {/* Tools in Category */}
                            {isExpanded && (
                                <div className="pb-2">
                                    {category.tools.map(tool => {
                                        const ToolIcon = getIcon(tool.icon);

                                        return (
                                            <div
                                                key={tool.id}
                                                draggable
                                                onDragStart={(e) => handleDragStart(e, tool)}
                                                className="flex items-center gap-2 px-4 py-2 mx-2 rounded-md cursor-grab hover:bg-[hsl(var(--color-muted))] active:cursor-grabbing transition-colors group"
                                            >
                                                <GripVertical className="w-3 h-3 text-[hsl(var(--color-muted-foreground))] opacity-0 group-hover:opacity-100 transition-opacity" />
                                                <ToolIcon className="w-4 h-4 text-[hsl(var(--color-muted-foreground))]" />
                                                <span className="text-sm text-[hsl(var(--color-foreground))] truncate flex-1">
                                                    {getToolName(tool.id)}
                                                </span>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Footer */}
            <div className="p-3 border-t border-[hsl(var(--color-border))] bg-[hsl(var(--color-muted)/0.3)]">
                <p className="text-xs text-center text-[hsl(var(--color-muted-foreground))]">
                    {tools.length} {tWorkflow('toolsAvailable') || 'tools available'}
                </p>
            </div>
        </div>
    );
}

export default ToolSidebar;

'use client';

import React, { useState, useCallback, useRef } from 'react';
import { useTranslations } from 'next-intl';
import { WorkflowExecutionState, WorkflowNode, WorkflowEdge, WorkflowValidation, WorkflowOutputFile } from '@/types/workflow';
import { Button } from '@/components/ui/Button';
import { FileListPanel } from './FileListPanel';
import {
    Play,
    Pause,
    Square,
    Download,
    Save,
    Upload,
    Trash2,
    AlertCircle,
    CheckCircle,
    XCircle,
    Loader2,
    Edit2,
    RefreshCcw,
    RotateCcw,
} from 'lucide-react';

interface WorkflowControlsProps {
    nodes: WorkflowNode[];
    edges: WorkflowEdge[];
    executionState: WorkflowExecutionState;
    validation: WorkflowValidation;
    onExecute: (files: File[]) => void;
    onStop: () => void;
    onSave: (name: string, description?: string) => void;
    onClear: () => void;
    onClearState?: () => void;
    onRetry?: () => void;
    onImport: (file: File) => void;
    onFilesChange?: (files: File[]) => void;
}

/**
 * Workflow Controls Toolbar
 * Provides execution, save, load, and validation controls
 */
export function WorkflowControls({
    nodes,
    edges,
    executionState,
    validation,
    onExecute,
    onStop,
    onSave,
    onClear,
    onClearState,
    onRetry,
    onImport,
    onFilesChange,
}: WorkflowControlsProps) {
    const tWorkflow = useTranslations('workflow');
    const tCommon = useTranslations('common');

    const [showSaveDialog, setShowSaveDialog] = useState(false);
    const [showFileListPanel, setShowFileListPanel] = useState(false);
    const [workflowName, setWorkflowName] = useState('');
    const [workflowDescription, setWorkflowDescription] = useState('');
    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const importInputRef = useRef<HTMLInputElement>(null);

    const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        setSelectedFiles(files);
        onFilesChange?.(files);
    }, [onFilesChange]);

    const handleExecute = useCallback(() => {
        if (selectedFiles.length > 0) {
            Promise.resolve(onExecute(selectedFiles)).catch((err) => {
                console.error('[Workflow] Unhandled execution error:', err);
            });
        }
    }, [selectedFiles, onExecute]);

    const handleSave = useCallback(() => {
        if (workflowName.trim()) {
            onSave(workflowName.trim(), workflowDescription.trim() || undefined);
            setShowSaveDialog(false);
            setWorkflowName('');
            setWorkflowDescription('');
        }
    }, [workflowName, workflowDescription, onSave]);

    const handleImportClick = useCallback(() => {
        importInputRef.current?.click();
    }, []);

    const handleImportFile = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            onImport(file);
            e.target.value = '';
        }
    }, [onImport]);

    const isRunning = executionState.status === 'running';
    const canExecute = nodes.length > 0 && selectedFiles.length > 0 && validation.isValid && !isRunning;

    return (
        <>
            <div className="flex items-center justify-between px-4 py-3 bg-[hsl(var(--color-background))] border-b border-[hsl(var(--color-border))]">
                {/* Left: File input and execute */}
                <div className="flex items-center gap-3">
                    {/* File selection */}
                    <div className="flex items-center gap-2">
                        <input
                            ref={fileInputRef}
                            type="file"
                            multiple
                            accept=".pdf,.jpg,.jpeg,.png,.webp,.bmp,.tiff,.tif,.svg,.heic,.heif,.txt,.json,.md,.markdown,.doc,.docx,.odt,.rtf,.xls,.xlsx,.ods,.csv,.ppt,.pptx,.odp,.epub,.mobi,.azw,.azw3,.xps,.djvu,.djv,.fb2,.cbz,.zip,.eml,.msg"
                            onChange={handleFileSelect}
                            className="hidden"
                        />
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={() => fileInputRef.current?.click()}
                            disabled={isRunning}
                        >
                            <Upload className="w-4 h-4 mr-2" />
                            {tWorkflow('selectFiles') || 'Select Files'}
                        </Button>
                        {selectedFiles.length > 0 && (
                            <button
                                onClick={() => setShowFileListPanel(true)}
                                disabled={isRunning}
                                className={`
                                    flex items-center gap-2 px-3 py-1.5 rounded-lg 
                                    bg-[hsl(var(--color-primary)/0.1)] 
                                    text-[hsl(var(--color-primary))]
                                    hover:bg-[hsl(var(--color-primary)/0.2)]
                                    transition-colors
                                    ${isRunning ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
                                `}
                                title={tWorkflow('viewEditFiles') || 'View/Edit Files'}
                            >
                                <span className="text-sm font-medium">
                                    {selectedFiles.length} {tWorkflow('filesSelected') || 'files selected'}
                                </span>
                                <Edit2 className="w-3.5 h-3.5" />
                            </button>
                        )}
                    </div>

                    {/* Execute button */}
                    <Button
                        variant="primary"
                        size="sm"
                        onClick={handleExecute}
                        disabled={!canExecute}
                        loading={isRunning}
                    >
                        <Play className="w-4 h-4 mr-2" />
                        {tWorkflow('execute') || 'Execute'}
                    </Button>

                    {/* Stop button */}
                    {isRunning && (
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={onStop}
                            className="text-red-600 border-red-300 hover:bg-red-50"
                        >
                            <Square className="w-4 h-4 mr-2" />
                            {tWorkflow('stop') || 'Stop'}
                        </Button>
                    )}

                    {/* Status */}
                    <StatusIndicator 
                        status={executionState.status} 
                        progress={executionState.progress} 
                        isValid={validation.isValid} 
                        errorCount={validation.errors.length}
                        translations={{
                            running: tWorkflow('running'),
                            complete: tWorkflow('complete'),
                            error: tWorkflow('error'),
                            issues: tWorkflow('issues')
                        }}
                    />
                </div>

                {/* Right: Save, Import, Clear */}
                <div className="flex items-center gap-2">
                    {/* Node count */}
                    <span className="text-sm text-[hsl(var(--color-muted-foreground))] mr-2">
                        {nodes.length} {tWorkflow('nodes') || 'nodes'}
                    </span>

                    {/* Save */}
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setShowSaveDialog(true)}
                        disabled={nodes.length === 0}
                    >
                        <Save className="w-4 h-4 mr-2" />
                        {tCommon('buttons.save') || 'Save'}
                    </Button>

                    {/* Import */}
                    <input
                        ref={importInputRef}
                        type="file"
                        accept=".json,.workflow.json"
                        onChange={handleImportFile}
                        className="hidden"
                    />
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleImportClick}
                    >
                        <Download className="w-4 h-4 mr-2" />
                        {tWorkflow('import') || 'Import'}
                    </Button>

                    {/* Clear */}
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={onClear}
                        disabled={nodes.length === 0 || isRunning}
                        className="text-red-600 hover:text-red-700 hover:bg-red-50"
                    >
                        <Trash2 className="w-4 h-4 mr-2" />
                        {tWorkflow('clear') || 'Clear'}
                    </Button>
                </div>
            </div>

            {/* Download output button */}
            {executionState.status === 'complete' && executionState.outputFiles && executionState.outputFiles.length > 0 && (
                <div className="px-4 py-2 bg-green-50 border-b border-green-200">
                    <div className="flex items-center justify-between">
                        <span className="text-sm text-green-700">
                            {tWorkflow('workflowComplete') || 'Workflow completed successfully!'}
                        </span>
                        <Button
                            variant="primary"
                            size="sm"
                            onClick={() => {
                                executionState.outputFiles?.forEach((item, index) => {
                                    let blob: Blob;
                                    let filename: string;

                                    if (item instanceof Blob) {
                                        blob = item;
                                        filename = `output_${index + 1}.pdf`;
                                    } else {
                                        blob = item.blob;
                                        filename = item.filename || `output_${index + 1}.pdf`;
                                    }

                                    // Create URL for download
                                    const url = URL.createObjectURL(blob);
                                    const a = document.createElement('a');
                                    a.href = url;
                                    a.download = filename;
                                    document.body.appendChild(a);
                                    a.click();
                                    document.body.removeChild(a);

                                    // Cleanup URL immediately after download
                                    setTimeout(() => URL.revokeObjectURL(url), 100);
                                });
                            }}
                        >
                            <Download className="w-4 h-4 mr-2" />
                            {tWorkflow('downloadResults') || 'Download Results'}
                        </Button>
                    </div>
                </div>
            )}

            {/* Execution error with retry option */}
            {executionState.status === 'error' && executionState.error && (
                <div className="px-4 py-3 bg-red-50 border-b border-red-200">
                    <div className="flex items-start justify-between gap-3">
                        <div className="flex items-start gap-2 flex-1">
                            <XCircle className="w-5 h-5 text-emerald-500 mt-0.5 flex-shrink-0" />
                            <div className="flex-1">
                                <p className="text-sm font-semibold text-red-700 mb-1">
                                    {tWorkflow('executionFailed') || 'Workflow execution failed'}
                                </p>
                                <p className="text-sm text-red-600 whitespace-pre-wrap">
                                    {executionState.error.message}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                            {onRetry && (
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={onRetry}
                                    className="text-red-600 border-red-300 hover:bg-red-100"
                                >
                                    <RefreshCcw className="w-4 h-4 mr-2" />
                                    {tWorkflow('retry') || 'Retry'}
                                </Button>
                            )}
                            {onClearState && (
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={onClearState}
                                    className="text-red-600 hover:bg-red-100"
                                >
                                    <RotateCcw className="w-4 h-4 mr-2" />
                                    {tWorkflow('reset') || 'Reset'}
                                </Button>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Validation errors */}
            {validation.errors.length > 0 && !isRunning && executionState.status !== 'error' && (
                <div className="px-4 py-2 bg-yellow-50 border-b border-yellow-200">
                    <div className="flex items-start gap-2">
                        <AlertCircle className="w-4 h-4 text-yellow-600 mt-0.5 flex-shrink-0" />
                        <div className="text-sm text-yellow-700">
                            <p className="font-semibold mb-1">{tWorkflow('validationErrors') || 'Validation Errors'}</p>
                            {validation.errors.map((error, index) => (
                                <p key={index} className="ml-2">- {error.message}</p>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* Validation warnings */}
            {validation.warnings.length > 0 && !isRunning && executionState.status !== 'error' && (
                <div className="px-4 py-2 bg-yellow-50 border-b border-yellow-100">
                    <div className="flex items-start gap-2">
                        <AlertCircle className="w-4 h-4 text-yellow-500 mt-0.5 flex-shrink-0" />
                        <div className="text-sm text-yellow-600">
                            <p className="font-semibold mb-1">{tWorkflow('warnings') || 'Warnings'}</p>
                            {validation.warnings.map((warning, index) => (
                                <p key={index} className="ml-2">- {warning.message}</p>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* Save Dialog */}
            {showSaveDialog && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
