'use client';

import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useTranslations } from 'next-intl';
import { Button } from '../ui/Button';
import { configurePdfjsWorker } from '@/lib/pdf/loader';

export interface FilePreviewProps {
  /** File to preview */
  file: File | Blob | null;
  /** File name for display */
  filename?: string;
  /** Custom class name */
  className?: string;
  /** Initial zoom level (default: 1) */
  initialZoom?: number;
  /** Minimum zoom level */
  minZoom?: number;
  /** Maximum zoom level */
  maxZoom?: number;
  /** Zoom step */
  zoomStep?: number;
  /** Show navigation controls */
  showNavigation?: boolean;
  /** Show zoom controls */
  showZoomControls?: boolean;
  /** Callback when page changes */
  onPageChange?: (page: number, totalPages: number) => void;
  /** Callback when zoom changes */
  onZoomChange?: (zoom: number) => void;
}

interface PDFPageInfo {
  pageNumber: number;
  totalPages: number;
}

/**
 * FilePreview Component
 * Requirements: 5.4
 * 
 * Displays PDF thumbnail preview with zoom and navigation support.
 */
export const FilePreview: React.FC<FilePreviewProps> = ({
  file,
  filename,
  className = '',
  initialZoom = 1,
  minZoom = 0.5,
  maxZoom = 3,
  zoomStep = 0.25,
  showNavigation = true,
  showZoomControls = true,
  onPageChange,
  onZoomChange,
}) => {
  const t = useTranslations('common');

  const [zoom, setZoom] = useState(initialZoom);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [pdfDoc, setPdfDoc] = useState<any>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  /**
   * Load PDF document
   */
  useEffect(() => {
    if (!file) {
      setPreviewUrl(null);
      setPdfDoc(null);
      setTotalPages(1);
      setCurrentPage(1);
      return;
    }

    const loadPdf = async () => {
      setIsLoading(true);
      setError(null);

      try {
        // Dynamically import pdfjs-dist
        const pdfjsLib = await import('pdfjs-dist');

        // Set worker source
        configurePdfjsWorker(pdfjsLib);

        // Create blob URL
        const url = URL.createObjectURL(file);
        setPreviewUrl(url);

        // Load PDF document
        const loadingTask = pdfjsLib.getDocument(url);
        const pdf = await loadingTask.promise;

        setPdfDoc(pdf);
        setTotalPages(pdf.numPages);
        setCurrentPage(1);

        onPageChange?.(1, pdf.numPages);
      } catch (err) {
        console.error('Failed to load PDF:', err);
        setError('Failed to load PDF preview');
      } finally {
        setIsLoading(false);
      }
    };

    loadPdf();

    return () => {
      if (previewUrl) {
        URL.revokeObjectURL(previewUrl);
      }
    };
  }, [file, onPageChange]);

  /**
   * Render current page
   */
  useEffect(() => {
    if (!pdfDoc || !canvasRef.current) return;

    const renderPage = async () => {
      try {
        const page = await pdfDoc.getPage(currentPage);
        const canvas = canvasRef.current;
        if (!canvas) return;

        const context = canvas.getContext('2d');
        if (!context) return;

        // Calculate scale based on zoom and container width
        const containerWidth = containerRef.current?.clientWidth || 600;
        const viewport = page.getViewport({ scale: 1 });
        const baseScale = (containerWidth - 40) / viewport.width;
        const scale = baseScale * zoom;

        const scaledViewport = page.getViewport({ scale });

        // Set canvas dimensions
        canvas.height = scaledViewport.height;
        canvas.width = scaledViewport.width;

        // Render page
        const renderContext = {
          canvasContext: context,
          viewport: scaledViewport,
          canvas: canvas,
        };

        await page.render(renderContext).promise;
      } catch (err) {
        console.error('Failed to render page:', err);
      }
    };

    renderPage();
  }, [pdfDoc, currentPage, zoom]);

  /**
   * Handle zoom in
   */
  const handleZoomIn = useCallback(() => {
    setZoom(prev => {
      const newZoom = Math.min(maxZoom, prev + zoomStep);
      onZoomChange?.(newZoom);
      return newZoom;
    });
  }, [maxZoom, zoomStep, onZoomChange]);

  /**
   * Handle zoom out
   */
  const handleZoomOut = useCallback(() => {
    setZoom(prev => {
      const newZoom = Math.max(minZoom, prev - zoomStep);
      onZoomChange?.(newZoom);
      return newZoom;
    });
  }, [minZoom, zoomStep, onZoomChange]);

  /**
   * Handle reset zoom
   */
  const handleResetZoom = useCallback(() => {
    setZoom(1);
    onZoomChange?.(1);
  }, [onZoomChange]);

  /**
   * Handle previous page
   */
  const handlePrevPage = useCallback(() => {
    setCurrentPage(prev => {
      const newPage = Math.max(1, prev - 1);
      onPageChange?.(newPage, totalPages);
      return newPage;
    });
  }, [totalPages, onPageChange]);

  /**
   * Handle next page
   */
  const handleNextPage = useCallback(() => {
    setCurrentPage(prev => {
      const newPage = Math.min(totalPages, prev + 1);
      onPageChange?.(newPage, totalPages);
      return newPage;
    });
  }, [totalPages, onPageChange]);

  /**
   * Handle wheel zoom
   */
  const handleWheel = useCallback((e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      if (e.deltaY < 0) {
        handleZoomIn();
      } else {
        handleZoomOut();
      }
    }
  }, [handleZoomIn, handleZoomOut]);

  // No file state
  if (!file) {
    return (
      <div className={`flex items-center justify-center min-h-[300px] bg-[hsl(var(--color-muted)/0.3)] rounded-[var(--radius-lg)] ${className}`}>
        <p className="text-[hsl(var(--color-muted-foreground))]">
          No file to preview
        </p>
      </div>
    );
  }

  // Loading state
  if (isLoading) {
    return (
      <div className={`flex items-center justify-center min-h-[300px] bg-[hsl(var(--color-muted)/0.3)] rounded-[var(--radius-lg)] ${className}`}>
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 border-2 border-[hsl(var(--color-primary))] border-t-transparent rounded-full animate-spin" />
          <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
            {t('status.loading')}
          </p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className={`flex items-center justify-center min-h-[300px] bg-[hsl(var(--color-muted)/0.3)] rounded-[var(--radius-lg)] ${className}`}>
        <div className="flex flex-col items-center gap-3 text-center p-4">
          <svg
            className="w-12 h-12 text-emerald-500"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
            aria-hidden="true"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={1.5}
              d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
            />
          </svg>
          <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
            {error}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={`flex flex-col ${className}`}>
      {/* Toolbar */}
      <div className="flex items-center justify-between p-2 bg-[hsl(var(--color-muted)/0.5)] rounded-t-[var(--radius-lg)] border-b border-[hsl(var(--color-border))]">
        {/* File name */}
        <div className="flex items-center gap-2 min-w-0">
          <svg
            className="w-5 h-5 text-[hsl(var(--color-muted-foreground))] flex-shrink-0"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
            aria-hidden="true"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={1.5}
              d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z"
            />
          </svg>
          <span className="text-sm text-[hsl(var(--color-foreground))] truncate">
            {filename || 'Document'}
          </span>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-2">
          {/* Zoom controls */}
          {showZoomControls && (
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="sm"
                onClick={handleZoomOut}
                disabled={zoom <= minZoom}
                aria-label="Zoom out"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                </svg>
              </Button>

              <button
                onClick={handleResetZoom}
                className="px-2 py-1 text-xs font-medium text-[hsl(var(--color-muted-foreground))] hover:text-[hsl(var(--color-foreground))] transition-colors"
                aria-label={`Zoom: ${Math.round(zoom * 100)}%`}
              >
                {Math.round(zoom * 100)}%
              </button>

              <Button
                variant="ghost"
                size="sm"
                onClick={handleZoomIn}
                disabled={zoom >= maxZoom}
                aria-label="Zoom in"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
              </Button>
            </div>
          )}

          {/* Page navigation */}
          {showNavigation && totalPages > 1 && (
            <div className="flex items-center gap-1 ml-2 pl-2 border-l border-[hsl(var(--color-border))]">
              <Button
                variant="ghost"
                size="sm"
                onClick={handlePrevPage}
                disabled={currentPage <= 1}
                aria-label="Previous page"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                </svg>
              </Button>

              <span className="text-xs text-[hsl(var(--color-muted-foreground))] whitespace-nowrap">
                {currentPage} / {totalPages}
              </span>

              <Button
                variant="ghost"
                size="sm"
                onClick={handleNextPage}
                disabled={currentPage >= totalPages}
                aria-label="Next page"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                </svg>
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Preview area */}
      <div
        ref={containerRef}
        className="relative flex items-center justify-center overflow-auto bg-[hsl(var(--color-muted)/0.3)] rounded-b-[var(--radius-lg)] min-h-[400px] max-h-[600px]"
        onWheel={handleWheel}
      >
        <canvas
          ref={canvasRef}
          className="max-w-full shadow-lg"
          style={{
            transform: `scale(1)`,
            transformOrigin: 'center center',
          }}
        />
      </div>
    </div>
  );
};

export default FilePreview;

'use client';

import React, { useCallback, useRef, useState, useEffect } from 'react';
import { useTranslations } from 'next-intl';
import { UploadCloud, File, Plus, X } from 'lucide-react';

export interface FileUploaderProps {
  /** Accepted file types (MIME types or extensions) */
  accept?: string[];
  /** Allow multiple file selection */
  multiple?: boolean;
  /** Maximum file size in bytes */
  maxSize?: number;
  /** Maximum number of files */
  maxFiles?: number;
  /** Callback when files are selected */
  onFilesSelected: (files: File[]) => void;
  /** Callback when an error occurs */
  onError?: (error: string) => void;
  /** Custom class name */
  className?: string;
  /** Disabled state */
  disabled?: boolean;
  /** Custom label text */
  label?: string;
  /** Custom description text */
  description?: string;
}

/**
 * FileUploader Component
 * Requirements: 5.2
 * 
 * Supports drag-and-drop, file picker, and paste from clipboard.
 * Beautified with premium UI and glassmorphism.
 */
export const FileUploader: React.FC<FileUploaderProps> = ({
  accept = ['application/pdf'],
  multiple = false,
  maxSize = Infinity, // No limit by default
  maxFiles = 10,
  onFilesSelected,
  onError,
  className = '',
  disabled = false,
  label,
  description,
}) => {
  const t = useTranslations('common');
  const tErrors = useTranslations('errors');

  const [isDragging, setIsDragging] = useState(false);
  const [dragCounter, setDragCounter] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const dropZoneRef = useRef<HTMLDivElement>(null);

  // Generate accept string for input element
  const acceptString = accept.join(',');

  /**
   * Validate files against constraints
   */
  const validateFiles = useCallback((files: File[]): { valid: File[]; errors: string[] } => {
    const valid: File[] = [];
    const errors: string[] = [];

    // Check max files
    if (!multiple && files.length > 1) {
      errors.push('Only one file can be uploaded at a time.');
      return { valid: [files[0]], errors };
    }

    if (files.length > maxFiles) {
      errors.push(`Maximum ${maxFiles} files allowed.`);
      files = files.slice(0, maxFiles);
    }

    for (const file of files) {
      // Check file size (skip if no limit)
      if (maxSize !== Infinity && file.size > maxSize) {
        const maxSizeMB = Math.round(maxSize / (1024 * 1024));
        errors.push(tErrors('fileTooLarge', { maxSize: maxSizeMB }));
        continue;
      }

      // Check file type
      const isValidType = accept.some(type => {
        // Accept all files
        if (type === '*/*' || type === '*') {
          return true;
        }
        if (type.startsWith('.')) {
          // Extension check
          return file.name.toLowerCase().endsWith(type.toLowerCase());
        }
        if (type.endsWith('/*')) {
          // Wildcard MIME type
          const baseType = type.slice(0, -2);
          return file.type.startsWith(baseType);
        }
        // Exact MIME type match
        return file.type === type;
      });

      // Also check by extension for PDF files
      const isPdfByExtension = file.name.toLowerCase().endsWith('.pdf');
      const acceptsPdf = accept.includes('application/pdf');

      if (!isValidType && !(acceptsPdf && isPdfByExtension)) {
        errors.push(tErrors('fileTypeInvalid', { acceptedTypes: accept.join(', ') }));
        continue;
      }

      valid.push(file);
    }

    return { valid, errors };
  }, [accept, maxSize, maxFiles, multiple, tErrors]);

  /**
   * Handle file selection
   */
  const handleFiles = useCallback((files: FileList | File[]) => {
    if (disabled) return;

    const fileArray = Array.from(files);
    if (fileArray.length === 0) return;

    const { valid, errors } = validateFiles(fileArray);

    if (errors.length > 0 && onError) {
      onError(errors[0]);
    }

    if (valid.length > 0) {
      onFilesSelected(valid);
    }
  }, [disabled, validateFiles, onError, onFilesSelected]);

  /**
   * Handle drag enter
   */
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (disabled) return;

    setDragCounter(prev => prev + 1);
    if (e.dataTransfer.items && e.dataTransfer.items.length > 0) {
      setIsDragging(true);
    }
  }, [disabled]);

  /**
   * Handle drag leave
   */
  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    setDragCounter(prev => {
      const newCount = prev - 1;
      if (newCount === 0) {
        setIsDragging(false);
      }
      return newCount;
    });
  }, []);

  /**
   * Handle drag over
   */
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  /**
   * Handle drop
   */
  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();

    setIsDragging(false);
    setDragCounter(0);

    if (disabled) return;

    const files = e.dataTransfer.files;
    handleFiles(files);
  }, [disabled, handleFiles]);

  /**
   * Handle file input change
   */
  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      handleFiles(files);
    }
    // Reset input value to allow selecting the same file again
    e.target.value = '';
  }, [handleFiles]);

  /**
   * Handle click to open file picker
   */
  const handleClick = useCallback(() => {
    if (disabled) return;
    fileInputRef.current?.click();
  }, [disabled]);

  /**
   * Handle keyboard interaction
   */
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (disabled) return;
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      fileInputRef.current?.click();
    }
  }, [disabled]);

  /**
   * Handle paste from clipboard
   */
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      if (disabled) return;

      const items = e.clipboardData?.items;
      if (!items) return;

      const files: File[] = [];
      for (let i = 0; i < items.length; i++) {
        const item = items[i];
        if (item.kind === 'file') {
          const file = item.getAsFile();
          if (file) {
            files.push(file);
          }
        }
      }

      if (files.length > 0) {
        e.preventDefault();
        handleFiles(files);
      }
    };

    document.addEventListener('paste', handlePaste);
    return () => {
      document.removeEventListener('paste', handlePaste);
    };
  }, [disabled, handleFiles]);

  const baseStyles = `
    relative flex flex-col items-center justify-center
    w-full min-h-[250px] p-10
    border-2 border-dashed
    rounded-[2rem]
    transition-all duration-300
    cursor-pointer
    group
  `;

  // Dynamic styles based on state
  const stateStyles = disabled
    ? 'border-[hsl(var(--color-muted))] bg-[hsl(var(--color-muted)/0.3)] cursor-not-allowed opacity-50'
    : isDragging
      ? 'border-[hsl(var(--color-primary))] bg-[hsl(var(--color-primary)/0.05)] scale-[1.01] shadow-2xl shadow-primary/10'
      : `
      border-[hsl(var(--color-border))] 
      bg-[hsl(var(--color-card)/0.5)] 
      hover:border-[hsl(var(--color-primary))] 
      hover:bg-[hsl(var(--color-background))] 
      hover:shadow-xl hover:shadow-[hsl(var(--color-primary)/0.05)]
      glass-card
    `;

  return (
    <div
      ref={dropZoneRef}
      role="button"
      tabIndex={disabled ? -1 : 0}
      aria-label={label || t('buttons.upload')}
      aria-disabled={disabled}
      className={`${baseStyles} ${stateStyles} ${className}`.trim()}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      onDragEnter={handleDragEnter}
      onDragLeave={handleDragLeave}
      onDragOver={handleDragOver}
      onDrop={handleDrop}
    >
      {/* Hidden file input */}
      <input
        ref={fileInputRef}
        type="file"
        accept={acceptString}
        multiple={multiple}
        onChange={handleInputChange}
        className="sr-only"
        tabIndex={-1}
        aria-hidden="true"
        disabled={disabled}
      />

      {/* Decorative background blob */}
      <div className="absolute inset-0 overflow-hidden rounded-[2rem] pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 bg-[hsl(var(--color-primary)/0.03)] rounded-full blur-3xl" />
      </div>

      {/* Upload icon */}
      <div className={`
        mb-6 p-4 rounded-full transition-transform duration-300 group-hover:scale-110
        ${isDragging ? 'bg-[hsl(var(--color-primary)/0.1)] text-[hsl(var(--color-primary))]' : 'bg-[hsl(var(--color-muted))] text-[hsl(var(--color-muted-foreground))] group-hover:bg-[hsl(var(--color-primary)/0.1)] group-hover:text-[hsl(var(--color-primary))]'}
      `}>
        <UploadCloud className="w-10 h-10" aria-hidden="true" />
      </div>

      {/* Label */}
      <p className="text-xl font-semibold text-[hsl(var(--color-foreground))] mb-3 text-center">
        {label || t('buttons.upload')}
      </p>

      {/* Description */}
      <div className="text-sm text-[hsl(var(--color-muted-foreground))] text-center max-w-sm leading-relaxed">
        {description || (
          <>
            <p className="mb-2">{t('fileUploader.dragDrop')}</p>
            <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-[hsl(var(--color-muted)/0.5)] text-xs font-medium">
              <span className="opacity-70">{t('fileUploader.support')}:</span>
              <span>{t('fileUploader.paste')}</span>
            </div>
          </>
        )}
      </div>

      {/* File info hints - only show when multiple files allowed */}
      {multiple && (
        <div className="mt-6 flex flex-wrap gap-2 justify-center">
          <span className="text-xs px-2 py-1 rounded-md bg-[hsl(var(--color-muted))] text-[hsl(var(--color-muted-foreground))]">
            Files: {maxFiles}
          </span>
        </div>
      )}

      {/* Drag overlay */}
      {isDragging && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-[hsl(var(--color-background)/0.9)] backdrop-blur-sm rounded-[2rem] z-10 transition-opacity duration-200">
          <div className="p-4 rounded-full bg-[hsl(var(--color-primary)/0.1)] text-[hsl(var(--color-primary))] mb-4 motion-safe:animate-bounce">
            <Plus className="w-8 h-8" />
          </div>
          <p className="text-xl font-bold text-[hsl(var(--color-primary))]">
            {t('fileUploader.dropToUpload')}
          </p>
        </div>
      )}
    </div>
  );
};

export default FileUploader;

'use client';

import React, { useMemo, useEffect, useRef, useState } from 'react';
import { useTranslations } from 'next-intl';

export type ProcessingStatus = 'idle' | 'uploading' | 'processing' | 'complete' | 'error';

export interface ProcessingProgressProps {
  /** Current progress (0-100) */
  progress: number;
  /** Current processing status */
  status: ProcessingStatus;
  /** Current step message */
  message?: string;
  /** Estimated time remaining in seconds */
  estimatedTime?: number;
  /** Custom class name */
  className?: string;
  /** Show percentage text */
  showPercentage?: boolean;
  /** Show estimated time */
  showEstimatedTime?: boolean;
  /** Callback when cancel is clicked */
  onCancel?: () => void;
}

/**
 * ProcessingProgress Component
 * Requirements: 5.3
 * 
 * Displays progress bar with current step and estimated time.
 */
export const ProcessingProgress: React.FC<ProcessingProgressProps> = ({
  progress,
  status,
  message,
  estimatedTime,
  className = '',
  showPercentage = true,
  showEstimatedTime = true,
  onCancel,
}) => {
  const t = useTranslations('common');

  // Clamp progress between 0 and 100
  const clampedProgress = Math.max(0, Math.min(100, progress));

  // Format estimated time
  const formattedTime = useMemo(() => {
    if (!estimatedTime || estimatedTime <= 0) return null;

    if (estimatedTime < 60) {
      return `${Math.ceil(estimatedTime)}s remaining`;
    }

    const minutes = Math.floor(estimatedTime / 60);
    const seconds = Math.ceil(estimatedTime % 60);

    if (minutes < 60) {
      return `${minutes}m ${seconds}s remaining`;
    }

    const hours = Math.floor(minutes / 60);
    const remainingMinutes = minutes % 60;
    return `${hours}h ${remainingMinutes}m remaining`;
  }, [estimatedTime]);

  // Get status text
  const statusText = useMemo(() => {
    switch (status) {
      case 'idle':
        return t('status.idle');
      case 'uploading':
        return t('status.uploading');
      case 'processing':
        return t('status.processing');
      case 'complete':
        return t('status.complete');
      case 'error':
        return t('status.error');
      default:
        return '';
    }
  }, [status, t]);

  // Get progress bar color based on status
  const progressBarColor = useMemo(() => {
    switch (status) {
      case 'complete':
        return 'bg-green-500';
      case 'error':
        return 'bg-emerald-500';
      case 'uploading':
      case 'processing':
        return 'bg-[hsl(var(--color-primary))]';
      default:
        return 'bg-[hsl(var(--color-muted))]';
    }
  }, [status]);

  // Determine if we should show the cancel button
  const showCancel = onCancel && (status === 'uploading' || status === 'processing');

  // Update announcement when status changes
  const announcement = useMemo(() => {
    let nextAnnouncement = '';
    if (status === 'complete') {
      nextAnnouncement = `${statusText}. ${message || ''}`;
    } else if (status === 'error') {
      nextAnnouncement = `${statusText}. ${message || ''}`;
    } else if (status === 'processing' || status === 'uploading') {
      nextAnnouncement = statusText;
    }
    return nextAnnouncement;
  }, [status, statusText, message]);

  // Don't render if idle
  if (status === 'idle') {
    return null;
  }

  return (
    <div
      className={`w-full ${className}`.trim()}
      role="progressbar"
      aria-valuenow={clampedProgress}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-label={`${statusText}: ${clampedProgress}%`}
    >
      {/* Screen reader announcement for status changes */}
      <div 
        role="status" 
        aria-live="polite" 
        aria-atomic="true" 
        className="sr-only"
      >
        {announcement}
      </div>
      {/* Status and percentage header */}
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
          {/* Status indicator */}
          {(status === 'uploading' || status === 'processing') && (
            <div className="relative">
              <div className="w-4 h-4 rounded-full bg-[hsl(var(--color-primary)/0.3)]" />
              <div className="absolute inset-0 w-4 h-4 rounded-full bg-[hsl(var(--color-primary))] animate-ping opacity-75" />
            </div>
          )}
          {status === 'complete' && (
            <svg
              className="w-5 h-5 text-green-500"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M5 13l4 4L19 7"
              />
            </svg>
          )}
          {status === 'error' && (
            <svg
              className="w-5 h-5 text-emerald-500"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          )}

          {/* Status text */}
          <span className="text-sm font-medium text-[hsl(var(--color-foreground))]">
            {statusText}
          </span>
        </div>

        {/* Percentage */}
        {showPercentage && (
          <span className="text-sm font-medium text-[hsl(var(--color-muted-foreground))]">
            {Math.round(clampedProgress)}%
          </span>
        )}
      </div>

      {/* Progress bar */}
      <div className="relative w-full h-2 bg-[hsl(var(--color-muted))] rounded-full overflow-hidden">
        <div
          className={`absolute left-0 top-0 h-full transition-all duration-300 ease-out rounded-full ${progressBarColor}`}
          style={{ width: `${clampedProgress}%` }}
        />

        {/* Animated shimmer for active states */}
        {(status === 'uploading' || status === 'processing') && clampedProgress < 100 && (
          <div
            className="absolute left-0 top-0 h-full bg-gradient-to-r from-transparent via-[hsl(var(--color-primary-foreground)/0.3)] to-transparent motion-safe:animate-shimmer"
            style={{ width: `${clampedProgress}%` }}
          />
        )}
      </div>

      {/* Message and estimated time */}
      <div className="flex items-center justify-between mt-2">
        {/* Current step message */}
        <p className="text-sm text-[hsl(var(--color-muted-foreground))] truncate flex-1">
          {message || ''}
        </p>

        {/* Estimated time */}
        {showEstimatedTime && formattedTime && (status === 'uploading' || status === 'processing') && (
          <span className="text-xs text-[hsl(var(--color-muted-foreground))] ml-4 whitespace-nowrap">
            {formattedTime}
          </span>
        )}
      </div>

      {/* Cancel button */}
      {showCancel && (
        <div className="mt-3">
          <button
            type="button"
            onClick={onCancel}
            className="text-sm text-[hsl(var(--color-muted-foreground))] hover:text-[hsl(var(--color-foreground))] transition-colors"
            aria-label={t('buttons.cancel')}
          >
            {t('buttons.cancel')}
          </button>
        </div>
      )}
    </div>
  );
};

export default ProcessingProgress;

'use client';
import React, { useMemo } from 'react';
import Link from 'next/link';
import { useTranslations } from 'next-intl';
import { Tool, ToolCategory } from '@/types/tool';
import { Card } from '@/components/ui/Card';
import { ArrowUpRight } from 'lucide-react';
import { getToolIcon } from '@/config/icons';
