                        {formatSize(attachment.data.byteLength)}
                        {attachment.page > 0 && ` • Page ${attachment.page}`}
                      </p>
                    </div>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleDownloadAttachment(attachment)}
                      disabled={isProcessing}
                    >
                      {t('buttons.download') || 'Download'}
