'use client';

import React, { useState, useCallback, useRef, useMemo } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { extractImages, type ExtractedImage, type ExtractImagesOptions } from '@/lib/pdf/processors/extract-images';
import type { ProcessOutput } from '@/types/pdf';
import JSZip from 'jszip';

/**
 * Generate a unique ID for files
 */
function generateId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

interface UploadedFile {
    id: string;
    file: File;
}

export interface ExtractImagesToolProps {
    /** Custom class name */
    className?: string;
}

/**
 * ExtractImagesTool Component
 * Requirements: 5.1, 5.2
 * 
 * Provides the UI for extracting images from PDF files.
 */
export function ExtractImagesTool({ className = '' }: ExtractImagesToolProps) {
    const t = useTranslations('common');
    const tTools = useTranslations('tools');

    // State
    const [files, setFiles] = useState<UploadedFile[]>([]);
    const [status, setStatus] = useState<ProcessingStatus>('idle');
    const [progress, setProgress] = useState(0);
    const [progressMessage, setProgressMessage] = useState('');
    const [extractedImages, setExtractedImages] = useState<ExtractedImage[]>([]);
    const [error, setError] = useState<string | null>(null);

    const [selectedImage, setSelectedImage] = useState<ExtractedImage | null>(null);

    // Filter options
    const [minWidth, setMinWidth] = useState(50);
    const [minHeight, setMinHeight] = useState(50);
    const [minSize, setMinSize] = useState(10); // KB

    // Ref for cancellation
    const cancelledRef = useRef(false);

    /**
     * Handle files selected from uploader
     */
    const handleFilesSelected = useCallback((newFiles: File[]) => {
        const uploadedFiles: UploadedFile[] = newFiles.map(file => ({
            id: generateId(),
            file,
        }));
        setFiles(prev => [...prev, ...uploadedFiles]);
        setError(null);
        setExtractedImages([]);
    }, []);

    /**
     * Handle file upload error
     */
    const handleUploadError = useCallback((errorMessage: string) => {
        setError(errorMessage);
    }, []);

    /**
     * Remove a file from the list
     */
    const handleRemoveFile = useCallback((id: string) => {
        setFiles(prev => prev.filter(f => f.id !== id));
        setExtractedImages([]);
    }, []);

    /**
     * Clear all files
     */
    const handleClearAll = useCallback(() => {
        setFiles([]);
        setExtractedImages([]);
        setError(null);
        setStatus('idle');
        setProgress(0);
    }, []);

    /**
     * Handle extract operation
     */
    const handleExtract = useCallback(async () => {
        if (files.length === 0) {
            setError('Please add at least one PDF file.');
            return;
        }

        cancelledRef.current = false;
        setStatus('processing');
        setProgress(0);
        setError(null);
        setExtractedImages([]);

        const options: ExtractImagesOptions = {
            minWidth,
            minHeight,
            minSize: minSize * 1024, // Convert KB to bytes
        };

        try {
            const output: ProcessOutput = await extractImages(
                files.map(f => f.file),
                options,
                (prog, message) => {
                    if (!cancelledRef.current) {
                        setProgress(prog);
                        setProgressMessage(message || '');
                    }
                }
            );

            if (cancelledRef.current) {
                setStatus('idle');
                return;
            }

            if (output.success && output.metadata?.images) {
                setExtractedImages(output.metadata.images as ExtractedImage[]);
                setStatus('complete');
            } else {
                setError(output.error?.message || 'No images found in the selected PDF(s).');
                setStatus('error');
            }
        } catch (err) {
            if (!cancelledRef.current) {
                setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
                setStatus('error');
            }
        }
    }, [files, minWidth, minHeight, minSize]);

    /**
     * Handle cancel operation
     */
    const handleCancel = useCallback(() => {
        cancelledRef.current = true;
        setStatus('idle');
        setProgress(0);
    }, []);

    /**
     * Download a single image
     */
    const handleDownloadImage = useCallback((image: ExtractedImage) => {
        const blob = new Blob([new Uint8Array(image.data)]);
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = image.name;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }, []);

    /**
     * Download all images as individual files
     */
    const handleDownloadAll = useCallback(() => {
        extractedImages.forEach((image, index) => {
            setTimeout(() => {
                handleDownloadImage(image);
            }, index * 200); // Stagger downloads to avoid browser blocking
        });
    }, [extractedImages, handleDownloadImage]);

    /**
     * Download all images as ZIP
     */
    const handleDownloadZip = useCallback(async () => {
        if (extractedImages.length === 0) return;

        try {
            setStatus('processing');
            setProgress(0);
            setProgressMessage('Creating ZIP archive...');

            const zip = new JSZip();

            extractedImages.forEach((image, index) => {
                setProgress((index / extractedImages.length) * 100);
                zip.file(image.name, new Uint8Array(image.data));
            });

            const zipBlob = await zip.generateAsync({
                type: 'blob',
                compression: 'DEFLATE',
                compressionOptions: { level: 6 }
            });

            const url = URL.createObjectURL(zipBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'extracted-images.zip';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);

            setStatus('complete');
            setProgress(100);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to create ZIP file.');
            setStatus('error');
        }
    }, [extractedImages]);

    /**
     * Format file size
     */
    const formatSize = (bytes: number): string => {
        if (bytes < 1024) return `${bytes} B`;
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
        return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    };

    /**
     * Create image preview URL
     */
    const getImagePreviewUrl = (image: ExtractedImage): string => {
        const blob = new Blob([new Uint8Array(image.data)]);
        return URL.createObjectURL(blob);
    };

    // Memoize image preview URLs
    const imagePreviewUrls = useMemo(() => {
        const urls: Record<number, string> = {};
        extractedImages.forEach(img => {
            urls[img.index] = getImagePreviewUrl(img);
        });
        return urls;
    }, [extractedImages]);

    // Cleanup preview URLs on unmount
    React.useEffect(() => {
        return () => {
            Object.values(imagePreviewUrls).forEach(url => {
                URL.revokeObjectURL(url);
            });
        };
    }, [imagePreviewUrls]);

    const isProcessing = status === 'processing' || status === 'uploading';
    const canExtract = files.length > 0 && !isProcessing;

    return (
        <div className={`space-y-6 ${className}`.trim()}>
            {/* File Upload Area */}
            <FileUploader
                accept={['application/pdf', '.pdf']}
                multiple
                maxFiles={20}
                onFilesSelected={handleFilesSelected}
                onError={handleUploadError}
                disabled={isProcessing}
                label={tTools('extractImages.uploadLabel') || 'Upload PDF Files'}
                description={tTools('extractImages.uploadDescription') || 'Select PDF files to extract images from.'}
            />

            {/* Error Message */}
            {error && (
                <div
                    className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700"
                    role="alert"
                >
                    <p className="text-sm">{error}</p>
                </div>
            )}

            {/* File List */}
            {files.length > 0 && (
                <Card variant="outlined" size="lg">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))]">
                            {tTools('extractImages.filesTitle') || 'Selected Files'} ({files.length})
                        </h3>
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={handleClearAll}
                            disabled={isProcessing}
                        >
                            {t('buttons.clearAll') || 'Clear All'}
                        </Button>
                    </div>

                    <ul className="space-y-2" role="list">
                        {files.map((item) => (
                            <li
                                key={item.id}
                                className="flex items-center gap-3 p-3 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))]"
                            >
                                <svg className="w-8 h-8 text-emerald-500" viewBox="0 0 24 24" fill="currentColor">
                                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                                    <path d="M14 2v6h6" fill="white" />
                                    <text x="7" y="17" fontSize="6" fill="white" fontWeight="bold">PDF</text>
                                </svg>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-medium text-[hsl(var(--color-foreground))] truncate">
                                        {item.file.name}
                                    </p>
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                                        {formatSize(item.file.size)}
                                    </p>
                                </div>
                                <button
                                    type="button"
                                    onClick={() => handleRemoveFile(item.id)}
                                    disabled={isProcessing}
                                    className="p-1 rounded hover:bg-red-100 text-[hsl(var(--color-muted-foreground))] hover:text-red-600"
                                    aria-label={`Remove ${item.file.name}`}
                                >
                                    <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M18 6L6 18M6 6l12 12" />
                                    </svg>
                                </button>
                            </li>
                        ))}
                    </ul>
                </Card>
            )}

            {/* Filter Options */}
            {files.length > 0 && !isProcessing && extractedImages.length === 0 && (
                <Card variant="outlined" size="lg">
                    <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))] mb-4">
                        {tTools('extractImages.filterTitle') || 'Filter Options'}
                    </h3>
                    <p className="text-sm text-[hsl(var(--color-muted-foreground))] mb-4">
                        {tTools('extractImages.filterDescription') || 'Filter out small images (icons, decorations, etc.)'}
                    </p>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                {tTools('extractImages.minWidth') || 'Min Width (px)'}
                            </label>
                            <input
                                type="number"
                                min="0"
                                max="5000"
                                value={minWidth}
                                onChange={(e) => setMinWidth(Math.max(0, parseInt(e.target.value) || 0))}
                                className="w-full px-3 py-2 border border-[hsl(var(--color-border))] rounded-[var(--radius-md)] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                {tTools('extractImages.minHeight') || 'Min Height (px)'}
                            </label>
                            <input
                                type="number"
                                min="0"
                                max="5000"
                                value={minHeight}
                                onChange={(e) => setMinHeight(Math.max(0, parseInt(e.target.value) || 0))}
                                className="w-full px-3 py-2 border border-[hsl(var(--color-border))] rounded-[var(--radius-md)] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                {tTools('extractImages.minSizeKB') || 'Min Size (KB)'}
                            </label>
                            <input
                                type="number"
                                min="0"
                                max="10000"
                                value={minSize}
                                onChange={(e) => setMinSize(Math.max(0, parseInt(e.target.value) || 0))}
                                className="w-full px-3 py-2 border border-[hsl(var(--color-border))] rounded-[var(--radius-md)] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                            />
                        </div>
                    </div>
                </Card>
            )}

            {/* Processing Progress */}
            {isProcessing && (
                <ProcessingProgress
                    progress={progress}
                    status={status}
                    message={progressMessage}
                    onCancel={handleCancel}
                    showPercentage
                />
            )}

            {/* Action Buttons */}
            <div className="flex flex-wrap items-center gap-4">
                <Button
                    variant="primary"
                    size="lg"
                    onClick={handleExtract}
                    disabled={!canExtract}
                    loading={isProcessing}
                >
                    {isProcessing
                        ? (t('status.processing') || 'Processing...')
                        : (tTools('extractImages.extractButton') || 'Extract Images')
                    }
                </Button>
            </div>

            {/* Extracted Images Grid */}
            {extractedImages.length > 0 && (
                <Card variant="outlined" size="lg">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))]">
                            {tTools('extractImages.extractedTitle') || 'Extracted Images'} ({extractedImages.length})
                        </h3>
                        <div className="flex gap-2">
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={handleDownloadAll}
                            >
                                {tTools('extractImages.downloadAll') || 'Download All'}
                            </Button>
                            <Button
                                variant="secondary"
                                size="sm"
                                onClick={handleDownloadZip}
                            >
                                {tTools('extractImages.downloadZip') || 'Download as ZIP'}
                            </Button>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
                        {extractedImages.map((image) => (
                            <div
                                key={image.index}
                                className="group relative rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] overflow-hidden bg-[hsl(var(--color-muted)/0.2)]"
                            >
                                {/* Image Preview with click handler */}
                                <div
                                    className="aspect-square flex items-center justify-center overflow-hidden bg-[hsl(var(--color-muted)/0.1)] cursor-pointer"
                                    onClick={() => setSelectedImage(image)}
                                >
                                    {/* eslint-disable-next-line @next/next/no-img-element */}
                                    <img
                                        src={imagePreviewUrls[image.index]}
                                        alt={image.name}
                                        className="max-w-full max-h-full object-contain transition-transform group-hover:scale-105"
                                        loading="lazy"
                                    />
                                    <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                        <svg className="w-8 h-8 text-white drop-shadow-md" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                            <path d="M15 3h6v6M14 10l6.1-6.1M9 21H3v-6M10 14l-6.1 6.1" />
                                        </svg>
                                    </div>
                                </div>

                                {/* Image Info */}
                                <div className="p-2">
                                    <p className="text-xs font-medium text-[hsl(var(--color-foreground))] truncate" title={image.name}>
                                        {image.name}
                                    </p>
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                                        {image.width}×{image.height} • {formatSize(image.size)}
                                    </p>
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                                        {tTools('extractImages.page') || 'Page'} {image.pageNumber}
                                    </p>
                                </div>

                                {/* Download Button Overlay */}
                                <button
                                    type="button"
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleDownloadImage(image);
                                    }}
                                    className="absolute top-2 right-2 p-1.5 rounded-[var(--radius-md)] bg-[hsl(var(--color-background)/0.9)] border border-[hsl(var(--color-border))] opacity-0 group-hover:opacity-100 transition-opacity hover:bg-[hsl(var(--color-primary))] hover:text-white"
                                    aria-label={`Download ${image.name}`}
                                >
                                    <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                                        <polyline points="7 10 12 15 17 10" />
                                        <line x1="12" y1="15" x2="12" y2="3" />
                                    </svg>
                                </button>
                            </div>
                        ))}
                    </div>
                </Card>
            )}

            {/* Success Message */}
            {status === 'complete' && extractedImages.length > 0 && (
                <div
                    className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700"
                    role="status"
                >
                    <p className="text-sm font-medium">
                        {tTools('extractImages.successMessage') || `Successfully extracted ${extractedImages.length} image(s). Click to download individual images or use "Download as ZIP".`}
                    </p>
                </div>
            )}

            {/* Image Preview Modal */}
            {selectedImage && (
                <div
                    className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4"
                    onClick={() => setSelectedImage(null)}
                >
                    <div
                        className="relative max-w-full max-h-full flex flex-col items-center"
                        onClick={(e) => e.stopPropagation()}
                    >
                        {/* Close Button */}
                        <button
                            className="absolute -top-12 right-0 p-2 text-white hover:text-white/80 transition-colors"
                            onClick={() => setSelectedImage(null)}
                        >
                            <svg className="w-8 h-8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <path d="M18 6L6 18M6 6l12 12" />
                            </svg>
                        </button>

                        {/* Image */}
                        <img
                            src={imagePreviewUrls[selectedImage.index]}
                            alt={selectedImage.name}
                            className="max-w-full max-h-[85vh] object-contain rounded shadow-2xl bg-[hsl(var(--color-background))]"
                        />

                        {/* Info Bar */}
                        <div className="mt-4 flex items-center gap-4 px-6 py-3 bg-[hsl(var(--color-background))] rounded-full shadow-lg">
                            <div className="text-sm text-[hsl(var(--color-foreground))]">
                                <span className="font-medium mr-2">{selectedImage.name}</span>
                                <span className="text-[hsl(var(--color-muted-foreground))]">
                                    {selectedImage.width}×{selectedImage.height} • {formatSize(selectedImage.size)}
                                </span>
                            </div>
                            <div className="h-4 w-px bg-[hsl(var(--color-border))]" />
                            <Button
                                size="sm"
                                variant="primary"
                                onClick={() => handleDownloadImage(selectedImage)}
                            >
                                {t('buttons.download') || 'Download'}
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

export default ExtractImagesTool;

'use client';

import React, { useState, useCallback, useRef } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { extractPages, parsePageSelection } from '@/lib/pdf/processors/extract';
import { configurePdfjsWorker } from '@/lib/pdf/loader';
import type { ProcessOutput } from '@/types/pdf';

export interface ExtractPagesToolProps {
  /** Custom class name */
  className?: string;
}

interface PagePreview {
  pageNumber: number;
  thumbnail?: string;
}

/**
 * ExtractPagesTool Component
 * Requirements: 5.1, 5.2
 * 
 * Provides the UI for extracting specific pages from a PDF.
 */
export function ExtractPagesTool({ className = '' }: ExtractPagesToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  // State
  const [file, setFile] = useState<File | null>(null);
  const [totalPages, setTotalPages] = useState<number>(0);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Page selection
  const [pagePreviews, setPagePreviews] = useState<PagePreview[]>([]);
  const [selectedPages, setSelectedPages] = useState<Set<number>>(new Set());
  const [pageInput, setPageInput] = useState('');
  const [isLoadingPreviews, setIsLoadingPreviews] = useState(false);

  // Ref for cancellation
  const cancelledRef = useRef(false);

  /**
   * Load PDF and generate page previews
   */
  const loadPdfPreviews = useCallback(async (pdfFile: File) => {
    setIsLoadingPreviews(true);
    setPagePreviews([]);

    try {
      const pdfjsLib = await import('pdfjs-dist');
      configurePdfjsWorker(pdfjsLib);

      const arrayBuffer = await pdfFile.arrayBuffer();
      const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;

      setTotalPages(pdf.numPages);

      // Generate thumbnails for each page
      const previews: PagePreview[] = [];
      const maxPreviewPages = Math.min(pdf.numPages, 50);

      for (let i = 1; i <= maxPreviewPages; i++) {
        const page = await pdf.getPage(i);
        const viewport = page.getViewport({ scale: 0.15 });

        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');

        if (context) {
          canvas.height = viewport.height;
          canvas.width = viewport.width;

          await page.render({
            canvasContext: context,
            viewport: viewport, canvas: canvas, }).promise;

          previews.push({
            pageNumber: i,
            thumbnail: canvas.toDataURL('image/jpeg', 0.6),
          });
        }
      }

      // Add remaining pages without thumbnails
      for (let i = maxPreviewPages + 1; i <= pdf.numPages; i++) {
        previews.push({ pageNumber: i });
      }

      setPagePreviews(previews);
    } catch (err) {
      console.error('Failed to load PDF previews:', err);
      setError('Failed to load PDF preview. The file may be corrupted or encrypted.');
    } finally {
      setIsLoadingPreviews(false);
    }
  }, []);

  /**
   * Handle file selected from uploader
   */
  const handleFilesSelected = useCallback((files: File[]) => {
    if (files.length > 0) {
      const selectedFile = files[0];
      setFile(selectedFile);
      setError(null);
      setResult(null);
      setSelectedPages(new Set());
      setPageInput('');
      loadPdfPreviews(selectedFile);
    }
  }, [loadPdfPreviews]);

  /**
   * Handle file upload error
   */
  const handleUploadError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  /**
   * Clear file and reset state
   */
  const handleClearFile = useCallback(() => {
    setFile(null);
    setTotalPages(0);
    setPagePreviews([]);
    setSelectedPages(new Set());
    setPageInput('');
    setResult(null);
    setError(null);
    setStatus('idle');
    setProgress(0);
  }, []);

  /**
   * Toggle page selection
   */
  const handleTogglePage = useCallback((pageNumber: number) => {
    setSelectedPages(prev => {
      const newSet = new Set(prev);
      if (newSet.has(pageNumber)) {
        newSet.delete(pageNumber);
      } else {
        newSet.add(pageNumber);
      }
      return newSet;
    });
    setResult(null);
  }, []);

  /**
   * Select all pages
   */
  const handleSelectAll = useCallback(() => {
    setSelectedPages(new Set(pagePreviews.map(p => p.pageNumber)));
    setResult(null);
  }, [pagePreviews]);

  /**
   * Deselect all pages
   */
  const handleDeselectAll = useCallback(() => {
    setSelectedPages(new Set());
    setResult(null);
  }, []);

  /**
   * Apply page input to selection
   */
  const handleApplyPageInput = useCallback(() => {
    if (pageInput.trim() && totalPages > 0) {
      const pages = parsePageSelection(pageInput, totalPages);
      setSelectedPages(new Set(pages));
      setResult(null);
    }
  }, [pageInput, totalPages]);

  /**
   * Handle extract operation
   */
  const handleExtract = useCallback(async () => {
    if (!file) {
      setError('Please upload a PDF file first.');
      return;
    }

    if (selectedPages.size === 0) {
      setError('Please select at least one page to extract.');
      return;
    }

    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);

    const pages = Array.from(selectedPages).sort((a, b) => a - b);

    try {
      const output: ProcessOutput = await extractPages(
        file,
        pages,
        (prog, message) => {
          if (!cancelledRef.current) {
            setProgress(prog);
            setProgressMessage(message || '');
          }
        }
      );

      if (cancelledRef.current) {
        setStatus('idle');
        return;
      }

      if (output.success && output.result) {
        setResult(output.result as Blob);
        setStatus('complete');
      } else {
        setError(output.error?.message || 'Failed to extract pages.');
        setStatus('error');
      }
    } catch (err) {
      if (!cancelledRef.current) {
        setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
        setStatus('error');
      }
    }
  }, [file, selectedPages]);

  /**
   * Handle cancel operation
   */
  const handleCancel = useCallback(() => {
    cancelledRef.current = true;
    setStatus('idle');
    setProgress(0);
  }, []);

  /**
   * Format file size
   */
  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing' || status === 'uploading';
  const canExtract = file && totalPages > 0 && selectedPages.size > 0 && !isProcessing;

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {/* File Upload Area */}
      {!file && (
        <FileUploader
          accept={['application/pdf', '.pdf']}
          multiple={false}
          maxFiles={1}
          onFilesSelected={handleFilesSelected}
          onError={handleUploadError}
          disabled={isProcessing}
          label={tTools('extractPages.uploadLabel') || 'Upload PDF File'}
          description={tTools('extractPages.uploadDescription') || 'Drag and drop a PDF file here, or click to browse.'}
        />
      )}

      {/* Error Message */}
      {error && (
        <div 
          className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700"
          role="alert"
        >
          <p className="text-sm">{error}</p>
        </div>
      )}

      {/* File Info */}
      {file && (
        <Card variant="outlined">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <svg className="w-10 h-10 text-emerald-500" viewBox="0 0 24 24" fill="currentColor">
                <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                <path d="M14 2v6h6" fill="white" />
                <text x="7" y="17" fontSize="6" fill="white" fontWeight="bold">PDF</text>
              </svg>
              <div>
                <p className="font-medium text-[hsl(var(--color-foreground))]">{file.name}</p>
                <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
                  {formatSize(file.size)} • {totalPages} {totalPages === 1 ? 'page' : 'pages'}
                </p>
              </div>
            </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleClearFile}
              disabled={isProcessing}
            >
              {t('buttons.remove') || 'Remove'}
            </Button>
          </div>
        </Card>
      )}

      {/* Page Selection */}
      {file && totalPages > 0 && (
        <Card variant="outlined" size="lg">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))]">
              {tTools('extractPages.selectTitle') || 'Select Pages to Extract'}
              {selectedPages.size > 0 && ` (${selectedPages.size} selected)`}
            </h3>
            <div className="flex gap-2">
              <Button variant="ghost" size="sm" onClick={handleSelectAll} disabled={isProcessing}>
                {t('buttons.selectAll') || 'Select All'}
              </Button>
              <Button variant="ghost" size="sm" onClick={handleDeselectAll} disabled={isProcessing}>
                {t('buttons.deselectAll') || 'Deselect All'}
              </Button>
            </div>
          </div>

          {/* Page range input */}
          <div className="mb-4 flex gap-2">
            <input
              type="text"
              value={pageInput}
              onChange={(e) => setPageInput(e.target.value)}
              placeholder="e.g., 1-5, 8, 10-15"
              disabled={isProcessing}
              className="flex-1 px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))] placeholder:text-[hsl(var(--color-muted-foreground))] focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
            />
            <Button
              variant="secondary"
              size="md"
              onClick={handleApplyPageInput}
              disabled={isProcessing || !pageInput.trim()}
            >
              {t('buttons.apply') || 'Apply'}
            </Button>
          </div>

          <p className="text-sm text-[hsl(var(--color-muted-foreground))] mb-4">
            {tTools('extractPages.selectHint') || 'Click pages to select them, or enter page numbers/ranges above.'}
          </p>

          {isLoadingPreviews ? (
            <div className="flex items-center justify-center py-12">
              <div className="flex flex-col items-center gap-3">
                <div className="w-8 h-8 border-2 border-[hsl(var(--color-primary))] border-t-transparent rounded-full animate-spin" />
                <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
                  {t('status.loading') || 'Loading previews...'}
                </p>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-3 max-h-[400px] overflow-y-auto p-1">
              {pagePreviews.map((preview) => (
                <button
                  key={preview.pageNumber}
                  type="button"
                  onClick={() => handleTogglePage(preview.pageNumber)}
                  disabled={isProcessing}
                  className={`relative aspect-[3/4] rounded-[var(--radius-md)] border-2 overflow-hidden transition-all ${
                    selectedPages.has(preview.pageNumber)
                      ? 'border-[hsl(var(--color-primary))] ring-2 ring-[hsl(var(--color-primary)/0.3)]'
                      : 'border-[hsl(var(--color-border))] hover:border-[hsl(var(--color-primary)/0.5)]'
                  }`}
                  aria-label={`Page ${preview.pageNumber}${selectedPages.has(preview.pageNumber) ? ' (selected)' : ''}`}
                >
                  {preview.thumbnail ? (
                    <img
                      src={preview.thumbnail}
                      alt={`Page ${preview.pageNumber}`}
                      className="w-full h-full object-cover"
                    />
                  ) : (
                    <div className="w-full h-full bg-[hsl(var(--color-muted))] flex items-center justify-center">
                      <span className="text-xs text-[hsl(var(--color-muted-foreground))]">
                        {preview.pageNumber}
                      </span>
                    </div>
                  )}
                  <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-xs py-0.5 text-center">
                    {preview.pageNumber}
                  </div>
                  {selectedPages.has(preview.pageNumber) && (
                    <div className="absolute top-1 right-1 w-5 h-5 bg-[hsl(var(--color-primary))] rounded-full flex items-center justify-center">
                      <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                      </svg>
                    </div>
                  )}
                </button>
              ))}
            </div>
          )}
        </Card>
      )}

      {/* Processing Progress */}
      {isProcessing && (
        <ProcessingProgress
          progress={progress}
          status={status}
          message={progressMessage}
          onCancel={handleCancel}
          showPercentage
        />
      )}

      {/* Action Buttons */}
      {file && (
        <div className="flex flex-wrap items-center gap-4">
          <Button
            variant="primary"
            size="lg"
            onClick={handleExtract}
            disabled={!canExtract}
            loading={isProcessing}
          >
            {isProcessing 
              ? (t('status.processing') || 'Processing...') 
              : (tTools('extractPages.extractButton') || `Extract ${selectedPages.size} Page${selectedPages.size !== 1 ? 's' : ''}`)
            }
          </Button>

          {result && (
            <DownloadButton
              file={result}
              filename={file.name.replace('.pdf', '_extracted.pdf')}
              variant="secondary"
              size="lg"
              showFileSize
            />
          )}
        </div>
      )}

      {/* Success Message */}
      {status === 'complete' && result && (
        <div 
          className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700"
          role="status"
        >
          <p className="text-sm font-medium">
            {tTools('extractPages.successMessage') || `Successfully extracted ${selectedPages.size} page(s)! Click the download button to save your file.`}
          </p>
        </div>
      )}
    </div>
  );
}

export default ExtractPagesTool;

'use client';

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import {
    searchTextInPDF,
    applyFindAndRedact,
    TextMatch,
    parseSearchTerms,
} from '@/lib/pdf/processors/find-and-redact';
import { loadPdfjs } from '@/lib/pdf/loader';

export interface FindAndRedactToolProps {
    className?: string;
}

/**
 * FindAndRedactTool Component
 * 
 * Provides functionality to search for text across all pages of a PDF
 * and redact matching content. Useful for removing sensitive information
 * like account numbers, names, etc. from multi-page documents.
 */
export function FindAndRedactTool({ className = '' }: FindAndRedactToolProps) {
    const t = useTranslations('common');
    const tTools = useTranslations('tools.findAndRedact');

    // File state
    const [file, setFile] = useState<File | null>(null);
    const [status, setStatus] = useState<ProcessingStatus>('idle');
    const [progress, setProgress] = useState(0);
    const [progressMessage, setProgressMessage] = useState('');
    const [result, setResult] = useState<Blob | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Search state
    const [searchTermsInput, setSearchTermsInput] = useState('');
    const [caseSensitive, setCaseSensitive] = useState(false);
    const [wholeWord, setWholeWord] = useState(false);
    const [useRegex, setUseRegex] = useState(false);
    const [matches, setMatches] = useState<TextMatch[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);

    // Redaction options
    const [redactionColor, setRedactionColor] = useState('#000000');
    const [addBorder, setAddBorder] = useState(false);
    const [replacementText, setReplacementText] = useState('');

    // Page filter for viewing matches
    const [selectedPage, setSelectedPage] = useState<number | 'all'>('all');

    // Preview state
    const [showPreview, setShowPreview] = useState(false);
    const [previewPage, setPreviewPage] = useState(1);
    const [totalPages, setTotalPages] = useState(0);
    const [previewScale, setPreviewScale] = useState(1.0);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const pdfDocRef = useRef<any>(null);

    const cancelledRef = useRef(false);

    // Parse search terms from input
    const parsedTerms = useMemo(() => parseSearchTerms(searchTermsInput), [searchTermsInput]);

    const handleFilesSelected = useCallback((files: File[]) => {
        if (files.length > 0) {
            setFile(files[0]);
            setError(null);
            setResult(null);
            setMatches([]);
            setHasSearched(false);
            setShowPreview(false);
            setPreviewPage(1);
            pdfDocRef.current = null;
        }
    }, []);

    const handleClearFile = useCallback(() => {
        setFile(null);
        setResult(null);
        setError(null);
        setStatus('idle');
        setMatches([]);
        setHasSearched(false);
        setSearchTermsInput('');
        setShowPreview(false);
        pdfDocRef.current = null;
    }, []);

    // Load PDF for preview
    const loadPdfForPreview = useCallback(async () => {
        if (!file) return;

        try {
            const pdfjs = await loadPdfjs();
            const arrayBuffer = await file.arrayBuffer();
            const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
            pdfDocRef.current = pdf;
            setTotalPages(pdf.numPages);

            // Immediately render the first page after loading
            if (canvasRef.current) {
                const canvas = canvasRef.current;
                const context = canvas.getContext('2d');
                if (context) {
                    const page = await pdf.getPage(previewPage);
                    const viewport = page.getViewport({ scale: previewScale });
                    canvas.height = viewport.height;
                    canvas.width = viewport.width;
                    context.clearRect(0, 0, canvas.width, canvas.height);
                    await page.render({
                        canvasContext: context,
                        viewport: viewport, canvas: canvas, }).promise;

                    // Draw match highlights
                    const pageMatches = matches.filter(m => m.page === previewPage);
                    for (const match of pageMatches) {
                        const x = match.x * previewScale;
                        const y = (viewport.height / previewScale - match.y - match.height) * previewScale;
                        const width = match.width * previewScale;
                        const height = match.height * previewScale;

                        if (match.selected) {
                            context.fillStyle = 'rgba(255, 0, 0, 0.3)';
                        } else {
                            context.fillStyle = 'rgba(255, 200, 0, 0.3)';
                        }
                        context.fillRect(x, y, width, height);

                        context.strokeStyle = match.selected ? 'rgba(255, 0, 0, 0.8)' : 'rgba(255, 200, 0, 0.8)';
                        context.lineWidth = 2;
                        context.strokeRect(x, y, width, height);
                    }
                }
            }
        } catch (err) {
            console.error('Failed to load PDF for preview:', err);
        }
    }, [file, previewPage, previewScale, matches]);

    // Render preview page with match highlights
    const renderPreviewPage = useCallback(async () => {
        if (!pdfDocRef.current || !canvasRef.current) return;

        const canvas = canvasRef.current;
        const context = canvas.getContext('2d');
        if (!context) return;

        try {
            const page = await pdfDocRef.current.getPage(previewPage);
            const viewport = page.getViewport({ scale: previewScale });

            canvas.height = viewport.height;
            canvas.width = viewport.width;

            // Clear canvas
            context.clearRect(0, 0, canvas.width, canvas.height);

            // Render the PDF page
            await page.render({
                canvasContext: context,
                viewport: viewport, canvas: canvas, }).promise;

            // Draw match highlights
            const pageMatches = matches.filter(m => m.page === previewPage);
            for (const match of pageMatches) {
                // Convert PDF coordinates to canvas coordinates
                // PDF has origin at bottom-left, canvas has origin at top-left
                const x = match.x * previewScale;
                const y = (viewport.height / previewScale - match.y - match.height) * previewScale;
                const width = match.width * previewScale;
                const height = match.height * previewScale;

                // Draw highlight rectangle
                if (match.selected) {
                    context.fillStyle = 'rgba(255, 0, 0, 0.3)';
                } else {
                    context.fillStyle = 'rgba(255, 200, 0, 0.3)';
                }
                context.fillRect(x, y, width, height);

                // Draw border
                context.strokeStyle = match.selected ? 'rgba(255, 0, 0, 0.8)' : 'rgba(255, 200, 0, 0.8)';
                context.lineWidth = 2;
                context.strokeRect(x, y, width, height);
            }
        } catch (err) {
            console.error('Failed to render preview page:', err);
        }
    }, [previewPage, previewScale, matches]);

    // Load PDF when file changes and preview is enabled
    useEffect(() => {
        if (file && showPreview) {
            loadPdfForPreview();
        }
    }, [file, showPreview, loadPdfForPreview]);

    // Render preview when page or matches change (only if PDF is already loaded)
    useEffect(() => {
        if (showPreview && pdfDocRef.current) {
            renderPreviewPage();
        }
    }, [showPreview, previewPage, matches, previewScale, renderPreviewPage]);

    // Search for matches
    const handleSearch = useCallback(async () => {
        if (!file || parsedTerms.length === 0) {
            setError(tTools('enterSearchTerm'));
            return;
        }

        setIsSearching(true);
        setError(null);
        setMatches([]);
        setProgress(0);

        try {
            const searchResult = await searchTextInPDF(
                file,
                {
                    searchTerms: parsedTerms,
                    caseSensitive,
                    useRegex,
                    wholeWord,
                },
                (prog, message) => {
                    setProgress(prog);
                    setProgressMessage(message || '');
                }
            );

            if (searchResult.success) {
                setMatches(searchResult.matches);
                setHasSearched(true);
                if (searchResult.matches.length === 0) {
                    setError(tTools('noMatchesFound'));
                } else {
                    // Show preview if matches found
                    setShowPreview(true);
                    // Jump to the first page with matches
                    if (searchResult.pagesWithMatches.length > 0) {
                        setPreviewPage(searchResult.pagesWithMatches[0]);
                    }
                }
            } else {
                setError(searchResult.error || tTools('searchFailed'));
            }
        } catch (err) {
            setError(err instanceof Error ? err.message : tTools('searchFailed'));
        } finally {
            setIsSearching(false);
            setProgress(0);
        }
    }, [file, parsedTerms, caseSensitive, useRegex, wholeWord, tTools]);

    // Toggle individual match selection
    const toggleMatchSelection = useCallback((matchId: string) => {
        setMatches(prev =>
            prev.map(match =>
                match.id === matchId ? { ...match, selected: !match.selected } : match
            )
        );
    }, []);

    // Select/deselect all matches
    const toggleSelectAll = useCallback((selected: boolean) => {
        setMatches(prev => prev.map(match => ({ ...match, selected })));
    }, []);

    // Select/deselect all matches on a specific page
    const toggleSelectPage = useCallback((pageNum: number, selected: boolean) => {
        setMatches(prev =>
            prev.map(match =>
                match.page === pageNum ? { ...match, selected } : match
            )
        );
    }, []);

    // Apply redactions
    const handleRedact = useCallback(async () => {
        if (!file) return;

        const selectedMatches = matches.filter(m => m.selected);
        if (selectedMatches.length === 0) {
            setError(tTools('selectMatchesToRedact'));
            return;
        }

        cancelledRef.current = false;
        setStatus('processing');
        setProgress(0);
        setError(null);
        setResult(null);

        try {
            // Parse hex color to RGB
            const hexToRgb = (hex: string) => {
                const r = parseInt(hex.slice(1, 3), 16);
                const g = parseInt(hex.slice(3, 5), 16);
                const b = parseInt(hex.slice(5, 7), 16);
                return { r, g, b };
            };

            const redactionResult = await applyFindAndRedact(
                file,
                matches,
                {
                    color: hexToRgb(redactionColor),
                    addBorder,
                    replacementText: replacementText.trim() || undefined,
                    selectedMatchIds: selectedMatches.map(m => m.id),
                },
                (prog, message) => {
                    if (!cancelledRef.current) {
                        setProgress(prog);
                        setProgressMessage(message || '');
                    }
                }
            );

            if (cancelledRef.current) {
                setStatus('idle');
                return;
            }

            if (redactionResult.success && redactionResult.result) {
                setResult(redactionResult.result);
                setStatus('complete');
            } else {
                setError(redactionResult.error || tTools('redactFailed'));
                setStatus('error');
            }
        } catch (err) {
            if (!cancelledRef.current) {
                setError(err instanceof Error ? err.message : tTools('redactFailed'));
                setStatus('error');
            }
        }
    }, [file, matches, redactionColor, addBorder, replacementText, tTools]);

    const formatSize = (bytes: number): string => {
        if (bytes < 1024) return `${bytes} B`;
        if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
        return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    };

    const isProcessing = status === 'processing';
    const selectedCount = matches.filter(m => m.selected).length;
    const pagesWithMatches = [...new Set(matches.map(m => m.page))].sort((a, b) => a - b);

    // Filter matches by selected page
    const filteredMatches = selectedPage === 'all'
        ? matches
        : matches.filter(m => m.page === selectedPage);

    return (
        <div className={`space-y-6 ${className}`.trim()}>
            {/* File Upload */}
            {!file && (
                <FileUploader
                    accept={['application/pdf', '.pdf']}
                    multiple={false}
                    maxFiles={1}
                    onFilesSelected={handleFilesSelected}
                    onError={setError}
                    disabled={isProcessing}
                    label={tTools('uploadLabel')}
                    description={tTools('uploadDescription')}
                />
            )}

            {error && (
                <div className="p-4 rounded-lg bg-red-50 border border-red-200 text-red-700 dark:bg-red-900/20 dark:border-red-800 dark:text-red-400">
                    <p className="text-sm">{error}</p>
                </div>
            )}

            {file && (
                <>
                    {/* File Info */}
                    <Card variant="outlined">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <svg className="w-10 h-10 text-emerald-500" viewBox="0 0 24 24" fill="currentColor">
                                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                                </svg>
                                <div>
                                    <p className="font-medium text-gray-900 dark:text-gray-100">{file.name}</p>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">{formatSize(file.size)}</p>
                                </div>
                            </div>
                            <Button variant="ghost" size="sm" onClick={handleClearFile} disabled={isProcessing || isSearching}>
                                {t('buttons.remove')}
                            </Button>
                        </div>
                    </Card>

                    {/* Search Section */}
                    <Card variant="outlined" size="lg">
                        <h3 className="text-lg font-medium mb-4 text-gray-900 dark:text-gray-100">
                            {tTools('searchTitle')}
                        </h3>

                        {/* Search Input - Multiple Terms */}
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium mb-2 text-gray-700 dark:text-gray-300">
                                    {tTools('searchTermLabel')}
                                </label>

                                {/* Main Input */}
                                <div className="relative">
                                    <input
                                        type="text"
                                        value={searchTermsInput}
                                        onChange={(e) => setSearchTermsInput(e.target.value)}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' && parsedTerms.length > 0) {
                                                e.preventDefault();
                                                handleSearch();
                                            }
                                        }}
                                        placeholder={tTools('searchInputPlaceholder') || '输入搜索词，用逗号分隔多个词'}
                                        className="w-full px-4 py-3 border rounded-lg bg-white dark:bg-gray-800 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
                                        disabled={isProcessing || isSearching}
                                    />
                                    <div className="absolute right-2 top-1/2 -translate-y-1/2">
                                        <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                                        </svg>
                                    </div>
                                </div>

                                {/* Help text */}
                                <p className="mt-1.5 text-xs text-gray-500 dark:text-gray-400">
                                    {tTools('searchInputHelp') || '提示：用逗号（,）分隔多个搜索词'}
                                </p>

                                {/* Parsed Terms Tags */}
                                {parsedTerms.length > 0 && (
                                    <div className="mt-3">
                                        <div className="flex items-center gap-2 mb-2">
                                            <span className="text-xs font-medium text-gray-600 dark:text-gray-400">
                                                {tTools('termsCount', { count: parsedTerms.length }) || `${parsedTerms.length} 个搜索词`}
                                            </span>
                                            <button
                                                type="button"
                                                onClick={() => setSearchTermsInput('')}
                                                className="text-xs text-emerald-500 hover:text-red-700 dark:text-red-400 dark:hover:text-red-300"
                                                disabled={isProcessing || isSearching}
                                            >
                                                {t('buttons.clearAll')}
                                            </button>
                                        </div>
                                        <div className="flex flex-wrap gap-2">
                                            {parsedTerms.map((term, index) => (
                                                <span
                                                    key={index}
                                                    className="inline-flex items-center gap-1 px-3 py-1.5 rounded-full text-sm bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300 border border-blue-200 dark:border-blue-800"
                                                >
                                                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                                                    </svg>
                                                    {term}
                                                    <button
                                                        type="button"
                                                        onClick={() => {
                                                            const newTerms = parsedTerms.filter((_, i) => i !== index);
                                                            setSearchTermsInput(newTerms.join(', '));
                                                        }}
                                                        className="ml-1 text-blue-600 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-200"
                                                        disabled={isProcessing || isSearching}
                                                    >
                                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                                        </svg>
                                                    </button>
                                                </span>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Search Options */}
                            <div className="flex flex-wrap items-center gap-x-6 gap-y-2 py-2 border-t border-gray-200 dark:border-gray-700">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={caseSensitive}
                                        onChange={(e) => setCaseSensitive(e.target.checked)}
                                        className="w-4 h-4 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                                        disabled={isProcessing || isSearching}
                                    />
                                    <span className="text-sm text-gray-700 dark:text-gray-300">
                                        {tTools('caseSensitive')}
                                    </span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={wholeWord}
                                        onChange={(e) => setWholeWord(e.target.checked)}
                                        className="w-4 h-4 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                                        disabled={isProcessing || isSearching || useRegex}
                                    />
                                    <span className="text-sm text-gray-700 dark:text-gray-300">
                                        {tTools('wholeWord')}
                                    </span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input
                                        type="checkbox"
                                        checked={useRegex}
                                        onChange={(e) => {
                                            setUseRegex(e.target.checked);
                                            if (e.target.checked) setWholeWord(false);
                                        }}
                                        className="w-4 h-4 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                                        disabled={isProcessing || isSearching}
                                    />
                                    <span className="text-sm text-gray-700 dark:text-gray-300">
                                        {tTools('useRegex')}
                                    </span>
                                </label>
                            </div>

                            {/* Search Button */}
                            <div className="flex justify-end">
                                <Button
                                    variant="primary"
                                    size="lg"
                                    onClick={handleSearch}
                                    disabled={parsedTerms.length === 0 || isProcessing || isSearching}
                                    loading={isSearching}
                                    className="px-8"
                                >
                                    <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
