              <div className="text-xs text-gray-500">
                <p>{tTools('formCreator.saveInfo', { fields: fields.length })}</p>
              </div>
              <div className="flex justify-end gap-2">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => {
                    setShowSaveDialog(false);
                    setProjectName('');
