      {/* Create Blank PDF Dialog */}
      {showBlankPdfDialog && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
          <Card variant="outlined" size="lg" className="w-full max-w-md mx-4 bg-white shadow-xl">
