                                        <div
                                            className="grid mx-auto border border-[hsl(var(--color-border))] rounded bg-white transition-all duration-300 ease-in-out"
                                            style={{
                                                gridTemplateColumns: `repeat(${cols}, 1fr)`,
                                                gridTemplateRows: `repeat(${rows}, 1fr)`,
                                                width: orientation === 'landscape' ? '160px' : '120px',
                                                height: orientation === 'landscape' ? '120px' : '160px',
                                                gap: `${spacing * 0.3}px`,
                                                padding: useMargins ? '12px' : '4px',
                                            }}
                                        >
                                            {Array.from({ length: cellsPerPage }).map((_, idx) => {
                                                const file = files[idx];
                                                const hasContent = idx < files.length ||
                                                    (fillMode === 'repeat' && files.length > 0) ||
                                                    (fillMode === 'stretch-last' && files.length > 0 && idx >= files.length);
                                                const repeatFile = fillMode === 'repeat' && files.length > 0
                                                    ? files[idx % files.length]
                                                    : fillMode === 'stretch-last' && files.length > 0 && idx >= files.length
                                                        ? files[files.length - 1]
                                                        : null;
                                                const displayFile = file || repeatFile;

                                                return (
                                                    <div
                                                        key={idx}
                                                        className={`
                                                            flex items-center justify-center text-xs font-medium rounded-sm overflow-hidden
                                                            ${displayFile
                                                                ? 'bg-[hsl(var(--color-primary)/0.1)]'
                                                                : 'bg-[hsl(var(--color-muted))] border border-dashed border-[hsl(var(--color-border))]'
                                                            }
                                                        `}
                                                        title={displayFile?.file.name}
                                                    >
                                                        {displayFile?.thumbnail ? (
                                                            <img
                                                                src={displayFile.thumbnail}
                                                                alt=""
                                                                className={`w-full h-full object-contain ${!file && repeatFile ? 'opacity-50' : ''}`}
                                                            />
                                                        ) : displayFile ? (
                                                            <span className={`text-[hsl(var(--color-primary))] ${!file && repeatFile ? 'opacity-50' : ''}`}>
                                                                {idx < files.length ? idx + 1 : '↺'}
                                                            </span>
                                                        ) : null}
                                                    </div>
                                                );
                                            })}
                                        </div>
                                        <p className="text-xs text-center text-[hsl(var(--color-muted-foreground))] mt-2">
                                            {cols} {tTools('gridCombine.columns') || 'columns'} × {rows} {tTools('gridCombine.rows') || 'rows'}
                                        </p>
                                    </div>
                                </div>

                                {/* Page Mode */}
                                <div>
                                    <label htmlFor="pageMode" className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                        {tTools('gridCombine.pageMode') || 'Page Mode'}
                                    </label>
                                    <select
                                        id="pageMode"
                                        value={pageMode}
                                        onChange={(e) => setPageMode(e.target.value as GridCombineOptions['pageMode'])}
                                        disabled={isProcessing}
                                        className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                                    >
                                        <option value="first-page-only">{tTools('gridCombine.firstPageOnly') || 'First page only'}</option>
                                        <option value="all-pages">{tTools('gridCombine.allPages') || 'All pages'}</option>
                                    </select>
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))] mt-1">
                                        {pageMode === 'all-pages'
                                            ? (tTools('gridCombine.allPagesHint') || 'Include all pages from each PDF in the grid.')
                                            : (tTools('gridCombine.firstPageOnlyHint') || 'Only use the first page from each PDF.')
                                        }
                                    </p>
                                </div>

                                {/* Fill Mode */}
                                <div>
                                    <label htmlFor="fillMode" className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                        {tTools('gridCombine.fillMode') || 'Fill Mode'}
                                    </label>
                                    <select
                                        id="fillMode"
                                        value={fillMode}
                                        onChange={(e) => setFillMode(e.target.value as GridCombineOptions['fillMode'])}
                                        disabled={isProcessing}
                                        className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                                    >
                                        <option value="leave-empty">{tTools('gridCombine.leaveEmpty') || 'Leave empty cells'}</option>
                                        <option value="repeat">{tTools('gridCombine.repeat') || 'Repeat from start'}</option>
                                        <option value="stretch-last">{tTools('gridCombine.stretchLast') || 'Repeat last page'}</option>
                                    </select>
                                    <p className="text-xs text-[hsl(var(--color-muted-foreground))] mt-1">
                                        {tTools('gridCombine.fillModeHint') || 'How to fill empty cells when files are fewer than grid cells.'}
                                    </p>
                                </div>

                                {/* Page Size */}
                                <div>
                                    <label htmlFor="pageSize" className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                        {tTools('gridCombine.pageSize') || 'Page Size'}
                                    </label>
                                    <select
                                        id="pageSize"
                                        value={pageSize}
                                        onChange={(e) => setPageSize(e.target.value as GridCombineOptions['pageSize'])}
                                        disabled={isProcessing}
                                        className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                                    >
                                        <option value="A4">A4</option>
                                        <option value="Letter">Letter</option>
                                        <option value="Legal">Legal</option>
                                        <option value="A3">A3</option>
                                    </select>
                                </div>

                                {/* Orientation */}
                                <div>
                                    <label htmlFor="orientation" className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                        {tTools('gridCombine.orientation') || 'Orientation'}
                                    </label>
                                    <select
                                        id="orientation"
                                        value={orientation}
                                        onChange={(e) => setOrientation(e.target.value as GridCombineOptions['orientation'])}
                                        disabled={isProcessing}
                                        className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-[hsl(var(--color-background))] text-[hsl(var(--color-foreground))]"
                                    >
                                        <option value="landscape">{t('options.landscape') || 'Landscape'}</option>
                                        <option value="portrait">{t('options.portrait') || 'Portrait'}</option>
                                    </select>
                                </div>

                                {/* Spacing */}
                                <div>
                                    <label htmlFor="spacing" className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-1">
                                        {tTools('gridCombine.spacing') || 'Spacing'} ({spacing}px)
                                    </label>
                                    <input
                                        type="range"
                                        id="spacing"
                                        min="0"
                                        max="50"
                                        step="1"
                                        value={spacing}
                                        onChange={(e) => setSpacing(Number(e.target.value))}
                                        disabled={isProcessing}
                                        className="w-full"
                                    />
                                </div>

                                {/* Margins & Borders */}
                                <div className="space-y-2 pt-2 border-t border-[hsl(var(--color-border))]">
                                    <div className="flex items-center gap-2">
                                        <input
                                            type="checkbox"
                                            id="useMargins"
                                            checked={useMargins}
                                            onChange={(e) => setUseMargins(e.target.checked)}
                                            disabled={isProcessing}
                                            className="w-4 h-4 rounded border-[hsl(var(--color-border))]"
                                        />
                                        <label htmlFor="useMargins" className="text-sm text-[hsl(var(--color-foreground))]">
                                            {tTools('gridCombine.useMargins') || 'Add margins'}
                                        </label>
                                    </div>

                                    <div className="flex items-center gap-2">
                                        <input
                                            type="checkbox"
                                            id="addBorder"
                                            checked={addBorder}
                                            onChange={(e) => setAddBorder(e.target.checked)}
                                            disabled={isProcessing}
                                            className="w-4 h-4 rounded border-[hsl(var(--color-border))]"
                                        />
                                        <label htmlFor="addBorder" className="text-sm text-[hsl(var(--color-foreground))]">
                                            {tTools('gridCombine.addBorder') || 'Add borders'}
                                        </label>
                                    </div>

                                    {addBorder && (
                                        <div className="pl-6">
                                            <label htmlFor="borderColor" className="block text-xs text-[hsl(var(--color-muted-foreground))] mb-1">
                                                {tTools('gridCombine.borderColor') || 'Border Color'}
                                            </label>
                                            <input
                                                type="color"
                                                id="borderColor"
                                                value={borderColor}
                                                onChange={(e) => setBorderColor(e.target.value)}
                                                disabled={isProcessing}
                                                className="w-full h-8 rounded border border-[hsl(var(--color-border))] cursor-pointer p-0"
                                            />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </Card>
                    )}
                </div>
            </div>

            {/* Processing Progress */}
            {isProcessing && (
                <ProcessingProgress
                    progress={progress}
                    status={status}
                    message={progressMessage}
                    onCancel={handleCancel}
                    showPercentage
                />
            )}

            {/* Action Buttons */}
            {files.length > 0 && (
                <div className="flex flex-wrap items-center gap-4">
                    <Button
                        variant="primary"
                        size="lg"
                        onClick={handleCombine}
                        disabled={!canCombine}
                        loading={isProcessing}
                    >
                        {isProcessing
                            ? (t('status.processing') || 'Processing...')
                            : (tTools('gridCombine.combineButton') || 'Combine PDFs')
                        }
                    </Button>

                    {result && (
                        <DownloadButton
                            file={result}
                            filename={`grid_combine_${files.length}_files.pdf`}
                            variant="secondary"
                            size="lg"
                            showFileSize
                        />
                    )}
                </div>
            )}

            {/* Success Message */}
            {status === 'complete' && result && (
                <div className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700" role="status">
                    <p className="text-sm font-medium">
                        {tTools('gridCombine.successMessage') || 'PDFs combined successfully! Click the download button to save your file.'}
                    </p>
                </div>
            )}
        </div>
    );
}

export default GridCombineTool;

'use client';

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { addHeaderFooter, HeaderFooterOptions } from '@/lib/pdf/processors/header-footer';
import type { ProcessOutput } from '@/types/pdf';

// Store pdfjs module reference
let pdfjsModule: typeof import('pdfjs-dist') | null = null;

// Load pdfjs module dynamically
const loadPdfjsLib = async () => {
  if (pdfjsModule) return pdfjsModule;

  const pdfjsLib = await import('pdfjs-dist');
  const { configurePdfjsWorker } = await import('@/lib/pdf/loader');

  if (typeof window !== 'undefined' && !pdfjsLib.GlobalWorkerOptions.workerSrc) {
    configurePdfjsWorker(pdfjsLib);
  }

  pdfjsModule = pdfjsLib;
  return pdfjsLib;
};

export interface HeaderFooterToolProps {
  className?: string;
}

export function HeaderFooterTool({ className = '' }: HeaderFooterToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Header/Footer options
  const [headerLeft, setHeaderLeft] = useState('');
  const [headerCenter, setHeaderCenter] = useState('');
  const [headerRight, setHeaderRight] = useState('');
  const [footerLeft, setFooterLeft] = useState('');
  const [footerCenter, setFooterCenter] = useState('Page {page} of {total}');
  const [footerRight, setFooterRight] = useState('{date}');
  const [fontSize, setFontSize] = useState(10);
  const [fontColor, setFontColor] = useState('#000000');
  const [margin, setMargin] = useState(30);
  const [skipFirstPage, setSkipFirstPage] = useState(false);
  const [pageRange, setPageRange] = useState('all');

  // Preview state
  const [totalPages, setTotalPages] = useState(0);
  const [currentPreviewPage, setCurrentPreviewPage] = useState(1);

  const cancelledRef = useRef(false);
  const previewCanvasRef = useRef<HTMLCanvasElement>(null);

  // Check if page is in range
  const isPageInRange = (pageNum: number): boolean => {
    if (!pageRange || pageRange.toLowerCase() === 'all' || pageRange.trim() === '') {
      return true;
    }
    const ranges = pageRange.split(',').map(s => s.trim());
    for (const range of ranges) {
      if (range.includes('-')) {
        const [start, end] = range.split('-').map(s => parseInt(s.trim()));
        if (!isNaN(start) && !isNaN(end) && pageNum >= start && pageNum <= end) {
          return true;
        }
      } else {
        const page = parseInt(range);
        if (!isNaN(page) && pageNum === page) {
          return true;
        }
      }
    }
    return false;
  };

  // Draw header and footer text on canvas
  const drawHeaderFooterOverlay = (
    ctx: CanvasRenderingContext2D,
    width: number,
    height: number,
    page: number,
    total: number
  ) => {
    const scaledMargin = margin * 0.6;
    const scaledFontSize = fontSize * 0.6;

    ctx.font = `${scaledFontSize}px Arial`;
    ctx.fillStyle = fontColor;

    const today = new Date().toLocaleDateString();

    const replaceVars = (text: string) => {
      return text
        .replace(/{page}/g, String(page))
        .replace(/{total}/g, String(total))
        .replace(/{date}/g, today);
    };

    // Draw header
    if (headerLeft) {
      ctx.textAlign = 'left';
      ctx.fillText(replaceVars(headerLeft), scaledMargin, scaledMargin + scaledFontSize);
    }
    if (headerCenter) {
      ctx.textAlign = 'center';
      ctx.fillText(replaceVars(headerCenter), width / 2, scaledMargin + scaledFontSize);
    }
    if (headerRight) {
      ctx.textAlign = 'right';
      ctx.fillText(replaceVars(headerRight), width - scaledMargin, scaledMargin + scaledFontSize);
    }

    // Draw footer
    if (footerLeft) {
      ctx.textAlign = 'left';
      ctx.fillText(replaceVars(footerLeft), scaledMargin, height - scaledMargin);
    }
    if (footerCenter) {
      ctx.textAlign = 'center';
      ctx.fillText(replaceVars(footerCenter), width / 2, height - scaledMargin);
    }
    if (footerRight) {
      ctx.textAlign = 'right';
      ctx.fillText(replaceVars(footerRight), width - scaledMargin, height - scaledMargin);
    }
  };

  // Render page preview with header/footer overlay
  const renderPagePreview = async (pdf: any, pageNum: number) => {
    if (!previewCanvasRef.current) return;

    try {
      const page = await pdf.getPage(pageNum);
      const scale = 0.6;
      const viewport = page.getViewport({ scale });

      const canvas = previewCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = viewport.width;
      canvas.height = viewport.height;

      await page.render({ canvasContext: ctx, viewport, canvas: canvas  }).promise;

      // Check if page should show header/footer
      const shouldShowContent = isPageInRange(pageNum) && !(skipFirstPage && pageNum === 1);
      if (shouldShowContent) {
        drawHeaderFooterOverlay(ctx, viewport.width, viewport.height, pageNum, pdf.numPages);
      }

    } catch (err) {
      console.error('Failed to render page:', err);
    }
  };

  // Load PDF and generate preview
  const loadPdfPreview = async (pdfFile: File) => {
    try {
      const pdfjsLib = await loadPdfjsLib();
      const arrayBuffer = await pdfFile.arrayBuffer();
      const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
      setTotalPages(pdf.numPages);
      renderPagePreview(pdf, 1);
    } catch (err) {
      console.error('Failed to load PDF preview:', err);
    }
  };

  // Re-render preview when options change
  useEffect(() => {
    if (file && totalPages > 0) {
      const loadAndRender = async () => {
        const pdfjsLib = await loadPdfjsLib();
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        renderPagePreview(pdf, currentPreviewPage);
      };
      loadAndRender();
    }
  }, [file, headerLeft, headerCenter, headerRight, footerLeft, footerCenter, footerRight, fontSize, fontColor, margin, skipFirstPage, pageRange, currentPreviewPage, totalPages]);

  const handleFilesSelected = (files: File[]) => {
    if (files.length > 0) {
      setFile(files[0]);
      setError(null);
      setResult(null);
      loadPdfPreview(files[0]);
    }
  };

  const handleClearFile = useCallback(() => {
    setFile(null);
    setResult(null);
    setError(null);
    setStatus('idle');
    setTotalPages(0);
    setCurrentPreviewPage(1);
  }, []);

  const handleProcess = useCallback(async () => {
    if (!file) return;
    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);

    try {
      const options: HeaderFooterOptions = {
        header: { left: headerLeft, center: headerCenter, right: headerRight },
        footer: { left: footerLeft, center: footerCenter, right: footerRight },
        fontSize,
        fontColor,
        margin,
        skipFirstPage,
        pageRange: pageRange === 'all' ? undefined : pageRange,
      };

      const output: ProcessOutput = await addHeaderFooter(file, options, (prog, message) => {
        if (!cancelledRef.current) {
          setProgress(prog);
          setProgressMessage(message || '');
        }
      });

      if (output.success && output.result) {
        setResult(output.result as Blob);
        setStatus('complete');
      } else {
        setError(output.error?.message || 'Failed to add header/footer.');
        setStatus('error');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error');
      setStatus('error');
    }
  }, [file, headerLeft, headerCenter, headerRight, footerLeft, footerCenter, footerRight, fontSize, fontColor, margin, skipFirstPage, pageRange]);

  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing';
  const hasContent = headerLeft || headerCenter || headerRight || footerLeft || footerCenter || footerRight;

  // Quick insert buttons
  const quickInserts = [
    { label: '{page}', desc: 'Page number' },
    { label: '{total}', desc: 'Total pages' },
    { label: '{date}', desc: 'Current date' },
  ];

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {!file && (
        <FileUploader
          accept={['application/pdf', '.pdf']}
          multiple={false}
          maxFiles={1}
          onFilesSelected={handleFilesSelected}
          onError={setError}
          disabled={isProcessing}
          label={tTools('headerFooter.uploadLabel') || 'Upload PDF File'}
          description={tTools('headerFooter.uploadDescription') || 'Drag and drop a PDF file here.'}
        />
      )}

      {error && (
        <div className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700">
          <p className="text-sm">{error}</p>
        </div>
      )}

      {file && (
        <div className="grid lg:grid-cols-2 gap-6">
          {/* Options Panel */}
          <div className="space-y-6">
            <Card variant="outlined">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <svg className="w-10 h-10 text-emerald-500" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                    <path d="M14 2v6h6" fill="white" />
                  </svg>
                  <div>
                    <p className="font-medium">{file.name}</p>
                    <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
                      {formatSize(file.size)} • {totalPages} pages
                    </p>
                  </div>
                </div>
                <Button variant="ghost" size="sm" onClick={handleClearFile} disabled={isProcessing}>
                  {t('buttons.remove') || 'Remove'}
                </Button>
              </div>
            </Card>

            <Card variant="outlined" size="lg">
              <h3 className="text-lg font-medium mb-4">
                {tTools('headerFooter.headerTitle') || 'Header'}
              </h3>
              <div className="grid grid-cols-3 gap-4 mb-6">
                <div>
                  <label className="block text-sm mb-1">Left</label>
                  <input
                    type="text"
                    value={headerLeft}
                    onChange={(e) => setHeaderLeft(e.target.value)}
                    placeholder="e.g., Company Name"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Center</label>
                  <input
                    type="text"
                    value={headerCenter}
                    onChange={(e) => setHeaderCenter(e.target.value)}
                    placeholder="e.g., Document Title"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Right</label>
                  <input
                    type="text"
                    value={headerRight}
                    onChange={(e) => setHeaderRight(e.target.value)}
                    placeholder="e.g., {date}"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              <h3 className="text-lg font-medium mb-4">
                {tTools('headerFooter.footerTitle') || 'Footer'}
              </h3>
              <div className="grid grid-cols-3 gap-4 mb-6">
                <div>
                  <label className="block text-sm mb-1">Left</label>
                  <input
                    type="text"
                    value={footerLeft}
                    onChange={(e) => setFooterLeft(e.target.value)}
                    placeholder="e.g., Confidential"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Center</label>
                  <input
                    type="text"
                    value={footerCenter}
                    onChange={(e) => setFooterCenter(e.target.value)}
                    placeholder="e.g., Page {page} of {total}"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Right</label>
                  <input
                    type="text"
                    value={footerRight}
                    onChange={(e) => setFooterRight(e.target.value)}
                    placeholder="e.g., {date}"
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              {/* Quick Insert Buttons */}
              <div className="mb-6">
                <label className="block text-sm font-medium mb-2">Quick Insert</label>
                <div className="flex flex-wrap gap-2">
                  {quickInserts.map((item) => (
                    <button
                      key={item.label}
                      onClick={() => navigator.clipboard.writeText(item.label)}
                      className="px-3 py-1.5 text-xs bg-gray-100 hover:bg-gray-200 rounded-full transition-colors"
                      title={`Copy "${item.label}" - ${item.desc}`}
                    >
                      <code>{item.label}</code>
                    </button>
                  ))}
                </div>
                <p className="text-xs text-gray-500 mt-1">Click to copy, then paste into any field</p>
              </div>

              {/* Style Options */}
              <h3 className="text-lg font-medium mb-4">
                {tTools('headerFooter.styleTitle') || 'Style'}
              </h3>
              <div className="grid grid-cols-3 gap-4 mb-4">
                <div>
                  <label className="block text-sm mb-1">Font Size</label>
                  <input
                    type="number"
                    value={fontSize}
                    onChange={(e) => setFontSize(parseInt(e.target.value) || 10)}
                    min={6}
                    max={24}
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)]"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Margin (pt)</label>
                  <input
                    type="number"
                    value={margin}
                    onChange={(e) => setMargin(parseInt(e.target.value) || 30)}
                    min={10}
                    max={100}
                    className="w-full px-3 py-2 border rounded-[var(--radius-md)]"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm mb-1">Text Color</label>
                  <input
                    type="color"
                    value={fontColor}
                    onChange={(e) => setFontColor(e.target.value)}
                    className="w-full h-10 p-1 cursor-pointer rounded border border-gray-300"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              {/* Page Range */}
              <div className="mb-4">
                <label className="block text-sm font-medium mb-1">Page Range</label>
                <input
                  type="text"
                  value={pageRange}
                  onChange={(e) => setPageRange(e.target.value)}
                  placeholder="e.g., 1-5, 8, 10-12 or 'all'"
                  className="w-full px-3 py-2 border rounded-[var(--radius-md)] text-sm"
                  disabled={isProcessing}
                />
                <p className="text-xs text-gray-500 mt-1">
                  Use &quot;all&quot; for all pages, or specify ranges like &quot;1-5, 8, 10-12&quot;
                </p>
              </div>

              {/* Skip First Page */}
              <label className="flex items-center gap-2">
                <input
                  type="checkbox"
                  checked={skipFirstPage}
                  onChange={(e) => setSkipFirstPage(e.target.checked)}
                  className="w-4 h-4"
                  disabled={isProcessing}
                />
                <span className="text-sm">Skip first page (cover page)</span>
              </label>
            </Card>
          </div>

          {/* Preview Panel */}
          <div className="space-y-4">
            <Card variant="outlined" size="lg">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-medium">
                  {tTools('headerFooter.preview') || 'Preview'}
                </h3>
                <div className="flex items-center gap-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setCurrentPreviewPage(p => Math.max(1, p - 1))}
                    disabled={currentPreviewPage <= 1}
                  >
                    ←
                  </Button>
                  <span className="text-sm">
                    Page {currentPreviewPage} of {totalPages}
                  </span>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setCurrentPreviewPage(p => Math.min(totalPages, p + 1))}
                    disabled={currentPreviewPage >= totalPages}
                  >
                    →
                  </Button>
                </div>
              </div>

              <div className="bg-gray-100 rounded-[var(--radius-md)] p-4 flex justify-center">
                <canvas
                  ref={previewCanvasRef}
                  className="shadow-lg bg-white max-w-full h-auto"
                  style={{ maxHeight: '500px' }}
                />
              </div>

              {/* Page status indicator */}
              <div className="mt-4 text-center">
                {isPageInRange(currentPreviewPage) && !(skipFirstPage && currentPreviewPage === 1) ? (
                  <span className="inline-flex items-center gap-1 text-sm text-green-600">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                    Header/Footer will be added to this page
                  </span>
                ) : (
                  <span className="inline-flex items-center gap-1 text-sm text-gray-500">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                    This page will be skipped
                  </span>
                )}
              </div>

              {!hasContent && (
                <p className="text-sm text-center text-gray-500 mt-4">
                  {tTools('headerFooter.previewHint') || 'Enter header or footer text to see preview'}
                </p>
              )}
            </Card>
          </div>
        </div>
      )}

      {isProcessing && (
        <ProcessingProgress
          progress={progress}
          status={status}
          message={progressMessage}
          onCancel={() => { cancelledRef.current = true; setStatus('idle'); }}
          showPercentage
        />
      )}

      {file && (
        <div className="flex flex-wrap items-center gap-4">
          <Button
            variant="primary"
            size="lg"
            onClick={handleProcess}
            disabled={!file || !hasContent || isProcessing}
            loading={isProcessing}
          >
            {isProcessing ? 'Processing...' : (tTools('headerFooter.addButton') || 'Add Header & Footer')}
          </Button>
          {result && (
            <DownloadButton
              file={result}
              filename={file.name.replace('.pdf', '_headerfooter.pdf')}
              variant="secondary"
              size="lg"
              showFileSize
            />
          )}
        </div>
      )}

      {status === 'complete' && result && (
        <div className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700">
          <p className="text-sm font-medium">
            {tTools('headerFooter.successMessage') || 'Header & footer added successfully!'}
          </p>
        </div>
      )}
    </div>
  );
}

export default HeaderFooterTool;

'use client';

import React, { useState, useCallback, useRef } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { imagesToPDF, imagesToPDFBatch, PAGE_SIZES, type PageSizeType, type ImageToPDFOptions, type BatchExportResult } from '@/lib/pdf/processors/image-to-pdf';
import type { UploadedFile, ProcessOutput } from '@/types/pdf';

/**
 * Generate a unique ID for files
 */
function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

export interface ImageToPDFToolProps {
  /** Custom class name */
  className?: string;
  /** Specific image type filter (e.g., 'jpg', 'png') */
  imageType?: string;
}

/**
 * ImageToPDFTool Component
 * Requirements: 5.1, 5.2
 * 
 * Converts images to PDF with support for multiple formats.
 */
export function ImageToPDFTool({ className = '', imageType }: ImageToPDFToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  // State
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Options state
  const [pageSize, setPageSize] = useState<PageSizeType>('A4');
  const [orientation, setOrientation] = useState<'portrait' | 'landscape' | 'auto'>('auto');
  const [margin, setMargin] = useState(36);
  const [centerImage, setCenterImage] = useState(true);
  const [scaleToFit, setScaleToFit] = useState(true);
  const [svgScale, setSvgScale] = useState(2); // SVG render scale for quality

  // Batch mode options
  const [batchMode, setBatchMode] = useState(false);
  const [imagesPerPdf, setImagesPerPdf] = useState(10);
  const [batchResult, setBatchResult] = useState<BatchExportResult | null>(null);

  // Drag state for reordering
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [dragOverIndex, setDragOverIndex] = useState<number | null>(null);

  // Ref for cancellation
  const cancelledRef = useRef(false);

  /**
   * Get accepted file types based on imageType prop
   */
  const getAcceptedTypes = useCallback(() => {
    if (imageType) {
      switch (imageType.toLowerCase()) {
        case 'jpg':
        case 'jpeg':
          return ['image/jpeg', '.jpg', '.jpeg'];
        case 'png':
          return ['image/png', '.png'];
        case 'webp':
          return ['image/webp', '.webp'];
        case 'bmp':
          return ['image/bmp', '.bmp'];
        case 'tiff':
        case 'tif':
          return ['image/tiff', '.tiff', '.tif'];
        case 'svg':
          return ['image/svg+xml', '.svg'];
        case 'heic':
        case 'heif':
          return ['image/heic', 'image/heif', '.heic', '.heif'];
        default:
          break;
      }
    }
    // All supported formats
    return [
      'image/jpeg', 'image/png', 'image/webp', 'image/bmp',
      'image/tiff', 'image/svg+xml', 'image/heic', 'image/heif',
      '.jpg', '.jpeg', '.png', '.webp', '.bmp', '.tiff', '.tif', '.svg', '.heic', '.heif'
    ];
  }, [imageType]);


  /**
   * Handle files selected from uploader
   */
  const handleFilesSelected = useCallback((newFiles: File[]) => {
    const uploadedFiles: UploadedFile[] = newFiles.map(file => ({
      id: generateId(),
      file,
      status: 'pending' as const,
      preview: URL.createObjectURL(file),
    }));

    setFiles(prev => [...prev, ...uploadedFiles]);
    setError(null);
    setResult(null);
  }, []);

  /**
   * Handle file upload error
   */
  const handleUploadError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  /**
   * Remove a file from the list
   */
  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => {
      const file = prev.find(f => f.id === id);
      if (file?.preview) {
        URL.revokeObjectURL(file.preview);
      }
      return prev.filter(f => f.id !== id);
    });
    setResult(null);
  }, []);

  /**
   * Clear all files
   */
  const handleClearAll = useCallback(() => {
    files.forEach(f => {
      if (f.preview) URL.revokeObjectURL(f.preview);
    });
    setFiles([]);
    setResult(null);
    setBatchResult(null);
    setError(null);
    setStatus('idle');
    setProgress(0);
  }, [files]);

  /**
   * Handle drag start
   */
  const handleDragStart = useCallback((index: number) => {
    setDraggedIndex(index);
  }, []);

  /**
   * Handle drag over
   */
  const handleDragOver = useCallback((e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedIndex !== null && draggedIndex !== index) {
      setDragOverIndex(index);
    }
  }, [draggedIndex]);

  /**
   * Handle drag end
   */
  const handleDragEnd = useCallback(() => {
    if (draggedIndex !== null && dragOverIndex !== null && draggedIndex !== dragOverIndex) {
      setFiles(prev => {
        const newFiles = [...prev];
        const [draggedFile] = newFiles.splice(draggedIndex, 1);
        newFiles.splice(dragOverIndex, 0, draggedFile);
        return newFiles;
      });
    }
    setDraggedIndex(null);
    setDragOverIndex(null);
  }, [draggedIndex, dragOverIndex]);

  /**
   * Handle convert operation
   */
  const handleConvert = useCallback(async () => {
    if (files.length < 1) {
      setError('Please add at least 1 image file.');
      return;
    }

    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);
    setBatchResult(null);

    const options: Partial<ImageToPDFOptions> = {
      pageSize,
      orientation,
      margin,
      centerImage,
      scaleToFit,
      svgScale,
    };

    try {
      // Check if batch mode is enabled and there are enough images
      if (batchMode && files.length > imagesPerPdf) {
        // Batch export mode
        const output = await imagesToPDFBatch(
          files.map(f => f.file),
          imagesPerPdf,
          options,
          (prog, message) => {
            if (!cancelledRef.current) {
              setProgress(prog);
              setProgressMessage(message || '');
            }
          }
        );

        if (cancelledRef.current) {
          setStatus('idle');
          return;
        }

        if (output.success && output.result) {
          setBatchResult(output.result);
          setStatus('complete');
        } else {
          setError(output.error?.message || 'Failed to create batch PDFs.');
          setStatus('error');
        }
      } else {
        // Single PDF mode
        const output: ProcessOutput = await imagesToPDF(
          files.map(f => f.file),
          options,
          (prog, message) => {
            if (!cancelledRef.current) {
              setProgress(prog);
              setProgressMessage(message || '');
            }
          }
        );

        if (cancelledRef.current) {
          setStatus('idle');
          return;
        }

        if (output.success && output.result) {
          setResult(output.result as Blob);
          setStatus('complete');
        } else {
          setError(output.error?.message || 'Failed to convert images to PDF.');
          setStatus('error');
        }
      }
    } catch (err) {
      if (!cancelledRef.current) {
        setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
        setStatus('error');
      }
    }
  }, [files, pageSize, orientation, margin, centerImage, scaleToFit, svgScale, batchMode, imagesPerPdf]);

  /**
   * Handle cancel operation
   */
  const handleCancel = useCallback(() => {
    cancelledRef.current = true;
    setStatus('idle');
    setProgress(0);
  }, []);

  /**
   * Format file size
   */
  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing' || status === 'uploading';
  const canConvert = files.length >= 1 && !isProcessing;

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {/* File Upload Area */}
      <FileUploader
        accept={getAcceptedTypes()}
        multiple
        maxFiles={100}
        onFilesSelected={handleFilesSelected}
        onError={handleUploadError}
        disabled={isProcessing}
        label={tTools('imageToPdf.uploadLabel') || 'Upload Images'}
        description={tTools('imageToPdf.uploadDescription') || 'Drag and drop images here, or click to browse. Supports JPG, PNG, WebP, BMP, TIFF, SVG, HEIC.'}
      />

      {/* Error Message */}
      {error && (
        <div
          className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700"
          role="alert"
        >
          <p className="text-sm">{error}</p>
        </div>
      )}

      {/* Image List */}
      {files.length > 0 && (
        <Card variant="outlined" size="lg">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))]">
              {tTools('imageToPdf.imagesTitle') || 'Images'} ({files.length})
            </h3>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleClearAll}
              disabled={isProcessing}
            >
              {t('buttons.clearAll') || 'Clear All'}
            </Button>
          </div>

          <p className="text-sm text-[hsl(var(--color-muted-foreground))] mb-4">
            {tTools('imageToPdf.reorderHint') || 'Drag and drop to reorder images. Images will appear in the PDF in the order shown.'}
          </p>

          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
            {files.map((file, index) => (
              <div
                key={file.id}
                draggable={!isProcessing}
                onDragStart={() => handleDragStart(index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDragEnd={handleDragEnd}
                className={`
                  relative group rounded-[var(--radius-md)] border overflow-hidden
                  transition-all duration-200
                  ${draggedIndex === index ? 'opacity-50 border-dashed' : ''}
                  ${dragOverIndex === index ? 'border-[hsl(var(--color-primary))] ring-2 ring-[hsl(var(--color-primary)/0.2)]' : 'border-[hsl(var(--color-border))]'}
                  ${!isProcessing ? 'cursor-grab hover:border-[hsl(var(--color-primary)/0.5)]' : ''}
                `}
              >
                {/* Image Preview */}
                <div className="aspect-square bg-[hsl(var(--color-muted)/0.3)]">
                  {file.preview && (
                    <img
                      src={file.preview}
                      alt={file.file.name}
                      className="w-full h-full object-cover"
                    />
                  )}
                </div>

                {/* Page Number Badge */}
                <span className="absolute top-2 left-2 w-6 h-6 rounded-full bg-[hsl(var(--color-primary))] text-[hsl(var(--color-primary-foreground))] text-xs font-medium flex items-center justify-center">
                  {index + 1}
                </span>

                {/* Remove Button */}
                <button
                  type="button"
                  onClick={() => handleRemoveFile(file.id)}
                  disabled={isProcessing}
                  className="absolute top-2 right-2 p-1 rounded-full bg-black/50 text-white opacity-0 group-hover:opacity-100 transition-opacity disabled:opacity-30"
                  aria-label={`Remove ${file.file.name}`}
                >
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M18 6L6 18M6 6l12 12" />
                  </svg>
                </button>

                {/* File Info */}
                <div className="p-2 bg-white">
                  <p className="text-xs font-medium text-[hsl(var(--color-foreground))] truncate">
                    {file.file.name}
                  </p>
                  <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                    {formatSize(file.file.size)}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </Card>
      )}


      {/* Options Panel */}
      {files.length >= 1 && (
        <Card variant="outlined">
          <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))] mb-4">
            {tTools('imageToPdf.optionsTitle') || 'PDF Options'}
          </h3>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {/* Page Size */}
            <div>
              <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-2">
                {tTools('imageToPdf.pageSize') || 'Page Size'}
              </label>
              <select
                value={pageSize}
                onChange={(e) => setPageSize(e.target.value as PageSizeType)}
                disabled={isProcessing}
                className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white text-sm focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
              >
                <option value="A4">A4</option>
                <option value="LETTER">Letter</option>
                <option value="LEGAL">Legal</option>
                <option value="A3">A3</option>
                <option value="A5">A5</option>
                <option value="FIT">Fit to Image</option>
              </select>
            </div>

            {/* Orientation */}
            <div>
              <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-2">
                {tTools('imageToPdf.orientation') || 'Orientation'}
              </label>
              <select
                value={orientation}
                onChange={(e) => setOrientation(e.target.value as 'portrait' | 'landscape' | 'auto')}
                disabled={isProcessing}
                className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white text-sm focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
              >
                <option value="auto">{tTools('imageToPdf.orientationAuto') || 'Auto (match image)'}</option>
                <option value="portrait">{tTools('imageToPdf.orientationPortrait') || 'Portrait'}</option>
                <option value="landscape">{tTools('imageToPdf.orientationLandscape') || 'Landscape'}</option>
              </select>
            </div>

            {/* Margin */}
            <div>
              <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-2">
                {tTools('imageToPdf.margin') || 'Margin'}
              </label>
              <select
                value={margin}
                onChange={(e) => setMargin(Number(e.target.value))}
                disabled={isProcessing}
                className="w-full px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white text-sm focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
              >
                <option value="0">{tTools('imageToPdf.marginNone') || 'None'}</option>
                <option value="18">{tTools('imageToPdf.marginSmall') || 'Small (0.25")'}</option>
                <option value="36">{tTools('imageToPdf.marginMedium') || 'Medium (0.5")'}</option>
                <option value="72">{tTools('imageToPdf.marginLarge') || 'Large (1")'}</option>
              </select>
            </div>
          </div>

          <div className="mt-4 space-y-3">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={centerImage}
                onChange={(e) => setCenterImage(e.target.checked)}
                disabled={isProcessing}
                className="w-4 h-4 rounded border-[hsl(var(--color-border))] text-[hsl(var(--color-primary))] focus:ring-[hsl(var(--color-primary))]"
              />
              <span className="text-sm text-[hsl(var(--color-foreground))]">
                {tTools('imageToPdf.centerImage') || 'Center images on page'}
              </span>
            </label>

            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={scaleToFit}
                onChange={(e) => setScaleToFit(e.target.checked)}
                disabled={isProcessing}
                className="w-4 h-4 rounded border-[hsl(var(--color-border))] text-[hsl(var(--color-primary))] focus:ring-[hsl(var(--color-primary))]"
              />
              <span className="text-sm text-[hsl(var(--color-foreground))]">
                {tTools('imageToPdf.scaleToFit') || 'Scale images to fit page'}
              </span>
            </label>
          </div>

          {/* Batch Export Options */}
          {files.length > 1 && (
            <div className="mt-4 pt-4 border-t border-[hsl(var(--color-border))]">
              <label className="flex items-center gap-3 cursor-pointer mb-3">
                <input
                  type="checkbox"
                  checked={batchMode}
                  onChange={(e) => setBatchMode(e.target.checked)}
                  disabled={isProcessing}
                  className="w-4 h-4 rounded border-[hsl(var(--color-border))] text-[hsl(var(--color-primary))] focus:ring-[hsl(var(--color-primary))]"
                />
                <span className="text-sm font-medium text-[hsl(var(--color-foreground))]">
                  {tTools('imageToPdf.batchMode') || 'Split into multiple PDFs'}
                </span>
              </label>

              {batchMode && (
                <div className="ml-7 space-y-2">
                  <label className="block text-sm text-[hsl(var(--color-foreground))]">
                    {tTools('imageToPdf.imagesPerPdf') || 'Images per PDF'}
                  </label>
                  <input
                    type="number"
                    min="1"
                    max={files.length}
                    value={imagesPerPdf}
                    onChange={(e) => setImagesPerPdf(Math.max(1, Math.min(files.length, parseInt(e.target.value) || 1)))}
                    disabled={isProcessing}
                    className="w-24 px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white text-sm focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
                  />
                  <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                    {tTools('imageToPdf.batchModeHint', { pdfCount: Math.ceil(files.length / imagesPerPdf) }) ||
                      `Will create ${Math.ceil(files.length / imagesPerPdf)} PDF file(s), packaged as a ZIP archive.`}
                  </p>
                </div>
              )}
            </div>
          )}

          {/* SVG Quality Option - only show for SVG files */}
          {(imageType === 'svg' || files.some(f => f.file.name.toLowerCase().endsWith('.svg') || f.file.type === 'image/svg+xml')) && (
            <div className="mt-4 pt-4 border-t border-[hsl(var(--color-border))]">
              <label className="block text-sm font-medium text-[hsl(var(--color-foreground))] mb-2">
                {tTools('imageToPdf.svgQuality') || 'SVG Export Quality'}
              </label>
              <select
                value={svgScale}
                onChange={(e) => setSvgScale(Number(e.target.value))}
                disabled={isProcessing}
                className="w-full sm:w-auto px-3 py-2 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white text-sm focus:outline-none focus:ring-2 focus:ring-[hsl(var(--color-primary))]"
              >
                <option value="1">{tTools('imageToPdf.svgQualityLow') || 'Low (1x - smaller file)'}</option>
                <option value="2">{tTools('imageToPdf.svgQualityMedium') || 'Medium (2x - balanced)'}</option>
                <option value="3">{tTools('imageToPdf.svgQualityHigh') || 'High (3x - better quality)'}</option>
                <option value="4">{tTools('imageToPdf.svgQualityVeryHigh') || 'Very High (4x - best quality)'}</option>
              </select>
              <p className="mt-1 text-xs text-[hsl(var(--color-muted-foreground))]">
                {tTools('imageToPdf.svgQualityHint') || 'Higher quality produces sharper images but larger file sizes.'}
              </p>
            </div>
          )}
        </Card>
      )}

      {/* Processing Progress */}
      {isProcessing && (
        <ProcessingProgress
          progress={progress}
          status={status}
          message={progressMessage}
          onCancel={handleCancel}
          showPercentage
        />
      )}

      {/* Action Buttons */}
      <div className="flex flex-wrap items-center gap-4">
        <Button
          variant="primary"
          size="lg"
          onClick={handleConvert}
          disabled={!canConvert}
          loading={isProcessing}
        >
          {isProcessing
            ? (t('status.processing') || 'Processing...')
            : (tTools('imageToPdf.convertButton') || 'Convert to PDF')
          }
        </Button>

        {result && (
          <DownloadButton
            file={result}
            filename={files.length === 1 ? `${files[0].file.name.replace(/\.[^/.]+$/, '')}.pdf` : `images_${files.length}_pages.pdf`}
            variant="secondary"
            size="lg"
            showFileSize
          />
        )}

        {batchResult && (
          <DownloadButton
            file={batchResult.zipBlob}
            filename={`images_${batchResult.pdfCount}_pdfs.zip`}
            variant="secondary"
            size="lg"
            showFileSize
          />
        )}
      </div>

      {/* Success Message */}
      {status === 'complete' && result && (
        <div
          className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700"
          role="status"
        >
          <p className="text-sm font-medium">
            {tTools('imageToPdf.successMessage') || 'Images converted to PDF successfully! Click the download button to save your file.'}
          </p>
        </div>
      )}

      {/* Batch Success Message */}
      {status === 'complete' && batchResult && (
        <div
          className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700"
          role="status"
        >
          <p className="text-sm font-medium">
            {tTools('imageToPdf.batchSuccessMessage', { pdfCount: batchResult.pdfCount, imageCount: batchResult.imageCount }) ||
              `Successfully created ${batchResult.pdfCount} PDF files from ${batchResult.imageCount} images! Click the download button to save your ZIP archive.`}
          </p>
        </div>
      )}
    </div>
  );
}

export default ImageToPDFTool;

'use client';

import React, { useState, useCallback, useRef } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { jsonToPDF, JSON_PAGE_SIZES, type JSONPageSizeType, type JSONToPDFOptions } from '@/lib/pdf/processors/json-to-pdf';
import type { UploadedFile, ProcessOutput } from '@/types/pdf';

/**
 * Generate a unique ID for files
 */
function generateId(): string {
  return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

export interface JSONToPDFToolProps {
  /** Custom class name */
  className?: string;
}

/**
 * JSONToPDFTool Component
 * Requirements: 5.1, 5.2
 * 
 * Converts JSON files to PDF with formatted output.
 */
export function JSONToPDFTool({ className = '' }: JSONToPDFToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  // State
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [jsonPreview, setJsonPreview] = useState<string>('');
  const [parseError, setParseError] = useState<string | null>(null);

  // Options state
  const [pageSize, setPageSize] = useState<JSONPageSizeType>('A4');
  const [fontSize, setFontSize] = useState(10);
  const [indentSpaces, setIndentSpaces] = useState(2);
  const [prettyPrint, setPrettyPrint] = useState(true);
  const [showLineNumbers, setShowLineNumbers] = useState(true);

  // Ref for cancellation
  const cancelledRef = useRef(false);

  /**
   * Handle files selected from uploader
   */
  const handleFilesSelected = useCallback(async (newFiles: File[]) => {
    const uploadedFiles: UploadedFile[] = newFiles.map(file => ({
      id: generateId(),
      file,
      status: 'pending' as const,
    }));

    setFiles(prev => [...prev, ...uploadedFiles]);
    setError(null);
    setResult(null);
    setParseError(null);

    // Load and validate preview of first file
    if (newFiles.length > 0) {
      try {
        const text = await newFiles[0].text();
        const parsed = JSON.parse(text);
        const formatted = JSON.stringify(parsed, null, 2);
        setJsonPreview(formatted.slice(0, 3000) + (formatted.length > 3000 ? '\n...' : ''));
        setParseError(null);
      } catch (err) {
        setJsonPreview('');
        setParseError(err instanceof Error ? err.message : 'Invalid JSON');
      }
    }
  }, []);

  /**
   * Handle file upload error
   */
  const handleUploadError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  /**
   * Remove a file from the list
   */
  const handleRemoveFile = useCallback((id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
    setResult(null);
    setJsonPreview('');
    setParseError(null);
  }, []);

  /**
   * Clear all files
   */
  const handleClearAll = useCallback(() => {
    setFiles([]);
    setResult(null);
    setError(null);
    setStatus('idle');
    setProgress(0);
    setJsonPreview('');
    setParseError(null);
  }, []);

  /**
   * Handle convert operation
   */
  const handleConvert = useCallback(async () => {
    if (files.length < 1) {
      setError('Please add at least 1 JSON file.');
      return;
    }

    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);

    const options: Partial<JSONToPDFOptions> = {
      pageSize,
      fontSize,
      indentSpaces,
      prettyPrint,
      showLineNumbers,
    };

    try {
      const output: ProcessOutput = await jsonToPDF(
        files.map(f => f.file),
        options,
        (prog, message) => {
          if (!cancelledRef.current) {
            setProgress(prog);
            setProgressMessage(message || '');
          }
        }
      );

      if (cancelledRef.current) {
        setStatus('idle');
        return;
      }

      if (output.success && output.result) {
        setResult(output.result as Blob);
        setStatus('complete');
      } else {
        setError(output.error?.message || 'Failed to convert JSON to PDF.');
        setStatus('error');
      }
    } catch (err) {
      if (!cancelledRef.current) {
        setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
        setStatus('error');
      }
    }
  }, [files, pageSize, fontSize, indentSpaces, prettyPrint, showLineNumbers]);

  /**
   * Handle cancel operation
   */
  const handleCancel = useCallback(() => {
    cancelledRef.current = true;
    setStatus('idle');
    setProgress(0);
  }, []);

  /**
   * Format file size
   */
  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing' || status === 'uploading';
  const canConvert = files.length >= 1 && !isProcessing && !parseError;

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {/* File Upload Area */}
      <FileUploader
        accept={['application/json', '.json']}
        multiple
        maxFiles={10}
        onFilesSelected={handleFilesSelected}
        onError={handleUploadError}
        disabled={isProcessing}
        label={tTools('jsonToPdf.uploadLabel') || 'Upload JSON Files'}
        description={tTools('jsonToPdf.uploadDescription') || 'Drag and drop JSON files here, or click to browse.'}
      />

      {/* Error Message */}
      {error && (
        <div 
          className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700"
          role="alert"
        >
          <p className="text-sm">{error}</p>
        </div>
      )}

      {/* Parse Error */}
      {parseError && (
        <div 
          className="p-4 rounded-[var(--radius-md)] bg-yellow-50 border border-yellow-200 text-yellow-700"
          role="alert"
        >
          <p className="text-sm font-medium">Invalid JSON</p>
          <p className="text-sm mt-1">{parseError}</p>
        </div>
      )}

      {/* File List */}
      {files.length > 0 && (
        <Card variant="outlined" size="lg">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))]">
              {tTools('jsonToPdf.filesTitle') || 'JSON Files'} ({files.length})
            </h3>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleClearAll}
              disabled={isProcessing}
            >
              {t('buttons.clearAll') || 'Clear All'}
            </Button>
          </div>

          <ul className="space-y-2" role="list">
            {files.map((file) => (
              <li
                key={file.id}
                className="flex items-center gap-3 p-3 rounded-[var(--radius-md)] border border-[hsl(var(--color-border))] bg-white"
              >
                {/* File Icon */}
                <div className="flex-shrink-0">
                  <svg className="w-8 h-8 text-orange-500" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                    <path d="M14 2v6h6" fill="white" />
                    <text x="5" y="17" fontSize="4.5" fill="white" fontWeight="bold">JSON</text>
                  </svg>
                </div>

                {/* File Info */}
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-[hsl(var(--color-foreground))] truncate">
                    {file.file.name}
                  </p>
                  <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                    {formatSize(file.file.size)}
                  </p>
                </div>

                {/* Remove Button */}
                <button
                  type="button"
                  onClick={() => handleRemoveFile(file.id)}
                  disabled={isProcessing}
                  className="flex-shrink-0 p-1 rounded hover:bg-red-100 text-[hsl(var(--color-muted-foreground))] hover:text-red-600 disabled:opacity-30"
                  aria-label={`Remove ${file.file.name}`}
                >
                  <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M18 6L6 18M6 6l12 12" />
                  </svg>
                </button>
              </li>
            ))}
          </ul>

          {/* JSON Preview */}
          {jsonPreview && !parseError && (
            <div className="mt-4">
              <h4 className="text-sm font-medium text-[hsl(var(--color-foreground))] mb-2">
                {tTools('jsonToPdf.preview') || 'Preview'}
              </h4>
              <pre className="p-3 rounded-[var(--radius-md)] bg-[hsl(var(--color-muted)/0.3)] text-xs font-mono text-[hsl(var(--color-foreground))] overflow-auto max-h-64 whitespace-pre">
                {jsonPreview}
              </pre>
            </div>
          )}
        </Card>
      )}


      {/* Options Panel */}
      {files.length >= 1 && (
        <Card variant="outlined">
          <h3 className="text-lg font-medium text-[hsl(var(--color-foreground))] mb-4">
            {tTools('jsonToPdf.optionsTitle') || 'PDF Options'}
          </h3>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            {/* Page Size */}
            <div>
