'use client';

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { addPageNumbers, PageNumberOptions } from '@/lib/pdf/processors/page-numbers';
import type { ProcessOutput } from '@/types/pdf';

// Store pdfjs module reference
let pdfjsModule: typeof import('pdfjs-dist') | null = null;

export interface PageNumbersToolProps {
  className?: string;
}

type Position = 'bottom-center' | 'bottom-left' | 'bottom-right' | 'top-center' | 'top-left' | 'top-right';
type Format = 'number' | 'roman' | 'page-of-total' | 'custom';

export function PageNumbersTool({ className = '' }: PageNumbersToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  const [file, setFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Options
  const [position, setPosition] = useState<Position>('bottom-center');
  const [format, setFormat] = useState<Format>('number');
  const [customFormat, setCustomFormat] = useState('Page {page} of {total}');
  const [startNumber, setStartNumber] = useState(1);
  const [fontSize, setFontSize] = useState(12);
  const [fontColor, setFontColor] = useState('#000000');
  const [margin, setMargin] = useState(30);
  const [skipFirstPage, setSkipFirstPage] = useState(false);
  const [prefix, setPrefix] = useState('');
  const [suffix, setSuffix] = useState('');
  // Odd/Even page settings
  const [pageMode, setPageMode] = useState<'all' | 'odd-only' | 'even-only' | 'odd-even-different'>('all');
  const [oddPosition, setOddPosition] = useState<Position>('bottom-right');
  const [evenPosition, setEvenPosition] = useState<Position>('bottom-left');

  // Preview state
  const [totalPages, setTotalPages] = useState(0);
  const [currentPreviewPage, setCurrentPreviewPage] = useState(1);
  const [previewScale, setPreviewScale] = useState(0.5);

  const previewCanvasRef = useRef<HTMLCanvasElement>(null);
  const cancelledRef = useRef(false);
  const renderTaskRef = useRef<{ cancel: () => void } | null>(null);

  // Load pdfjs module dynamically
  const loadPdfjsLib = async () => {
    if (pdfjsModule) return pdfjsModule;

    const pdfjsLib = await import('pdfjs-dist');
    const { configurePdfjsWorker } = await import('@/lib/pdf/loader');

    if (typeof window !== 'undefined' && !pdfjsLib.GlobalWorkerOptions.workerSrc) {
      configurePdfjsWorker(pdfjsLib);
    }

    pdfjsModule = pdfjsLib;
    return pdfjsLib;
  };

  // Load PDF preview
  const loadPdfPreview = useCallback(async (pdfFile: File) => {
    try {
      const pdfjsLib = await loadPdfjsLib();
      const arrayBuffer = await pdfFile.arrayBuffer();
      const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
      setTotalPages(pdf.numPages);
      renderPagePreview(pdf, 1);
    } catch (err) {
      console.error('Failed to load PDF:', err);
    }
  }, []);

  // Render page with page number overlay
  const renderPagePreview = async (pdf: any, pageNum: number) => {
    if (!previewCanvasRef.current) return;

    // Cancel any ongoing render task
    if (renderTaskRef.current) {
      try {
        renderTaskRef.current.cancel();
      } catch {
        // Ignore cancel errors
      }
      renderTaskRef.current = null;
    }

    try {
      const page = await pdf.getPage(pageNum);
      // Use scale 1.5 for good quality preview
      const renderScale = 1.5;
      const viewport = page.getViewport({ scale: renderScale });

      const canvas = previewCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      canvas.width = viewport.width;
      canvas.height = viewport.height;

      const renderTask = page.render({ canvasContext: ctx, viewport, canvas: canvas  });
      renderTaskRef.current = renderTask;

      await renderTask.promise;
      renderTaskRef.current = null;

      // Check if page number should be drawn based on pageMode
      const isOddPage = pageNum % 2 === 1;
      let shouldDraw = true;

      if (skipFirstPage && pageNum === 1) shouldDraw = false;
      else if (pageMode === 'odd-only' && !isOddPage) shouldDraw = false;
      else if (pageMode === 'even-only' && isOddPage) shouldDraw = false;

      if (shouldDraw) {
        drawPageNumberOverlay(ctx, viewport.width, viewport.height, pageNum, pdf.numPages, renderScale, isOddPage);
      }

    } catch (err) {
      // Ignore cancelled render errors
      if (err instanceof Error && err.message.includes('cancelled')) {
        return;
      }
      console.error('Failed to render page:', err);
    }
  };

  // Format page number based on options
  const formatPageNumber = (page: number, total: number): string => {
    const adjustedPage = page - 1 + startNumber;
    let text = '';

    switch (format) {
      case 'number':
        text = String(adjustedPage);
        break;
      case 'roman':
        text = toRoman(adjustedPage);
        break;
      case 'page-of-total':
        text = `Page ${adjustedPage} of ${total - 1 + startNumber}`;
        break;
      case 'custom':
        text = customFormat
          .replace(/{page}/g, String(adjustedPage))
          .replace(/{total}/g, String(total - 1 + startNumber));
        break;
    }

    return `${prefix}${text}${suffix}`;
  };

  // Convert number to Roman numeral
  const toRoman = (num: number): string => {
    const romanNumerals: [number, string][] = [
      [1000, 'M'], [900, 'CM'], [500, 'D'], [400, 'CD'],
      [100, 'C'], [90, 'XC'], [50, 'L'], [40, 'XL'],
      [10, 'X'], [9, 'IX'], [5, 'V'], [4, 'IV'], [1, 'I']
    ];
    let result = '';
    let n = num;
    for (const [value, symbol] of romanNumerals) {
      while (n >= value) {
        result += symbol;
        n -= value;
      }
    }
    return result;
  };

  // Draw page number on canvas
  const drawPageNumberOverlay = (
    ctx: CanvasRenderingContext2D,
    width: number,
    height: number,
    page: number,
    total: number,
    renderScale: number = 1,
    isOddPage: boolean = true
  ) => {
    const text = formatPageNumber(page, total);
    // Scale font size and margin according to render scale
    const scaledFontSize = fontSize * renderScale;
    const scaledMargin = margin * renderScale;

    ctx.font = `${scaledFontSize}px Arial`;
    ctx.fillStyle = fontColor;

    // Determine effective position based on page mode
    let effectivePosition: Position = position;
    if (pageMode === 'odd-even-different') {
      effectivePosition = isOddPage ? oddPosition : evenPosition;
    }

    // Calculate position
    let x = 0;
    let y = 0;

    switch (effectivePosition) {
      case 'bottom-center':
        ctx.textAlign = 'center';
        x = width / 2;
        y = height - scaledMargin;
        break;
      case 'bottom-left':
        ctx.textAlign = 'left';
        x = scaledMargin;
        y = height - scaledMargin;
        break;
      case 'bottom-right':
        ctx.textAlign = 'right';
        x = width - scaledMargin;
        y = height - scaledMargin;
        break;
      case 'top-center':
        ctx.textAlign = 'center';
        x = width / 2;
        y = scaledMargin + scaledFontSize;
        break;
      case 'top-left':
        ctx.textAlign = 'left';
        x = scaledMargin;
        y = scaledMargin + scaledFontSize;
        break;
      case 'top-right':
        ctx.textAlign = 'right';
        x = width - scaledMargin;
        y = scaledMargin + scaledFontSize;
        break;
    }

    // Draw background for visibility
    const metrics = ctx.measureText(text);
    const padding = 4 * renderScale;
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.fillRect(
      x - (ctx.textAlign === 'center' ? metrics.width / 2 : ctx.textAlign === 'right' ? metrics.width : 0) - padding,
      y - scaledFontSize,
      metrics.width + padding * 2,
      scaledFontSize + padding
    );

    // Draw text
    ctx.fillStyle = fontColor;
    ctx.fillText(text, x, y);
  };

  // Re-render preview when options change
  useEffect(() => {
    if (file && totalPages > 0) {
      const loadAndRender = async () => {
        const pdfjsLib = await loadPdfjsLib();
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        renderPagePreview(pdf, currentPreviewPage);
      };
      loadAndRender();
    }
  }, [file, position, format, customFormat, startNumber, fontSize, fontColor, margin, skipFirstPage, prefix, suffix, currentPreviewPage, totalPages, pageMode, oddPosition, evenPosition]);

  const handleFilesSelected = useCallback((files: File[]) => {
    if (files.length > 0) {
      setFile(files[0]);
      setError(null);
      setResult(null);
      loadPdfPreview(files[0]);
    }
  }, [loadPdfPreview]);

  const handleClearFile = useCallback(() => {
    setFile(null);
    setResult(null);
    setError(null);
    setStatus('idle');
    setTotalPages(0);
    setCurrentPreviewPage(1);
  }, []);

  const handleProcess = useCallback(async () => {
    if (!file) return;

    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);

    try {
      const options: PageNumberOptions = {
        position,
        format: format as PageNumberOptions['format'],
        startNumber,
        fontSize,
        fontColor,
        margin,
        skipFirstPage,
        prefix,
        suffix,
        customFormat: format === 'custom' ? customFormat : undefined,
        pageMode,
        oddPosition,
        evenPosition,
      };

      const output: ProcessOutput = await addPageNumbers(file, options, (prog, message) => {
        if (!cancelledRef.current) {
          setProgress(prog);
          setProgressMessage(message || '');
        }
      });

      if (output.success && output.result) {
        setResult(output.result as Blob);
        setStatus('complete');
      } else {
        setError(output.error?.message || 'Failed to add page numbers.');
        setStatus('error');
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
      setStatus('error');
    }
  }, [file, position, format, customFormat, startNumber, fontSize, fontColor, margin, skipFirstPage, prefix, suffix, pageMode, oddPosition, evenPosition]);

  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing';

  // Position options with visual representation
  const positionOptions = [
    { value: 'top-left', label: 'Top Left', icon: '↖' },
    { value: 'top-center', label: 'Top Center', icon: '↑' },
    { value: 'top-right', label: 'Top Right', icon: '↗' },
    { value: 'bottom-left', label: 'Bottom Left', icon: '↙' },
    { value: 'bottom-center', label: 'Bottom Center', icon: '↓' },
    { value: 'bottom-right', label: 'Bottom Right', icon: '↘' },
  ];

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {!file && (
        <FileUploader
          accept={['application/pdf', '.pdf']}
          multiple={false}
          maxFiles={1}
          onFilesSelected={handleFilesSelected}
          onError={setError}
          disabled={isProcessing}
          label={tTools('pageNumbers.uploadLabel')}
          description={tTools('pageNumbers.uploadDescription')}
        />
      )}

      {error && (
        <div className="p-4 rounded-[var(--radius-md)] bg-red-50 border border-red-200 text-red-700">
          <p className="text-sm">{error}</p>
        </div>
      )}

      {file && (
        <div className="grid lg:grid-cols-2 gap-4">
          {/* Options Panel */}
          <div className="space-y-3 lg:max-h-[850px] lg:overflow-y-auto lg:pr-2">
            {/* File Info */}
            <Card variant="outlined" className="p-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <svg className="w-8 h-8 text-emerald-500 shrink-0" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z" />
                  </svg>
                  <div className="min-w-0">
                    <p className="font-medium text-sm truncate">{file.name}</p>
                    <p className="text-xs text-[hsl(var(--color-muted-foreground))]">
                      {formatSize(file.size)} • {totalPages} pages
                    </p>
                  </div>
                </div>
                <Button variant="ghost" size="sm" onClick={handleClearFile} disabled={isProcessing}>
                  {t('buttons.remove')}
                </Button>
              </div>
            </Card>

            {/* Main Options Card */}
            <Card variant="outlined" className="p-4">
              {/* Position Section */}
              <h4 className="text-sm font-semibold mb-2 text-gray-700">
                {tTools('pageNumbers.positionTitle')}
              </h4>
              <div className="grid grid-cols-3 gap-1.5 mb-4">
                {positionOptions.map((opt) => (
                  <button
                    key={opt.value}
                    onClick={() => setPosition(opt.value as Position)}
                    disabled={isProcessing}
                    className={`
                      p-2 rounded-md border transition-all text-center
                      ${position === opt.value
                        ? 'border-blue-500 bg-blue-50 text-blue-700'
                        : 'border-gray-200 hover:border-gray-300'
                      }
                      disabled:opacity-50 disabled:cursor-not-allowed
                    `}
                  >
                    <span className="text-base">{opt.icon}</span>
                    <span className="block text-xs">{opt.label}</span>
                  </button>
                ))}
              </div>

              {/* Format Section */}
              <h4 className="text-sm font-semibold mb-2 text-gray-700">
                {tTools('pageNumbers.formatTitle')}
              </h4>
              <div className="grid grid-cols-2 gap-2 mb-3">
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.style')}</label>
                  <select
                    value={format}
                    onChange={(e) => setFormat(e.target.value as Format)}
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  >
                    <option value="number">1, 2, 3...</option>
                    <option value="roman">I, II, III...</option>
                    <option value="page-of-total">Page 1 of N</option>
                    <option value="custom">Custom</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.startNumber')}</label>
                  <input
                    type="number"
                    value={startNumber}
                    onChange={(e) => setStartNumber(parseInt(e.target.value) || 1)}
                    min={1}
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              {format === 'custom' && (
                <div className="mb-3">
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.customFormat')}</label>
                  <input
                    type="text"
                    value={customFormat}
                    onChange={(e) => setCustomFormat(e.target.value)}
                    placeholder="Page {page} of {total}"
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                  <p className="text-xs text-gray-500 mt-1">{tTools('pageNumbers.customFormatHint')}</p>
                </div>
              )}

              <div className="grid grid-cols-2 gap-2 mb-3">
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.prefix')}</label>
                  <input
                    type="text"
                    value={prefix}
                    onChange={(e) => setPrefix(e.target.value)}
                    placeholder="e.g., Page "
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.suffix')}</label>
                  <input
                    type="text"
                    value={suffix}
                    onChange={(e) => setSuffix(e.target.value)}
                    placeholder="e.g., -"
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              {/* Style Section */}
              <h4 className="text-sm font-semibold mb-2 text-gray-700 pt-2 border-t">
                {tTools('pageNumbers.styleTitle')}
              </h4>
              <div className="grid grid-cols-2 gap-2 mb-3">
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.fontSize')}</label>
                  <input
                    type="number"
                    value={fontSize}
                    onChange={(e) => setFontSize(parseInt(e.target.value) || 12)}
                    min={6}
                    max={72}
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.margin')}</label>
                  <input
                    type="number"
                    value={margin}
                    onChange={(e) => setMargin(parseInt(e.target.value) || 30)}
                    min={10}
                    max={100}
                    className="w-full px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
              </div>
              <div className="mb-3">
                <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.color')}</label>
                <div className="flex items-center gap-2">
                  <input
                    type="color"
                    value={fontColor}
                    onChange={(e) => setFontColor(e.target.value)}
                    className="w-10 h-10 p-0.5 cursor-pointer rounded border border-gray-300"
                    disabled={isProcessing}
                  />
                  <input
                    type="text"
                    value={fontColor}
                    onChange={(e) => setFontColor(e.target.value)}
                    className="flex-1 px-2 py-1.5 text-sm border rounded-md"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              <label className="flex items-center gap-2">
                <input
                  type="checkbox"
                  checked={skipFirstPage}
                  onChange={(e) => setSkipFirstPage(e.target.checked)}
                  className="w-3.5 h-3.5"
                  disabled={isProcessing}
                />
                <span className="text-sm">{tTools('pageNumbers.skipFirstPage')}</span>
              </label>

              {/* Odd/Even Page Mode */}
              <div className="mt-3 pt-3 border-t border-gray-200">
                <h4 className="text-sm font-semibold mb-2 text-gray-700">
                  {tTools('pageNumbers.oddEvenTitle')}
                </h4>

                <div className="space-y-2">
                  <div>
                    <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.pageMode')}</label>
                    <select
                      value={pageMode}
                      onChange={(e) => setPageMode(e.target.value as typeof pageMode)}
                      className="w-full px-2 py-1.5 text-sm border rounded-md"
                      disabled={isProcessing}
                    >
                      <option value="all">{tTools('pageNumbers.modeAll')}</option>
                      <option value="odd-only">{tTools('pageNumbers.modeOddOnly')}</option>
                      <option value="even-only">{tTools('pageNumbers.modeEvenOnly')}</option>
                      <option value="odd-even-different">{tTools('pageNumbers.modeDifferent')}</option>
                    </select>
                  </div>

                  {pageMode === 'odd-even-different' && (
                    <div className="grid grid-cols-2 gap-2">
                      <div>
                        <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.oddPosition')}</label>
                        <select
                          value={oddPosition}
                          onChange={(e) => setOddPosition(e.target.value as Position)}
                          className="w-full px-2 py-1.5 text-sm border rounded-md"
                          disabled={isProcessing}
                        >
                          <option value="bottom-left">{tTools('pageNumbers.posBottomLeft')}</option>
                          <option value="bottom-center">{tTools('pageNumbers.posBottomCenter')}</option>
                          <option value="bottom-right">{tTools('pageNumbers.posBottomRight')}</option>
                          <option value="top-left">{tTools('pageNumbers.posTopLeft')}</option>
                          <option value="top-center">{tTools('pageNumbers.posTopCenter')}</option>
                          <option value="top-right">{tTools('pageNumbers.posTopRight')}</option>
                        </select>
                        <p className="text-xs text-gray-500">{tTools('pageNumbers.oddPositionHint')}</p>
                      </div>
                      <div>
                        <label className="block text-sm font-medium mb-1">{tTools('pageNumbers.evenPosition')}</label>
                        <select
                          value={evenPosition}
                          onChange={(e) => setEvenPosition(e.target.value as Position)}
                          className="w-full px-2 py-1.5 text-sm border rounded-md"
                          disabled={isProcessing}
                        >
                          <option value="bottom-left">{tTools('pageNumbers.posBottomLeft')}</option>
                          <option value="bottom-center">{tTools('pageNumbers.posBottomCenter')}</option>
                          <option value="bottom-right">{tTools('pageNumbers.posBottomRight')}</option>
                          <option value="top-left">{tTools('pageNumbers.posTopLeft')}</option>
                          <option value="top-center">{tTools('pageNumbers.posTopCenter')}</option>
                          <option value="top-right">{tTools('pageNumbers.posTopRight')}</option>
                        </select>
                        <p className="text-xs text-gray-500">{tTools('pageNumbers.evenPositionHint')}</p>
                      </div>
                    </div>
                  )}

                  {pageMode === 'odd-even-different' && (
                    <div className="p-2 bg-blue-50 rounded text-sm text-blue-700">
                      <p>{tTools('pageNumbers.differentModeHint')}</p>
                    </div>
                  )}
                </div>
              </div>
            </Card>
          </div>

          {/* Preview Panel */}
          <div>
            <Card variant="outlined" size="lg">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-medium">
                  {tTools('pageNumbers.preview')}
                </h3>
                <div className="flex items-center gap-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setCurrentPreviewPage(p => Math.max(1, p - 1))}
                    disabled={currentPreviewPage <= 1}
                  >
                    ←
                  </Button>
                  <span className="text-sm">
                    {tTools('pageNumbers.pageOf', { current: currentPreviewPage, total: totalPages })}
                  </span>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setCurrentPreviewPage(p => Math.min(totalPages, p + 1))}
                    disabled={currentPreviewPage >= totalPages}
                  >
                    →
                  </Button>
                </div>
              </div>

              {/* Zoom Controls */}
              <div className="flex items-center justify-center gap-2 mb-4">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setPreviewScale(s => Math.max(0.5, s - 0.25))}
                  disabled={previewScale <= 0.5}
                  title={tTools('pageNumbers.zoomOut')}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM13 10H7" />
                  </svg>
                </Button>
                <span className="text-sm min-w-[60px] text-center">{Math.round(previewScale * 100)}%</span>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setPreviewScale(s => Math.min(2, s + 0.25))}
                  disabled={previewScale >= 2}
                  title={tTools('pageNumbers.zoomIn')}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v6m3-3H7" />
                  </svg>
                </Button>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setPreviewScale(0.5)}
                  disabled={previewScale === 0.5}
                  title={tTools('pageNumbers.zoomReset')}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                </Button>
              </div>

              <div className="bg-gray-100 dark:bg-gray-800 rounded-[var(--radius-md)] p-4 overflow-auto" style={{ maxHeight: '600px', minHeight: '500px' }}>
                <div
                  className="flex justify-center"
                  style={{
                    transform: `scale(${previewScale})`,
                    transformOrigin: 'top center',
                    minHeight: previewScale < 1 ? 'auto' : undefined
                  }}
                >
                  <canvas
                    ref={previewCanvasRef}
                    className="shadow-lg bg-white"
                  />
                </div>
              </div>

              <p className="text-sm text-center text-gray-500 dark:text-gray-400 mt-4">
                {skipFirstPage && currentPreviewPage === 1
                  ? tTools('pageNumbers.firstPageSkipped')
                  : tTools('pageNumbers.previewText', { text: formatPageNumber(currentPreviewPage, totalPages) })
                }
              </p>
            </Card>
          </div>
        </div>
      )}

      {isProcessing && (
        <ProcessingProgress
          progress={progress}
          status={status}
          message={progressMessage}
          onCancel={() => { cancelledRef.current = true; setStatus('idle'); }}
          showPercentage
        />
      )}

      {file && (
        <div className="flex flex-wrap items-center gap-4">
          <Button
            variant="primary"
            size="lg"
            onClick={handleProcess}
            disabled={!file || isProcessing}
            loading={isProcessing}
          >
            {isProcessing ? t('status.processing') : tTools('pageNumbers.addButton')}
          </Button>
          {result && (
            <DownloadButton
              file={result}
              filename={file.name.replace('.pdf', '_numbered.pdf')}
              variant="secondary"
              size="lg"
              showFileSize
            />
          )}
        </div>
      )}

      {status === 'complete' && result && (
        <div className="p-4 rounded-[var(--radius-md)] bg-green-50 border border-green-200 text-green-700">
          <p className="text-sm font-medium">
            {tTools('pageNumbers.successMessage')}
          </p>
        </div>
      )}
    </div>
  );
}

export default PageNumbersTool;

'use client';

import React, { useState, useCallback, useRef } from 'react';
import { useTranslations } from 'next-intl';
import { FileUploader } from '../FileUploader';
import { ProcessingProgress, ProcessingStatus } from '../ProcessingProgress';
import { DownloadButton } from '../DownloadButton';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { configurePdfjsWorker } from '@/lib/pdf/loader';

export interface PDFMultiToolProps {
  className?: string;
}

interface PagePreview {
  pageNumber: number;
  originalPageNumber: number;
  sourceFileIndex: number;
  sourceFileName: string;
  thumbnail?: string;
  rotation: number;
  selected: boolean;
}

interface SourceFile {
  file: File;
  pageCount: number;
}

interface HistoryState {
  pages: PagePreview[];
}

/**
 * PDFMultiTool Component
 * All-in-one PDF editor with multi-file support
 */
export function PDFMultiTool({ className = '' }: PDFMultiToolProps) {
  const t = useTranslations('common');
  const tTools = useTranslations('tools');

  // State
  const [sourceFiles, setSourceFiles] = useState<SourceFile[]>([]);
  const [status, setStatus] = useState<ProcessingStatus>('idle');
  const [progress, setProgress] = useState(0);
  const [progressMessage, setProgressMessage] = useState('');
  const [result, setResult] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Page management
  const [pagePreviews, setPagePreviews] = useState<PagePreview[]>([]);
  const [isLoadingPreviews, setIsLoadingPreviews] = useState(false);

  // History for undo/redo
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Drag state
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [dragOverIndex, setDragOverIndex] = useState<number | null>(null);

  // Add blank page modal
  const [showAddBlankModal, setShowAddBlankModal] = useState(false);
  const [blankPagePosition, setBlankPagePosition] = useState(1);
  const [blankPageCount, setBlankPageCount] = useState(1);

  const cancelledRef = useRef(false);

  // Save to history
  const saveToHistory = useCallback((pages: PagePreview[]) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1);
      newHistory.push({ pages: JSON.parse(JSON.stringify(pages)) });
      return newHistory.slice(-30);
    });
    setHistoryIndex(prev => Math.min(prev + 1, 29));
  }, [historyIndex]);

  // Update pages with history
  const updatePages = useCallback((newPages: PagePreview[], skipHistory = false) => {
    if (!skipHistory) {
      saveToHistory(newPages);
    }
    setPagePreviews(newPages);
  }, [saveToHistory]);

  /**
   * Load PDF and generate page previews
   */
  const loadPdfPreviews = useCallback(async (files: File[], existingPages: PagePreview[] = []) => {
    setIsLoadingPreviews(true);
    setError(null);

    try {
      const pdfjsLib = await import('pdfjs-dist');
      configurePdfjsWorker(pdfjsLib);

      const newPreviews: PagePreview[] = [...existingPages];
      const newSourceFiles: SourceFile[] = [...sourceFiles];

      for (let fileIdx = 0; fileIdx < files.length; fileIdx++) {
        const file = files[fileIdx];
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;

        const sourceFileIndex = newSourceFiles.length;
        newSourceFiles.push({ file, pageCount: pdf.numPages });

        const maxPreviewPages = Math.min(pdf.numPages, 50);

        for (let i = 1; i <= pdf.numPages; i++) {
          let thumbnail: string | undefined;

          if (i <= maxPreviewPages) {
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 0.2 });

            const canvas = document.createElement('canvas');
            const context = canvas.getContext('2d');

            if (context) {
              canvas.height = viewport.height;
              canvas.width = viewport.width;

              await page.render({
                canvasContext: context,
                viewport: viewport,
                canvas: canvas,
              }).promise;

              thumbnail = canvas.toDataURL('image/jpeg', 0.7);
            }
          }

          newPreviews.push({
            pageNumber: newPreviews.length + 1,
            originalPageNumber: i,
            sourceFileIndex,
            sourceFileName: file.name,
            thumbnail,
            rotation: 0,
            selected: false,
          });
        }
      }

      setSourceFiles(newSourceFiles);
      setPagePreviews(newPreviews);
      setHistory([{ pages: JSON.parse(JSON.stringify(newPreviews)) }]);
      setHistoryIndex(0);
    } catch (err) {
      console.error('Failed to load PDF:', err);
      setError('Failed to load PDF. The file may be corrupted or encrypted.');
    } finally {
      setIsLoadingPreviews(false);
    }
  }, [sourceFiles]);

  const handleFilesSelected = useCallback((files: File[]) => {
    if (files.length > 0) {
      setResult(null);
      loadPdfPreviews(files, pagePreviews);
    }
  }, [loadPdfPreviews, pagePreviews]);

  const handleUploadError = useCallback((errorMessage: string) => {
    setError(errorMessage);
  }, []);

  const handleClearAll = useCallback(() => {
    setSourceFiles([]);
    setPagePreviews([]);
    setResult(null);
    setError(null);
    setStatus('idle');
    setProgress(0);
    setHistory([]);
    setHistoryIndex(-1);
  }, []);

  // Undo
  const handleUndo = useCallback(() => {
    if (historyIndex > 0) {
      setHistoryIndex(prev => prev - 1);
      setPagePreviews(JSON.parse(JSON.stringify(history[historyIndex - 1].pages)));
    }
  }, [history, historyIndex]);

  // Redo
  const handleRedo = useCallback(() => {
    if (historyIndex < history.length - 1) {
      setHistoryIndex(prev => prev + 1);
      setPagePreviews(JSON.parse(JSON.stringify(history[historyIndex + 1].pages)));
    }
  }, [history, historyIndex]);

  // Reset
  const handleReset = useCallback(() => {
    if (history.length > 0) {
      setPagePreviews(JSON.parse(JSON.stringify(history[0].pages)));
      setHistoryIndex(0);
    }
    setResult(null);
  }, [history]);

  // Drag handlers
  const handleDragStart = useCallback((index: number) => {
    setDraggedIndex(index);
  }, []);

  const handleDragOver = useCallback((e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedIndex !== null && draggedIndex !== index) {
      setDragOverIndex(index);
    }
  }, [draggedIndex]);

  const handleDragEnd = useCallback(() => {
    if (draggedIndex !== null && dragOverIndex !== null && draggedIndex !== dragOverIndex) {
      const newPreviews = [...pagePreviews];
      const [draggedPage] = newPreviews.splice(draggedIndex, 1);
      newPreviews.splice(dragOverIndex, 0, draggedPage);
      updatePages(newPreviews);
    }
    setDraggedIndex(null);
    setDragOverIndex(null);
  }, [draggedIndex, dragOverIndex, pagePreviews, updatePages]);

  // Selection
  const handleToggleSelect = useCallback((index: number) => {
    const newPreviews = pagePreviews.map((p, i) =>
      i === index ? { ...p, selected: !p.selected } : p
    );
    setPagePreviews(newPreviews);
  }, [pagePreviews]);

  const handleSelectAll = useCallback(() => {
    setPagePreviews(prev => prev.map(p => ({ ...p, selected: true })));
  }, []);

  const handleDeselectAll = useCallback(() => {
    setPagePreviews(prev => prev.map(p => ({ ...p, selected: false })));
  }, []);

  // Delete
  const handleDeletePage = useCallback((index: number) => {
    const newPreviews = pagePreviews.filter((_, i) => i !== index);
    if (newPreviews.length > 0) {
      updatePages(newPreviews);
    } else {
      setError('Cannot delete all pages.');
    }
  }, [pagePreviews, updatePages]);

  const handleDeleteSelected = useCallback(() => {
    const newPreviews = pagePreviews.filter(p => !p.selected);
    if (newPreviews.length > 0) {
      updatePages(newPreviews);
    } else {
      setError('Cannot delete all pages.');
    }
  }, [pagePreviews, updatePages]);

  // Rotate
  const handleRotatePage = useCallback((index: number, degrees: number) => {
    const newPreviews = pagePreviews.map((p, i) =>
      i === index ? { ...p, rotation: (p.rotation + degrees + 360) % 360 } : p
    );
    updatePages(newPreviews);
  }, [pagePreviews, updatePages]);

  const handleRotateSelected = useCallback((degrees: number) => {
    const hasSelected = pagePreviews.some(p => p.selected);
    const newPreviews = pagePreviews.map(p =>
      (hasSelected ? p.selected : true) ? { ...p, rotation: (p.rotation + degrees + 360) % 360 } : p
    );
    updatePages(newPreviews);
  }, [pagePreviews, updatePages]);

  // Duplicate
  const handleDuplicatePage = useCallback((index: number) => {
    const newPreviews = [...pagePreviews];
    const dup = { ...pagePreviews[index], selected: false };
    newPreviews.splice(index + 1, 0, dup);
    updatePages(newPreviews);
  }, [pagePreviews, updatePages]);

  const handleDuplicateSelected = useCallback(() => {
    const newPreviews: PagePreview[] = [];
    pagePreviews.forEach(p => {
      newPreviews.push(p);
      if (p.selected) {
        newPreviews.push({ ...p, selected: false });
      }
    });
    updatePages(newPreviews);
  }, [pagePreviews, updatePages]);

  // Add blank page
  const handleAddBlankPage = useCallback(() => {
    const insertIndex = Math.max(0, Math.min(blankPagePosition - 1, pagePreviews.length));
    const newPages: PagePreview[] = [];

    for (let i = 0; i < blankPageCount; i++) {
      newPages.push({
        pageNumber: -1,
        originalPageNumber: -1,
        sourceFileIndex: -1,
        sourceFileName: 'Blank Page',
        rotation: 0,
        selected: false,
      });
    }

    const newPreviews = [...pagePreviews];
    newPreviews.splice(insertIndex, 0, ...newPages);
    updatePages(newPreviews);
    setShowAddBlankModal(false);
  }, [blankPagePosition, blankPageCount, pagePreviews, updatePages]);

  // Download selected
  const handleDownloadSelected = useCallback(async () => {
    const selectedPages = pagePreviews.filter(p => p.selected);
    if (selectedPages.length === 0) return;

    setStatus('processing');
    setProgress(0);

    try {
      const pdfLib = await import('pdf-lib');
      const newPdf = await pdfLib.PDFDocument.create();

      // Load all source files
      const loadedPdfs: any[] = [];
      for (const sf of sourceFiles) {
        const arrayBuffer = await sf.file.arrayBuffer();
        const pdf = await pdfLib.PDFDocument.load(arrayBuffer);
        loadedPdfs.push(pdf);
      }

      for (const pageInfo of selectedPages) {
        if (pageInfo.sourceFileIndex >= 0) {
          const sourcePdf = loadedPdfs[pageInfo.sourceFileIndex];
          const [copiedPage] = await newPdf.copyPages(sourcePdf, [pageInfo.originalPageNumber - 1]);
          if (pageInfo.rotation !== 0) {
            copiedPage.setRotation(pdfLib.degrees(pageInfo.rotation));
          }
          newPdf.addPage(copiedPage);
        } else {
          // Blank page
          newPdf.addPage([595, 842]); // A4 size
        }
      }

      const pdfBytes = await newPdf.save();
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'selected_pages.pdf';
      a.click();
      URL.revokeObjectURL(url);

      setStatus('idle');
    } catch (err) {
      setError('Failed to download selected pages');
      setStatus('error');
    }
  }, [sourceFiles, pagePreviews]);

  // Export PDF
  const handleExport = useCallback(async () => {
    if (pagePreviews.length === 0) {
      setError('No pages to export.');
      return;
    }

    cancelledRef.current = false;
    setStatus('processing');
    setProgress(0);
    setError(null);
    setResult(null);

    try {
      setProgress(5);
      setProgressMessage('Loading PDF library...');

      const pdfLib = await import('pdf-lib');

      if (cancelledRef.current) {
        setStatus('idle');
        return;
      }

      setProgress(10);
      setProgressMessage('Loading source files...');

      // Load all source PDFs
      const loadedPdfs: any[] = [];
      for (const sf of sourceFiles) {
        const arrayBuffer = await sf.file.arrayBuffer();
        const pdf = await pdfLib.PDFDocument.load(arrayBuffer);
        loadedPdfs.push(pdf);
      }

      setProgress(20);
      setProgressMessage('Creating new document...');

      const newPdf = await pdfLib.PDFDocument.create();
      const progressPerPage = 70 / pagePreviews.length;

      for (let i = 0; i < pagePreviews.length; i++) {
        if (cancelledRef.current) {
          setStatus('idle');
          return;
        }

        const pageInfo = pagePreviews[i];
        setProgress(20 + (i * progressPerPage));
        setProgressMessage(`Processing page ${i + 1} of ${pagePreviews.length}...`);

        if (pageInfo.sourceFileIndex >= 0) {
          const sourcePdf = loadedPdfs[pageInfo.sourceFileIndex];
          const [copiedPage] = await newPdf.copyPages(sourcePdf, [pageInfo.originalPageNumber - 1]);

          if (pageInfo.rotation !== 0) {
            copiedPage.setRotation(pdfLib.degrees(pageInfo.rotation));
          }

          newPdf.addPage(copiedPage);
        } else {
          // Blank page
          newPdf.addPage([595, 842]);
        }
      }

      setProgress(90);
      setProgressMessage('Saving PDF...');

      const pdfBytes = await newPdf.save();
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      setProgress(100);
      setProgressMessage('Complete!');
      setResult(blob);
      setStatus('complete');

    } catch (err) {
      if (!cancelledRef.current) {
        setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
        setStatus('error');
      }
    }
  }, [sourceFiles, pagePreviews]);

  const handleCancel = useCallback(() => {
    cancelledRef.current = true;
    setStatus('idle');
    setProgress(0);
  }, []);

  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const isProcessing = status === 'processing';
  const canExport = pagePreviews.length > 0 && !isProcessing;
  const selectedCount = pagePreviews.filter(p => p.selected).length;
  const canUndo = historyIndex > 0;
  const canRedo = historyIndex < history.length - 1;
  const totalPages = pagePreviews.length;

  return (
    <div className={`space-y-6 ${className}`.trim()}>
      {/* File Upload Area */}
      <FileUploader
        accept={['application/pdf', '.pdf']}
        multiple={true}
        maxFiles={1000}
        onFilesSelected={handleFilesSelected}
        onError={handleUploadError}
        disabled={isProcessing}
        label={sourceFiles.length > 0
          ? (tTools('pdfMultiTool.addMoreFiles') || 'Add More PDF Files')
          : (tTools('pdfMultiTool.uploadLabel') || 'Upload PDF Files')
        }
        description={tTools('pdfMultiTool.uploadDescription') || 'Drag and drop PDF files here, or click to browse. You can upload multiple files.'}
      />

      {/* Error Message */}
      {error && (
        <Card variant="outlined" className="!bg-red-50 dark:!bg-red-900/20 !border-red-200 dark:!border-red-800">
          <p className="text-sm text-red-700 dark:text-red-400">{error}</p>
        </Card>
      )}

      {/* Editor Panel */}
      {pagePreviews.length > 0 && (
        <Card variant="outlined" size="lg">
          {/* Toolbar */}
          <div className="flex flex-wrap items-center gap-2 pb-4 mb-4 border-b border-[hsl(var(--color-border))]">
            {/* Edit Actions */}
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="sm"
                onClick={handleUndo}
                disabled={!canUndo || isProcessing}
                title="Undo"
              >
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
                </svg>
                {tTools('pdfMultiTool.undo') || 'Undo'}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleRedo}
                disabled={!canRedo || isProcessing}
                title="Redo"
              >
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 10h-10a8 8 0 00-8 8v2M21 10l-6 6m6-6l-6-6" />
                </svg>
                {tTools('pdfMultiTool.redo') || 'Redo'}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleReset}
                disabled={isProcessing}
                title="Reset"
              >
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                </svg>
                {tTools('pdfMultiTool.reset') || 'Reset'}
              </Button>
            </div>

            <div className="w-px h-6 bg-[hsl(var(--color-border))]" />

            {/* Selection Actions */}
            <div className="flex items-center gap-1">
              <Button variant="ghost" size="sm" onClick={handleSelectAll} disabled={isProcessing}>
                {tTools('pdfMultiTool.selectAll') || 'Select All'}
              </Button>
              <Button variant="ghost" size="sm" onClick={handleDeselectAll} disabled={selectedCount === 0 || isProcessing}>
                {tTools('pdfMultiTool.deselectAll') || 'Deselect'}
              </Button>
            </div>

            <div className="w-px h-6 bg-[hsl(var(--color-border))]" />

            {/* Rotate Actions */}
            <div className="flex items-center gap-1">
              <Button variant="ghost" size="sm" onClick={() => handleRotateSelected(-90)} disabled={isProcessing}>
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12a9 9 0 109-9 9.75 9.75 0 00-6.74 2.74L3 8M3 3v5h5" />
                </svg>
                {tTools('pdfMultiTool.rotateLeft') || 'Left'}
              </Button>
              <Button variant="ghost" size="sm" onClick={() => handleRotateSelected(90)} disabled={isProcessing}>
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-9-9 9.75 9.75 0 016.74 2.74L21 8M21 3v5h-5" />
                </svg>
                {tTools('pdfMultiTool.rotateRight') || 'Right'}
              </Button>
            </div>

            <div className="w-px h-6 bg-[hsl(var(--color-border))]" />

            {/* Transform Actions */}
            <div className="flex items-center gap-1">
              <Button variant="ghost" size="sm" onClick={handleDuplicateSelected} disabled={selectedCount === 0 || isProcessing}>
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <rect x="9" y="9" width="13" height="13" rx="2" strokeWidth={2} />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" />
                </svg>
                {tTools('pdfMultiTool.duplicate') || 'Duplicate'}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setShowAddBlankModal(true)}
                disabled={isProcessing}
              >
                <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
                {tTools('pdfMultiTool.addBlank') || 'Add Blank'}
              </Button>
            </div>

            <div className="w-px h-6 bg-[hsl(var(--color-border))]" />

            {/* Delete Action */}
            <Button
              variant="outline"
              size="sm"
              onClick={handleDeleteSelected}
              disabled={selectedCount === 0 || isProcessing}
              className="!text-red-600 !border-red-200 hover:!bg-red-50 dark:!border-red-800 dark:hover:!bg-red-900/20"
            >
              <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              {tTools('pdfMultiTool.delete') || 'Delete'}
            </Button>

            {/* Spacer */}
            <div className="flex-1" />

            {/* Info */}
            <div className="text-sm text-[hsl(var(--color-muted-foreground))]">
              {totalPages} {totalPages === 1 ? 'page' : 'pages'}
              {selectedCount > 0 && ` • ${selectedCount} selected`}
            </div>

            {/* Clear All */}
            <Button variant="ghost" size="sm" onClick={handleClearAll} disabled={isProcessing}>
              {tTools('pdfMultiTool.clearAll') || 'Clear All'}
            </Button>
          </div>

          {/* Page Grid */}
          {isLoadingPreviews ? (
            <div className="flex items-center justify-center py-16">
              <div className="flex flex-col items-center gap-3">
                <div className="w-8 h-8 border-2 border-[hsl(var(--color-primary))] border-t-transparent rounded-full animate-spin" />
                <p className="text-sm text-[hsl(var(--color-muted-foreground))]">
                  {t('status.loading') || 'Loading previews...'}
                </p>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 xl:grid-cols-8 gap-4 max-h-[500px] overflow-y-auto p-1">
              {pagePreviews.map((page, index) => (
                <div
                  key={`page-${index}`}
                  draggable={!isProcessing}
                  onDragStart={() => handleDragStart(index)}
                  onDragOver={(e) => handleDragOver(e, index)}
                  onDragEnd={handleDragEnd}
