                      </svg>
                    </button>
                    <button
                      onClick={(e) => { e.stopPropagation(); handleRotatePage(index, 90); }}
                      className="w-6 h-6 bg-white/90 dark:bg-slate-800/90 rounded shadow flex items-center justify-center hover:bg-white dark:hover:bg-slate-700"
                      title="Rotate right"
