          {isProcessing
            ? (t('status.processing') || 'Processing...')
            : (tTools('pdfToImage.convertButton') || 'Convert to Images')
          }
        </Button>

        {result && !isMultipleImages && (
          <DownloadButton
            file={result as Blob}
            filename={`${file?.file.name.replace(/\.pdf$/i, '')}.${format === 'jpeg' ? 'jpg' : format}`}
            variant="secondary"
            size="lg"
