                                    prose-pre:bg-gray-900 prose-pre:text-gray-100 prose-pre:p-4 prose-pre:rounded-lg prose-pre:overflow-x-auto
                                    prose-ul:list-disc prose-ul:pl-6 prose-ul:mb-4
