    );
}

/**
 * Excel to PDF Processor
 * 
 * Converts Excel spreadsheets to PDF using LibreOffice WASM.
 * Uses the shared LibreOfficeConverter singleton (same approach as BentoPDF).
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/** Maximum file size: 50 MB */
const MAX_FILE_SIZE = 50 * 1024 * 1024;
/** Conversion timeout: 5 minutes */
const CONVERT_TIMEOUT_MS = 5 * 60 * 1000;

let converterPromise: Promise<any> | null = null;
let converterInstance: any = null;

async function getConverter(onProgress?: (percent: number, message: string) => void): Promise<any> {
    if (converterInstance?.isReady()) return converterInstance;

    if (converterPromise) {
        await converterPromise;
        return converterInstance;
    }

    converterPromise = (async () => {
        const { getLibreOfficeConverter } = await import('@/lib/libreoffice');
        converterInstance = getLibreOfficeConverter();
        await converterInstance.initialize((progress: any) => {
            onProgress?.(progress.percent, progress.message);
        });
    })();

    await converterPromise;
    return converterInstance;
}
export interface ExcelToPDFOptions {
    /** Reserved for future options */
}

export class ExcelToPDFProcessor extends BasePDFProcessor {
    private conversionProgressTimer: ReturnType<typeof setInterval> | null = null;

    private startConversionProgress(): void {
        this.stopConversionProgress();
        // LibreOffice convert() does not expose granular runtime progress.
        // Keep UI responsive by advancing a bounded pseudo-progress while waiting.
        this.conversionProgressTimer = setInterval(() => {
            if (this.progress >= 98) return;
            this.updateProgress(this.progress + 1, 'Converting Excel to PDF...');
        }, 800);
    }

    private stopConversionProgress(): void {
        if (this.conversionProgressTimer) {
            clearInterval(this.conversionProgressTimer);
            this.conversionProgressTimer = null;
        }
    }

    protected reset(): void {
        this.stopConversionProgress();
        super.reset();
    }

    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one Excel spreadsheet.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];
        const ext = file.name.split('.').pop()?.toLowerCase() || '';
        const validExts = ['xlsx', 'xls', 'ods', 'csv'];

        if (!validExts.includes(ext)) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload .xlsx, .xls, .ods, or .csv.',
                `Received: ${file.type || file.name}`
            );
        }

        // File size guard
        if (file.size > MAX_FILE_SIZE) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                `File is too large (${(file.size / 1024 / 1024).toFixed(1)} MB). Maximum supported size is ${MAX_FILE_SIZE / 1024 / 1024} MB.`,
                `File size: ${file.size} bytes, limit: ${MAX_FILE_SIZE} bytes`
            );
        }

        try {
            this.updateProgress(5, 'Loading conversion engine (first time may take 1-2 minutes)...');

            const converter = await getConverter((percent, message) => {
                this.updateProgress(Math.min(percent * 0.8, 80), message);
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(85, 'Converting Excel to PDF...');
            this.startConversionProgress();

            // Convert with timeout protection
            const pdfBlob = await Promise.race([
                converter.convertToPdf(file),
                new Promise<never>((_, reject) =>
                    setTimeout(() => reject(new Error(
                        `Conversion timed out after ${CONVERT_TIMEOUT_MS / 60000} minutes. The file may be too complex.`
                    )), CONVERT_TIMEOUT_MS)
                ),
            ]);
            this.stopConversionProgress();

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.(xlsx?|ods|csv)$/i, '');
            return this.createSuccessOutput(pdfBlob, `${baseName}.pdf`, { format: 'pdf' });

        } catch (error) {
            this.stopConversionProgress();
            console.error('Conversion error:', error);
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert Excel to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

export function createExcelToPDFProcessor(): ExcelToPDFProcessor {
    return new ExcelToPDFProcessor();
}

export async function excelToPDF(
    file: File,
    options?: Partial<ExcelToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createExcelToPDFProcessor();
    return processor.process({ files: [file], options: options || {} }, onProgress);
}

/**
 * Extract Images from PDF Processor
 * Requirements: 5.1
 * 
 * Extracts all embedded images from PDF files using PyMuPDF (WASM).
 * Supports filtering small images and batch downloads as ZIP.
 */


import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * Extracted image info
 */
export interface ExtractedImage {
    /** Unique index */
    index: number;
    /** Image name (e.g., "image_1.png") */
    name: string;
    /** File extension without dot */
    ext: string;
    /** Image data as ArrayBuffer */
    data: ArrayBuffer;
    /** Image width in pixels */
    width: number;
    /** Image height in pixels */
    height: number;
    /** Page number where image was found */
    pageNumber: number;
    /** File size in bytes */
    size: number;
}

/**
 * Extract Images options
 */
export interface ExtractImagesOptions {
    /** Minimum width to include (pixels) */
    minWidth: number;
    /** Minimum height to include (pixels) */
    minHeight: number;
    /** Minimum file size to include (bytes) */
    minSize: number;
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: ExtractImagesOptions = {
    minWidth: 50,  // Filter out images smaller than 50px
    minHeight: 50,
    minSize: 10240, // Filter out images smaller than 10KB
};

/**
 * Extract Images from PDF Processor
 */
export class ExtractImagesPDFProcessor extends BasePDFProcessor {
    private worker: Worker | null = null;
    private workerReady = false;

    /**
     * Initialize the worker
     */
    private async initWorker(): Promise<void> {
        if (this.worker) return;

        return new Promise((resolve, reject) => {
            try {
                this.worker = new Worker('/workers/extract-images.worker.js', { type: 'module' });

                const handleMessage = (event: MessageEvent) => {
                    const { type, error, message } = event.data;

                    if (type === 'init-complete') {
                        this.workerReady = true;
                        resolve();
                    } else if (type === 'status') {
                        this.updateProgress(0, message);
                    } else if (type === 'error') {
                        reject(new Error(error || 'Worker initialization failed'));
                    }
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', (err) => {
                    reject(new Error('Worker connection failed'));
                });

                // Send init message
                this.worker.postMessage({
                    type: 'init',
                    id: 'init-' + Date.now(),
                    data: {}
                });

            } catch (err) {
                reject(err);
            }
        });
    }

    /**
     * Terminate the worker
     */
    private terminateWorker() {
        if (this.worker) {
            this.worker.terminate();
            this.worker = null;
            this.workerReady = false;
        }
    }

    /**
     * Process PDF file(s) and extract images
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files, options } = input;
        const extractOptions: ExtractImagesOptions = {
            ...DEFAULT_OPTIONS,
            ...(options as Partial<ExtractImagesOptions>),
        };

        if (files.length === 0) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide at least one PDF file.',
                'No files provided.'
            );
        }

        try {
            this.updateProgress(5, 'Initializing extractor...');

            try {
                await this.initWorker();
            } catch (err) {
                console.error('Failed to initialize worker:', err);
                return this.createErrorOutput(
                    PDFErrorCode.WORKER_FAILED,
                    'Failed to initialize extraction worker.',
                    err instanceof Error ? err.message : String(err)
                );
            }

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            const allExtractedImages: ExtractedImage[] = [];
            const progressPerFile = 90 / files.length;
            let currentImageIndex = 0;

            for (let fileIndex = 0; fileIndex < files.length; fileIndex++) {
                const file = files[fileIndex];

                if (this.checkCancelled()) {
                    break;
                }

                this.updateProgress(
                    10 + fileIndex * progressPerFile,
                    `Processing ${file.name}...`
                );

                try {
                    // Extract images using Worker
                    const fileImages = await new Promise<any[]>((resolve, reject) => {
                        if (!this.worker) {
                            reject(new Error('Worker not initialized'));
                            return;
                        }

                        const msgId = 'extract-' + Date.now();

                        const handleMessage = (event: MessageEvent) => {
                            const { type, id, result, error, message } = event.data;

                            if (type === 'status') {
                                // Optional: update progress with detailed message
                                return;
                            }

                            if (id !== msgId) return;

                            if (type === 'extract-complete') {
                                cleanup();
                                resolve(result);
                            } else if (type === 'error') {
                                cleanup();
                                reject(new Error(error || 'Extraction failed'));
                            }
                        };

                        const handleError = (error: ErrorEvent) => {
                            cleanup();
                            reject(new Error('Worker error: ' + error.message));
                        };

                        const cleanup = () => {
                            this.worker?.removeEventListener('message', handleMessage);
                            this.worker?.removeEventListener('error', handleError);
                        };

                        this.worker.addEventListener('message', handleMessage);
                        this.worker.addEventListener('error', handleError);

                        this.worker.postMessage({
                            type: 'extract',
                            id: msgId,
                            data: {
                                file: file,
                                options: extractOptions
                            }
                        });
                    });

                    // Process results
                    for (const rawImg of fileImages) {
                        currentImageIndex++;
                        allExtractedImages.push({
                            ...rawImg,
                            index: currentImageIndex,
                            // Ensure data is ArrayBuffer (Worker might return Uint8Array)
                            data: rawImg.data instanceof Uint8Array ? rawImg.data.buffer : rawImg.data,
                            name: `image_${currentImageIndex}.${rawImg.ext}`
                        });
                    }

                } catch (fileError) {
                    console.warn(`Failed to process file ${file.name}:`, fileError);
                    // Continue with other files if one fails? 
                    // Or maybe we should just log it. 
                    // The UI will show whatever images were successfully extracted.
                }
            }

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(100, 'Complete!');

            if (allExtractedImages.length === 0) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_FAILED,
                    'No images found in the selected PDF(s).',
                    'The PDF may not contain any embedded images that match the filter criteria.'
                );
            }

            // Return images as metadata
            return {
                success: true,
                result: undefined,
                metadata: {
                    images: allExtractedImages,
                    imageCount: allExtractedImages.length,
                    totalSize: allExtractedImages.reduce((sum, img) => sum + img.size, 0),
                },
            };

        } catch (error) {
            this.terminateWorker();
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to extract images from PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }

    /**
     * Get accepted file types
     */
    protected getAcceptedTypes(): string[] {
        return ['application/pdf'];
    }
}

