        },
        onProgress
    );
}

/**
 * Extract Tables Processor
 * 
 * Extracts tables from PDF and exports them as JSON, Markdown, or CSV.
 * Uses text extraction and table detection algorithms.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfjs } from '../loader';

/**
 * Output format for extracted tables
 */
export type TableExportFormat = 'json' | 'markdown' | 'csv';

/**
 * Extract Tables options
 */
export interface ExtractTablesOptions {
    /** Output format */
    format: TableExportFormat;
    /** Page range (e.g., "1-5,8", empty for all) */
    pageRange?: string;
    /** Minimum number of columns to consider as table */
    minColumns: number;
    /** Minimum number of rows to consider as table */
    minRows: number;
    /** Whether to include page numbers in output */
    includePageNumbers: boolean;
}

/**
 * Default extract tables options
 */
const DEFAULT_EXTRACT_OPTIONS: ExtractTablesOptions = {
    format: 'json',
    pageRange: '',
    minColumns: 2,
    minRows: 2,
    includePageNumbers: true,
};

/**
 * Represents a detected table
 */
interface DetectedTable {
    pageNumber: number;
    rows: string[][];
    startY: number;
    endY: number;
}

/**
 * Text item from PDF.js
 */
interface TextItem {
    str: string;
    transform: number[];
    width: number;
    height: number;
}

/**
 * Parse page range string
 */
function parsePageRange(rangeStr: string, totalPages: number): number[] {
    if (!rangeStr || rangeStr.trim() === '') {
        return Array.from({ length: totalPages }, (_, i) => i + 1);
    }

    const pages = new Set<number>();
    const parts = rangeStr.split(',').map(p => p.trim());

    for (const part of parts) {
        if (part.includes('-')) {
            const [start, end] = part.split('-').map(n => parseInt(n.trim(), 10));
            if (!isNaN(start) && !isNaN(end)) {
                for (let i = Math.max(1, start); i <= Math.min(totalPages, end); i++) {
                    pages.add(i);
                }
            }
        } else {
            const pageNum = parseInt(part, 10);
            if (!isNaN(pageNum) && pageNum >= 1 && pageNum <= totalPages) {
                pages.add(pageNum);
            }
        }
    }

    return Array.from(pages).sort((a, b) => a - b);
}

/**
 * Detect tables from text items on a page
 * This is a simplified algorithm - real table detection is more complex
 */
function detectTables(
    textItems: TextItem[],
    pageNumber: number,
    minColumns: number,
    minRows: number
): DetectedTable[] {
    if (textItems.length === 0) return [];

    // Group text items by Y position (rows)
    const tolerance = 5; // Y position tolerance for grouping
    const rowGroups = new Map<number, TextItem[]>();

    for (const item of textItems) {
        const y = Math.round(item.transform[5] / tolerance) * tolerance;
        if (!rowGroups.has(y)) {
            rowGroups.set(y, []);
        }
        rowGroups.get(y)!.push(item);
    }

    // Sort rows by Y position (descending for PDF coordinates)
    const sortedYs = Array.from(rowGroups.keys()).sort((a, b) => b - a);

    // Detect potential column positions
    const columnPositions = new Set<number>();
    const xTolerance = 10;

    for (const items of rowGroups.values()) {
        for (const item of items) {
            const x = Math.round(item.transform[4] / xTolerance) * xTolerance;
            columnPositions.add(x);
        }
    }

    const sortedColumns = Array.from(columnPositions).sort((a, b) => a - b);

    // If not enough columns, no table
    if (sortedColumns.length < minColumns) return [];

    // Look for consecutive rows with similar column structure
    const tables: DetectedTable[] = [];
    let currentTable: string[][] = [];
    let tableStartY = 0;
    let tableEndY = 0;

    for (const y of sortedYs) {
        const items = rowGroups.get(y)!;

        // Assign items to columns
        const row: string[] = new Array(sortedColumns.length).fill('');

        for (const item of items) {
            const x = Math.round(item.transform[4] / xTolerance) * xTolerance;
            const colIndex = sortedColumns.indexOf(x);
            if (colIndex >= 0) {
                row[colIndex] = (row[colIndex] + ' ' + item.str).trim();
            }
        }

        // Check if this row has enough non-empty cells
        const nonEmptyCells = row.filter(cell => cell.trim() !== '').length;

        if (nonEmptyCells >= minColumns) {
            if (currentTable.length === 0) {
                tableStartY = y;
            }
            tableEndY = y;
            currentTable.push(row);
        } else if (currentTable.length >= minRows) {
            // End of table
            tables.push({
                pageNumber,
                rows: currentTable,
                startY: tableStartY,
                endY: tableEndY,
            });
            currentTable = [];
        } else {
            // Not enough rows, reset
            currentTable = [];
        }
    }

    // Don't forget the last table
    if (currentTable.length >= minRows) {
        tables.push({
            pageNumber,
            rows: currentTable,
            startY: tableStartY,
            endY: tableEndY,
        });
    }

    return tables;
}

/**
 * Convert tables to JSON
 */
function tablesToJson(tables: DetectedTable[], includePageNumbers: boolean): string {
    const output = tables.map((table, index) => {
        const headers = table.rows[0];
        const dataRows = table.rows.slice(1);

        const result: any = {
            tableIndex: index + 1,
            headers,
            rows: dataRows.map(row => {
                const obj: Record<string, string> = {};
                headers.forEach((header, i) => {
                    obj[header || `column_${i + 1}`] = row[i] || '';
                });
                return obj;
            }),
        };

        if (includePageNumbers) {
            result.pageNumber = table.pageNumber;
        }

        return result;
    });

    return JSON.stringify(output, null, 2);
}

/**
 * Convert tables to Markdown
 */
function tablesToMarkdown(tables: DetectedTable[], includePageNumbers: boolean): string {
    let output = '';

    tables.forEach((table, index) => {
        if (includePageNumbers) {
            output += `## Table ${index + 1} (Page ${table.pageNumber})\n\n`;
        } else {
            output += `## Table ${index + 1}\n\n`;
        }

        // Header row
        output += '| ' + table.rows[0].map(cell => cell || ' ').join(' | ') + ' |\n';

        // Separator
        output += '| ' + table.rows[0].map(() => '---').join(' | ') + ' |\n';

        // Data rows
        for (let i = 1; i < table.rows.length; i++) {
            output += '| ' + table.rows[i].map(cell => cell || ' ').join(' | ') + ' |\n';
        }

        output += '\n';
    });

    return output;
}

/**
 * Convert tables to CSV
 */
function tablesToCsv(tables: DetectedTable[], includePageNumbers: boolean): string {
    let output = '';

    tables.forEach((table, index) => {
        if (includePageNumbers) {
            output += `# Table ${index + 1} (Page ${table.pageNumber})\n`;
        }

        for (const row of table.rows) {
            output += row.map(cell => {
                // Escape quotes and wrap in quotes if contains comma
                const escaped = cell.replace(/"/g, '""');
                return escaped.includes(',') || escaped.includes('\n')
                    ? `"${escaped}"`
                    : escaped;
            }).join(',') + '\n';
        }

        output += '\n';
    });

    return output;
}

/**
 * Extract Tables Processor
 */
export class ExtractTablesProcessor extends BasePDFProcessor {
    /**
     * Process PDF file and extract tables
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files, options } = input;
        const extractOptions: ExtractTablesOptions = {
            ...DEFAULT_EXTRACT_OPTIONS,
            ...(options as Partial<ExtractTablesOptions>),
        };

        // Validate single file
        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one PDF file.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];

        try {
            this.updateProgress(5, 'Loading PDF library...');

            // Load PDF.js library
            const pdfjsLib = await loadPdfjs();

            this.updateProgress(10, 'Loading PDF file...');

            // Read file as ArrayBuffer
            const arrayBuffer = await file.arrayBuffer();

            // Load PDF with pdf.js
            const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
            const pdfDoc = await loadingTask.promise;

            const totalPages = pdfDoc.numPages;

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(10, 'Parsing page range...');

            // Parse page range
            const pagesToProcess = parsePageRange(extractOptions.pageRange || '', totalPages);

            this.updateProgress(15, 'Extracting tables...');

            const allTables: DetectedTable[] = [];

            // Process each page
            for (let i = 0; i < pagesToProcess.length; i++) {
                if (this.checkCancelled()) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_CANCELLED,
                        'Processing was cancelled.'
                    );
                }

                const pageNum = pagesToProcess[i];
                const progress = 15 + ((i / pagesToProcess.length) * 70);
                this.updateProgress(progress, `Analyzing page ${pageNum}...`);

                try {
                    const page = await pdfDoc.getPage(pageNum);
                    const textContent = await page.getTextContent();

                    const textItems: TextItem[] = textContent.items
                        .filter((item: any) => 'str' in item)
                        .map((item: any) => ({
                            str: item.str,
                            transform: item.transform,
                            width: item.width,
                            height: item.height,
                        }));

                    const tables = detectTables(
                        textItems,
                        pageNum,
                        extractOptions.minColumns,
                        extractOptions.minRows
                    );

                    allTables.push(...tables);
                } catch (pageError) {
                    console.warn(`Failed to process page ${pageNum}:`, pageError);
                }
            }

            this.updateProgress(90, 'Formatting output...');

            if (allTables.length === 0) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_FAILED,
                    'No tables found in the PDF.',
                    'Try adjusting the minimum columns/rows settings or check a different page range.'
                );
            }

            // Format output
            let content: string;
            let mimeType: string;
            let extension: string;

            switch (extractOptions.format) {
                case 'json':
                    content = tablesToJson(allTables, extractOptions.includePageNumbers);
                    mimeType = 'application/json';
                    extension = '.json';
                    break;
                case 'markdown':
                    content = tablesToMarkdown(allTables, extractOptions.includePageNumbers);
                    mimeType = 'text/markdown';
                    extension = '.md';
                    break;
                case 'csv':
                    content = tablesToCsv(allTables, extractOptions.includePageNumbers);
                    mimeType = 'text/csv';
                    extension = '.csv';
                    break;
                default:
                    content = tablesToJson(allTables, extractOptions.includePageNumbers);
                    mimeType = 'application/json';
                    extension = '.json';
            }

            const blob = new Blob([content], { type: mimeType });

            this.updateProgress(100, 'Complete!');

            // Generate output filename
            const baseName = file.name.replace(/\.pdf$/i, '');
            const outputFilename = `${baseName}_tables${extension}`;

            return this.createSuccessOutput(blob, outputFilename, {
                tablesFound: allTables.length,
                pagesProcessed: pagesToProcess.length,
                format: extractOptions.format,
            });

        } catch (error) {
            if (error instanceof Error && error.message.includes('encrypt')) {
                return this.createErrorOutput(
                    PDFErrorCode.PDF_ENCRYPTED,
                    'The PDF file is encrypted.',
                    'Please decrypt the file first.'
                );
            }

            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to extract tables from PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }

    /**
     * Get accepted file types
     */
    protected getAcceptedTypes(): string[] {
        return ['application/pdf'];
    }
}

/**
 * Create a new instance of the extract tables processor
 */
export function createExtractTablesProcessor(): ExtractTablesProcessor {
    return new ExtractTablesProcessor();
}

/**
 * Extract tables from PDF (convenience function)
 */
export async function extractTables(
    file: File,
    options?: Partial<ExtractTablesOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createExtractTablesProcessor();
    return processor.process(
        {
            files: [file],
            options: options || {},
        },
        onProgress
    );
}

/**
 * PDF Extract Pages Processor
 * Requirements: 5.1
 * 
 * Implements PDF page extraction functionality using pdf-lib.
 * Supports extracting specific pages into a new PDF.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
  PageRange,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Extract options for page extraction
 */
export interface ExtractOptions {
  /** Pages to extract (1-based page numbers) */
  pages: number[];
}

/**
 * Default extract options
 */
const DEFAULT_EXTRACT_OPTIONS: ExtractOptions = {
  pages: [],
};

/**
 * Extract Pages PDF Processor
 * Extracts specific pages from a PDF document into a new PDF.
 */
export class ExtractPagesPDFProcessor extends BasePDFProcessor {
  /**
   * Process a PDF file and extract specified pages
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const extractOptions: ExtractOptions = {
      ...DEFAULT_EXTRACT_OPTIONS,
      ...(options as Partial<ExtractOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Exactly 1 PDF file is required for extraction.',
        `Received ${files.length} file(s).`
      );
    }

    // Validate pages are provided
    if (!extractOptions.pages || extractOptions.pages.length === 0) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'At least one page is required for extraction.',
        'Please specify pages to extract.'
      );
    }

    try {
      this.updateProgress(5, 'Loading PDF library...');

      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Loading source PDF...');

      const file = files[0];
      const arrayBuffer = await file.arrayBuffer();

      // Load the source PDF
      let sourcePdf;
      try {
        sourcePdf = await pdfLib.PDFDocument.load(arrayBuffer, {
          ignoreEncryption: false,
        });
      } catch (error) {
        if (error instanceof Error && error.message.includes('encrypt')) {
          return this.createErrorOutput(
            PDFErrorCode.PDF_ENCRYPTED,
            'The PDF file is encrypted.',
            'Please decrypt the file before extracting pages.'
          );
        }
        throw error;
      }

      const totalPages = sourcePdf.getPageCount();
      this.updateProgress(20, `Source PDF has ${totalPages} pages.`);

      // Validate pages
      const validationError = validatePages(extractOptions.pages, totalPages);
      if (validationError) {
        return this.createErrorOutput(
          PDFErrorCode.INVALID_PAGE_RANGE,
          validationError,
          `The PDF has ${totalPages} pages.`
        );
      }

      // Remove duplicates and sort
      const uniquePages = [...new Set(extractOptions.pages)].sort((a, b) => a - b);

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(30, 'Creating new document...');

      // Create a new PDF document
      const newPdf = await pdfLib.PDFDocument.create();

      // Copy pages
      const progressPerPage = 60 / uniquePages.length;

      for (let i = 0; i < uniquePages.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }

        const pageNum = uniquePages[i];
        const pageIndex = pageNum - 1; // Convert to 0-based index

        this.updateProgress(
          30 + (i * progressPerPage),
          `Extracting page ${pageNum}...`
        );

        const [copiedPage] = await newPdf.copyPages(sourcePdf, [pageIndex]);
        newPdf.addPage(copiedPage);
      }

      this.updateProgress(90, 'Saving extracted pages...');

      // Save the new PDF
      const pdfBytes = await newPdf.save({ useObjectStreams: true });
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateExtractedFilename(file.name, uniquePages);

      return this.createSuccessOutput(blob, outputFilename, {
        extractedPageCount: uniquePages.length,
        originalPageCount: totalPages,
        extractedPages: uniquePages,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to extract pages from PDF file.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for extract processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Validate pages array
 */
function validatePages(pages: number[], totalPages: number): string | null {
  if (pages.length === 0) {
    return 'No pages specified for extraction.';
  }

  for (let i = 0; i < pages.length; i++) {
    const pageNum = pages[i];

    if (!Number.isInteger(pageNum)) {
      return `Invalid page number: ${pageNum}`;
    }

    if (pageNum < 1) {
      return `Page number must be at least 1. Found ${pageNum}.`;
    }

    if (pageNum > totalPages) {
      return `Page ${pageNum} exceeds total pages (${totalPages}).`;
    }
  }

  return null;
}

/**
 * Get filename without extension
 */
function getFileNameWithoutExtension(filename: string): string {
  const lastDot = filename.lastIndexOf('.');
  if (lastDot === -1) return filename;
  return filename.slice(0, lastDot);
}

/**
 * Generate a filename for the extracted PDF
 */
function generateExtractedFilename(originalName: string, pages: number[]): string {
  const baseName = getFileNameWithoutExtension(originalName);

  if (pages.length === 1) {
    return `${baseName}_page_${pages[0]}.pdf`;
  }

  if (pages.length <= 3) {
    return `${baseName}_pages_${pages.join('-')}.pdf`;
  }

  return `${baseName}_${pages.length}_pages_extracted.pdf`;
}

/**
 * Parse page selection string into array of page numbers
 * Supports formats like: "1,3,5", "1-5", "1-3,5,7-10"
 */
export function parsePageSelection(selectionString: string, totalPages: number): number[] {
  const pages: number[] = [];
  const parts = selectionString.split(',').map(s => s.trim()).filter(s => s.length > 0);

  for (const part of parts) {
    if (part.includes('-')) {
      const [startStr, endStr] = part.split('-').map(s => s.trim());
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (!isNaN(start) && !isNaN(end) && start <= end) {
        for (let i = start; i <= Math.min(end, totalPages); i++) {
          if (i >= 1) pages.push(i);
        }
      }
    } else {
      const pageNum = parseInt(part, 10);
      if (!isNaN(pageNum) && pageNum >= 1 && pageNum <= totalPages) {
        pages.push(pageNum);
      }
    }
  }

  // Remove duplicates and sort
  return [...new Set(pages)].sort((a, b) => a - b);
}

/**
 * Create a new instance of the extract processor
 */
export function createExtractProcessor(): ExtractPagesPDFProcessor {
  return new ExtractPagesPDFProcessor();
}

/**
 * Extract pages from a PDF file (convenience function)
 */
export async function extractPages(
  file: File,
  pages: number[],
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createExtractProcessor();
  return processor.process(
    {
      files: [file],
      options: { pages },
    },
    onProgress
  );
}

/**
 * FB2 to PDF Processor
 * 
 * Converts FictionBook (FB2) e-book files to PDF documents.
 * Uses PyMuPDF's native convert_to_pdf() for optimal file size and text preservation.
 * 
 * Benefits of native conversion:
 * - Much smaller file sizes (text is vector, not images)
 * - Searchable/selectable text in output PDF
 * - Better quality at any zoom level
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * FB2 to PDF options
 */
export interface FB2ToPDFOptions {
    // Reserved for future options
}

/**
 * FB2 to PDF Processor
 * Converts FB2 files to PDF using a Web Worker.
 */
export class FB2ToPDFProcessor extends BasePDFProcessor {
    private worker: Worker | null = null;
    private workerReady = false;

    /**
     * Initialize the worker
     */
    private async initWorker(): Promise<void> {
        if (this.worker) return;

        return new Promise((resolve, reject) => {
            try {
                this.worker = new Worker('/workers/fb2-to-pdf.worker.js', { type: 'module' });

                const handleMessage = (event: MessageEvent) => {
                    const { type, error, message } = event.data;

                    if (type === 'init-complete') {
                        this.workerReady = true;
                        resolve();
                    } else if (type === 'status') {
                        this.updateProgress(0, message);
                    } else if (type === 'error') {
                        reject(new Error(error || 'Worker initialization failed'));
                    }
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', (err) => {
                    reject(new Error('Worker connection failed'));
                });

                // Send init message
                this.worker.postMessage({
                    type: 'init',
                    id: 'init-' + Date.now(),
                    data: {}
                });

            } catch (err) {
                reject(err);
            }
        });
    }

    /**
     * Terminate the worker
     */
    private terminateWorker() {
        if (this.worker) {
            this.worker.terminate();
            this.worker = null;
            this.workerReady = false;
        }
    }

    /**
     * Reset processor state
     */
    protected reset(): void {
        super.reset();
    }

    /**
     * Process FB2 and convert to PDF
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        // Support multiple files
        if (files.length === 0) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide at least one FB2 file.',
                'No files received.'
            );
        }

        // Validate file types
        for (const file of files) {
            if (!file.name.toLowerCase().endsWith('.fb2') && !file.name.toLowerCase().endsWith('.fb2.zip')) {
                return this.createErrorOutput(
                    PDFErrorCode.FILE_TYPE_INVALID,
                    'Invalid file type. Please upload FB2 files (.fb2, .fb2.zip).',
                    `Received: ${file.type || file.name}`
                );
            }
        }

        try {
            this.updateProgress(10, 'Initializing converter...');

            try {
                await this.initWorker();
            } catch (err) {
                console.error('Failed to initialize worker:', err);
                return this.createErrorOutput(
                    PDFErrorCode.WORKER_FAILED,
                    'Failed to initialize conversion worker.',
                    err instanceof Error ? err.message : String(err)
                );
            }

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            // Process single or multiple files
            if (files.length === 1) {
                return await this.processSingleFile(files[0]);
            } else {
                return await this.processMultipleFiles(files);
            }

        } catch (error) {
            console.error('Conversion error:', error);
            this.terminateWorker();

            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert FB2 to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }

    /**
     * Process a single FB2 file
     */
    private async processSingleFile(file: File): Promise<ProcessOutput> {
        this.updateProgress(30, 'Converting FB2 to PDF...');

        const pdfBlob = await this.convertFile(file);

        if (this.checkCancelled()) {
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_CANCELLED,
                'Processing was cancelled.'
            );
        }

        this.updateProgress(100, 'Conversion complete!');

        const baseName = file.name.replace(/\.fb2(\.zip)?$/i, '');
        const outputName = `${baseName}.pdf`;

        return this.createSuccessOutput(
            pdfBlob,
            outputName,
            { format: 'pdf' }
        );
    }

    /**
     * Process multiple FB2 files
     */
    private async processMultipleFiles(files: File[]): Promise<ProcessOutput> {
        const results: Blob[] = [];
        const totalFiles = files.length;

        for (let i = 0; i < totalFiles; i++) {
            const file = files[i];
            const baseProgress = 30 + (i * 60 / totalFiles);

            this.updateProgress(baseProgress, `Converting ${i + 1}/${totalFiles}: ${file.name}...`);

            const pdfBlob = await this.convertFile(file);
            results.push(pdfBlob);

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }
        }

        this.updateProgress(100, 'All conversions complete!');

        return this.createSuccessOutput(
            results,
            'fb2-converted.pdf',
            { format: 'pdf' }
        );
    }

    /**
     * Convert a single file using the worker
     */
    private async convertFile(file: File): Promise<Blob> {
        return new Promise<Blob>((resolve, reject) => {
            if (!this.worker) {
                reject(new Error('Worker not initialized'));
                return;
            }

            const msgId = 'convert-' + Date.now() + '-' + Math.random();

            const handleMessage = (event: MessageEvent) => {
                const { type, id, result, error } = event.data;

                if (type === 'status') {
                    return;
                }

                if (id !== msgId) return;

                if (type === 'convert-complete') {
                    cleanup();
                    resolve(result);
                } else if (type === 'error') {
                    cleanup();
                    reject(new Error(error || 'Conversion failed'));
                }
            };

            const handleError = (error: ErrorEvent) => {
                cleanup();
                reject(new Error('Worker error: ' + error.message));
            };

            const cleanup = () => {
                this.worker?.removeEventListener('message', handleMessage);
                this.worker?.removeEventListener('error', handleError);
            };

            this.worker.addEventListener('message', handleMessage);
            this.worker.addEventListener('error', handleError);

            this.worker.postMessage({
                type: 'convert',
                id: msgId,
                data: {
                    file: file
                }
            });
        });
    }
}

/**
 * Create a new instance of the FB2 to PDF processor
 */
export function createFB2ToPDFProcessor(): FB2ToPDFProcessor {
    return new FB2ToPDFProcessor();
}

/**
 * Convert FB2 to PDF (convenience function)
 */
export async function fb2ToPDF(
    files: File | File[],
    options?: Partial<FB2ToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createFB2ToPDFProcessor();
    const fileArray = Array.isArray(files) ? files : [files];
    return processor.process(
        {
            files: fileArray,
            options: options || {},
        },
        onProgress
    );
}

/**
 * Find and Redact Processor
 * Requirements: 5.1
 * 
 * Search for specific text/patterns across all pages and redact matching content.
 * Useful for batch redacting sensitive information like account numbers, names, etc.
 */

import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';
import { loadPdfjs } from '../loader';

/**
 * Text match found in the PDF
 */
export interface TextMatch {
    /** Page number (1-indexed) */
    page: number;
    /** Text content that matched */
    text: string;
    /** X coordinate from left edge (in points) */
    x: number;
    /** Y coordinate from bottom edge (in points) - PDF coordinates */
    y: number;
    /** Width of the text (in points) */
    width: number;
    /** Height of the text (in points) */
    height: number;
    /** Unique identifier for this match */
    id: string;
    /** Whether this match is selected for redaction */
    selected: boolean;
}

/**
 * Search options for finding text
 */
export interface SearchOptions {
    /** Single search term or pattern (for backwards compatibility) */
    searchTerm?: string;
    /** Multiple search terms (comma or newline separated in input) */
    searchTerms?: string[];
    /** Whether to use case-sensitive matching */
    caseSensitive: boolean;
    /** Whether to use regex pattern matching */
    useRegex: boolean;
    /** Whether to match whole words only */
    wholeWord: boolean;
}

/**
 * Parse search input into multiple terms
 */
export function parseSearchTerms(input: string): string[] {
    // Split by comma (both English and Chinese), newline, trim whitespace, and filter empty strings
    return input
        .split(/[,，\n]/)
        .map(term => term.trim())
        .filter(term => term.length > 0);
}

/**
 * Redaction options
 */
export interface FindAndRedactOptions extends SearchOptions {
    /** Color for the redaction boxes (default: black) */
    color?: { r: number; g: number; b: number };
    /** Whether to add a border around redaction boxes */
    addBorder?: boolean;
    /** Replacement text to show in redacted areas */
    replacementText?: string;
    /** Array of match IDs to redact (if empty, redact all matches) */
    selectedMatchIds?: string[];
}

/**
 * Search result containing all matches
 */
export interface SearchResult {
    success: boolean;
    matches: TextMatch[];
    totalCount: number;
    pagesWithMatches: number[];
    error?: string;
}

/**
 * Redaction result
 */
export interface RedactionResult {
    success: boolean;
    result?: Blob;
    error?: string;
    redactedCount: number;
}

/**
 * Progress callback type
 */
export type ProgressCallback = (progress: number, message?: string) => void;

/**
 * Search for text in a PDF document
 * Returns all matches with their positions for preview
 */
export async function searchTextInPDF(
    file: File,
    options: SearchOptions,
    onProgress?: ProgressCallback
): Promise<SearchResult> {
    try {
        if (!file) {
            return {
                success: false,
                matches: [],
                totalCount: 0,
                pagesWithMatches: [],
                error: 'No file provided',
            };
        }

        // Get search terms array
        const searchTerms: string[] = options.searchTerms && options.searchTerms.length > 0
            ? options.searchTerms
            : options.searchTerm
                ? [options.searchTerm]
                : [];

        if (searchTerms.length === 0 || searchTerms.every(t => t.trim() === '')) {
            return {
                success: false,
                matches: [],
                totalCount: 0,
                pagesWithMatches: [],
                error: 'Search term is required',
            };
        }

        onProgress?.(5, 'Loading PDF library...');

        const pdfjs = await loadPdfjs();
        const arrayBuffer = await file.arrayBuffer();

        onProgress?.(10, 'Loading PDF document...');

        const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
        const totalPages = pdf.numPages;
        const matches: TextMatch[] = [];
        const pagesWithMatches: Set<number> = new Set();

        // Build search patterns for all terms
        const searchPatterns: { pattern: RegExp; term: string }[] = [];
        try {
            for (const term of searchTerms) {
                if (!term.trim()) continue;

                let pattern: RegExp;
                if (options.useRegex) {
                    pattern = new RegExp(
                        term,
                        options.caseSensitive ? 'g' : 'gi'
                    );
                } else {
                    // Escape special regex characters for literal search
                    let escapedTerm = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
                    if (options.wholeWord) {
                        escapedTerm = `\\b${escapedTerm}\\b`;
                    }
                    pattern = new RegExp(
                        escapedTerm,
                        options.caseSensitive ? 'g' : 'gi'
                    );
                }
                searchPatterns.push({ pattern, term });
            }
        } catch (regexError) {
            return {
                success: false,
                matches: [],
                totalCount: 0,
                pagesWithMatches: [],
                error: `Invalid search pattern: ${regexError instanceof Error ? regexError.message : 'Unknown error'}`,
            };
        }

        if (searchPatterns.length === 0) {
            return {
                success: false,
                matches: [],
                totalCount: 0,
                pagesWithMatches: [],
                error: 'No valid search terms provided',
            };
        }

        const progressPerPage = 85 / totalPages;

        for (let pageNum = 1; pageNum <= totalPages; pageNum++) {
            const pageProgress = 10 + (pageNum - 1) * progressPerPage;
            onProgress?.(pageProgress, `Searching page ${pageNum} of ${totalPages}...`);

            try {
                const page = await pdf.getPage(pageNum);
                const viewport = page.getViewport({ scale: 1 });
                const textContent = await page.getTextContent();

                // Process text items to find matches
                for (const item of textContent.items) {
                    if (!('str' in item) || !('transform' in item)) continue;

                    const textItem = item as {
                        str: string;
                        transform: number[];
                        width: number;
                        height: number;
                        fontName?: string;
                    };

                    const text = textItem.str;
                    if (!text) continue;

                    // Search for each pattern in the text
                    for (const { pattern: searchPattern } of searchPatterns) {
                        // Find all matches in this text item
                        let match: RegExpExecArray | null;
                        searchPattern.lastIndex = 0; // Reset regex state

                        while ((match = searchPattern.exec(text)) !== null) {
                            // Calculate approximate position of the match within the text item
                            const matchStart = match.index;
                            const matchText = match[0];
                            const fullTextWidth = textItem.width;
                            const charWidth = fullTextWidth / text.length;

                            // Transform matrix: [scaleX, skewX, skewY, scaleY, translateX, translateY]
                            const transform = textItem.transform;
                            const x = transform[4] + matchStart * charWidth;
                            const y = transform[5];
                            const width = matchText.length * charWidth;
                            const height = Math.abs(textItem.height) || Math.abs(transform[0]) * 0.8;

                            // Convert to PDF coordinates (origin at bottom-left)
                            // The y-coordinate from getTextContent is already in PDF coordinates
                            const pdfY = y;

                            matches.push({
                                page: pageNum,
                                text: matchText,
                                x: x,
                                y: pdfY,
                                width: width,
                                height: height,
                                id: `match-${pageNum}-${x.toFixed(2)}-${pdfY.toFixed(2)}-${matches.length}`,
                                selected: true, // Selected by default
                            });

                            pagesWithMatches.add(pageNum);

                            // Prevent infinite loop for zero-length matches
                            if (match[0].length === 0) {
                                searchPattern.lastIndex++;
                            }
                        }
                    }
                }
            } catch (pageError) {
                console.warn(`Error processing page ${pageNum}:`, pageError);
                // Continue with other pages
            }
        }

        onProgress?.(100, 'Search complete');

        return {
            success: true,
            matches,
            totalCount: matches.length,
            pagesWithMatches: Array.from(pagesWithMatches).sort((a, b) => a - b),
        };
    } catch (error) {
        console.error('Search error:', error);
        return {
            success: false,
            matches: [],
            totalCount: 0,
            pagesWithMatches: [],
            error: error instanceof Error ? error.message : 'Failed to search PDF',
        };
    }
}

/**
 * Apply redactions to found text matches
 */
export async function applyFindAndRedact(
    file: File,
    matches: TextMatch[],
    options: Omit<FindAndRedactOptions, keyof SearchOptions>,
    onProgress?: ProgressCallback
): Promise<RedactionResult> {
    try {
        if (!file) {
            return {
                success: false,
                error: 'No file provided',
                redactedCount: 0,
            };
        }

        // Filter to only selected matches
        const selectedMatches = options.selectedMatchIds && options.selectedMatchIds.length > 0
            ? matches.filter(m => options.selectedMatchIds!.includes(m.id))
            : matches.filter(m => m.selected);

        if (selectedMatches.length === 0) {
            return {
                success: false,
                error: 'No matches selected for redaction',
                redactedCount: 0,
            };
        }

        onProgress?.(10, 'Loading PDF...');

        // Load the PDF with pdf-lib
        const arrayBuffer = await file.arrayBuffer();
        const pdfDoc = await PDFDocument.load(arrayBuffer, {
            ignoreEncryption: true,
        });

        const pages = pdfDoc.getPages();
        const pageCount = pages.length;

        // Default redaction color (black)
        const redactionColor = options.color
            ? rgb(options.color.r / 255, options.color.g / 255, options.color.b / 255)
            : rgb(0, 0, 0);

        let redactedCount = 0;
        const progressPerMatch = 80 / selectedMatches.length;

        // Embed font for replacement text
        let font = null;
        if (options.replacementText) {
            font = await pdfDoc.embedFont(StandardFonts.Helvetica);
        }

        for (let i = 0; i < selectedMatches.length; i++) {
            const match = selectedMatches[i];
            const progress = 10 + i * progressPerMatch;
            onProgress?.(progress, `Redacting ${i + 1} of ${selectedMatches.length}...`);

            // Validate page number
            if (match.page < 1 || match.page > pageCount) {
                console.warn(`Invalid page number: ${match.page}. Skipping.`);
                continue;
            }

            const page = pages[match.page - 1];
            const { height: pageHeight } = page.getSize();

            // The y-coordinate is already in PDF coordinates (from bottom)
            // We need to draw the rectangle at this position
            const pdfY = match.y;

            // Draw filled rectangle over the matched text
            page.drawRectangle({
                x: match.x,
                y: pdfY,
                width: match.width,
                height: match.height,
                color: redactionColor,
                opacity: 1, // Fully opaque
            });

            // Add border if requested
            if (options.addBorder) {
                page.drawRectangle({
                    x: match.x,
                    y: pdfY,
                    width: match.width,
                    height: match.height,
                    borderColor: rgb(0.3, 0.3, 0.3),
                    borderWidth: 0.5,
                });
            }

            // Add replacement text if specified
            if (options.replacementText && font) {
                const fontSize = Math.min(match.height * 0.7, 10);
                const textWidth = font.widthOfTextAtSize(options.replacementText, fontSize);

                // Center the text in the redaction box
                const textX = match.x + (match.width - textWidth) / 2;
                const textY = pdfY + (match.height - fontSize) / 2;

                page.drawText(options.replacementText, {
                    x: textX,
                    y: textY,
                    size: fontSize,
                    font,
                    color: rgb(1, 1, 1), // White text on black background
                });
            }

            redactedCount++;
        }

        onProgress?.(95, 'Saving PDF...');

        // Save the modified PDF
        const pdfBytes = await pdfDoc.save({ useObjectStreams: true });
        const outputBuffer = pdfBytes.buffer.slice(
            pdfBytes.byteOffset,
            pdfBytes.byteOffset + pdfBytes.byteLength
        ) as ArrayBuffer;
        const blob = new Blob([outputBuffer], { type: 'application/pdf' });

        onProgress?.(100, 'Complete!');

        return {
            success: true,
            result: blob,
            redactedCount,
        };
    } catch (error) {
        console.error('Redaction error:', error);
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to apply redactions',
            redactedCount: 0,
        };
    }
}

/**
 * Combined function to search and redact in one step
 */
export async function findAndRedact(
    file: File,
    options: FindAndRedactOptions,
    onProgress?: ProgressCallback
): Promise<RedactionResult> {
    // First, search for matches
    const searchResult = await searchTextInPDF(
        file,
        {
            searchTerm: options.searchTerm,
            caseSensitive: options.caseSensitive,
            useRegex: options.useRegex,
            wholeWord: options.wholeWord,
        },
        (progress, message) => onProgress?.(progress * 0.5, message)
    );

    if (!searchResult.success || searchResult.matches.length === 0) {
        return {
            success: searchResult.success,
            error: searchResult.error || 'No matches found',
            redactedCount: 0,
        };
    }

    // Then apply redactions
    return applyFindAndRedact(
        file,
        searchResult.matches,
        {
            color: options.color,
            addBorder: options.addBorder,
            replacementText: options.replacementText,
            selectedMatchIds: options.selectedMatchIds,
        },
        (progress, message) => onProgress?.(50 + progress * 0.5, message)
    );
}

export default {
    searchTextInPDF,
    applyFindAndRedact,
    findAndRedact,
    parseSearchTerms,
};

/**
 * PDF Flatten Processor
 * Requirements: 5.1
 * 
 * Implements PDF flattening functionality using pdf-lib.
 * Flattens form fields into the page content, making them non-editable.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Flatten PDF options
 */
export interface FlattenPDFOptions {
  /** Flatten form fields */
  flattenForms: boolean;
  /** Flatten annotations */
  flattenAnnotations?: boolean;
  /** Flatten layers */
  flattenLayers?: boolean;
}

/**
 * Default flatten options
 */
const DEFAULT_FLATTEN_OPTIONS: FlattenPDFOptions = {
  flattenForms: true,
  flattenAnnotations: true,
  flattenLayers: true,
};

/**
 * Flatten PDF Processor
 * Flattens form fields into static page content.
 */
export class FlattenPDFProcessor extends BasePDFProcessor {
  /**
   * Process PDF file and flatten it
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const flattenOptions: FlattenPDFOptions = {
      ...DEFAULT_FLATTEN_OPTIONS,
      ...(options as Partial<FlattenPDFOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Please provide exactly one PDF file to flatten.',
        `Received ${files.length} file(s).`
      );
    }

    const file = files[0];

    try {
      this.updateProgress(5, 'Loading PDF library...');

      // Load pdf-lib
      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Reading PDF file...');

      // Read file as ArrayBuffer
      const arrayBuffer = await file.arrayBuffer();
      const originalSize = arrayBuffer.byteLength;

      this.updateProgress(20, 'Loading PDF document...');

      // Load the source PDF
      let pdfDoc;
      try {
        pdfDoc = await pdfLib.PDFDocument.load(arrayBuffer, {
          ignoreEncryption: true,
        });
      } catch (error) {
        if (error instanceof Error && error.message.includes('encrypt')) {
          return this.createErrorOutput(
            PDFErrorCode.PDF_ENCRYPTED,
            'The PDF file is encrypted.',
            'Please decrypt the file before flattening.'
          );
        }
        throw error;
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(30, 'Analyzing PDF structure...');

      const pageCount = pdfDoc.getPageCount();

      if (pageCount === 0) {
        return this.createErrorOutput(
          PDFErrorCode.PDF_MALFORMED,
          'The PDF file contains no pages.',
          'Cannot flatten an empty PDF.'
        );
      }

      // Track what was flattened
      const flattenedItems: string[] = [];
      let hasFormFields = false;

      this.updateProgress(50, 'Flattening form fields...');

      // Flatten form fields using pdf-lib's form.flatten() method
      if (flattenOptions.flattenForms) {
        try {
          const form = pdfDoc.getForm();
          const fields = form.getFields();

          if (fields.length > 0) {
            hasFormFields = true;
            form.flatten();
            flattenedItems.push(`${fields.length} form field(s)`);
          }
        } catch (e: any) {
          // PDF might not have a form or form might be malformed
          if (!e.message?.includes('getForm')) {
            console.warn('Could not flatten forms:', e.message);
          }
        }
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(80, 'Saving flattened PDF...');

      // Save the flattened PDF
      const flattenedPdfBytes = await pdfDoc.save({ useObjectStreams: true });

      // Create blob from the Uint8Array
      const blob = new Blob([new Uint8Array(flattenedPdfBytes)], { type: 'application/pdf' });
      const newSize = flattenedPdfBytes.length;

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateFlattenedFilename(file.name);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount,
        originalSize,
        newSize,
        flattenedItems,
        hasFormFields,
        flattened: true,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to flatten PDF file.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for flatten processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Generate a filename for the flattened PDF
 */
function generateFlattenedFilename(originalName: string): string {
  const lastDot = originalName.lastIndexOf('.');
  const baseName = lastDot === -1 ? originalName : originalName.slice(0, lastDot);
  return `${baseName}_flattened.pdf`;
}

/**
 * Create a new instance of the flatten processor
 */
export function createFlattenProcessor(): FlattenPDFProcessor {
  return new FlattenPDFProcessor();
}

/**
 * Flatten a PDF file (convenience function)
 */
export async function flattenPDF(
  file: File,
  options?: Partial<FlattenPDFOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createFlattenProcessor();
  return processor.process(
    {
      files: [file],
      options: options || {},
    },
    onProgress
  );
}

/**
 * PDF Grid Combine Processor
 * 
 * Combines multiple PDF files into a grid layout on single pages.
 * Unlike N-Up which arranges pages from ONE PDF, this tool arranges
 * pages from MULTIPLE PDFs side by side.
 * 
 * Uses pdfjs to render each page as a high-resolution image, then
 * creates a new PDF with the images in a grid layout using pdf-lib.
 * This approach works reliably with ALL types of PDFs including those
 * with annotation-only content or missing Contents streams.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib, loadPdfjs } from '../loader';

/**
 * Grid Combine options
 */
export interface GridCombineOptions {
    /** Grid layout: columns x rows */
    gridLayout: '2x1' | '1x2' | '2x2' | '3x3' | '2x3' | '3x2' | '4x4';
    /** Output page size */
    pageSize: 'A4' | 'Letter' | 'Legal' | 'A3';
    /** Page orientation */
    orientation: 'portrait' | 'landscape';
    /** Add margins */
    useMargins: boolean;
    /** Add border around each PDF */
    addBorder: boolean;
    /** Border color (hex) */
    borderColor: string;
    /** Include spacing between items */
    spacing: number;
    /** Fill mode: how to handle empty cells when files < grid cells */
    fillMode: 'leave-empty' | 'repeat' | 'stretch-last';
    /** Page mode: use only first page or all pages from each PDF */
    pageMode: 'first-page-only' | 'all-pages';
    /** Auto trim visible area using each page's CropBox */
    autoTrimCropBox: boolean;
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: GridCombineOptions = {
    gridLayout: '2x2',
    pageSize: 'A4',
    orientation: 'landscape',
    useMargins: true,
    addBorder: true,
    borderColor: '#CCCCCC',
    spacing: 10,
    fillMode: 'leave-empty',
    pageMode: 'first-page-only',
    autoTrimCropBox: true,
};

/**
 * Page sizes in points
 */
const PAGE_SIZES: Record<string, [number, number]> = {
    A4: [595.28, 841.89],
    Letter: [612, 792],
    Legal: [612, 1008],
    A3: [841.89, 1190.55],
};

/**
 * Parse grid layout string to [cols, rows]
 */
function parseGridLayout(layout: string): [number, number] {
    const match = layout.match(/(\d+)x(\d+)/);
    if (match) {
        return [parseInt(match[1], 10), parseInt(match[2], 10)];
    }
    return [2, 2]; // Default
}

/**
 * A rendered page ready to be placed in the grid
 */
interface RenderedCell {
    /** Embedded PNG image in the output PDF */
    image: any;
    /** Image width in pixels */
    width: number;
    /** Image height in pixels */
    height: number;
    /** Source file name */
    name: string;
    /** Page number in source file */
    pageNum: number;
}

/**
 * PDF Grid Combine Processor
 */
export class GridCombineProcessor extends BasePDFProcessor {
    /**
     * Process multiple PDF files and combine them in a grid layout
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files, options } = input;
        const combineOptions: GridCombineOptions = {
            ...DEFAULT_OPTIONS,
            ...(options as Partial<GridCombineOptions>),
        };

        // Validate we have at least 2 files
        if (files.length < 2) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'At least 2 PDF files are required for grid combine.',
                `Received ${files.length} file(s).`
            );
        }

        try {
            this.updateProgress(5, 'Loading libraries...');

            const [pdfLib, pdfjsLib] = await Promise.all([
                loadPdfLib(),
                loadPdfjs(),
            ]);

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            // Get grid dimensions
            const [cols, rows] = parseGridLayout(combineOptions.gridLayout);
            const cellsPerPage = cols * rows;

            // Get page size
            let [pageWidth, pageHeight] = PAGE_SIZES[combineOptions.pageSize];

            // Apply orientation
            if (combineOptions.orientation === 'landscape' && pageWidth < pageHeight) {
                [pageWidth, pageHeight] = [pageHeight, pageWidth];
            } else if (combineOptions.orientation === 'portrait' && pageWidth > pageHeight) {
                [pageWidth, pageHeight] = [pageHeight, pageWidth];
            }

            // Calculate margins and spacing
            const margin = combineOptions.useMargins ? 36 : 0;
            const spacing = combineOptions.spacing;

            const usableWidth = pageWidth - margin * 2;
            const usableHeight = pageHeight - margin * 2;

            const cellWidth = (usableWidth - spacing * (cols - 1)) / cols;
            const cellHeight = (usableHeight - spacing * (rows - 1)) / rows;

            // Create new output PDF
            const newPdf = await pdfLib.PDFDocument.create();

            // Parse border color
            const borderRgb = hexToRgb(combineOptions.borderColor);

            // Render all source pages to images and embed them
            const cellItems: RenderedCell[] = [];
            const totalFiles = files.length;

            this.updateProgress(10, 'Rendering source pages...');

            for (let fileIdx = 0; fileIdx < totalFiles; fileIdx++) {
                if (this.checkCancelled()) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_CANCELLED,
                        'Processing was cancelled.'
                    );
                }

                const file = files[fileIdx];
                this.updateProgress(
                    10 + (fileIdx / totalFiles) * 50,
                    `Rendering ${file.name}...`
                );

                let arrayBuffer: ArrayBuffer;
                try {
                    arrayBuffer = await file.arrayBuffer();
                } catch (error) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_FAILED,
                        `Failed to read "${file.name}".`,
                        error instanceof Error ? error.message : 'Unknown error'
                    );
                }

                // Load PDF with pdfjs for rendering
                let pdf: any;
                try {
                    pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
                } catch (error) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_FAILED,
                        `Failed to load "${file.name}".`,
                        error instanceof Error ? error.message : 'Unknown error'
                    );
                }

                const numPages = pdf.numPages;

                // Determine which pages to render
                const pageNumbers: number[] = [];
                if (combineOptions.pageMode === 'all-pages') {
                    for (let p = 1; p <= numPages; p++) {
                        pageNumbers.push(p);
                    }
                } else {
                    if (numPages > 0) {
                        pageNumbers.push(1);
                    }
                }

                // Render each page to PNG and embed into output PDF
                for (const pageNum of pageNumbers) {
                    if (this.checkCancelled()) {
                        pdf.destroy();
                        return this.createErrorOutput(
                            PDFErrorCode.PROCESSING_CANCELLED,
                            'Processing was cancelled.'
                        );
                    }

                    try {
                        const page = await pdf.getPage(pageNum);
                        // Use scale 4.0 for high quality rendering in the grid
                        const viewport = page.getViewport({ scale: 4.0 });

                        const canvas = document.createElement('canvas');
                        canvas.width = viewport.width;
                        canvas.height = viewport.height;
                        const ctx = canvas.getContext('2d')!;

                        await page.render({
                            canvasContext: ctx,
                            viewport,
                            canvas: canvas,
                        }).promise;

                        // Convert to PNG bytes
                        const blob: Blob = await new Promise((resolve) => {
                            canvas.toBlob((b) => resolve(b!), 'image/png');
                        });
                        const pngBuffer = await blob.arrayBuffer();
                        const pngBytes = new Uint8Array(pngBuffer);

                        // Embed PNG into output PDF
                        const pngImage = await newPdf.embedPng(pngBytes);

                        cellItems.push({
                            image: pngImage,
                            width: pngImage.width,
                            height: pngImage.height,
                            name: file.name,
                            pageNum,
                        });

                        // Clean up canvas
                        canvas.width = 0;
                        canvas.height = 0;
                    } catch (renderErr) {
                        // If rendering fails for this page, skip it
                        console.warn(
                            `Failed to render page ${pageNum} of "${file.name}":`,
                            renderErr
                        );
                    }
                }

                pdf.destroy();
            }

            if (cellItems.length === 0) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_FAILED,
                    'No pages could be rendered from the source PDFs.'
                );
            }

            this.updateProgress(65, 'Building grid layout...');

            // Apply fill mode if needed
            const allItems = [...cellItems];
            if (cellItems.length < cellsPerPage) {
                if (combineOptions.fillMode === 'repeat') {
                    while (allItems.length < cellsPerPage) {
                        const idx = allItems.length % cellItems.length;
                        allItems.push({ ...cellItems[idx] });
                    }
                } else if (combineOptions.fillMode === 'stretch-last') {
                    const lastItem = cellItems[cellItems.length - 1];
                    while (allItems.length < cellsPerPage) {
                        allItems.push({ ...lastItem });
                    }
                }
                // 'leave-empty' - do nothing
            }

            // Calculate how many output pages we need
            const totalOutputPages = Math.ceil(allItems.length / cellsPerPage);
            const progressPerPage = 20 / totalOutputPages;

            for (let outputPageNum = 0; outputPageNum < totalOutputPages; outputPageNum++) {
                if (this.checkCancelled()) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_CANCELLED,
                        'Processing was cancelled.'
                    );
                }

                this.updateProgress(
                    65 + outputPageNum * progressPerPage,
                    `Creating page ${outputPageNum + 1} of ${totalOutputPages}...`
                );

                const outputPage = newPdf.addPage([pageWidth, pageHeight]);

                // Get the subset of items for this output page
                const startIdx = outputPageNum * cellsPerPage;
                const endIdx = Math.min(startIdx + cellsPerPage, allItems.length);
                const pageSubset = allItems.slice(startIdx, endIdx);

                for (let cellIdx = 0; cellIdx < pageSubset.length; cellIdx++) {
                    const item = pageSubset[cellIdx];

                    // Calculate position in grid
                    // PDF坐标系原点在左下角，Y轴向上
                    const col = cellIdx % cols;
                    const row = Math.floor(cellIdx / cols);
                    const cellX = margin + col * (cellWidth + spacing);
                    // 从顶部开始排列，第一行在最上面
                    const cellY = pageHeight - margin - cellHeight - row * (cellHeight + spacing);

                    // Calculate scale to fit in cell
                    const scale = Math.min(
                        cellWidth / item.width,
                        cellHeight / item.height
                    );
                    const scaledWidth = item.width * scale;
                    const scaledHeight = item.height * scale;

                    // Center within cell
                    const x = cellX + (cellWidth - scaledWidth) / 2;
                    const y = cellY + (cellHeight - scaledHeight) / 2;

                    // Draw rendered image
                    outputPage.drawImage(item.image, {
                        x,
                        y,
                        width: scaledWidth,
                        height: scaledHeight,
                    });

                    // Draw border if enabled
                    if (combineOptions.addBorder) {
                        outputPage.drawRectangle({
                            x,
                            y,
                            width: scaledWidth,
                            height: scaledHeight,
                            borderColor: pdfLib.rgb(borderRgb.r, borderRgb.g, borderRgb.b),
                            borderWidth: 0.5,
                        });
                    }
                }
            }

            this.updateProgress(90, 'Saving PDF...');

            // Save the new PDF
            const pdfBytes = await newPdf.save({
                useObjectStreams: true,
            });
            const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

            this.updateProgress(100, 'Complete!');

            // Generate output filename
            const outputFilename = `combined_${cols}x${rows}_grid.pdf`;

            return this.createSuccessOutput(blob, outputFilename, {
                sourceFileCount: files.length,
                totalSourcePages: allItems.length,
                gridLayout: combineOptions.gridLayout,
                outputPageCount: totalOutputPages,
                pageMode: combineOptions.pageMode,
                fillMode: combineOptions.fillMode,
            });

        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : 'Unknown error';
            const errorStack = error instanceof Error ? error.stack : undefined;
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                `Failed to create grid combined PDF: ${errorMessage}`,
                errorStack || errorMessage
            );
        }
    }

    /**
     * Get accepted file types
     */
    protected getAcceptedTypes(): string[] {
        return ['application/pdf'];
    }
}

/**
 * Convert hex color to RGB (0-1 range)
 */
function hexToRgb(hex: string): { r: number; g: number; b: number } {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    if (result) {
        return {
            r: parseInt(result[1], 16) / 255,
            g: parseInt(result[2], 16) / 255,
            b: parseInt(result[3], 16) / 255,
        };
    }
    return { r: 0.8, g: 0.8, b: 0.8 }; // Default light gray
}

/**
 * Create a new instance of the processor
 */
export function createGridCombineProcessor(): GridCombineProcessor {
    return new GridCombineProcessor();
}

/**
 * Combine multiple PDFs in a grid layout (convenience function)
 */
export async function createGridCombinePDF(
    files: File[],
    options: Partial<GridCombineOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createGridCombineProcessor();
    return processor.process(
        {
            files,
            options: options as Record<string, unknown>,
        },
        onProgress
    );
}

/**
 * Image to PDF Processor
 * Requirements: 5.1
 * 
 * Converts images (JPG, PNG, WebP, BMP, TIFF, SVG, HEIC) to PDF.
 * Supports multiple images combined into a single PDF.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Page size presets in points (72 points = 1 inch)
 */
export const PAGE_SIZES = {
  A4: { width: 595.28, height: 841.89 },
  LETTER: { width: 612, height: 792 },
  LEGAL: { width: 612, height: 1008 },
  A3: { width: 841.89, height: 1190.55 },
  A5: { width: 419.53, height: 595.28 },
  FIT: { width: 0, height: 0 }, // Fit to image size
} as const;

export type PageSizeType = keyof typeof PAGE_SIZES;

/**
 * Image to PDF options
 */
export interface ImageToPDFOptions {
  /** Page size preset or custom dimensions */
  pageSize: PageSizeType | { width: number; height: number };
  /** Page orientation */
  orientation: 'portrait' | 'landscape' | 'auto';
  /** Margin in points */
  margin: number;
  /** Image quality (0-1) for JPEG compression */
  quality: number;
  /** Whether to center images on the page */
  centerImage: boolean;
  /** Whether to scale images to fit the page */
  scaleToFit: boolean;
  /** SVG render scale for quality (1-4) */
  svgScale: number;
  /** Whether to enable batch mode (split into multiple PDFs) */
  batchMode?: boolean;
  /** Number of images per PDF file in batch mode */
  imagesPerPdf?: number;
}

/**
 * Batch export result
 */
export interface BatchExportResult {
  /** The ZIP file containing all PDFs */
  zipBlob: Blob;
  /** Number of PDF files created */
  pdfCount: number;
  /** Total number of images processed */
  imageCount: number;
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: ImageToPDFOptions = {
  pageSize: 'A4',
  orientation: 'auto',
  margin: 36, // 0.5 inch
  quality: 0.92,
  centerImage: true,
  scaleToFit: true,
  svgScale: 2,
  batchMode: false,
  imagesPerPdf: 10,
};

/**
 * Supported image MIME types
 */
const SUPPORTED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/bmp',
  'image/tiff',
  'image/svg+xml',
  'image/heic',
  'image/heif',
];

/**
 * Supported file extensions
 */
const SUPPORTED_EXTENSIONS = [
  '.jpg', '.jpeg', '.png', '.webp', '.bmp',
  '.tiff', '.tif', '.svg', '.heic', '.heif'
];


/**
 * Image to PDF Processor
 * Converts multiple images to a single PDF document.
 */
export class ImageToPDFProcessor extends BasePDFProcessor {
  /**
   * Process images and convert to PDF
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const pdfOptions: ImageToPDFOptions = {
      ...DEFAULT_OPTIONS,
      ...(options as Partial<ImageToPDFOptions>),
    };

    // Validate we have at least 1 file
    if (files.length < 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'At least 1 image file is required.',
        `Received ${files.length} file(s).`
      );
    }

    // Validate file types
    for (const file of files) {
      if (!this.isValidImageFile(file)) {
        return this.createErrorOutput(
          PDFErrorCode.FILE_TYPE_INVALID,
          `Invalid file type: ${file.name}`,
          'Supported formats: JPG, PNG, WebP, BMP, TIFF, SVG, HEIC'
        );
      }
    }

    try {
      this.updateProgress(5, 'Loading PDF library...');

      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Creating PDF document...');

      // Create a new PDF document
      const pdfDoc = await pdfLib.PDFDocument.create();

      // Process each image
      const progressPerFile = 80 / files.length;

      for (let i = 0; i < files.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }

        const file = files[i];
        const fileProgress = 10 + (i * progressPerFile);

        this.updateProgress(
          fileProgress,
          `Processing image ${i + 1} of ${files.length}: ${file.name}`
        );

        try {
          await this.addImageToDocument(pdfDoc, file, pdfOptions, pdfLib);
        } catch (error) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_FAILED,
            `Failed to process image "${file.name}".`,
            error instanceof Error ? error.message : 'Unknown error'
          );
        }
      }

      this.updateProgress(95, 'Saving PDF...');

      // Save the PDF
      const pdfBytes = await pdfDoc.save({ useObjectStreams: true });
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = this.generateOutputFilename(files);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount: files.length,
        imageCount: files.length,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to convert images to PDF.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Check if file is a valid image
   */
  private isValidImageFile(file: File): boolean {
    // Check MIME type
    if (SUPPORTED_MIME_TYPES.includes(file.type)) {
      return true;
    }

    // Check extension as fallback
    const ext = '.' + file.name.split('.').pop()?.toLowerCase();
    return SUPPORTED_EXTENSIONS.includes(ext);
  }

  /**
   * Add an image to the PDF document
   */
  private async addImageToDocument(
    pdfDoc: Awaited<ReturnType<typeof loadPdfLib>>['PDFDocument'] extends { create(): Promise<infer T> } ? T : never,
    file: File,
    options: ImageToPDFOptions,
    pdfLib: Awaited<ReturnType<typeof loadPdfLib>>
  ): Promise<void> {
    // Read file as ArrayBuffer
    const arrayBuffer = await file.arrayBuffer();
    const uint8Array = new Uint8Array(arrayBuffer);

    // Determine image type and embed
    let image: Awaited<ReturnType<typeof pdfDoc.embedJpg>>;
    const fileType = file.type.toLowerCase();
    const ext = file.name.split('.').pop()?.toLowerCase() || '';

    try {
      if (fileType === 'image/jpeg' || ext === 'jpg' || ext === 'jpeg') {
        image = await pdfDoc.embedJpg(uint8Array);
      } else if (fileType === 'image/png' || ext === 'png') {
        image = await pdfDoc.embedPng(uint8Array);
      } else {
        throw new Error('Format requires conversion');
      }
    } catch (error) {
      // Fallback: convert to PNG via canvas
      // This handles cases where extension doesn't match content (e.g. jpg renamed to png)
      // or formats not natively supported by pdf-lib
      const isSvg = fileType === 'image/svg+xml' || ext === 'svg';
      image = await this.convertAndEmbedImage(pdfDoc, file, pdfLib, isSvg ? options.svgScale : 1);
    }

    // Calculate page dimensions
    const { pageWidth, pageHeight } = this.calculatePageDimensions(
      image.width,
      image.height,
      options
    );

    // Add page
    const page = pdfDoc.addPage([pageWidth, pageHeight]);

    // Calculate image position and size
    const { x, y, width, height } = this.calculateImagePlacement(
      image.width,
      image.height,
      pageWidth,
      pageHeight,
      options
    );

    // Draw image
    page.drawImage(image, {
      x,
      y,
      width,
      height,
    });
  }

  /**
   * Convert image to PNG and embed (for formats not natively supported by pdf-lib)
   */
  private async convertAndEmbedImage(
    pdfDoc: Awaited<ReturnType<typeof loadPdfLib>>['PDFDocument'] extends { create(): Promise<infer T> } ? T : never,
    file: File,
    _pdfLib: Awaited<ReturnType<typeof loadPdfLib>>,
    scale: number = 1
  ): Promise<Awaited<ReturnType<typeof pdfDoc.embedPng>>> {
    return new Promise((resolve, reject) => {
      const img = new Image();
      const url = URL.createObjectURL(file);

      img.onload = async () => {
        try {
          // Create canvas with scale for higher quality (especially for SVG)
          const canvas = document.createElement('canvas');
          canvas.width = img.width * scale;
          canvas.height = img.height * scale;

          const ctx = canvas.getContext('2d');
          if (!ctx) {
            throw new Error('Failed to get canvas context');
          }

          // Scale the context for higher quality rendering
          ctx.scale(scale, scale);
          ctx.drawImage(img, 0, 0);

          // Convert to PNG blob
          const pngBlob = await new Promise<Blob>((res, rej) => {
            canvas.toBlob(
              (blob) => blob ? res(blob) : rej(new Error('Failed to convert to PNG')),
              'image/png'
            );
          });

          // Embed PNG
          const pngArrayBuffer = await pngBlob.arrayBuffer();
          const pngImage = await pdfDoc.embedPng(new Uint8Array(pngArrayBuffer));

          URL.revokeObjectURL(url);
          resolve(pngImage);
        } catch (error) {
          URL.revokeObjectURL(url);
          reject(error);
        }
      };

      img.onerror = () => {
        URL.revokeObjectURL(url);
        reject(new Error(`Failed to load image: ${file.name}`));
      };

      img.src = url;
    });
  }

  /**
   * Calculate page dimensions based on options
   */
  private calculatePageDimensions(
    imageWidth: number,
    imageHeight: number,
    options: ImageToPDFOptions
  ): { pageWidth: number; pageHeight: number } {
    let pageWidth: number;
    let pageHeight: number;

    // Get base page size
    if (typeof options.pageSize === 'string') {
      const preset = PAGE_SIZES[options.pageSize];
      if (options.pageSize === 'FIT') {
        // Fit to image size plus margins
        pageWidth = imageWidth + (options.margin * 2);
        pageHeight = imageHeight + (options.margin * 2);
      } else {
        pageWidth = preset.width;
        pageHeight = preset.height;
      }
    } else {
      pageWidth = options.pageSize.width;
      pageHeight = options.pageSize.height;
    }

    // Handle orientation
    if (options.orientation === 'landscape') {
      if (pageWidth < pageHeight) {
        [pageWidth, pageHeight] = [pageHeight, pageWidth];
      }
    } else if (options.orientation === 'portrait') {
      if (pageWidth > pageHeight) {
        [pageWidth, pageHeight] = [pageHeight, pageWidth];
      }
    } else if (options.orientation === 'auto') {
      // Match page orientation to image orientation
      const imageIsLandscape = imageWidth > imageHeight;
      const pageIsLandscape = pageWidth > pageHeight;

      if (imageIsLandscape !== pageIsLandscape && typeof options.pageSize === 'string' && options.pageSize !== 'FIT') {
        [pageWidth, pageHeight] = [pageHeight, pageWidth];
      }
    }

    return { pageWidth, pageHeight };
  }

  /**
   * Calculate image placement on the page
   */
  private calculateImagePlacement(
    imageWidth: number,
    imageHeight: number,
    pageWidth: number,
    pageHeight: number,
    options: ImageToPDFOptions
  ): { x: number; y: number; width: number; height: number } {
    const availableWidth = pageWidth - (options.margin * 2);
    const availableHeight = pageHeight - (options.margin * 2);

    let width = imageWidth;
    let height = imageHeight;

    // Scale to fit if needed
    if (options.scaleToFit) {
      const scaleX = availableWidth / imageWidth;
      const scaleY = availableHeight / imageHeight;
      const scale = Math.min(scaleX, scaleY, 1); // Don't upscale

      width = imageWidth * scale;
      height = imageHeight * scale;
    }

    // Calculate position
    let x = options.margin;
    let y = options.margin;

    if (options.centerImage) {
      x = (pageWidth - width) / 2;
      y = (pageHeight - height) / 2;
    }

    return { x, y, width, height };
  }

  /**
   * Generate output filename
   */
  private generateOutputFilename(files: File[]): string {
    if (files.length === 1) {
      const baseName = files[0].name.replace(/\.[^/.]+$/, '');
      return `${baseName}.pdf`;
    }
    return `images_${files.length}_pages.pdf`;
  }

  /**
   * Get accepted file types
   */
  protected getAcceptedTypes(): string[] {
    return SUPPORTED_MIME_TYPES;
  }
}

/**
 * Create a new instance of the image to PDF processor
 */
export function createImageToPDFProcessor(): ImageToPDFProcessor {
  return new ImageToPDFProcessor();
}

/**
 * Convert images to PDF (convenience function)
 */
export async function imagesToPDF(
  files: File[],
  options?: Partial<ImageToPDFOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createImageToPDFProcessor();
  return processor.process(
    {
      files,
      options: options || {},
    },
    onProgress
  );
}

/**
 * Convert images to multiple PDFs based on batch size and package as ZIP
 */
export async function imagesToPDFBatch(
  files: File[],
  imagesPerPdf: number,
  options?: Partial<ImageToPDFOptions>,
  onProgress?: ProgressCallback
): Promise<{ success: boolean; result?: BatchExportResult; error?: { message: string } }> {
  try {
    // Dynamically import JSZip
    const JSZip = (await import('jszip')).default;

    const totalImages = files.length;
    const batchCount = Math.ceil(totalImages / imagesPerPdf);
    const zip = new JSZip();

    onProgress?.(5, 'Creating batch PDFs...');

    const processor = createImageToPDFProcessor();

    for (let i = 0; i < batchCount; i++) {
      const startIndex = i * imagesPerPdf;
      const endIndex = Math.min(startIndex + imagesPerPdf, totalImages);
      const batchFiles = files.slice(startIndex, endIndex);

      const progressStart = 5 + (i / batchCount) * 85;
      const progressEnd = 5 + ((i + 1) / batchCount) * 85;

      onProgress?.(
        progressStart,
        `Processing batch ${i + 1} of ${batchCount} (images ${startIndex + 1}-${endIndex})...`
      );

      const result = await processor.process(
        {
          files: batchFiles,
          options: options || {},
        },
        (prog, message) => {
          // Map the individual progress to the batch range
          const mappedProgress = progressStart + (prog / 100) * (progressEnd - progressStart);
          onProgress?.(mappedProgress, message);
        }
      );

      if (!result.success || !result.result) {
        return {
          success: false,
          error: { message: result.error?.message || `Failed to create PDF for batch ${i + 1}` },
        };
      }

      // Add PDF to ZIP
      const pdfBlob = result.result as Blob;
      const pdfArrayBuffer = await pdfBlob.arrayBuffer();
      const paddedIndex = String(i + 1).padStart(String(batchCount).length, '0');
      zip.file(`images_part_${paddedIndex}.pdf`, pdfArrayBuffer);
    }

    onProgress?.(92, 'Creating ZIP archive...');

    // Generate ZIP file
    const zipBlob = await zip.generateAsync(
      { type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } },
      (metadata) => {
        const zipProgress = 92 + (metadata.percent / 100) * 8;
        onProgress?.(zipProgress, `Compressing: ${Math.round(metadata.percent)}%`);
      }
    );

    onProgress?.(100, 'Complete!');

    return {
      success: true,
      result: {
        zipBlob,
        pdfCount: batchCount,
        imageCount: totalImages,
      },
    };
  } catch (error) {
    return {
      success: false,
      error: { message: error instanceof Error ? error.message : 'Failed to create batch PDFs' },
    };
  }
}

/**
 * JSON to PDF Processor
 * Requirements: 5.1
 * 
 * Converts JSON files to PDF with formatted output and optional syntax highlighting.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Page size presets in points (72 points = 1 inch)
 */
export const JSON_PAGE_SIZES = {
  A4: { width: 595.28, height: 841.89 },
  LETTER: { width: 612, height: 792 },
  LEGAL: { width: 612, height: 1008 },
  A3: { width: 841.89, height: 1190.55 },
} as const;

export type JSONPageSizeType = keyof typeof JSON_PAGE_SIZES;

/**
 * JSON to PDF options
 */
export interface JSONToPDFOptions {
  /** Page size preset */
  pageSize: JSONPageSizeType;
  /** Font size in points */
  fontSize: number;
  /** Line height multiplier */
  lineHeight: number;
  /** Indentation spaces */
  indentSpaces: number;
  /** Page margins in points */
  margin: {
    top: number;
    right: number;
    bottom: number;
    left: number;
  };
  /** Whether to format/pretty-print JSON */
  prettyPrint: boolean;
  /** Whether to show line numbers */
  showLineNumbers: boolean;
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: JSONToPDFOptions = {
  pageSize: 'A4',
  fontSize: 10,
  lineHeight: 1.4,
  indentSpaces: 2,
  margin: {
    top: 72,
    right: 72,
    bottom: 72,
    left: 72,
  },
  prettyPrint: true,
  showLineNumbers: true,
};


/**
 * JSON to PDF Processor
 * Converts JSON files to PDF documents with formatting.
 */
export class JSONToPDFProcessor extends BasePDFProcessor {
  /**
   * Process JSON files and convert to PDF
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const pdfOptions: JSONToPDFOptions = {
      ...DEFAULT_OPTIONS,
      ...(options as Partial<JSONToPDFOptions>),
    };

    // Validate we have at least 1 file
    if (files.length < 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'At least 1 JSON file is required.',
        `Received ${files.length} file(s).`
      );
    }

    try {
      this.updateProgress(5, 'Loading PDF library...');

      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Creating PDF document...');

      // Create a new PDF document
      const pdfDoc = await pdfLib.PDFDocument.create();

      // Get monospace font for JSON
      const font = await pdfDoc.embedFont(pdfLib.StandardFonts.Courier);

      // Process each JSON file
      const progressPerFile = 80 / files.length;

      for (let i = 0; i < files.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }

        const file = files[i];
        const fileProgress = 10 + (i * progressPerFile);

        this.updateProgress(
          fileProgress,
          `Processing file ${i + 1} of ${files.length}: ${file.name}`
        );

        try {
          // Read and parse JSON content
          const text = await file.text();
          let jsonContent: string;

          try {
            // Parse and re-stringify to validate and format
            const parsed = JSON.parse(text);
            if (pdfOptions.prettyPrint) {
              jsonContent = JSON.stringify(parsed, null, pdfOptions.indentSpaces);
            } else {
              jsonContent = JSON.stringify(parsed);
            }
          } catch (parseError) {
            return this.createErrorOutput(
              PDFErrorCode.FILE_CORRUPTED,
              `Invalid JSON in file "${file.name}".`,
              parseError instanceof Error ? parseError.message : 'JSON parse error'
            );
          }

          // Add JSON to PDF
          await this.addJSONToDocument(pdfDoc, jsonContent, file.name, font, pdfOptions, pdfLib);
        } catch (error) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_FAILED,
            `Failed to process file "${file.name}".`,
            error instanceof Error ? error.message : 'Unknown error'
          );
        }
      }

      this.updateProgress(95, 'Saving PDF...');

      // Save the PDF
      const pdfBytes = await pdfDoc.save({ useObjectStreams: true });
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = this.generateOutputFilename(files);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount: pdfDoc.getPageCount(),
        fileCount: files.length,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to convert JSON to PDF.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Add JSON content to PDF document
   */
  private async addJSONToDocument(
    pdfDoc: Awaited<ReturnType<typeof loadPdfLib>>['PDFDocument'] extends { create(): Promise<infer T> } ? T : never,
    jsonContent: string,
    filename: string,
    font: Awaited<ReturnType<typeof pdfDoc.embedFont>>,
    options: JSONToPDFOptions,
    pdfLib: Awaited<ReturnType<typeof loadPdfLib>>
  ): Promise<void> {
    const pageSize = JSON_PAGE_SIZES[options.pageSize];
    const { margin, fontSize, lineHeight, showLineNumbers } = options;

    // Calculate available width and height
    const lineNumberWidth = showLineNumbers ? fontSize * 4 : 0;
    const availableWidth = pageSize.width - margin.left - margin.right - lineNumberWidth;
    const availableHeight = pageSize.height - margin.top - margin.bottom;
    const lineSpacing = fontSize * lineHeight;

    // Split JSON into lines
    const lines = jsonContent.split('\n');

    // Wrap lines if needed
    const wrappedLines = this.wrapLines(lines, font, fontSize, availableWidth);

    // Add header with filename
    let currentPage = pdfDoc.addPage([pageSize.width, pageSize.height]);
    let yPosition = pageSize.height - margin.top;

    // Draw filename header
    currentPage.drawText(`File: ${filename}`, {
      x: margin.left,
      y: yPosition - fontSize,
      size: fontSize,
      font,
      color: pdfLib.rgb(0.4, 0.4, 0.4),
    });
    yPosition -= lineSpacing * 2;

    // Draw separator line
    currentPage.drawLine({
      start: { x: margin.left, y: yPosition },
      end: { x: pageSize.width - margin.right, y: yPosition },
      thickness: 0.5,
      color: pdfLib.rgb(0.8, 0.8, 0.8),
    });
    yPosition -= lineSpacing;

    // Draw JSON content
    let lineNumber = 1;
    for (const line of wrappedLines) {
      // Check if we need a new page
      if (yPosition - lineSpacing < margin.bottom) {
        currentPage = pdfDoc.addPage([pageSize.width, pageSize.height]);
        yPosition = pageSize.height - margin.top;
      }

      // Draw line number
      if (showLineNumbers) {
        currentPage.drawText(String(lineNumber).padStart(3, ' '), {
          x: margin.left,
          y: yPosition - fontSize,
          size: fontSize,
          font,
          color: pdfLib.rgb(0.6, 0.6, 0.6),
        });
      }

      // Draw JSON line
      currentPage.drawText(line, {
        x: margin.left + lineNumberWidth,
        y: yPosition - fontSize,
        size: fontSize,
        font,
        color: pdfLib.rgb(0, 0, 0),
      });

      yPosition -= lineSpacing;
      lineNumber++;
    }
  }

  /**
   * Wrap lines to fit within available width
   */
  private wrapLines(
    lines: string[],
    font: { widthOfTextAtSize: (text: string, size: number) => number },
    fontSize: number,
    maxWidth: number
  ): string[] {
    const wrappedLines: string[] = [];

    for (const line of lines) {
      if (line === '') {
        wrappedLines.push('');
        continue;
      }

      // Check if line fits
      if (font.widthOfTextAtSize(line, fontSize) <= maxWidth) {
        wrappedLines.push(line);
        continue;
      }

      // Need to wrap - preserve indentation
      const indent = line.match(/^(\s*)/)?.[1] || '';
      const content = line.slice(indent.length);

      let currentLine = indent;
      let i = 0;

      while (i < content.length) {
        const char = content[i];
        const testLine = currentLine + char;

        if (font.widthOfTextAtSize(testLine, fontSize) <= maxWidth) {
          currentLine = testLine;
          i++;
        } else {
          if (currentLine.trim()) {
            wrappedLines.push(currentLine);
          }
          currentLine = indent + '  '; // Continue with extra indent
        }
      }

      if (currentLine.trim()) {
        wrappedLines.push(currentLine);
      }
    }

    return wrappedLines;
  }

  /**
   * Generate output filename
   */
  private generateOutputFilename(files: File[]): string {
    if (files.length === 1) {
      const baseName = files[0].name.replace(/\.[^/.]+$/, '');
      return `${baseName}.pdf`;
    }
    return `json_${files.length}_files.pdf`;
  }

  /**
   * Get accepted file types
   */
  protected getAcceptedTypes(): string[] {
    return ['application/json', '.json'];
  }
}

/**
 * Create a new instance of the JSON to PDF processor
 */
export function createJSONToPDFProcessor(): JSONToPDFProcessor {
  return new JSONToPDFProcessor();
}

/**
 * Convert JSON files to PDF (convenience function)
 */
export async function jsonToPDF(
  files: File[],
  options?: Partial<JSONToPDFOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createJSONToPDFProcessor();
  return processor.process(
