  );
}

/**
 * PDF Merge Processor
 * Requirements: 5.1
 * 
 * Implements PDF merging functionality using pdf-lib.
 * Supports merging multiple PDFs with optional bookmark preservation.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
  MergeOptions,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor, createPDFError } from '../processor';
import { loadPdfLib, loadPdfDocument, createPdfDocument } from '../loader';

/**
 * Default merge options
 */
const DEFAULT_MERGE_OPTIONS: MergeOptions = {
  preserveBookmarks: true,
  pageOrder: 'sequential',
};

/**
 * Merge PDF Processor
 * Merges multiple PDF files into a single PDF document.
 */
export class MergePDFProcessor extends BasePDFProcessor {
  /**
   * Process multiple PDF files and merge them into one
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const mergeOptions: MergeOptions = {
      ...DEFAULT_MERGE_OPTIONS,
      ...(options as Partial<MergeOptions>),
    };

    // Validate we have at least 2 files
    if (files.length < 2) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'At least 2 PDF files are required for merging.',
        `Received ${files.length} file(s).`
      );
    }

    try {
      this.updateProgress(5, 'Loading PDF library...');

      // Load pdf-lib
      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Creating merged document...');

      // Create a new PDF document for the merged result
      const mergedPdf = await pdfLib.PDFDocument.create();

      // Track bookmarks if preserving them
      const bookmarks: BookmarkEntry[] = [];
      let currentPageIndex = 0;

      // Process each file
      const progressPerFile = 80 / files.length;

      for (let i = 0; i < files.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }

        const file = files[i];
        const fileProgress = 10 + (i * progressPerFile);

        this.updateProgress(
          fileProgress,
          `Processing file ${i + 1} of ${files.length}: ${file.name}`
        );

        try {
          // Read file as ArrayBuffer
          const arrayBuffer = await file.arrayBuffer();

          // Load the source PDF
          const sourcePdf = await pdfLib.PDFDocument.load(arrayBuffer, {
            ignoreEncryption: false,
          });

          // Get page count for bookmark tracking
          const pageCount = sourcePdf.getPageCount();

          // Copy all pages from source to merged document
          const copiedPages = await mergedPdf.copyPages(
            sourcePdf,
            sourcePdf.getPageIndices()
          );

          // Add copied pages to merged document
          for (const page of copiedPages) {
            mergedPdf.addPage(page);
          }

          // Track bookmark for this file if preserving bookmarks
          if (mergeOptions.preserveBookmarks) {
            bookmarks.push({
              title: getFileNameWithoutExtension(file.name),
              pageIndex: currentPageIndex,
              pageCount,
            });
          }

          currentPageIndex += pageCount;

        } catch (error) {
          // Check if it's an encryption error
          if (error instanceof Error && error.message.includes('encrypt')) {
            return this.createErrorOutput(
              PDFErrorCode.PDF_ENCRYPTED,
              `File "${file.name}" is encrypted.`,
              'Please decrypt the file before merging.'
            );
          }

          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_FAILED,
            `Failed to process file "${file.name}".`,
            error instanceof Error ? error.message : 'Unknown error'
          );
        }
      }

      this.updateProgress(90, 'Adding bookmarks...');

      // Add bookmarks if preserving them
      if (mergeOptions.preserveBookmarks && bookmarks.length > 0) {
        await addBookmarksToDocument(mergedPdf, bookmarks);
      }

      this.updateProgress(95, 'Saving merged PDF...');

      // Save the merged PDF
      const mergedPdfBytes = await mergedPdf.save({ useObjectStreams: true });
      // Create blob from the Uint8Array
      const blob = new Blob([new Uint8Array(mergedPdfBytes)], { type: 'application/pdf' });

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateMergedFilename(files);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount: currentPageIndex,
        fileCount: files.length,
        bookmarkCount: bookmarks.length,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to merge PDF files.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for merge processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Bookmark entry for tracking file positions
 */
interface BookmarkEntry {
  title: string;
  pageIndex: number;
  pageCount: number;
}

/**
 * Add bookmarks to a PDF document
 * Creates a bookmark for each merged file pointing to its first page
 * 
 * Note: pdf-lib has limited bookmark support, so we use low-level PDF operations
 */
async function addBookmarksToDocument(
  pdfDoc: Awaited<ReturnType<typeof createPdfDocument>>,
  bookmarks: BookmarkEntry[]
): Promise<void> {
  const pdfLib = await loadPdfLib();

  // Get the document's context and catalog
  const context = pdfDoc.context;
  const catalog = pdfDoc.catalog;

  // Create outline entries array to track refs
  const outlineEntryRefs: ReturnType<typeof context.register>[] = [];

  // Create each bookmark entry first
  for (let i = 0; i < bookmarks.length; i++) {
    const bookmark = bookmarks[i];
    const page = pdfDoc.getPage(bookmark.pageIndex);
    const pageRef = page.ref;

    // Create destination array [page /XYZ left top zoom]
    const destArray = pdfLib.PDFArray.withContext(context);
    destArray.push(pageRef);
    destArray.push(pdfLib.PDFName.of('XYZ'));
    destArray.push(pdfLib.PDFNull);
    destArray.push(pdfLib.PDFNull);
    destArray.push(pdfLib.PDFNull);

    // Create bookmark dictionary
    const bookmarkDict = pdfLib.PDFDict.withContext(context);
    bookmarkDict.set(pdfLib.PDFName.of('Title'), pdfLib.PDFHexString.fromText(bookmark.title));
    bookmarkDict.set(pdfLib.PDFName.of('Dest'), destArray);

    const bookmarkRef = context.register(bookmarkDict);
    outlineEntryRefs.push(bookmarkRef);
  }

  // Create outline dictionary
  const outlineDict = pdfLib.PDFDict.withContext(context);
  outlineDict.set(pdfLib.PDFName.of('Type'), pdfLib.PDFName.of('Outlines'));
  outlineDict.set(pdfLib.PDFName.of('Count'), pdfLib.PDFNumber.of(bookmarks.length));

  const outlineRef = context.register(outlineDict);

  // Link bookmarks together and set parent
  for (let i = 0; i < outlineEntryRefs.length; i++) {
    const entryRef = outlineEntryRefs[i];
    const entryDict = context.lookup(entryRef) as ReturnType<typeof pdfLib.PDFDict.withContext>;

    // Set parent
    entryDict.set(pdfLib.PDFName.of('Parent'), outlineRef);

    // Set prev/next links
    if (i > 0) {
      entryDict.set(pdfLib.PDFName.of('Prev'), outlineEntryRefs[i - 1]);
    }
    if (i < outlineEntryRefs.length - 1) {
      entryDict.set(pdfLib.PDFName.of('Next'), outlineEntryRefs[i + 1]);
    }
  }

  // Set first and last in outline
  if (outlineEntryRefs.length > 0) {
    outlineDict.set(pdfLib.PDFName.of('First'), outlineEntryRefs[0]);
    outlineDict.set(pdfLib.PDFName.of('Last'), outlineEntryRefs[outlineEntryRefs.length - 1]);
  }

  // Add outline to catalog
  catalog.set(pdfLib.PDFName.of('Outlines'), outlineRef);
}

/**
 * Get filename without extension
 */
function getFileNameWithoutExtension(filename: string): string {
  const lastDot = filename.lastIndexOf('.');
  if (lastDot === -1) return filename;
  return filename.slice(0, lastDot);
}

/**
 * Generate a filename for the merged PDF
 */
function generateMergedFilename(files: File[]): string {
  if (files.length === 0) return 'merged.pdf';

  // Use first file's name as base
  const firstName = getFileNameWithoutExtension(files[0].name);

  if (files.length === 2) {
    const secondName = getFileNameWithoutExtension(files[1].name);
    return `${firstName}_${secondName}_merged.pdf`;
  }

  return `${firstName}_and_${files.length - 1}_more_merged.pdf`;
}

/**
 * Create a new instance of the merge processor
 */
export function createMergeProcessor(): MergePDFProcessor {
  return new MergePDFProcessor();
}

/**
 * Merge multiple PDF files (convenience function)
 */
export async function mergePDFs(
  files: File[],
  options?: Partial<MergeOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createMergeProcessor();
  return processor.process(
    {
      files,
      options: options || {},
    },
    onProgress
  );
}

/**
 * MOBI to PDF Processor
 * 
 * Converts MOBI e-book files to PDF documents.
 * Uses PyMuPDF's native convert_to_pdf() for optimal file size and text preservation.
 * 
 * Benefits:
 * - Much smaller file sizes (text is vector, not images)
 * - Searchable/selectable text in output PDF
 * - Better quality at any zoom level
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * MOBI to PDF options
 */
export interface MOBIToPDFOptions {
    // Reserved for future options
}

/**
 * MOBI to PDF Processor
 * Converts MOBI files to PDF using a Web Worker.
 */
export class MOBIToPDFProcessor extends BasePDFProcessor {
    private worker: Worker | null = null;
    private workerReady = false;

    /**
     * Initialize the worker
     */
    private async initWorker(): Promise<void> {
        if (this.worker) return;

        return new Promise((resolve, reject) => {
            try {
                this.worker = new Worker('/workers/mobi-to-pdf.worker.js', { type: 'module' });

                const handleMessage = (event: MessageEvent) => {
                    const { type, error, message } = event.data;

                    if (type === 'init-complete') {
                        this.workerReady = true;
                        resolve();
                    } else if (type === 'status') {
                        this.updateProgress(0, message);
                    } else if (type === 'error') {
                        reject(new Error(error || 'Worker initialization failed'));
                    }
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', (err) => {
                    reject(new Error('Worker connection failed'));
                });

                // Send init message
                this.worker.postMessage({
                    type: 'init',
                    id: 'init-' + Date.now(),
                    data: {}
                });

            } catch (err) {
                reject(err);
            }
        });
    }

    /**
     * Terminate the worker
     */
    private terminateWorker() {
        if (this.worker) {
            this.worker.terminate();
            this.worker = null;
            this.workerReady = false;
        }
    }

    /**
     * Reset processor state
     */
    protected reset(): void {
        super.reset();
    }

    /**
     * Process MOBI and convert to PDF
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        // Validate we have exactly 1 MOBI file
        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one MOBI file.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];

        // Validate file type
        if (!file.name.toLowerCase().endsWith('.mobi') && !file.name.toLowerCase().endsWith('.azw') && !file.name.toLowerCase().endsWith('.azw3')) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload a MOBI file (.mobi, .azw, .azw3).',
                `Received: ${file.type || file.name}`
            );
        }

        try {
            this.updateProgress(10, 'Initializing converter...');

            try {
                await this.initWorker();
            } catch (err) {
                console.error('Failed to initialize worker:', err);
                return this.createErrorOutput(
                    PDFErrorCode.WORKER_FAILED,
                    'Failed to initialize conversion worker.',
                    err instanceof Error ? err.message : String(err)
                );
            }

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(30, 'Converting MOBI to PDF...');

            // Process conversion via worker
            const pdfBlob = await new Promise<Blob>((resolve, reject) => {
                if (!this.worker) {
                    reject(new Error('Worker not initialized'));
                    return;
                }

                const msgId = 'convert-' + Date.now();

                const handleMessage = (event: MessageEvent) => {
                    const { type, id, result, error, message } = event.data;

                    if (type === 'status') {
                        this.updateProgress(this.progress, message);
                        return;
                    }

                    if (id !== msgId) return;

                    if (type === 'convert-complete') {
                        cleanup();
                        resolve(result);
                    } else if (type === 'error') {
                        cleanup();
                        reject(new Error(error || 'Conversion failed'));
                    }
                };

                const handleError = (error: ErrorEvent) => {
                    cleanup();
                    reject(new Error('Worker error: ' + error.message));
                };

                const cleanup = () => {
                    this.worker?.removeEventListener('message', handleMessage);
                    this.worker?.removeEventListener('error', handleError);
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', handleError);

                this.worker.postMessage({
                    type: 'convert',
                    id: msgId,
                    data: {
                        file: file
                    }
                });
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.(mobi|azw|azw3)$/i, '');
            const outputName = `${baseName}.pdf`;

            return this.createSuccessOutput(
                pdfBlob,
                outputName,
                { format: 'pdf' }
            );

        } catch (error) {
            console.error('Conversion error:', error);
            this.terminateWorker();

            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert MOBI to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

/**
 * Create a new instance of the MOBI to PDF processor
 */
export function createMOBIToPDFProcessor(): MOBIToPDFProcessor {
    return new MOBIToPDFProcessor();
}

/**
 * Convert MOBI to PDF (convenience function)
 */
export async function mobiToPDF(
    file: File,
    options?: Partial<MOBIToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createMOBIToPDFProcessor();
    return processor.process(
        {
            files: [file],
            options: options || {},
        },
        onProgress
    );
}

/**
 * PDF Page Dimensions Processor
 * Requirements: 5.1
 * 
 * Implements PDF page dimensions analysis functionality.
 * Analyzes and reports the dimensions of each page in a PDF document.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Page dimension information
 */
export interface PageDimension {
  /** Page number (1-indexed) */
  pageNumber: number;
  /** Width in points */
  widthPt: number;
  /** Height in points */
  heightPt: number;
  /** Width in inches */
  widthIn: number;
  /** Height in inches */
  heightIn: number;
  /** Width in millimeters */
  widthMm: number;
  /** Height in millimeters */
  heightMm: number;
  /** Page orientation */
  orientation: 'portrait' | 'landscape' | 'square';
  /** Standard page size name if matches */
  standardSize: string | null;
}

/**
 * Page dimensions analysis result
 */
export interface PageDimensionsResult {
  /** Total number of pages */
  pageCount: number;
  /** Dimensions for each page */
  pages: PageDimension[];
  /** Summary of unique sizes */
  uniqueSizes: {
    size: string;
    count: number;
    pages: number[];
  }[];
  /** Whether all pages have the same size */
  uniformSize: boolean;
}

/**
 * Page Dimensions options
 */
export interface PageDimensionsOptions {
  /** Unit for display (points, inches, mm) */
  displayUnit: 'pt' | 'in' | 'mm';
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: PageDimensionsOptions = {
  displayUnit: 'pt',
};

/**
 * Standard page sizes in points (width x height for portrait)
 */
const STANDARD_SIZES: Record<string, { width: number; height: number }> = {
  'Letter': { width: 612, height: 792 },
  'Legal': { width: 612, height: 1008 },
  'Tabloid': { width: 792, height: 1224 },
  'A0': { width: 2384, height: 3370 },
  'A1': { width: 1684, height: 2384 },
  'A2': { width: 1191, height: 1684 },
  'A3': { width: 842, height: 1191 },
  'A4': { width: 595, height: 842 },
  'A5': { width: 420, height: 595 },
  'A6': { width: 298, height: 420 },
  'B4': { width: 709, height: 1001 },
  'B5': { width: 499, height: 709 },
  'Executive': { width: 522, height: 756 },
};

/**
 * Points per inch
 */
const POINTS_PER_INCH = 72;

/**
 * Millimeters per inch
 */
const MM_PER_INCH = 25.4;

/**
 * Page Dimensions Processor
 * Analyzes PDF page dimensions and provides detailed information.
 */
export class PageDimensionsProcessor extends BasePDFProcessor {
  /**
   * Process PDF file and analyze page dimensions
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files } = input;

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Please provide exactly one PDF file to analyze.',
        `Received ${files.length} file(s).`
      );
    }

    const file = files[0];

    try {
      this.updateProgress(5, 'Loading PDF library...');

      // Load pdf-lib
      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Reading PDF file...');

      // Read file as ArrayBuffer
      const arrayBuffer = await file.arrayBuffer();

      this.updateProgress(20, 'Loading PDF document...');

      // Load the PDF
      let sourcePdf;
      try {
        sourcePdf = await pdfLib.PDFDocument.load(arrayBuffer, {
          ignoreEncryption: true,
          updateMetadata: false,
        });
      } catch (loadError) {
        return this.createErrorOutput(
          PDFErrorCode.PDF_MALFORMED,
          'Unable to load the PDF file.',
          loadError instanceof Error ? loadError.message : 'The file may be corrupted.'
        );
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(40, 'Analyzing page dimensions...');

      // Get page count
      const pageCount = sourcePdf.getPageCount();

      if (pageCount === 0) {
        return this.createErrorOutput(
          PDFErrorCode.PDF_MALFORMED,
          'The PDF file contains no pages.',
          'Cannot analyze dimensions of an empty PDF.'
        );
      }

      // Analyze each page
      const pages: PageDimension[] = [];
      const sizeMap = new Map<string, { count: number; pages: number[] }>();

      for (let i = 0; i < pageCount; i++) {
        const progressPercent = 40 + (i / pageCount) * 50;
        this.updateProgress(progressPercent, `Analyzing page ${i + 1} of ${pageCount}...`);

        const page = sourcePdf.getPage(i);
        const { width, height } = page.getSize();

        // Convert to different units
        const widthIn = width / POINTS_PER_INCH;
        const heightIn = height / POINTS_PER_INCH;
        const widthMm = widthIn * MM_PER_INCH;
        const heightMm = heightIn * MM_PER_INCH;

        // Determine orientation
        let orientation: 'portrait' | 'landscape' | 'square';
        if (Math.abs(width - height) < 1) {
          orientation = 'square';
        } else if (width > height) {
          orientation = 'landscape';
        } else {
          orientation = 'portrait';
        }

        // Find standard size match
        const standardSize = findStandardSize(width, height);

        const pageDimension: PageDimension = {
          pageNumber: i + 1,
          widthPt: Math.round(width * 100) / 100,
          heightPt: Math.round(height * 100) / 100,
          widthIn: Math.round(widthIn * 100) / 100,
          heightIn: Math.round(heightIn * 100) / 100,
          widthMm: Math.round(widthMm * 10) / 10,
          heightMm: Math.round(heightMm * 10) / 10,
          orientation,
          standardSize,
        };

        pages.push(pageDimension);

        // Track unique sizes
        const sizeKey = `${Math.round(width)}x${Math.round(height)}`;
        const existing = sizeMap.get(sizeKey);
        if (existing) {
          existing.count++;
          existing.pages.push(i + 1);
        } else {
          sizeMap.set(sizeKey, { count: 1, pages: [i + 1] });
        }

        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }
      }

      this.updateProgress(95, 'Generating report...');

      // Build unique sizes summary
      const uniqueSizes = Array.from(sizeMap.entries()).map(([size, data]) => ({
        size,
        count: data.count,
        pages: data.pages,
      }));

      // Check if all pages have the same size
      const uniformSize = uniqueSizes.length === 1;

      const result: PageDimensionsResult = {
        pageCount,
        pages,
        uniqueSizes,
        uniformSize,
      };

      // Create JSON output
      const jsonString = JSON.stringify(result, null, 2);
      const blob = new Blob([jsonString], { type: 'application/json' });

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateDimensionsFilename(file.name);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount,
        uniformSize,
        uniqueSizeCount: uniqueSizes.length,
        result,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to analyze PDF page dimensions.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for page dimensions processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Find matching standard page size
 */
function findStandardSize(width: number, height: number): string | null {
  const tolerance = 2; // Allow 2 points tolerance

  for (const [name, size] of Object.entries(STANDARD_SIZES)) {
    // Check portrait orientation
    if (
      Math.abs(width - size.width) <= tolerance &&
      Math.abs(height - size.height) <= tolerance
    ) {
      return name;
    }
    // Check landscape orientation
    if (
      Math.abs(width - size.height) <= tolerance &&
      Math.abs(height - size.width) <= tolerance
    ) {
      return `${name} (Landscape)`;
    }
  }

  return null;
}

/**
 * Generate a filename for the dimensions report
 */
function generateDimensionsFilename(originalName: string): string {
  const lastDot = originalName.lastIndexOf('.');
  const baseName = lastDot === -1 ? originalName : originalName.slice(0, lastDot);
  return `${baseName}_dimensions.json`;
}

