            const excelBlob = await new Promise<Blob>((resolve, reject) => {
                if (!this.worker) {
                    reject(new Error('Worker not initialized'));
                    return;
                }

                const handleMessage = (event: MessageEvent) => {
                    const { type, data, error, message } = event.data;

                    if (type === 'status') {
