                    }

                    if (type === 'complete') {
                        cleanup();
                        // Create Blob from Uint8Array
                        resolve(new Blob([data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }));
                    } else if (type === 'error') {
