                    type: 'convert',
                    data: uint8Array,
                    options: excelOptions
                }, [uint8Array.buffer]);
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
