    /** Specific pages to convert (empty = all pages) */
    pages: number[];
    /** Background color for transparent PDFs (hex color) */
    backgroundColor: string;
    /** Whether to embed fonts in SVG */
    embedFonts: boolean;
}

/**
 * Default options
 */
