}

/**
 * PDF to SVG Processor
 * Converts PDF pages to SVG using pdfjs-dist for rendering.
 */
export class PDFToSVGProcessor extends BasePDFProcessor {
    /**
     * Process PDF and convert to SVG
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files, options } = input;
        const svgOptions: PDFToSVGOptions = {
            ...DEFAULT_OPTIONS,
            ...(options as Partial<PDFToSVGOptions>),
        };

        // Validate we have exactly 1 PDF file
        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one PDF file.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];

        // Validate file type
        if (!file.type.includes('pdf') && !file.name.toLowerCase().endsWith('.pdf')) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload a PDF file.',
                `Received: ${file.type || 'unknown'}`
            );
        }

        try {
            this.updateProgress(5, 'Loading PDF library...');

            // Use modern pdfjs-dist
            const pdfjs = await loadPdfjs();

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(10, 'Loading PDF document...');

            // Load the PDF document
            const arrayBuffer = await file.arrayBuffer();
            const pdf = await pdfjs.getDocument({ data: arrayBuffer }).promise;
            const totalPages = pdf.numPages;

            // Determine which pages to convert
            const pagesToConvert = svgOptions.pages.length > 0
                ? svgOptions.pages.filter(p => p >= 1 && p <= totalPages)
                : Array.from({ length: totalPages }, (_, i) => i + 1);

            if (pagesToConvert.length === 0) {
                return this.createErrorOutput(
                    PDFErrorCode.INVALID_PAGE_RANGE,
                    'No valid pages to convert.',
                    `PDF has ${totalPages} pages.`
                );
            }

            this.updateProgress(15, `Converting ${pagesToConvert.length} page(s) to SVG...`);

            const svgResults: SVGResult[] = [];
            const progressPerPage = 80 / pagesToConvert.length;

            for (let i = 0; i < pagesToConvert.length; i++) {
                if (this.checkCancelled()) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_CANCELLED,
                        'Processing was cancelled.'
                    );
                }

                const pageNum = pagesToConvert[i];
                const pageProgress = 15 + (i * progressPerPage);

                this.updateProgress(
                    pageProgress,
                    `Converting page ${pageNum} of ${totalPages}...`
                );

                try {
                    const svgResult = await this.renderPageToSVG(
                        pdf,
                        pageNum,
                        svgOptions
                    );
                    svgResults.push(svgResult);
                } catch (error) {
                    return this.createErrorOutput(
                        PDFErrorCode.PROCESSING_FAILED,
                        `Failed to convert page ${pageNum}.`,
                        error instanceof Error ? error.message : 'Unknown error'
                    );
                }
            }

            this.updateProgress(95, 'Finalizing...');

            // Generate output
            const baseName = file.name.replace(/\.pdf$/i, '');
            const blobs = svgResults.map(r => r.blob);

            if (blobs.length === 1) {
                // Single SVG output
                this.updateProgress(100, 'Complete!');
                return this.createSuccessOutput(
                    blobs[0],
                    `${baseName}.svg`,
                    {
                        pageCount: 1,
                        format: 'svg',
                        svgResults: svgResults
                    }
                );
            } else {
                // Multiple SVGs output
                this.updateProgress(100, 'Complete!');
                return this.createSuccessOutput(
                    blobs,
                    `${baseName}_pages.svg`,
                    {
                        pageCount: blobs.length,
                        format: 'svg',
                        svgResults: svgResults
                    }
                );
            }

        } catch (error) {
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert PDF to SVG.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }

    /**
     * Render a single PDF page to SVG
     */
    private async renderPageToSVG(
        pdf: any,
        pageNum: number,
        options: PDFToSVGOptions
    ): Promise<SVGResult> {
        const page = await pdf.getPage(pageNum);
        const viewport = page.getViewport({ scale: options.scale });

        // Since modern PDF.js distributions often exclude SVGGraphics for bundle size,
        // we use a high-quality raster-to-SVG conversion with a selectable text layer.
        // This ensures the SVG remains searchable and selectable while being visually accurate.
        return this.renderPageToRasterSVG(page, viewport, options, pageNum);
    }

    /**
     * Render page to SVG with embedded raster image and vector text layer
     */
    private async renderPageToRasterSVG(
        page: any,
        viewport: any,
        options: PDFToSVGOptions,
        pageNum: number
    ): Promise<SVGResult> {
        // Create canvas with higher resolution for better quality
        const canvas = document.createElement('canvas');
        canvas.width = viewport.width;
        canvas.height = viewport.height;

        const ctx = canvas.getContext('2d');
        if (!ctx) {
            throw new Error('Failed to get canvas context');
        }

        // Fill background
        ctx.fillStyle = options.backgroundColor;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Render PDF page to canvas
        await page.render({
            canvasContext: ctx,
            viewport: viewport,
            canvas: canvas,
        }).promise;

        // Get text content for vector text layer
        const textContent = await page.getTextContent();

        // Build text layer SVG elements
        let textLayerSVG = '';
        if (textContent && textContent.items && textContent.items.length > 0) {
            for (const item of textContent.items as any[]) {
                if (!item.str || item.str.trim() === '') continue;

                // PDF.js v4+ items have transform directly
                const it = item.transform;
                const tx = viewport.transform;

                // Apply viewport transform to get screen coordinates
                const x = tx[0] * it[4] + tx[2] * it[5] + tx[4];
                const y = tx[1] * it[4] + tx[3] * it[5] + tx[5];

                // Calculate font size based on transform
                const fontSize = Math.sqrt(it[0] * it[0] + it[1] * it[1]) * options.scale;

                // Escape special XML characters
                const escapedText = item.str
                    .replace(/&/g, '&amp;')
                    .replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;')
                    .replace(/"/g, '&quot;')
                    .replace(/'/g, '&apos;');

                // Add text element (invisible by default, but selectable and searchable)
                textLayerSVG += `
    <text x="${x.toFixed(2)}" y="${y.toFixed(2)}" 
          font-size="${fontSize.toFixed(1)}" 
          font-family="${item.fontName || 'sans-serif'}"
          fill="transparent" fill-opacity="0">${escapedText}</text>`;
            }
        }

        // Convert canvas to data URL
        const dataUrl = canvas.toDataURL('image/png');

        // Create SVG with image and text layer
        const svgString = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" 
     width="${viewport.width}" height="${viewport.height}" viewBox="0 0 ${viewport.width} ${viewport.height}">
  <title>PDF Page ${pageNum}</title>
  <defs>
    <style>
      .text-layer text {
        fill: transparent;
        fill-opacity: 0;
        pointer-events: all;
        user-select: text;
        -webkit-user-select: text;
      }
      .text-layer text::selection {
        background: #0078d4;
        fill: #fff;
      }
    </style>
  </defs>
  <!-- Raster layer -->
  <image width="${viewport.width}" height="${viewport.height}" xlink:href="${dataUrl}" />
  <!-- Vector text layer (selectable) -->
  <g class="text-layer">${textLayerSVG}
  </g>
</svg>`;

        const svgBlob = new Blob([svgString], { type: 'image/svg+xml' });

        return {
            svg: svgString,
            blob: svgBlob,
            pageNumber: pageNum,
            width: viewport.width,
            height: viewport.height,
        };
    }
}


/**
 * Create a new instance of the PDF to SVG processor
 */
export function createPDFToSVGProcessor(): PDFToSVGProcessor {
    return new PDFToSVGProcessor();
}

/**
 * Convert PDF to SVG (convenience function)
 */
export async function pdfToSVG(
    file: File,
    options?: Partial<PDFToSVGOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createPDFToSVGProcessor();
    return processor.process(
        {
            files: [file],
            options: options || {},
        },
        onProgress
    );
}

/**
 * PowerPoint to PDF Processor
 * 
 * Converts PowerPoint presentations to PDF using LibreOffice WASM.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/** Maximum file size: 50 MB */
const MAX_FILE_SIZE = 50 * 1024 * 1024;
/** Conversion timeout: 5 minutes */
const CONVERT_TIMEOUT_MS = 5 * 60 * 1000;

export interface PPTXToPDFOptions {
    /** Reserved for future options */
}

let converterPromise: Promise<any> | null = null;
let converterInstance: any = null;

async function getConverter(onProgress?: (percent: number, message: string) => void): Promise<any> {
    if (converterInstance?.isReady()) return converterInstance;

    if (converterPromise) {
        await converterPromise;
        return converterInstance;
    }

    converterPromise = (async () => {
        const { getLibreOfficeConverter } = await import('@/lib/libreoffice');
        converterInstance = getLibreOfficeConverter();
        await converterInstance.initialize((progress: any) => {
            onProgress?.(progress.percent, progress.message);
        });
    })();

    await converterPromise;
    return converterInstance;
}

export class PPTXToPDFProcessor extends BasePDFProcessor {
    private conversionProgressTimer: ReturnType<typeof setInterval> | null = null;

    private startConversionProgress(message: string): void {
        this.stopConversionProgress();
        // LibreOffice convert() does not expose granular runtime progress.
        // Keep UI responsive by advancing a bounded pseudo-progress while waiting.
        this.conversionProgressTimer = setInterval(() => {
            if (this.progress >= 98) return;
            this.updateProgress(this.progress + 1, message);
        }, 800);
    }

    private stopConversionProgress(): void {
        if (this.conversionProgressTimer) {
            clearInterval(this.conversionProgressTimer);
            this.conversionProgressTimer = null;
        }
    }

    protected reset(): void {
        this.stopConversionProgress();
        super.reset();
    }

    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one PowerPoint presentation.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];
        const ext = file.name.split('.').pop()?.toLowerCase() || '';
        const validExts = ['pptx', 'ppt', 'odp'];

        if (!validExts.includes(ext)) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload .pptx, .ppt, or .odp.',
                `Received: ${file.type || file.name}`
            );
        }

        // File size guard
        if (file.size > MAX_FILE_SIZE) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                `File is too large (${(file.size / 1024 / 1024).toFixed(1)} MB). Maximum supported size is ${MAX_FILE_SIZE / 1024 / 1024} MB.`,
                `File size: ${file.size} bytes, limit: ${MAX_FILE_SIZE} bytes`
            );
        }

        try {
            this.updateProgress(5, 'Loading conversion engine (first time may take 1-2 minutes)...');

            const converter = await getConverter((percent, message) => {
                this.updateProgress(Math.min(percent * 0.8, 80), message);
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(85, 'Converting PowerPoint to PDF...');
            this.startConversionProgress('Converting PowerPoint to PDF...');

            // Convert with timeout protection
            const pdfBlob = await Promise.race([
                converter.convertToPdf(file),
                new Promise<never>((_, reject) =>
                    setTimeout(() => reject(new Error(
                        `Conversion timed out after ${CONVERT_TIMEOUT_MS / 60000} minutes. The file may be too complex.`
                    )), CONVERT_TIMEOUT_MS)
                ),
            ]);
            this.stopConversionProgress();

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.(pptx?|odp)$/i, '');
            return this.createSuccessOutput(pdfBlob, `${baseName}.pdf`, { format: 'pdf' });

        } catch (error) {
            this.stopConversionProgress();
            console.error('Conversion error:', error);
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert PowerPoint to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

export function createPPTXToPDFProcessor(): PPTXToPDFProcessor {
    return new PPTXToPDFProcessor();
}

export async function pptxToPDF(
    file: File,
    options?: Partial<PPTXToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createPPTXToPDFProcessor();
    return processor.process({ files: [file], options: options || {} }, onProgress);
}

/**
 * PDF Redaction Processor
 * Requirements: 5.1
 * 
 * Implements redaction functionality for permanently removing content from PDFs.
 * Redaction involves:
 * 1. Drawing black rectangles over specified areas
 * 2. Removing the underlying content (text, images) from those areas
 * 
 * Note: True redaction requires removing the actual content from the PDF,
 * not just covering it with a black box. This implementation uses pdf-lib
 * to draw opaque rectangles and flatten the PDF.
 */

import { PDFDocument, rgb, StandardFonts } from 'pdf-lib';

/**
 * Represents a rectangular area to be redacted
 */
export interface RedactionArea {
  /** Page number (1-indexed) */
  page: number;
  /** X coordinate from left edge (in points) */
  x: number;
  /** Y coordinate from bottom edge (in points) */
  y: number;
  /** Width of the redaction area (in points) */
  width: number;
  /** Height of the redaction area (in points) */
  height: number;
  /** Optional replacement text to show in the redacted area */
  replacementText?: string;
}

/**
 * Options for the redaction process
 */
export interface RedactionOptions {
  /** Areas to redact */
  areas: RedactionArea[];
  /** Color for the redaction boxes (default: black) */
  color?: { r: number; g: number; b: number };
  /** Whether to add a border around redaction boxes */
  addBorder?: boolean;
  /** Replacement text to show in all redacted areas */
  defaultReplacementText?: string;
}

/**
 * Result of the redaction process
 */
export interface RedactionResult {
  success: boolean;
  result?: Blob;
  error?: string;
  redactedCount: number;
}

/**
 * Apply redactions to a PDF document
 * 
 * @param file - The PDF file to redact
 * @param options - Redaction options including areas to redact
 * @returns Promise resolving to the redaction result
 */
export async function applyRedactions(
  file: File,
  options: RedactionOptions
): Promise<RedactionResult> {
  try {
    // Validate input
    if (!file) {
      return {
        success: false,
        error: 'No file provided',
        redactedCount: 0,
      };
    }

    if (!options.areas || options.areas.length === 0) {
      return {
        success: false,
        error: 'No redaction areas specified',
        redactedCount: 0,
      };
    }

    // Load the PDF
    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await PDFDocument.load(arrayBuffer, {
      ignoreEncryption: true,
    });

    const pages = pdfDoc.getPages();
    const pageCount = pages.length;

    // Default redaction color (black)
    const redactionColor = options.color
      ? rgb(options.color.r / 255, options.color.g / 255, options.color.b / 255)
      : rgb(0, 0, 0);

    let redactedCount = 0;

    // Apply redactions to each specified area
    for (const area of options.areas) {
      // Validate page number
      if (area.page < 1 || area.page > pageCount) {
        console.warn(`Invalid page number: ${area.page}. Skipping.`);
        continue;
      }

      const page = pages[area.page - 1];
      const { height: pageHeight } = page.getSize();

      // Convert coordinates if needed (PDF coordinates are from bottom-left)
      // The y coordinate from the UI is typically from top-left
      const pdfY = pageHeight - area.y - area.height;

      // Draw a filled rectangle over the area
      page.drawRectangle({
        x: area.x,
        y: pdfY,
        width: area.width,
        height: area.height,
        color: redactionColor,
        opacity: 1, // Fully opaque to cover content
      });

      // Add border if requested
      if (options.addBorder) {
        page.drawRectangle({
          x: area.x,
          y: pdfY,
          width: area.width,
          height: area.height,
          borderColor: rgb(0.3, 0.3, 0.3),
          borderWidth: 1,
        });
      }

      // Add replacement text if specified
      const replacementText = area.replacementText || options.defaultReplacementText;
      if (replacementText) {
        const font = await pdfDoc.embedFont(StandardFonts.Helvetica);
        const fontSize = Math.min(area.height * 0.6, 12);
        const textWidth = font.widthOfTextAtSize(replacementText, fontSize);

        // Center the text in the redaction box
        const textX = area.x + (area.width - textWidth) / 2;
        const textY = pdfY + (area.height - fontSize) / 2;

        page.drawText(replacementText, {
          x: textX,
          y: textY,
          size: fontSize,
          font,
          color: rgb(1, 1, 1), // White text on black background
        });
      }

      redactedCount++;
    }

    // Save the modified PDF
    const pdfBytes = await pdfDoc.save({ useObjectStreams: true });
    // Convert Uint8Array to ArrayBuffer for Blob compatibility
    const outputBuffer = pdfBytes.buffer.slice(
      pdfBytes.byteOffset,
      pdfBytes.byteOffset + pdfBytes.byteLength
    ) as ArrayBuffer;
    const blob = new Blob([outputBuffer], { type: 'application/pdf' });

    return {
      success: true,
      result: blob,
      redactedCount,
    };
  } catch (error) {
    console.error('Redaction error:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Failed to apply redactions',
      redactedCount: 0,
    };
  }
}

/**
 * Validate redaction areas
 * 
 * @param areas - Array of redaction areas to validate
 * @param pageCount - Total number of pages in the PDF
 * @returns Object with validation result and any errors
 */
export function validateRedactionAreas(
  areas: RedactionArea[],
  pageCount: number
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];

  if (!areas || areas.length === 0) {
    errors.push('No redaction areas specified');
    return { valid: false, errors };
  }

  for (let i = 0; i < areas.length; i++) {
    const area = areas[i];

    if (area.page < 1 || area.page > pageCount) {
      errors.push(`Area ${i + 1}: Invalid page number ${area.page}`);
    }

    if (area.width <= 0) {
      errors.push(`Area ${i + 1}: Width must be positive`);
    }

    if (area.height <= 0) {
      errors.push(`Area ${i + 1}: Height must be positive`);
    }

    if (area.x < 0) {
      errors.push(`Area ${i + 1}: X coordinate cannot be negative`);
    }

    if (area.y < 0) {
      errors.push(`Area ${i + 1}: Y coordinate cannot be negative`);
    }
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

export default {
  applyRedactions,
  validateRedactionAreas,
};

/**
 * PDF Remove Annotations Processor
 * Requirements: 5.1
 */

import type { ProcessInput, ProcessOutput, ProgressCallback } from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

export interface RemoveAnnotationsOptions {
  removeComments?: boolean;
  removeHighlights?: boolean;
  removeLinks?: boolean;
  removeAll?: boolean;
  pages?: number[] | 'all';
}

export class RemoveAnnotationsProcessor extends BasePDFProcessor {
  async process(input: ProcessInput, onProgress?: ProgressCallback): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const removeOptions: RemoveAnnotationsOptions = {
      removeAll: true,
      pages: 'all',
      ...options as RemoveAnnotationsOptions,
    };

    if (files.length !== 1) {
      return this.createErrorOutput(PDFErrorCode.INVALID_OPTIONS, 'Exactly 1 PDF file is required.');
    }

    try {
      this.updateProgress(10, 'Loading PDF library...');
      const pdfLib = await loadPdfLib();

      this.updateProgress(20, 'Loading PDF...');
      const file = files[0];
      const arrayBuffer = await file.arrayBuffer();
      const pdf = await pdfLib.PDFDocument.load(arrayBuffer, { ignoreEncryption: true });

      const totalPages = pdf.getPageCount();
      const pagesToProcess = removeOptions.pages === 'all'
        ? Array.from({ length: totalPages }, (_, i) => i)
        : (removeOptions.pages as number[]).map(p => p - 1);

      this.updateProgress(30, 'Removing annotations...');

      let removedCount = 0;

      for (let i = 0; i < pagesToProcess.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
        }

        const pageIndex = pagesToProcess[i];
        const page = pdf.getPage(pageIndex);

        // Get the page's annotation references
        const annots = page.node.get(pdfLib.PDFName.of('Annots'));

        if (annots) {
          if (removeOptions.removeAll) {
            // Remove all annotations
            page.node.delete(pdfLib.PDFName.of('Annots'));
            removedCount++;
          } else {
            // Selective removal would require parsing annotation types
            // This is a simplified implementation
            page.node.delete(pdfLib.PDFName.of('Annots'));
            removedCount++;
          }
        }

        this.updateProgress(30 + (60 * (i + 1) / pagesToProcess.length), `Processing page ${pageIndex + 1}...`);
      }

      this.updateProgress(95, 'Saving PDF...');
      const pdfBytes = await pdf.save({ useObjectStreams: true });
      const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });

      this.updateProgress(100, 'Complete!');
      return this.createSuccessOutput(blob, file.name.replace('.pdf', '_no_annotations.pdf'), {
        pageCount: totalPages,
        pagesProcessed: pagesToProcess.length,
      });

    } catch (error) {
      return this.createErrorOutput(PDFErrorCode.PROCESSING_FAILED, 'Failed to remove annotations.', error instanceof Error ? error.message : 'Unknown error');
    }
  }

  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

export function createRemoveAnnotationsProcessor(): RemoveAnnotationsProcessor {
  return new RemoveAnnotationsProcessor();
}

export async function removeAnnotations(file: File, options: RemoveAnnotationsOptions, onProgress?: ProgressCallback): Promise<ProcessOutput> {
  const processor = createRemoveAnnotationsProcessor();
  return processor.process({ files: [file], options: options as Record<string, unknown> }, onProgress);
}

/**
 * PDF Remove Restrictions Processor
 * Requirements: 5.1
 * 
 * Implements PDF restriction removal functionality using qpdf-wasm.
 * Removes security restrictions (permissions) from PDF files,
 * allowing printing, copying, and editing.
 * 
 * Note: This only removes owner password restrictions, not user passwords.
 * If a PDF requires a password to open, the user must provide it.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * Remove Restrictions options
 */
export interface RemoveRestrictionsOptions {
  /** Owner password if known (optional) */
  ownerPassword?: string;
}

/**
 * Default options
 */
const DEFAULT_OPTIONS: RemoveRestrictionsOptions = {
  ownerPassword: '',
};

// QPDF instance singleton
let qpdfInstance: any = null;
let qpdfLoadPromise: Promise<any> | null = null;

// Store captured stderr output
let capturedStderr: string[] = [];

/**
 * Initialize qpdf-wasm singleton
 * Uses script tag loading to avoid Next.js SSR bundling issues
 */
async function initializeQpdf(): Promise<any> {
  // Return cached instance if available
  if (qpdfInstance) {
    return qpdfInstance;
  }

  // Return existing loading promise if already loading
  if (qpdfLoadPromise) {
    return qpdfLoadPromise;
  }

  // Only run in browser environment
  if (typeof window === 'undefined') {
    throw new Error('QPDF can only be initialized in browser environment');
  }

  qpdfLoadPromise = new Promise((resolve, reject) => {
    // Check if Module is already available
    if ((window as any).Module && typeof (window as any).Module === 'function') {
      initQpdfModule(resolve, reject);
      return;
    }

    // Load the script dynamically
    const script = document.createElement('script');
    script.src = '/qpdf.js';
    script.async = true;

    script.onload = () => {
      initQpdfModule(resolve, reject);
    };

    script.onerror = () => {
      qpdfLoadPromise = null;
      reject(new Error('Failed to load QPDF script'));
    };

    document.head.appendChild(script);
  });

  return qpdfLoadPromise;
}

/**
 * Initialize the QPDF module after script is loaded
 */
function initQpdfModule(resolve: (value: any) => void, reject: (reason: any) => void) {
  try {
    const createModule = (window as any).Module;

    if (!createModule || typeof createModule !== 'function') {
      reject(new Error('QPDF module not found after script load'));
      return;
    }

    createModule({
      locateFile: (path: string) => {
        if (path.endsWith('.wasm')) {
          return '/qpdf.wasm';
        }
        return path;
      },
    }).then((instance: any) => {
      qpdfInstance = instance;
      resolve(instance);
    }).catch((err: any) => {
      qpdfLoadPromise = null;
      reject(err);
    });
  } catch (err) {
    qpdfLoadPromise = null;
    reject(err);
  }
}

/**
 * Remove Restrictions Processor
 * Removes security restrictions from PDF files using qpdf.
 */
export class RemoveRestrictionsProcessor extends BasePDFProcessor {
  /**
   * Process PDF file and remove restrictions
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const removeOptions: RemoveRestrictionsOptions = {
      ...DEFAULT_OPTIONS,
      ...(options as Partial<RemoveRestrictionsOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Please provide exactly one PDF file.',
        `Received ${files.length} file(s).`
      );
    }

    const file = files[0];
    const inputPath = '/input.pdf';
    const outputPath = '/output.pdf';
    let qpdf: any;

    try {
      this.updateProgress(5, 'Initializing...');

      // Initialize qpdf-wasm
      qpdf = await initializeQpdf();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(15, 'Reading PDF file...');

      // Read file as ArrayBuffer
      const arrayBuffer = await file.arrayBuffer();
      const originalSize = arrayBuffer.byteLength;
      const uint8Array = new Uint8Array(arrayBuffer);

      // Write input file to WASM filesystem
      qpdf.FS.writeFile(inputPath, uint8Array);

      this.updateProgress(30, 'Preparing...');

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(50, 'Removing restrictions...');

      // Build qpdf command arguments
      const args = [inputPath];

      // Add password if provided
      if (removeOptions.ownerPassword) {
        args.push('--password=' + removeOptions.ownerPassword);
      }

      // --decrypt removes encryption, --remove-restrictions removes permission restrictions
      args.push('--decrypt', '--remove-restrictions', '--', outputPath);

      // Capture stderr by temporarily overriding console.error
      capturedStderr = [];
      const originalConsoleError = console.error;
      console.error = (...errorArgs: any[]) => {
        const message = errorArgs.map(a => String(a)).join(' ');
        capturedStderr.push(message);
        originalConsoleError.apply(console, errorArgs);
      };

      // Execute qpdf
      let qpdfError: Error | null = null;
      try {
        qpdf.callMain(args);
      } catch (err: any) {
        qpdfError = err;
      } finally {
        // Restore console.error
        console.error = originalConsoleError;
      }

      // Check if output file was created (indicates success)
      let outputFileExists = false;
      let outputFile: Uint8Array | null = null;
      try {
        outputFile = qpdf.FS.readFile(outputPath, { encoding: 'binary' });
        outputFileExists = !!(outputFile && outputFile.length > 0);
      } catch (e) {
        outputFileExists = false;
      }

      // If output file doesn't exist or is empty, check for password error
      if (!outputFileExists) {
        // Check captured stderr for password error
        const stderrOutput = capturedStderr.join(' ').toLowerCase();
        const hasPasswordError = 
          stderrOutput.includes('invalid password') ||
          stderrOutput.includes('incorrect password') ||
          stderrOutput.includes('wrong password') ||
          stderrOutput.includes('password');

        if (hasPasswordError || qpdfError) {
          const errorMessage = qpdfError ? String(qpdfError.message || qpdfError || '').toLowerCase() : '';
          if (
            hasPasswordError ||
            errorMessage.includes('invalid password') ||
            errorMessage.includes('incorrect password') ||
            errorMessage.includes('wrong password') ||
            errorMessage.includes('password')
          ) {
            return this.createErrorOutput(
              PDFErrorCode.INVALID_PASSWORD,
              'INVALID_PASSWORD',
              'The password you entered is incorrect. Please check and try again.'
            );
          }
          throw qpdfError || new Error('Failed to remove restrictions');
        }

        // If no specific error found, assume password error for encrypted PDFs
        return this.createErrorOutput(
          PDFErrorCode.INVALID_PASSWORD,
          'INVALID_PASSWORD',
          'The password you entered is incorrect. Please check and try again.'
        );
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(80, 'Preparing file...');

      // Create blob from the output
      const blob = new Blob([new Uint8Array(outputFile!)], { type: 'application/pdf' });
      const newSize = outputFile!.length;

      // Cleanup WASM filesystem
      try {
        qpdf.FS.unlink(inputPath);
      } catch (e) {
        console.warn('Failed to unlink input file:', e);
      }
      try {
        qpdf.FS.unlink(outputPath);
      } catch (e) {
        console.warn('Failed to unlink output file:', e);
      }

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateUnrestrictedFilename(file.name);

      return this.createSuccessOutput(blob, outputFilename, {
        originalSize,
        newSize,
        restrictionsRemoved: true,
      });

    } catch (error) {
      // Cleanup on error
      if (qpdf?.FS) {
        try {
          qpdf.FS.unlink(inputPath);
        } catch (e) {
          // Ignore cleanup errors
        }
        try {
          qpdf.FS.unlink(outputPath);
        } catch (e) {
          // Ignore cleanup errors
        }
      }

      // Check for password-related errors in the outer catch as well
      const errorMessage = String(error instanceof Error ? error.message : error || '').toLowerCase();
      if (
        errorMessage.includes('invalid password') ||
        errorMessage.includes('incorrect password') ||
        errorMessage.includes('wrong password') ||
        errorMessage.includes('password')
      ) {
        return this.createErrorOutput(
          PDFErrorCode.INVALID_PASSWORD,
          'INVALID_PASSWORD',
          'The password you entered is incorrect. Please check and try again.'
        );
      }

      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to remove PDF restrictions.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for remove restrictions processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Generate a filename for the unrestricted PDF
 */
function generateUnrestrictedFilename(originalName: string): string {
  const lastDot = originalName.lastIndexOf('.');
  const baseName = lastDot === -1 ? originalName : originalName.slice(0, lastDot);
  return `${baseName}_unrestricted.pdf`;
}

/**
 * Create a new instance of the remove restrictions processor
 */
export function createRemoveRestrictionsProcessor(): RemoveRestrictionsProcessor {
  return new RemoveRestrictionsProcessor();
}

/**
 * Remove restrictions from a PDF file (convenience function)
 */
export async function removeRestrictions(
  file: File,
  options?: Partial<RemoveRestrictionsOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createRemoveRestrictionsProcessor();
  return processor.process(
    {
      files: [file],
      options: options || {},
    },
    onProgress
  );
}

/**
 * PDF Repair Processor
 * Requirements: 5.1
 * 
 * Implements PDF repair functionality using qpdf-wasm.
 * Attempts to fix corrupted or malformed PDF files by:
 * - Rebuilding cross-reference tables
 * - Fixing corrupted objects
 * - Handling encryption issues
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * Repair PDF options
 */
export interface RepairPDFOptions {
  /** Attempt to recover from encryption issues */
  ignoreEncryption: boolean;
  /** Rebuild cross-reference table */
  rebuildXref: boolean;
  /** Remove corrupted objects */
  removeCorruptedObjects: boolean;
}

/**
 * Default repair options
 */
const DEFAULT_REPAIR_OPTIONS: RepairPDFOptions = {
  ignoreEncryption: true,
  rebuildXref: true,
  removeCorruptedObjects: true,
};

// QPDF instance singleton
let qpdfInstance: any = null;
let qpdfLoadPromise: Promise<any> | null = null;

/**
 * Initialize qpdf-wasm singleton
 * Uses script tag loading to avoid Next.js SSR bundling issues
 */
async function initializeQpdf(): Promise<any> {
  // Return cached instance if available
  if (qpdfInstance) {
    return qpdfInstance;
  }

  // Return existing loading promise if already loading
  if (qpdfLoadPromise) {
    return qpdfLoadPromise;
  }

  // Only run in browser environment
  if (typeof window === 'undefined') {
    throw new Error('QPDF can only be initialized in browser environment');
  }

  qpdfLoadPromise = new Promise((resolve, reject) => {
    // Check if Module is already available
    if ((window as any).Module && typeof (window as any).Module === 'function') {
      initQpdfModule(resolve, reject);
      return;
    }

    // Load the script dynamically
    const script = document.createElement('script');
    script.src = '/qpdf.js';
    script.async = true;

    script.onload = () => {
      initQpdfModule(resolve, reject);
    };

    script.onerror = () => {
      qpdfLoadPromise = null;
      reject(new Error('Failed to load QPDF script'));
    };

    document.head.appendChild(script);
  });

  return qpdfLoadPromise;
}

/**
 * Initialize the QPDF module after script is loaded
 */
function initQpdfModule(resolve: (value: any) => void, reject: (reason: any) => void) {
  try {
    const createModule = (window as any).Module;

    if (!createModule || typeof createModule !== 'function') {
      reject(new Error('QPDF module not found after script load'));
      return;
    }

    createModule({
      locateFile: (path: string) => {
        if (path.endsWith('.wasm')) {
          return '/qpdf.wasm';
        }
        return path;
      },
    }).then((instance: any) => {
      qpdfInstance = instance;
      resolve(instance);
    }).catch((err: any) => {
      qpdfLoadPromise = null;
      reject(err);
    });
  } catch (err) {
    qpdfLoadPromise = null;
    reject(err);
  }
}

/**
 * Repair PDF Processor
 * Attempts to repair corrupted or malformed PDF files using qpdf.
 */
export class RepairPDFProcessor extends BasePDFProcessor {
  /**
   * Process PDF file and attempt to repair it
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const repairOptions: RepairPDFOptions = {
      ...DEFAULT_REPAIR_OPTIONS,
      ...(options as Partial<RepairPDFOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Please provide exactly one PDF file to repair.',
        `Received ${files.length} file(s).`
      );
    }

    const file = files[0];
    const inputPath = '/input.pdf';
    const outputPath = '/output.pdf';
    let qpdf: any;

    try {
      this.updateProgress(5, 'Initializing repair engine...');

      // Initialize qpdf-wasm
      qpdf = await initializeQpdf();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(15, 'Reading PDF file...');

      // Read file as ArrayBuffer
      const arrayBuffer = await file.arrayBuffer();
      const originalSize = arrayBuffer.byteLength;
      const uint8Array = new Uint8Array(arrayBuffer);

      // Write input file to WASM filesystem
      qpdf.FS.writeFile(inputPath, uint8Array);

      this.updateProgress(30, 'Analyzing PDF structure...');

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(50, 'Repairing PDF...');

      // Build qpdf command arguments
      // --decrypt will rebuild the PDF structure and fix many issues
      const args = [inputPath, '--decrypt', outputPath];

      // Execute qpdf repair
      try {
        qpdf.callMain(args);
      } catch (err: any) {
        // qpdf may throw warnings but still produce output
        console.warn('QPDF execution warning:', err);
      }

      // Check if output file was created
      let outputFile: Uint8Array | null = null;
      let outputFileExists = false;
      try {
        outputFile = qpdf.FS.readFile(outputPath, { encoding: 'binary' });
        outputFileExists = !!(outputFile && outputFile.length > 0);
      } catch (e) {
        outputFileExists = false;
      }

      if (!outputFileExists) {
        return this.createErrorOutput(
          PDFErrorCode.PDF_MALFORMED,
          'Unable to repair the PDF file.',
          'The file may be too corrupted to recover.'
        );
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(80, 'Saving repaired PDF...');

      // Create blob from the output
      const blob = new Blob([new Uint8Array(outputFile!)], { type: 'application/pdf' });
      const repairedSize = outputFile!.length;

      // Cleanup WASM filesystem
      try {
        qpdf.FS.unlink(inputPath);
      } catch (e) {
        console.warn('Failed to unlink input file:', e);
      }
      try {
        qpdf.FS.unlink(outputPath);
      } catch (e) {
        console.warn('Failed to unlink output file:', e);
      }

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateRepairedFilename(file.name);

      return this.createSuccessOutput(blob, outputFilename, {
        originalSize,
        repairedSize,
        repaired: true,
      });

    } catch (error) {
      // Cleanup on error
      if (qpdf?.FS) {
        try {
          qpdf.FS.unlink(inputPath);
        } catch (e) {
          // Ignore cleanup errors
        }
        try {
          qpdf.FS.unlink(outputPath);
        } catch (e) {
          // Ignore cleanup errors
        }
      }

      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to repair PDF file.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for repair processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Generate a filename for the repaired PDF
 */
function generateRepairedFilename(originalName: string): string {
  const lastDot = originalName.lastIndexOf('.');
  const baseName = lastDot === -1 ? originalName : originalName.slice(0, lastDot);
  return `${baseName}_repaired.pdf`;
}

/**
 * Create a new instance of the repair processor
 */
export function createRepairProcessor(): RepairPDFProcessor {
  return new RepairPDFProcessor();
}

/**
 * Repair a PDF file (convenience function)
 */
export async function repairPDF(
  file: File,
  options?: Partial<RepairPDFOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createRepairProcessor();
  return processor.process(
    {
      files: [file],
      options: options || {},
    },
    onProgress
  );
}

/**
 * RTF to PDF Processor
 * 
 * Converts RTF documents to PDF using LibreOffice WASM.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/** Maximum file size: 50 MB */
const MAX_FILE_SIZE = 50 * 1024 * 1024;
/** Conversion timeout: 5 minutes */
const CONVERT_TIMEOUT_MS = 5 * 60 * 1000;

export interface RTFToPDFOptions {
    /** Reserved for future options */
}

let converterPromise: Promise<any> | null = null;
let converterInstance: any = null;

async function getConverter(onProgress?: (percent: number, message: string) => void): Promise<any> {
    if (converterInstance?.isReady()) return converterInstance;

    if (converterPromise) {
        await converterPromise;
        return converterInstance;
    }

    converterPromise = (async () => {
        const { getLibreOfficeConverter } = await import('@/lib/libreoffice');
        converterInstance = getLibreOfficeConverter();
        await converterInstance.initialize((progress: any) => {
            onProgress?.(progress.percent, progress.message);
        });
    })();

    await converterPromise;
    return converterInstance;
}

export class RTFToPDFProcessor extends BasePDFProcessor {
    private conversionProgressTimer: ReturnType<typeof setInterval> | null = null;

    private startConversionProgress(message: string): void {
        this.stopConversionProgress();
        // LibreOffice convert() does not expose granular runtime progress.
        // Keep UI responsive by advancing a bounded pseudo-progress while waiting.
        this.conversionProgressTimer = setInterval(() => {
            if (this.progress >= 98) return;
            this.updateProgress(this.progress + 1, message);
        }, 800);
    }

    private stopConversionProgress(): void {
        if (this.conversionProgressTimer) {
            clearInterval(this.conversionProgressTimer);
            this.conversionProgressTimer = null;
        }
    }

    protected reset(): void {
        this.stopConversionProgress();
        super.reset();
    }

    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one RTF file.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];
        const ext = file.name.split('.').pop()?.toLowerCase() || '';

        if (ext !== 'rtf') {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload an .rtf file.',
                `Received: ${file.type || file.name}`
            );
        }

        // File size guard
        if (file.size > MAX_FILE_SIZE) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                `File is too large (${(file.size / 1024 / 1024).toFixed(1)} MB). Maximum supported size is ${MAX_FILE_SIZE / 1024 / 1024} MB.`,
                `File size: ${file.size} bytes, limit: ${MAX_FILE_SIZE} bytes`
            );
        }

        try {
            this.updateProgress(5, 'Loading conversion engine (first time may take 1-2 minutes)...');

            const converter = await getConverter((percent, message) => {
                this.updateProgress(Math.min(percent * 0.8, 80), message);
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(85, 'Converting RTF to PDF...');
            this.startConversionProgress('Converting RTF to PDF...');

            // Convert with timeout protection
            const pdfBlob = await Promise.race([
                converter.convertToPdf(file),
                new Promise<never>((_, reject) =>
                    setTimeout(() => reject(new Error(
                        `Conversion timed out after ${CONVERT_TIMEOUT_MS / 60000} minutes. The file may be too complex.`
                    )), CONVERT_TIMEOUT_MS)
                ),
            ]);
            this.stopConversionProgress();

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.rtf$/i, '');
            return this.createSuccessOutput(pdfBlob, `${baseName}.pdf`, { format: 'pdf' });

        } catch (error) {
            this.stopConversionProgress();
            console.error('Conversion error:', error);
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert RTF to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

export function createRTFToPDFProcessor(): RTFToPDFProcessor {
    return new RTFToPDFProcessor();
}

export async function rtfToPDF(
    file: File,
    options?: Partial<RTFToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createRTFToPDFProcessor();
    return processor.process({ files: [file], options: options || {} }, onProgress);
}

/**
 * PDF Sanitize Processor
 * Requirements: 5.1
 * 
 * Implements PDF sanitization functionality using pdf-lib.
 * Removes potentially harmful content from PDF files including:
 * - JavaScript
 * - Embedded files/attachments
 * - External links
 * - Form actions
 * - Metadata
 * - Annotations
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Sanitize PDF options
 */
export interface SanitizePDFOptions {
  /** Remove JavaScript */
  removeJavaScript: boolean;
  /** Remove embedded files/attachments */
  removeAttachments: boolean;
  /** Remove external links */
  removeLinks: boolean;
  /** Flatten form fields */
  flattenForms: boolean;
  /** Remove metadata */
  removeMetadata: boolean;
  /** Remove annotations */
  removeAnnotations: boolean;
}

/**
 * Default sanitize options
 */
const DEFAULT_SANITIZE_OPTIONS: SanitizePDFOptions = {
  removeJavaScript: true,
  removeAttachments: true,
  removeLinks: true,
  flattenForms: true,
  removeMetadata: true,
  removeAnnotations: false,
};

/**
 * Sanitize PDF Processor
 * Removes potentially harmful content from PDF files.
 */
export class SanitizePDFProcessor extends BasePDFProcessor {
  /**
   * Process PDF file and sanitize it
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const sanitizeOptions: SanitizePDFOptions = {
      ...DEFAULT_SANITIZE_OPTIONS,
      ...(options as Partial<SanitizePDFOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Please provide exactly one PDF file to sanitize.',
        `Received ${files.length} file(s).`
      );
    }

    const file = files[0];

    try {
      this.updateProgress(5, 'Loading PDF library...');

      // Load pdf-lib
      const pdfLib = await loadPdfLib();
      const { PDFName } = pdfLib;

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Reading PDF file...');

      // Read file as ArrayBuffer
      const arrayBuffer = await file.arrayBuffer();
      const originalSize = arrayBuffer.byteLength;

      this.updateProgress(20, 'Loading PDF document...');

      // Load the source PDF
      let pdfDoc;
      try {
        pdfDoc = await pdfLib.PDFDocument.load(arrayBuffer, {
          ignoreEncryption: true,
        });
      } catch (error) {
        if (error instanceof Error && error.message.includes('encrypt')) {
          return this.createErrorOutput(
            PDFErrorCode.PDF_ENCRYPTED,
            'The PDF file is encrypted.',
            'Please decrypt the file before sanitizing.'
          );
        }
        throw error;
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(30, 'Analyzing PDF content...');

      const pageCount = pdfDoc.getPageCount();

      if (pageCount === 0) {
        return this.createErrorOutput(
          PDFErrorCode.PDF_MALFORMED,
          'The PDF file contains no pages.',
          'Cannot sanitize an empty PDF.'
        );
      }

      // Track what was removed
      const removedItems: string[] = [];

      this.updateProgress(40, 'Sanitizing PDF content...');

      // Flatten forms
      if (sanitizeOptions.flattenForms) {
        try {
          const form = pdfDoc.getForm();
          const fields = form.getFields();
          if (fields.length > 0) {
            form.flatten();
            removedItems.push('form fields (flattened)');
          }
        } catch (e: any) {
          // Try to remove AcroForm if flatten fails
          try {
            const catalogDict = (pdfDoc.catalog as any).dict;
            if (catalogDict.has(PDFName.of('AcroForm'))) {
              catalogDict.delete(PDFName.of('AcroForm'));
              removedItems.push('form fields');
            }
          } catch (removeError) {
            console.warn('Could not remove AcroForm:', removeError);
          }
        }
      }

      this.updateProgress(50, 'Removing metadata...');

      // Remove metadata
      if (sanitizeOptions.removeMetadata) {
        try {
          // Clear info dict
          const infoDict = (pdfDoc as any).getInfoDict();
          const allKeys = infoDict.keys();
          allKeys.forEach((key: any) => {
            infoDict.delete(key);
          });

          pdfDoc.setTitle('');
          pdfDoc.setAuthor('');
          pdfDoc.setSubject('');
          pdfDoc.setKeywords([]);
          pdfDoc.setCreator('');
          pdfDoc.setProducer('Akubrecah Dev Cave PDF');

          // Remove XMP metadata
          try {
            const catalogDict = (pdfDoc.catalog as any).dict;
            if (catalogDict.has(PDFName.of('Metadata'))) {
              catalogDict.delete(PDFName.of('Metadata'));
            }
          } catch (e) {
            console.warn('Could not remove XMP metadata');
          }

          removedItems.push('metadata');
        } catch (e) {
          console.warn('Could not remove metadata:', e);
        }
      }

      this.updateProgress(60, 'Removing annotations...');

      // Remove annotations
      if (sanitizeOptions.removeAnnotations) {
        const pages = pdfDoc.getPages();
        for (const page of pages) {
          try {
            page.node.delete(PDFName.of('Annots'));
          } catch (e) {
            // Page might not have annotations
          }
        }
        removedItems.push('annotations');
      }

      this.updateProgress(70, 'Removing JavaScript...');

      // Remove JavaScript
      if (sanitizeOptions.removeJavaScript) {
        try {
          const catalogDict = (pdfDoc.catalog as any).dict;

          // Remove from Names/JavaScript
          const namesRef = catalogDict.get(PDFName.of('Names'));
          if (namesRef) {
            try {
              const namesDict = pdfDoc.context.lookup(namesRef) as any;
              if (namesDict.has(PDFName.of('JavaScript'))) {
                namesDict.delete(PDFName.of('JavaScript'));
              }
            } catch (e) {
              // Ignore
            }
          }

          // Remove OpenAction
          if (catalogDict.has(PDFName.of('OpenAction'))) {
            catalogDict.delete(PDFName.of('OpenAction'));
          }

          // Remove AA (Additional Actions)
          if (catalogDict.has(PDFName.of('AA'))) {
            catalogDict.delete(PDFName.of('AA'));
          }

          // Remove from pages
          const pages = pdfDoc.getPages();
          for (const page of pages) {
            try {
              const pageDict = page.node;
              if (pageDict.has(PDFName.of('AA'))) {
                pageDict.delete(PDFName.of('AA'));
              }
            } catch (e) {
              // Ignore
            }
          }

          removedItems.push('JavaScript');
        } catch (e) {
          console.warn('Could not remove JavaScript:', e);
        }
      }

      this.updateProgress(80, 'Removing embedded files...');

      // Remove embedded files/attachments
      if (sanitizeOptions.removeAttachments) {
        try {
          const catalogDict = (pdfDoc.catalog as any).dict;

          // Remove from Names/EmbeddedFiles
          const namesRef = catalogDict.get(PDFName.of('Names'));
          if (namesRef) {
            try {
              const namesDict = pdfDoc.context.lookup(namesRef) as any;
              if (namesDict.has(PDFName.of('EmbeddedFiles'))) {
                namesDict.delete(PDFName.of('EmbeddedFiles'));
              }
            } catch (e) {
              // Ignore
            }
          }

          // Remove Collection
          if (catalogDict.has(PDFName.of('Collection'))) {
            catalogDict.delete(PDFName.of('Collection'));
          }

          removedItems.push('embedded files');
        } catch (e) {
          console.warn('Could not remove embedded files:', e);
        }
      }

      // Remove links
      if (sanitizeOptions.removeLinks) {
        try {
          const pages = pdfDoc.getPages();
          for (const page of pages) {
            try {
              const pageDict = page.node;
              const annotsRef = pageDict.get(PDFName.of('Annots'));
              if (!annotsRef) continue;

              const annotsArray = pdfDoc.context.lookup(annotsRef) as any;
              const annotRefs = annotsArray.asArray();
              const annotsToKeep = [];

              for (const ref of annotRefs) {
                try {
                  const annot = pdfDoc.context.lookup(ref) as any;
                  const subtype = annot.get(PDFName.of('Subtype'))?.toString().substring(1);

                  // Keep non-link annotations
                  if (subtype !== 'Link') {
                    annotsToKeep.push(ref);
                  }
                } catch (e) {
                  annotsToKeep.push(ref);
                }
              }

              if (annotsToKeep.length !== annotRefs.length) {
                if (annotsToKeep.length > 0) {
                  const newAnnotsArray = pdfDoc.context.obj(annotsToKeep);
                  pageDict.set(PDFName.of('Annots'), newAnnotsArray);
                } else {
                  pageDict.delete(PDFName.of('Annots'));
                }
              }
            } catch (e) {
              // Ignore page errors
            }
          }
          removedItems.push('links');
        } catch (e) {
          console.warn('Could not remove links:', e);
        }
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(90, 'Saving sanitized PDF...');

      // Save the sanitized PDF
      const sanitizedPdfBytes = await pdfDoc.save({ useObjectStreams: true });

      // Create blob from the Uint8Array
      const blob = new Blob([new Uint8Array(sanitizedPdfBytes)], { type: 'application/pdf' });
      const newSize = sanitizedPdfBytes.length;

      this.updateProgress(100, 'Complete!');

      // Generate output filename
      const outputFilename = generateSanitizedFilename(file.name);

      return this.createSuccessOutput(blob, outputFilename, {
        pageCount,
        originalSize,
        newSize,
        removedItems,
        sanitized: true,
      });

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to sanitize PDF file.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for sanitize processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Generate a filename for the sanitized PDF
 */
function generateSanitizedFilename(originalName: string): string {
  const lastDot = originalName.lastIndexOf('.');
  const baseName = lastDot === -1 ? originalName : originalName.slice(0, lastDot);
  return `${baseName}_sanitized.pdf`;
}

/**
 * Create a new instance of the sanitize processor
 */
export function createSanitizeProcessor(): SanitizePDFProcessor {
  return new SanitizePDFProcessor();
}

/**
 * Sanitize a PDF file (convenience function)
 */
export async function sanitizePDF(
  file: File,
  options?: Partial<SanitizePDFOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createSanitizeProcessor();
  return processor.process(
    {
      files: [file],
      options: options || {},
    },
    onProgress
  );
}

/**
 * PDF Split Processor
 * Requirements: 5.1
 * 
 * Implements PDF splitting functionality using pdf-lib.
 * Supports splitting by page ranges with multiple output files.
 */

import type {
  ProcessInput,
  ProcessOutput,
  ProgressCallback,
  SplitOptions,
  PageRange,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor, createPDFError } from '../processor';
import { loadPdfLib } from '../loader';

/**
 * Default split options
 */
const DEFAULT_SPLIT_OPTIONS: SplitOptions = {
  ranges: [],
  outputFormat: 'multiple',
};

/**
 * Split PDF Processor
 * Splits a PDF file into multiple documents based on page ranges.
 */
export class SplitPDFProcessor extends BasePDFProcessor {
  /**
   * Process a PDF file and split it into multiple documents
   */
  async process(
    input: ProcessInput,
    onProgress?: ProgressCallback
  ): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const splitOptions: SplitOptions = {
      ...DEFAULT_SPLIT_OPTIONS,
      ...(options as Partial<SplitOptions>),
    };

    // Validate we have exactly 1 file
    if (files.length !== 1) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'Exactly 1 PDF file is required for splitting.',
        `Received ${files.length} file(s).`
      );
    }

    // Validate we have at least one range
    if (!splitOptions.ranges || splitOptions.ranges.length === 0) {
      return this.createErrorOutput(
        PDFErrorCode.INVALID_OPTIONS,
        'At least one page range is required for splitting.',
        'Please specify page ranges to extract.'
      );
    }

    try {
      this.updateProgress(5, 'Loading PDF library...');

      // Load pdf-lib
      const pdfLib = await loadPdfLib();

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      this.updateProgress(10, 'Loading source PDF...');

      const file = files[0];
      const arrayBuffer = await file.arrayBuffer();

      // Load the source PDF
      let sourcePdf;
      try {
        sourcePdf = await pdfLib.PDFDocument.load(arrayBuffer, {
          ignoreEncryption: false,
        });
      } catch (error) {
        if (error instanceof Error && error.message.includes('encrypt')) {
          return this.createErrorOutput(
            PDFErrorCode.PDF_ENCRYPTED,
            'The PDF file is encrypted.',
            'Please decrypt the file before splitting.'
          );
        }
        throw error;
      }

      const totalPages = sourcePdf.getPageCount();
      this.updateProgress(15, `Source PDF has ${totalPages} pages.`);

      // Validate all page ranges
      const validationError = validatePageRanges(splitOptions.ranges, totalPages);
      if (validationError) {
        return this.createErrorOutput(
          PDFErrorCode.INVALID_PAGE_RANGE,
          validationError,
          `The PDF has ${totalPages} pages.`
        );
      }

      if (this.checkCancelled()) {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_CANCELLED,
          'Processing was cancelled.'
        );
      }

      // Process each range
      const outputBlobs: Blob[] = [];
      const outputFilenames: string[] = [];
      const progressPerRange = 75 / splitOptions.ranges.length;

      for (let i = 0; i < splitOptions.ranges.length; i++) {
        if (this.checkCancelled()) {
          return this.createErrorOutput(
            PDFErrorCode.PROCESSING_CANCELLED,
            'Processing was cancelled.'
          );
        }

        const range = splitOptions.ranges[i];
        const rangeProgress = 15 + (i * progressPerRange);

        this.updateProgress(
          rangeProgress,
          `Extracting pages ${range.start}-${range.end}...`
        );

        // Create a new PDF for this range
        const newPdf = await pdfLib.PDFDocument.create();

        // Get page indices (0-based)
        const pageIndices: number[] = [];
        for (let pageNum = range.start; pageNum <= range.end; pageNum++) {
          pageIndices.push(pageNum - 1); // Convert to 0-based index
        }

        // Copy pages from source to new document
        const copiedPages = await newPdf.copyPages(sourcePdf, pageIndices);
        for (const page of copiedPages) {
          newPdf.addPage(page);
        }

        // Save the new PDF
        const pdfBytes = await newPdf.save({ useObjectStreams: true });
        const blob = new Blob([new Uint8Array(pdfBytes)], { type: 'application/pdf' });
        outputBlobs.push(blob);

        // Generate filename for this range
        const filename = generateSplitFilename(file.name, range, i + 1, splitOptions.ranges.length);
        outputFilenames.push(filename);
      }

      this.updateProgress(95, 'Finalizing...');

      // Return based on output format
      if (splitOptions.outputFormat === 'single' && outputBlobs.length === 1) {
        this.updateProgress(100, 'Complete!');
        return this.createSuccessOutput(outputBlobs[0], outputFilenames[0], {
          pageCount: splitOptions.ranges[0].end - splitOptions.ranges[0].start + 1,
          rangeCount: 1,
          sourcePageCount: totalPages,
        });
      }

      this.updateProgress(100, 'Complete!');

      return {
        success: true,
        result: outputBlobs,
        filename: outputFilenames.join(', '),
        metadata: {
          rangeCount: splitOptions.ranges.length,
          sourcePageCount: totalPages,
          outputFiles: outputFilenames,
        },
      };

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to split PDF file.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    }
  }

  /**
   * Get accepted file types for split processor
   */
  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

/**
 * Validate page ranges against total page count
 */
function validatePageRanges(ranges: PageRange[], totalPages: number): string | null {
  for (let i = 0; i < ranges.length; i++) {
    const range = ranges[i];

    // Check for valid range values
    if (range.start < 1) {
      return `Range ${i + 1}: Start page must be at least 1.`;
    }

    if (range.end < range.start) {
      return `Range ${i + 1}: End page (${range.end}) cannot be less than start page (${range.start}).`;
    }

    if (range.end > totalPages) {
      return `Range ${i + 1}: End page (${range.end}) exceeds total pages (${totalPages}).`;
    }

    if (range.start > totalPages) {
      return `Range ${i + 1}: Start page (${range.start}) exceeds total pages (${totalPages}).`;
    }
  }

  return null;
}

/**
 * Get filename without extension
 */
function getFileNameWithoutExtension(filename: string): string {
  const lastDot = filename.lastIndexOf('.');
  if (lastDot === -1) return filename;
  return filename.slice(0, lastDot);
}

/**
 * Generate a filename for a split PDF
 */
function generateSplitFilename(
  originalName: string,
  range: PageRange,
  rangeIndex: number,
  totalRanges: number
): string {
  const baseName = getFileNameWithoutExtension(originalName);

  if (totalRanges === 1) {
    if (range.start === range.end) {
      return `${baseName}_page_${range.start}.pdf`;
    }
    return `${baseName}_pages_${range.start}-${range.end}.pdf`;
  }

  if (range.start === range.end) {
    return `${baseName}_part${rangeIndex}_page_${range.start}.pdf`;
  }
  return `${baseName}_part${rangeIndex}_pages_${range.start}-${range.end}.pdf`;
}

/**
 * Parse a page range string into PageRange objects
 * Supports formats like: "1-5", "1,3,5", "1-3,5,7-10"
 */
export function parsePageRanges(rangeString: string, totalPages: number): PageRange[] {
  const ranges: PageRange[] = [];
  const parts = rangeString.split(',').map(s => s.trim()).filter(s => s.length > 0);

  for (const part of parts) {
    if (part.includes('-')) {
      const [startStr, endStr] = part.split('-').map(s => s.trim());
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);

      if (!isNaN(start) && !isNaN(end)) {
        ranges.push({ start, end });
      }
    } else {
      const pageNum = parseInt(part, 10);
      if (!isNaN(pageNum)) {
        ranges.push({ start: pageNum, end: pageNum });
      }
    }
  }

  return ranges;
}

/**
 * Create ranges to split every N pages
 */
export function createSplitEveryNPages(totalPages: number, n: number): PageRange[] {
  const ranges: PageRange[] = [];

  for (let start = 1; start <= totalPages; start += n) {
    const end = Math.min(start + n - 1, totalPages);
    ranges.push({ start, end });
  }

  return ranges;
}

/**
 * Create ranges to split into individual pages
 */
export function createSplitEveryPage(totalPages: number): PageRange[] {
  return createSplitEveryNPages(totalPages, 1);
}

/**
 * Create ranges for even and odd pages
 * Returns two ranges: one for odd pages, one for even pages
 */
export function createSplitByEvenOdd(totalPages: number): { odd: PageRange[], even: PageRange[] } {
  const oddRanges: PageRange[] = [];
  const evenRanges: PageRange[] = [];

  for (let i = 1; i <= totalPages; i++) {
    if (i % 2 === 1) {
      oddRanges.push({ start: i, end: i });
    } else {
      evenRanges.push({ start: i, end: i });
    }
  }

  return { odd: oddRanges, even: evenRanges };
}

/**
 * Create ranges to split PDF into N equal parts
 */
export function createSplitNTimes(totalPages: number, n: number): PageRange[] {
  if (n <= 0 || n > totalPages) {
    return [{ start: 1, end: totalPages }];
  }

  const ranges: PageRange[] = [];
  const pagesPerPart = Math.floor(totalPages / n);
  const remainder = totalPages % n;

  let currentPage = 1;
  for (let i = 0; i < n; i++) {
    // Distribute remainder pages across the first parts
    const extraPage = i < remainder ? 1 : 0;
    const endPage = currentPage + pagesPerPart - 1 + extraPage;
    ranges.push({ start: currentPage, end: Math.min(endPage, totalPages) });
    currentPage = endPage + 1;
  }

  return ranges;
}

/**
 * Bookmark information extracted from PDF
 */
export interface BookmarkInfo {
  title: string;
  pageNumber: number;
  children?: BookmarkInfo[];
}

/**
 * Create ranges based on PDF bookmarks
 * Each top-level bookmark becomes a split point
 * @param bookmarks - Array of bookmark info with page numbers
 * @param totalPages - Total number of pages in the PDF
 * @returns Array of page ranges for splitting
 */
export function createSplitByBookmarks(
  bookmarks: BookmarkInfo[],
  totalPages: number
): { ranges: PageRange[], labels: string[] } {
  if (!bookmarks || bookmarks.length === 0) {
    return {
      ranges: [{ start: 1, end: totalPages }],
      labels: ['Complete Document']
    };
  }

  // Get unique sorted page numbers from top-level bookmarks
  const sortedBookmarks = [...bookmarks]
    .filter(b => b.pageNumber >= 1 && b.pageNumber <= totalPages)
    .sort((a, b) => a.pageNumber - b.pageNumber);

  if (sortedBookmarks.length === 0) {
    return {
      ranges: [{ start: 1, end: totalPages }],
      labels: ['Complete Document']
    };
  }

  const ranges: PageRange[] = [];
  const labels: string[] = [];

  for (let i = 0; i < sortedBookmarks.length; i++) {
    const current = sortedBookmarks[i];
    const next = sortedBookmarks[i + 1];

    const start = current.pageNumber;
    const end = next ? next.pageNumber - 1 : totalPages;

    // Only add if range is valid (at least 1 page)
    if (end >= start) {
      ranges.push({ start, end });
      labels.push(current.title);
    }
  }

  // Handle case where first bookmark doesn't start at page 1
  if (sortedBookmarks[0].pageNumber > 1) {
    ranges.unshift({ start: 1, end: sortedBookmarks[0].pageNumber - 1 });
    labels.unshift('Introduction');
  }

  return { ranges, labels };
}

/**
 * Create a new instance of the split processor
 */
export function createSplitProcessor(): SplitPDFProcessor {
  return new SplitPDFProcessor();
}

/**
 * Split a PDF file (convenience function)
 */
export async function splitPDF(
  file: File,
  options?: Partial<SplitOptions>,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createSplitProcessor();
  return processor.process(
    {
      files: [file],
      options: options || {},
    },
    onProgress
  );
}

/**
 * PDF Table of Contents Processor
 * Uses PyMuPDF worker to generate clickable TOC from PDF bookmarks
 * Supports CJK (Chinese, Japanese, Korean) and other non-ASCII characters
 * Requirements: 5.1
 */

import type { ProcessInput, ProcessOutput, ProgressCallback } from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

export interface TOCOptions {
  title?: string;
  fontSize?: number;
  fontFamily?: string; // Standard PDF font codes (e.g. 'helv', 'tiit', etc.)
  addBookmark?: boolean;
}

export class TableOfContentsProcessor extends BasePDFProcessor {
  private worker: Worker | null = null;

  async process(input: ProcessInput, onProgress?: ProgressCallback): Promise<ProcessOutput> {
    this.reset();
    this.onProgress = onProgress;

    const { files, options } = input;
    const tocOptions = options as TOCOptions;

    if (files.length !== 1) {
      return this.createErrorOutput(PDFErrorCode.INVALID_OPTIONS, 'Exactly 1 PDF file is required.');
    }

    try {
      this.updateProgress(10, 'Loading PDF...');
      const file = files[0];
      const arrayBuffer = await file.arrayBuffer();

      this.updateProgress(30, 'Generating table of contents...');

      const result = await this.generateTOCWithWorker(
        arrayBuffer,
        tocOptions.title || 'Table of Contents',
        tocOptions.fontSize || 12,
        tocOptions.fontFamily ?? 'helv', // Default to Helvetica
        tocOptions.addBookmark ?? true
      );

      console.log('[TOC Processor] Worker returned result:', {
        status: result.status,
        hasPdfBytes: 'pdfBytes' in result,
        pdfBytesType: (result as any).pdfBytes ? (result as any).pdfBytes.constructor.name : 'N/A',
        byteLength: (result as any).pdfBytes ? (result as any).pdfBytes.byteLength : 0
      });

      if (result.status === 'error') {
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_FAILED,
          result.message || 'Failed to generate table of contents.'
        );
      }

      const blobResult = (result as any).pdfBlob;
      const bytesResult = (result as any).pdfBytes;

      let finalBlob: Blob;

      if (blobResult instanceof Blob) {
        finalBlob = blobResult;
      } else if (bytesResult && bytesResult.byteLength > 0) {
        finalBlob = new Blob([new Uint8Array(bytesResult)], { type: 'application/pdf' });
      } else {
        console.error('[TOC Processor] Critical: Received empty data from worker');
        return this.createErrorOutput(
          PDFErrorCode.PROCESSING_FAILED,
          'Internal Error: Generated PDF data was empty.'
        );
      }

      this.updateProgress(90, 'Saving PDF...');
      console.log('[TOC Processor] Final Blob size:', finalBlob.size);

      this.updateProgress(100, 'Complete!');
      return this.createSuccessOutput(finalBlob, file.name.replace('.pdf', '_with_toc.pdf'), {});

    } catch (error) {
      return this.createErrorOutput(
        PDFErrorCode.PROCESSING_FAILED,
        'Failed to generate table of contents.',
        error instanceof Error ? error.message : 'Unknown error'
      );
    } finally {
      this.terminateWorker();
    }
  }

  private generateTOCWithWorker(
    pdfData: ArrayBuffer,
    title: string,
    fontSize: number,
    fontFamily: string,
    addBookmark: boolean
  ): Promise<{ status: 'success'; pdfBytes: ArrayBuffer } | { status: 'error'; message: string }> {
    return new Promise((resolve) => {
      // Use V2 worker to bypass cache and use robust byte handling
      this.worker = new Worker('/workers/table-of-contents-v2.worker.js', { type: 'module' });

      this.worker.onmessage = (e) => {
        const data = e.data;
        // Only resolve on final success or error messages
        // Ignore intermediate status messages like { type: 'status', message: '...' }
        if (data.status === 'success' || data.status === 'error') {
          resolve(data);
        }
        // Intermediate status messages are ignored (they could be used for progress updates)
      };

      this.worker.onerror = (error) => {
        resolve({
          status: 'error',
          message: error.message || 'Worker error occurred',
        });
      };

      this.worker.postMessage(
        {
          command: 'generate-toc',
          pdfData,
          title,
          fontSize,
          fontFamily,
          addBookmark,
        },
        [pdfData]
      );
    });
  }

  private terminateWorker(): void {
    if (this.worker) {
      this.worker.terminate();
      this.worker = null;
    }
  }

  protected getAcceptedTypes(): string[] {
    return ['application/pdf'];
  }
}

export function createTableOfContentsProcessor(): TableOfContentsProcessor {
  return new TableOfContentsProcessor();
}

export async function generateTableOfContents(
  file: File,
  options: TOCOptions,
  onProgress?: ProgressCallback
): Promise<ProcessOutput> {
  const processor = createTableOfContentsProcessor();
  return processor.process({ files: [file], options: options as unknown as Record<string, unknown> }, onProgress);
}

/**
 * Validate Signature Processor
 * Extracts and validates digital signatures from PDFs.
 */
import forge from 'node-forge';
import type { ExtractedSignature, SignatureValidationResult } from '@/types/digital-signature';

/**
 * Extract all signatures from a PDF
 */
export function extractSignatures(pdfBytes: Uint8Array): ExtractedSignature[] {
  const signatures: ExtractedSignature[] = [];
  const pdfString = new TextDecoder('latin1').decode(pdfBytes);

  const sigRegex = /\/Type\s*\/Sig\b/g;
  let sigMatch;
  let sigIndex = 0;

  while ((sigMatch = sigRegex.exec(pdfString)) !== null) {
    try {
      const searchStart = Math.max(0, sigMatch.index - 5000);
      const searchEnd = Math.min(pdfString.length, sigMatch.index + 10000);
      const context = pdfString.substring(searchStart, searchEnd);

      const byteRangeMatch = context.match(/\/ByteRange\s*\[\s*(\d+)\s+(\d+)\s+(\d+)\s+(\d+)\s*\]/);
      if (!byteRangeMatch) continue;

      const byteRange = [
        parseInt(byteRangeMatch[1], 10),
        parseInt(byteRangeMatch[2], 10),
        parseInt(byteRangeMatch[3], 10),
        parseInt(byteRangeMatch[4], 10),
      ];

      const contentsMatch = context.match(/\/Contents\s*<([0-9A-Fa-f]+)>/);
      if (!contentsMatch) continue;

      const contentsBytes = hexToBytes(contentsMatch[1]);
      const reasonMatch = context.match(/\/Reason\s*\(([^)]*)\)/);
      const locationMatch = context.match(/\/Location\s*\(([^)]*)\)/);
      const contactMatch = context.match(/\/ContactInfo\s*\(([^)]*)\)/);
      const nameMatch = context.match(/\/Name\s*\(([^)]*)\)/);
      const timeMatch = context.match(/\/M\s*\(D:(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})(\d{2})/);

      let signingTime: string | undefined;
      if (timeMatch) {
        signingTime = `${timeMatch[1]}-${timeMatch[2]}-${timeMatch[3]}T${timeMatch[4]}:${timeMatch[5]}:${timeMatch[6]}`;
      }

      signatures.push({
        index: sigIndex++,
        contents: contentsBytes,
        byteRange,
        reason: reasonMatch ? reasonMatch[1] : undefined,
        location: locationMatch ? locationMatch[1] : undefined,
        contactInfo: contactMatch ? contactMatch[1] : undefined,
        name: nameMatch ? nameMatch[1] : undefined,
        signingTime,
      });
    } catch {
      // Skip malformed signatures
    }
  }

  return signatures;
}

/**
 * Validate a single signature
 */
export function validateSignature(
  signature: ExtractedSignature,
  pdfBytes: Uint8Array,
  trustedCert?: forge.pki.Certificate
): SignatureValidationResult {
  const result: SignatureValidationResult = {
    signatureIndex: signature.index,
    isValid: false,
    signerName: 'Unknown',
    issuer: 'Unknown',
    validFrom: new Date(0),
    validTo: new Date(0),
    isExpired: false,
    isSelfSigned: false,
    isTrusted: false,
    algorithms: { digest: 'Unknown', signature: 'Unknown' },
    serialNumber: '',
    byteRange: signature.byteRange,
    coverageStatus: 'unknown',
    reason: signature.reason,
    location: signature.location,
    contactInfo: signature.contactInfo,
  };

  try {
    const binaryString = uint8ArrayToBinaryString(signature.contents);
    const asn1 = forge.asn1.fromDer(binaryString);
    const p7 = forge.pkcs7.messageFromAsn1(asn1) as any;

    if (!p7.certificates || p7.certificates.length === 0) {
      result.errorMessage = 'No certificates found in signature';
      return result;
    }

    const signerCert = p7.certificates[0] as forge.pki.Certificate;

    const subjectCN = signerCert.subject.getField('CN');
    const subjectO = signerCert.subject.getField('O');
    const subjectE = signerCert.subject.getField('E') || signerCert.subject.getField('emailAddress');
    const issuerCN = signerCert.issuer.getField('CN');
    const issuerO = signerCert.issuer.getField('O');

    result.signerName = (subjectCN?.value as string) ?? 'Unknown';
    result.signerOrg = subjectO?.value as string | undefined;
    result.signerEmail = subjectE?.value as string | undefined;
    result.issuer = (issuerCN?.value as string) ?? 'Unknown';
    result.issuerOrg = issuerO?.value as string | undefined;
    result.validFrom = signerCert.validity.notBefore;
    result.validTo = signerCert.validity.notAfter;
    result.serialNumber = signerCert.serialNumber;

    const now = new Date();
    result.isExpired = now > result.validTo || now < result.validFrom;
    result.isSelfSigned = signerCert.isIssuer(signerCert);

    if (trustedCert) {
      try {
        const isTrustedIssuer = trustedCert.isIssuer(signerCert);
        const isSameCert = signerCert.serialNumber === trustedCert.serialNumber;
        let chainTrusted = false;
        for (const cert of p7.certificates) {
          if (trustedCert.isIssuer(cert) || (cert as forge.pki.Certificate).serialNumber === trustedCert.serialNumber) {
            chainTrusted = true;
            break;
          }
        }
        result.isTrusted = isTrustedIssuer || isSameCert || chainTrusted;
      } catch {
        result.isTrusted = false;
      }
    }

    result.algorithms = {
      digest: getDigestAlgorithmName(signerCert.siginfo?.algorithmOid || ''),
      signature: getSignatureAlgorithmName(signerCert.signatureOid || ''),
    };

    if (signature.signingTime) {
      result.signatureDate = new Date(signature.signingTime);
    }

    if (signature.byteRange && signature.byteRange.length === 4) {
      const [, len1, start2, len2] = signature.byteRange;
      const totalEnd = start2 + len2;
      if (totalEnd === pdfBytes.length) {
        result.coverageStatus = 'full';
      } else if (totalEnd < pdfBytes.length) {
        result.coverageStatus = 'partial';
      }
    }

    result.isValid = true;
  } catch (e) {
    result.errorMessage = e instanceof Error ? e.message : 'Failed to parse signature';
  }

  return result;
}

/**
 * Validate all signatures in a PDF
 */
export async function validatePdfSignatures(
  pdfBytes: Uint8Array,
  trustedCert?: forge.pki.Certificate
): Promise<SignatureValidationResult[]> {
  const signatures = extractSignatures(pdfBytes);
  return signatures.map(sig => validateSignature(sig, pdfBytes, trustedCert));
}

/**
 * Convert Uint8Array to binary string without stack overflow
 */
function uint8ArrayToBinaryString(bytes: Uint8Array): string {
  const CHUNK_SIZE = 8192;
  let result = '';
  for (let i = 0; i < bytes.length; i += CHUNK_SIZE) {
    const chunk = bytes.subarray(i, Math.min(i + CHUNK_SIZE, bytes.length));
    result += String.fromCharCode.apply(null, Array.from(chunk));
  }
  return result;
}

function hexToBytes(hex: string): Uint8Array {
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
  }
  let actualLength = bytes.length;
  while (actualLength > 0 && bytes[actualLength - 1] === 0) {
    actualLength--;
  }
  return bytes.slice(0, actualLength);
}

const DIGEST_ALGORITHMS: Record<string, string> = {
  '1.2.840.113549.2.5': 'MD5',
  '1.3.14.3.2.26': 'SHA-1',
  '2.16.840.1.101.3.4.2.1': 'SHA-256',
  '2.16.840.1.101.3.4.2.2': 'SHA-384',
  '2.16.840.1.101.3.4.2.3': 'SHA-512',
};

const SIGNATURE_ALGORITHMS: Record<string, string> = {
  '1.2.840.113549.1.1.1': 'RSA',
  '1.2.840.113549.1.1.5': 'RSA with SHA-1',
  '1.2.840.113549.1.1.11': 'RSA with SHA-256',
  '1.2.840.113549.1.1.12': 'RSA with SHA-384',
  '1.2.840.113549.1.1.13': 'RSA with SHA-512',
  '1.2.840.10045.2.1': 'ECDSA',
  '1.2.840.10045.4.3.2': 'ECDSA with SHA-256',
  '1.2.840.10045.4.3.3': 'ECDSA with SHA-384',
  '1.2.840.10045.4.3.4': 'ECDSA with SHA-512',
};

function getDigestAlgorithmName(oid: string): string {
  return DIGEST_ALGORITHMS[oid] || oid || 'Unknown';
}

function getSignatureAlgorithmName(oid: string): string {
  return SIGNATURE_ALGORITHMS[oid] || oid || 'Unknown';
}

/**
 * Word to PDF Processor
 * 
 * Converts Word documents to PDF using LibreOffice WASM.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/** Maximum file size: 50 MB */
const MAX_FILE_SIZE = 50 * 1024 * 1024;
/** Conversion timeout: 5 minutes */
const CONVERT_TIMEOUT_MS = 5 * 60 * 1000;

export interface WordToPDFOptions {
    /** Reserved for future options */
}

let converterPromise: Promise<any> | null = null;
let converterInstance: any = null;

async function getConverter(onProgress?: (percent: number, message: string) => void): Promise<any> {
    if (converterInstance?.isReady()) return converterInstance;

    if (converterPromise) {
        await converterPromise;
        return converterInstance;
    }

    converterPromise = (async () => {
        const { getLibreOfficeConverter } = await import('@/lib/libreoffice');
        converterInstance = getLibreOfficeConverter();
        await converterInstance.initialize((progress: any) => {
            onProgress?.(progress.percent, progress.message);
        });
    })();

    await converterPromise;
    return converterInstance;
}

export class WordToPDFProcessor extends BasePDFProcessor {
    private conversionProgressTimer: ReturnType<typeof setInterval> | null = null;

    private startConversionProgress(message: string): void {
        this.stopConversionProgress();
        // LibreOffice convert() does not expose granular runtime progress.
        // Keep UI responsive by advancing a bounded pseudo-progress while waiting.
        this.conversionProgressTimer = setInterval(() => {
            if (this.progress >= 98) return;
            this.updateProgress(this.progress + 1, message);
        }, 800);
    }

    private stopConversionProgress(): void {
        if (this.conversionProgressTimer) {
            clearInterval(this.conversionProgressTimer);
            this.conversionProgressTimer = null;
        }
    }

    protected reset(): void {
        this.stopConversionProgress();
        super.reset();
    }

    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one Word document.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];
        const ext = file.name.split('.').pop()?.toLowerCase() || '';
        const validExts = ['docx', 'doc', 'odt', 'rtf'];

        if (!validExts.includes(ext)) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload .docx, .doc, .odt, or .rtf.',
                `Received: ${file.type || file.name}`
            );
        }

        // File size guard
        if (file.size > MAX_FILE_SIZE) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                `File is too large (${(file.size / 1024 / 1024).toFixed(1)} MB). Maximum supported size is ${MAX_FILE_SIZE / 1024 / 1024} MB.`,
                `File size: ${file.size} bytes, limit: ${MAX_FILE_SIZE} bytes`
            );
        }

        try {
            this.updateProgress(5, 'Loading conversion engine (first time may take 1-2 minutes)...');

            const converter = await getConverter((percent, message) => {
                this.updateProgress(Math.min(percent * 0.8, 80), message);
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(85, 'Converting Word document to PDF...');
            this.startConversionProgress('Converting Word document to PDF...');

            // Convert with timeout protection
            const pdfBlob = await Promise.race([
                converter.convertToPdf(file),
                new Promise<never>((_, reject) =>
                    setTimeout(() => reject(new Error(
                        `Conversion timed out after ${CONVERT_TIMEOUT_MS / 60000} minutes. The file may be too complex.`
                    )), CONVERT_TIMEOUT_MS)
                ),
            ]);
            this.stopConversionProgress();

            if (this.checkCancelled()) {
                return this.createErrorOutput(PDFErrorCode.PROCESSING_CANCELLED, 'Processing was cancelled.');
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.(docx?|odt|rtf)$/i, '');
            return this.createSuccessOutput(pdfBlob, `${baseName}.pdf`, { format: 'pdf' });

        } catch (error) {
            this.stopConversionProgress();
            console.error('Conversion error:', error);
            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert Word document to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

export function createWordToPDFProcessor(): WordToPDFProcessor {
    return new WordToPDFProcessor();
}

export async function wordToPDF(
    file: File,
    options?: Partial<WordToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createWordToPDFProcessor();
    return processor.process({ files: [file], options: options || {} }, onProgress);
}

/**
 * XPS to PDF Processor
 * 
 * Converts XPS files to PDF documents.
 * Uses Pyodide via a Web Worker with PyMuPDF's native XPS support.
 */

import type {
    ProcessInput,
    ProcessOutput,
    ProgressCallback,
} from '@/types/pdf';
import { PDFErrorCode } from '@/types/pdf';
import { BasePDFProcessor } from '../processor';

/**
 * XPS to PDF options
 */
export interface XPSToPDFOptions {
    /** Reserved for future options */
}

/**
 * XPS to PDF Processor
 * Converts XPS files to PDF using a Web Worker.
 */
export class XPSToPDFProcessor extends BasePDFProcessor {
    private worker: Worker | null = null;
    private workerReady = false;

    /**
     * Initialize the worker
     */
    private async initWorker(): Promise<void> {
        if (this.worker) return;

        return new Promise((resolve, reject) => {
            try {
                this.worker = new Worker('/workers/xps-to-pdf.worker.js', { type: 'module' });

                const handleMessage = (event: MessageEvent) => {
                    const { type, error, message } = event.data;

                    if (type === 'init-complete') {
                        this.workerReady = true;
                        resolve();
                    } else if (type === 'status') {
                        this.updateProgress(0, message);
                    } else if (type === 'error') {
                        reject(new Error(error || 'Worker initialization failed'));
                    }
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', (err) => {
                    reject(new Error('Worker connection failed'));
                });

                // Send init message
                this.worker.postMessage({
                    type: 'init',
                    id: 'init-' + Date.now(),
                    data: {}
                });

            } catch (err) {
                reject(err);
            }
        });
    }

    /**
     * Terminate the worker
     */
    private terminateWorker() {
        if (this.worker) {
            this.worker.terminate();
            this.worker = null;
            this.workerReady = false;
        }
    }

    /**
     * Reset processor state
     */
    protected reset(): void {
        super.reset();
    }

    /**
     * Process XPS and convert to PDF
     */
    async process(
        input: ProcessInput,
        onProgress?: ProgressCallback
    ): Promise<ProcessOutput> {
        this.reset();
        this.onProgress = onProgress;

        const { files } = input;

        // Validate we have exactly 1 XPS file
        if (files.length !== 1) {
            return this.createErrorOutput(
                PDFErrorCode.INVALID_OPTIONS,
                'Please provide exactly one XPS file.',
                `Received ${files.length} file(s).`
            );
        }

        const file = files[0];

        // Validate file type
        if (!file.name.toLowerCase().endsWith('.xps')) {
            return this.createErrorOutput(
                PDFErrorCode.FILE_TYPE_INVALID,
                'Invalid file type. Please upload an XPS file.',
                `Received: ${file.type || file.name}`
            );
        }

        try {
            this.updateProgress(10, 'Initializing converter...');

            try {
                await this.initWorker();
            } catch (err) {
                console.error('Failed to initialize worker:', err);
                return this.createErrorOutput(
                    PDFErrorCode.WORKER_FAILED,
                    'Failed to initialize conversion worker.',
                    err instanceof Error ? err.message : String(err)
                );
            }

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(30, 'Converting XPS to PDF...');

            // Process conversion via worker
            const pdfBlob = await new Promise<Blob>((resolve, reject) => {
                if (!this.worker) {
                    reject(new Error('Worker not initialized'));
                    return;
                }

                const msgId = 'convert-' + Date.now();

                const handleMessage = (event: MessageEvent) => {
                    const { type, id, result, error, message } = event.data;

                    if (type === 'status') {
                        this.updateProgress(this.progress, message);
                        return;
                    }

                    if (id !== msgId) return;

                    if (type === 'convert-complete') {
                        cleanup();
                        resolve(result);
                    } else if (type === 'error') {
                        cleanup();
                        reject(new Error(error || 'Conversion failed'));
                    }
                };

                const handleError = (error: ErrorEvent) => {
                    cleanup();
                    reject(new Error('Worker error: ' + error.message));
                };

                const cleanup = () => {
                    this.worker?.removeEventListener('message', handleMessage);
                    this.worker?.removeEventListener('error', handleError);
                };

                this.worker.addEventListener('message', handleMessage);
                this.worker.addEventListener('error', handleError);

                this.worker.postMessage({
                    type: 'convert',
                    id: msgId,
                    data: {
                        file: file
                    }
                });
            });

            if (this.checkCancelled()) {
                return this.createErrorOutput(
                    PDFErrorCode.PROCESSING_CANCELLED,
                    'Processing was cancelled.'
                );
            }

            this.updateProgress(100, 'Conversion complete!');

            const baseName = file.name.replace(/\.xps$/i, '');
            const outputName = `${baseName}.pdf`;

            return this.createSuccessOutput(
                pdfBlob,
                outputName,
                { format: 'pdf' }
            );

        } catch (error) {
            console.error('Conversion error:', error);
            this.terminateWorker();

            return this.createErrorOutput(
                PDFErrorCode.PROCESSING_FAILED,
                'Failed to convert XPS to PDF.',
                error instanceof Error ? error.message : 'Unknown error'
            );
        }
    }
}

/**
 * Create a new instance of the XPS to PDF processor
 */
export function createXPSToPDFProcessor(): XPSToPDFProcessor {
    return new XPSToPDFProcessor();
}

/**
 * Convert XPS to PDF (convenience function)
 */
export async function xpsToPDF(
    file: File,
    options?: Partial<XPSToPDFOptions>,
    onProgress?: ProgressCallback
): Promise<ProcessOutput> {
    const processor = createXPSToPDFProcessor();
    return processor.process(
        {
            files: [file],
            options: options || {},
        },
        onProgress
    );
}

/**
 * PyMuPDF Loader
 * Dynamically loads PyMuPDF WASM module using ES module import
 */

// Singleton instance
let pymupdfInstance: any = null;
let loadingPromise: Promise<any> | null = null;

function resolvePublicAssetPath(assetPath: string): string {
  if (typeof window === 'undefined') return assetPath;

  const normalizedAssetPath = assetPath.startsWith('/') ? assetPath : `/${assetPath}`;
  const scripts = Array.from(document.querySelectorAll('script[src]')) as HTMLScriptElement[];
  const nextScript = scripts.find((script) => script.src.includes('/_next/'));

  if (!nextScript) return normalizedAssetPath;

  try {
    const scriptUrl = new URL(nextScript.src);
    const nextIndex = scriptUrl.pathname.indexOf('/_next/');
    if (nextIndex <= 0) return normalizedAssetPath;

    const basePath = scriptUrl.pathname.slice(0, nextIndex).replace(/\/$/, '');
    return `${basePath}${normalizedAssetPath}`;
  } catch {
    return normalizedAssetPath;
  }
}

/**
 * Load PyMuPDF using Pyodide directly
 */
export async function loadPyMuPDF(): Promise<any> {
  if (pymupdfInstance) {
    return pymupdfInstance;
  }

  if (loadingPromise) {
    return loadingPromise;
  }

  loadingPromise = (async () => {
    try {
      const basePath = new URL(
        resolvePublicAssetPath('/pymupdf-wasm/'),
        window.location.origin
      ).toString();

      // Dynamically import Pyodide as ES module
      const pyodideModule = await import(/* webpackIgnore: true */ `${basePath}pyodide.js`);
      const loadPyodide = pyodideModule.loadPyodide;

      // Initialize Pyodide
      const pyodide = await loadPyodide({
        indexURL: basePath,
        fullStdLib: false
      });

      // Helper function to load local wheels (same as pdf-to-docx.worker.js)
      const loadWheel = async (url: string) => {
        await pyodide.loadPackage(url);
      };

      // Mock missing non-critical dependencies (same as pdf-to-docx.worker.js)
      pyodide.runPython(`
import sys
from types import ModuleType

# Mock tqdm (used for progress bars)
tqdm_mod = ModuleType("tqdm")
def tqdm(iterable=None, *args, **kwargs):
    return iterable if iterable else []
tqdm_mod.tqdm = tqdm
sys.modules["tqdm"] = tqdm_mod

# Mock fire (CLI tool, not needed for library usage)
fire_mod = ModuleType("fire")
sys.modules["fire"] = fire_mod
      `);

      // Install dependencies in order (same as pdf-to-docx.worker.js)
      await loadWheel(`${basePath}numpy-2.2.5-cp313-cp313-pyodide_2025_0_wasm32.whl`);
      await loadWheel(`${basePath}typing_extensions-4.12.2-py3-none-any.whl`);
      await loadWheel(`${basePath}packaging-24.1-py3-none-any.whl`);
      await loadWheel(`${basePath}fonttools-4.56.0-py3-none-any.whl`);
      await loadWheel(`${basePath}lxml-5.4.0-cp313-cp313-pyodide_2025_0_wasm32.whl`);
      await loadWheel(`${basePath}pymupdf-1.26.3-cp313-none-pyodide_2025_0_wasm32.whl`);

      // Import pymupdf
      await pyodide.runPythonAsync('import pymupdf');

      // Create a wrapper object with pdfToDocx method
      pymupdfInstance = {
        pyodide,
        async pdfToDocx(file: File): Promise<Blob> {
          const arrayBuffer = await file.arrayBuffer();
          const pdfData = new Uint8Array(arrayBuffer);

          // Write PDF to virtual filesystem
          pyodide.FS.writeFile('/input.pdf', pdfData);

          // Convert using pdf2docx
          const result = await pyodide.runPythonAsync(`
import base64
from pdf2docx import Converter

cv = Converter('/input.pdf')
cv.convert('/output.docx')
cv.close()

with open('/output.docx', 'rb') as f:
    docx_data = f.read()

base64.b64encode(docx_data).decode('ascii')
`);

          // Clean up
          try {
            pyodide.FS.unlink('/input.pdf');
            pyodide.FS.unlink('/output.docx');
          } catch {
            // Ignore cleanup errors
          }

          // Convert base64 to Blob
          const binary = atob(result);
          const bytes = new Uint8Array(binary.length);
          for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
          }

          return new Blob([bytes], {
            type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
          });
        },

        async pdfToPdfa(file: File, options: any): Promise<{ pdf: Blob }> {
          const arrayBuffer = await file.arrayBuffer();
          const pdfData = new Uint8Array(arrayBuffer);
          // Options are available for future use (level, embedFonts, flattenTransparency)
          const _options = options;

          // Use unique file names to avoid race conditions during concurrent processing
          const uid = `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
          const inputPath = `/input_pdfa_${uid}.pdf`;
          const outputPath = `/output_pdfa_${uid}.pdf`;

          pyodide.FS.writeFile(inputPath, pdfData);

          const result = await pyodide.runPythonAsync(`
import pymupdf
import base64

doc = pymupdf.open("${inputPath}")

# Attempt to make it PDF/A compliant (Best Effort)
# In a real scenario, we would need to attach an ICC profile and valid OutputIntent.

# Ensure all fonts are embedded and subsetted if possible
# garbage=4 will remove unused objects and deduplicate
save_options = {
    "garbage": 4,
    "deflate": True,
}

doc.save("${outputPath}", **save_options)
doc.close()

with open("${outputPath}", "rb") as f:
    pdf_data = f.read()

base64.b64encode(pdf_data).decode('ascii')
`);

          try {
            pyodide.FS.unlink(inputPath);
            pyodide.FS.unlink(outputPath);
          } catch {
            // Ignore cleanup errors
          }

          const binary = atob(result);
          const bytes = new Uint8Array(binary.length);
          for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
          }

          return {
            pdf: new Blob([bytes], { type: 'application/pdf' })
          };
        },

        async htmlToPdf(html: string, options: any): Promise<Blob> {
          const { pageSize = 'a4', margins = { top: 50, right: 50, bottom: 50, left: 50 }, attachments = [] } = options || {};

          // Page dimensions in points (72 points per inch)
          const pageSizes: Record<string, [number, number]> = {
            'a4': [595, 842],
            'letter': [612, 792],
            'legal': [612, 1008],
          };
          const [width, height] = pageSizes[pageSize] || pageSizes['a4'];

          // Write HTML to virtual filesystem
          const encoder = new TextEncoder();
          const htmlBytes = encoder.encode(html);
          pyodide.FS.writeFile('/input.html', htmlBytes);

          // Write attachments to virtual filesystem
          for (let i = 0; i < attachments.length; i++) {
            const att = attachments[i];
            if (att.content) {
              const attData = new Uint8Array(att.content);
              pyodide.FS.writeFile(`/attachment_${i}`, attData);
            }
          }

          // Build attachments info for Python
          const attachmentsJson = JSON.stringify(attachments.map((att: any, idx: number) => ({
            filename: att.filename,
            contentType: att.contentType,
            path: `/attachment_${idx}`,
            hasContent: !!att.content
          })));

          const result = await pyodide.runPythonAsync(`
import pymupdf
import base64
import json

# Read HTML
with open('/input.html', 'r', encoding='utf-8') as f:
    html_content = f.read()

# Margins
margin_left = ${margins.left}
margin_top = ${margins.top}
margin_right = ${margins.right}
margin_bottom = ${margins.bottom}
page_width = ${width}
page_height = ${height}

# Create PDF document
doc = pymupdf.open()

try:
    # Try using Story API (available in newer PyMuPDF versions)
    rect = pymupdf.Rect(margin_left, margin_top, page_width - margin_right, page_height - margin_bottom)
    story = pymupdf.Story(html=html_content)

