          const binary = atob(result);
          const bytes = new Uint8Array(binary.length);
          for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
          }

          return new Blob([bytes], { type: 'application/pdf' });
        },

        async photonCompress(file: File, options: any): Promise<Blob> {
          const arrayBuffer = await file.arrayBuffer();
          const pdfData = new Uint8Array(arrayBuffer);
          const { dpi = 150, format = 'jpeg', quality = 85 } = options || {};

          pyodide.FS.writeFile('/input.pdf', pdfData);

          const result = await pyodide.runPythonAsync(`
import pymupdf
import base64

doc = pymupdf.open("/input.pdf")

# Create a new document
new_doc = pymupdf.open()

target_dpi = ${dpi}
jpeg_quality = ${quality}

# Process each page - render to image and create new PDF
for page_num in range(len(doc)):
    page = doc[page_num]

    # Get page dimensions
    rect = page.rect

    # Calculate zoom factor for target DPI (72 is base PDF DPI)
    zoom = target_dpi / 72
    mat = pymupdf.Matrix(zoom, zoom)

    # Render page to pixmap
    pix = page.get_pixmap(matrix=mat, alpha=False)

    # Convert to JPEG bytes
    img_bytes = pix.tobytes(output="jpeg", jpg_quality=jpeg_quality)

    # Create new page with same dimensions
    new_page = new_doc.new_page(width=rect.width, height=rect.height)

    # Insert the rendered image
    new_page.insert_image(new_page.rect, stream=img_bytes)

# Save compressed document
pdf_bytes = new_doc.tobytes(garbage=4, deflate=True)

doc.close()
new_doc.close()

base64.b64encode(pdf_bytes).decode('ascii')
`);

          try {
            pyodide.FS.unlink('/input.pdf');
          } catch {
            // Ignore cleanup errors
          }

          const binary = atob(result);
          const bytes = new Uint8Array(binary.length);
          for (let i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
          }

          return new Blob([bytes], { type: 'application/pdf' });
        },
      };

      return pymupdfInstance;
    } catch (error) {
      loadingPromise = null;
      throw error;
    }
  })();

  return loadingPromise;
}

/**
 * Reset the loader (for testing)
 */
export function resetPyMuPDF(): void {
  pymupdfInstance = null;
  loadingPromise = null;
}

/**
 * QPDF WASM Loader
 * 
 * Dynamically loads qpdf-wasm in browser environment.
 * Uses script injection to avoid Next.js SSR bundling issues.
 */

// QPDF instance singleton
let qpdfInstance: any = null;
let loadingPromise: Promise<any> | null = null;

/**
 * Load the QPDF WASM module dynamically
 */
export async function loadQpdf(): Promise<any> {
  // Return cached instance if available
  if (qpdfInstance) {
    return qpdfInstance;
  }

  // Return existing loading promise if already loading
  if (loadingPromise) {
    return loadingPromise;
  }

  // Only run in browser environment
  if (typeof window === 'undefined') {
    throw new Error('QPDF can only be initialized in browser environment');
  }

  loadingPromise = new Promise(async (resolve, reject) => {
    try {
      // Check if createModule is already available (script already loaded)
      if ((window as any).createQpdfModule) {
        qpdfInstance = await (window as any).createQpdfModule({
          locateFile: (path: string) => {
            if (path.endsWith('.wasm')) {
              return '/qpdf.wasm';
            }
            return path;
          },
        });
        resolve(qpdfInstance);
        return;
      }

      // Load the script dynamically
      const script = document.createElement('script');
      script.src = '/qpdf.js';
      script.async = true;

      script.onload = async () => {
        try {
          // The script should expose createModule or similar
          const createModule = (window as any).createQpdfModule || (window as any).Module;

          if (!createModule) {
            throw new Error('QPDF module not found after script load');
          }

          qpdfInstance = await createModule({
            locateFile: (path: string) => {
              if (path.endsWith('.wasm')) {
                return '/qpdf.wasm';
              }
              return path;
            },
          });

          resolve(qpdfInstance);
        } catch (err) {
          reject(err);
        }
      };

      script.onerror = () => {
        reject(new Error('Failed to load QPDF script'));
      };

      document.head.appendChild(script);
    } catch (err) {
      reject(err);
    }
  });

  return loadingPromise;
}

/**
 * Check if QPDF is available
 */
export function isQpdfAvailable(): boolean {
  return qpdfInstance !== null;
}

/**
 * Reset QPDF instance (for testing)
 */
export function resetQpdf(): void {
  qpdfInstance = null;
  loadingPromise = null;
}

import prisma from '@/lib/prisma';
import { auth } from '@clerk/nextjs/server';
import { TIERS, isValidTier } from '@/lib/pricing';

export type UsageType = 'KRA' | 'PDF';

function getTierLimit(tier: string | null | undefined): number {
  if (!tier || !isValidTier(tier)) return 0;
  return TIERS[tier].filings;
}

export async function checkUsageLimit(type: UsageType): Promise<{
  allowed: boolean;
  count: number;
  remaining: number;
  isPremium: boolean;
  tier: string;
  filingLimit: number;
  timeExpired: boolean;
  subscriptionEnd: string | null;
}> {
  const { userId: clerkId } = await auth();

  // Return unlimited even if no user, but try to find user for metadata
  const dbUser = clerkId ? await prisma.user.findUnique({
    where: { clerkId },
    select: {
      subscriptionTier: true,
      subscriptionEnd: true,
    },
  }) : null;

  return {
    allowed: true, // Always allowed
    count: 0,
    remaining: 999999, // Unlimited
    isPremium: true,
    tier: dbUser?.subscriptionTier || 'unlimited',
    filingLimit: 999999,
    timeExpired: false,
    subscriptionEnd: dbUser?.subscriptionEnd?.toISOString() ?? null,
  };
}

export async function incrementUsage(type: UsageType): Promise<void> {
  const { userId: clerkId } = await auth();
  if (!clerkId) return;

  const dbUser = await prisma.user.findUnique({
    where: { clerkId },
    select: { id: true },
  });
  if (!dbUser) return;

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  await prisma.usageLimit.upsert({
    where: {
      userId_type_date: {
        userId: dbUser.id,
        type,
        date: today,
      },
    },
    create: {
      userId: dbUser.id,
      type,
      date: today,
      count: 1,
    },
    update: {
      count: {
        increment: 1,
      },
    },
  });
}

/**
 * File Validation Utilities
 * Requirements: 5.1
 * 
 * Provides validation functions for files before PDF processing.
 */

import type { ValidationResult, PDFError } from '@/types/pdf';
import {
  PDFErrorCode,
  ErrorCategory,
  ERROR_CODE_CATEGORY,
  PDF_MAGIC_BYTES,
  FILE_SIZE_LIMITS,
  SUPPORTED_FILE_TYPES,
} from '@/types/pdf';

/**
 * File validation options
 */
export interface FileValidationOptions {
  maxSize?: number;
  acceptedTypes?: string[];
  requirePdf?: boolean;
}

/**
 * Default validation options
 */
const DEFAULT_OPTIONS: FileValidationOptions = {
  maxSize: FILE_SIZE_LIMITS.DEFAULT_MAX_SIZE,
  acceptedTypes: [...SUPPORTED_FILE_TYPES.PDF],
  requirePdf: true,
};

/**
 * Validate a file against specified criteria
 */
export function validateFile(
  file: File,
  options: FileValidationOptions = {}
): ValidationResult {
  const opts = { ...DEFAULT_OPTIONS, ...options };
  const errors: PDFError[] = [];

  // Check if file exists and has content
  if (!file || file.size === 0) {
    errors.push(createValidationError(
      PDFErrorCode.FILE_EMPTY,
      'The file is empty or could not be read.'
    ));
    return { valid: false, errors };
  }

  // Check file size (skip if no limit)
  if (opts.maxSize && opts.maxSize !== Infinity && file.size > opts.maxSize) {
    const maxSizeMB = Math.round(opts.maxSize / (1024 * 1024));
    errors.push(createValidationError(
      PDFErrorCode.FILE_TOO_LARGE,
      `File size exceeds the maximum limit of ${maxSizeMB}MB.`,
      `File size: ${formatFileSize(file.size)}, Maximum: ${maxSizeMB}MB`
    ));
  }

  // Check file type
  if (opts.acceptedTypes && opts.acceptedTypes.length > 0) {
    const isAcceptedType = opts.acceptedTypes.includes(file.type) ||
      opts.acceptedTypes.some(type => {
        // Handle wildcard types like 'image/*'
        if (type.endsWith('/*')) {
          const baseType = type.slice(0, -2);
          return file.type.startsWith(baseType);
        }
        return false;
      });

    // Also check by file extension for PDF files
    const isPdfByExtension = file.name.toLowerCase().endsWith('.pdf');
    const acceptsPdf = opts.acceptedTypes.includes('application/pdf');

    if (!isAcceptedType && !(acceptsPdf && isPdfByExtension)) {
      errors.push(createValidationError(
        PDFErrorCode.FILE_TYPE_INVALID,
        `Invalid file type. Expected: ${opts.acceptedTypes.join(', ')}`,
        `Received: ${file.type || 'unknown'}`
      ));
    }
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

/**
 * Validate PDF file structure by checking magic bytes
 */
export async function validatePdfStructure(file: File): Promise<ValidationResult> {
  const errors: PDFError[] = [];

  try {
    // Read the first few bytes to check PDF magic bytes
    const headerBytes = await readFileHeader(file, 8);

    if (!isPdfHeader(headerBytes)) {
      errors.push(createValidationError(
        PDFErrorCode.FILE_NOT_PDF,
        'The file does not appear to be a valid PDF.',
        'PDF files must start with %PDF-'
      ));
      return { valid: false, errors };
    }

    // Check for PDF version
    const version = extractPdfVersion(headerBytes);
    if (!version) {
      errors.push(createValidationError(
        PDFErrorCode.PDF_MALFORMED,
        'Could not determine PDF version.',
        'The PDF header may be corrupted.'
      ));
    }

    // Check for EOF marker (basic structure validation)
    const hasEof = await checkPdfEofMarker(file);
    if (!hasEof) {
      errors.push(createValidationError(
        PDFErrorCode.PDF_MALFORMED,
        'PDF file appears to be incomplete or corrupted.',
        'Missing EOF marker.'
      ));
    }

  } catch (error) {
    errors.push(createValidationError(
      PDFErrorCode.FILE_CORRUPTED,
      'Could not read the file.',
      error instanceof Error ? error.message : 'Unknown error'
    ));
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

/**
 * Check if a PDF is encrypted
 */
export async function checkPdfEncryption(file: File): Promise<boolean> {
  try {
    const content = await readFileAsText(file, 0, 4096);
    // Look for /Encrypt dictionary in the PDF
    return content.includes('/Encrypt');
  } catch {
    return false;
  }
}

/**
 * Read the first n bytes of a file
 */
async function readFileHeader(file: File, bytes: number): Promise<Uint8Array> {
  const slice = file.slice(0, bytes);
  const buffer = await slice.arrayBuffer();
  return new Uint8Array(buffer);
}

/**
 * Read file content as text
 */
async function readFileAsText(file: File, start: number, end: number): Promise<string> {
  const slice = file.slice(start, end);
  return slice.text();
}

/**
 * Check if bytes match PDF magic bytes (%PDF-)
 */
function isPdfHeader(bytes: Uint8Array): boolean {
  if (bytes.length < 5) return false;

  // Check for %PDF-
  return bytes[0] === 0x25 && // %
    bytes[1] === 0x50 && // P
    bytes[2] === 0x44 && // D
    bytes[3] === 0x46 && // F
    bytes[4] === 0x2D;   // -
}

/**
 * Extract PDF version from header bytes
 */
function extractPdfVersion(bytes: Uint8Array): string | null {
  if (bytes.length < 8) return null;

  // Convert bytes 5-7 to string (version number like "1.7")
  const versionBytes = bytes.slice(5, 8);
  const version = String.fromCharCode(...versionBytes).trim();

  // Validate version format (e.g., "1.7", "2.0")
  if (/^\d\.\d/.test(version)) {
    return version;
  }

  return null;
}

/**
 * Check for PDF EOF marker
 */
async function checkPdfEofMarker(file: File): Promise<boolean> {
  try {
    // Read the last 1024 bytes
    const tailSize = Math.min(1024, file.size);
    const tail = await readFileAsText(file, file.size - tailSize, file.size);

    // Look for %%EOF marker
    return tail.includes('%%EOF');
  } catch {
    return false;
  }
}

/**
 * Create a validation error
 */
function createValidationError(
  code: PDFErrorCode,
  message: string,
  details?: string
): PDFError {
  return {
    code,
    category: ERROR_CODE_CATEGORY[code] || ErrorCategory.VALIDATION_ERROR,
    message,
    details,
    recoverable: code !== PDFErrorCode.FILE_CORRUPTED,
  };
}

/**
 * Format file size for display
 */
export function formatFileSize(bytes: number): string {
  if (bytes === 0) return '0 Bytes';

  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
}

/**
 * Get file extension from filename
 */
export function getFileExtension(filename: string): string {
  const lastDot = filename.lastIndexOf('.');
  if (lastDot === -1) return '';
  return filename.slice(lastDot + 1).toLowerCase();
}

/**
 * Check if file is a PDF by extension
 */
export function isPdfFile(file: File): boolean {
  return file.type === 'application/pdf' ||
    file.name.toLowerCase().endsWith('.pdf');
}

/**
 * Check if file is an image
 */
export function isImageFile(file: File): boolean {
  return SUPPORTED_FILE_TYPES.IMAGES.some(type =>
    file.type === type || file.type.startsWith('image/')
  );
}

import { neonConfig, Pool } from '@neondatabase/serverless'
import { PrismaNeon } from '@prisma/adapter-neon'
import { PrismaClient } from '@prisma/client'
import ws from 'ws'

// Configure Neon to use the ws package for WebSockets
neonConfig.webSocketConstructor = ws

const prismaClientSingleton = () => {
  // Use the database URL exactly as provided in .env
  const connectionString = (process.env.DATABASE_URL || '').replace(/^["']|["']$/g, '');

  // If no connection string is provided (common during build time), 
  // return a standard client without the Neon adapter to avoid hangs.
  if (!connectionString) {
    return new PrismaClient();
  }

  const pool = new Pool({ connectionString });
  const adapter = new PrismaNeon(pool as any);
  return new PrismaClient({ adapter });
}

declare const globalThis: {
  prismaGlobal: ReturnType<typeof prismaClientSingleton>;
} & typeof global;

const prisma = globalThis.prismaGlobal ?? prismaClientSingleton()

export default prisma

if (process.env.NODE_ENV !== 'production') globalThis.prismaGlobal = prisma

/**
 * SEO Metadata Generation Utilities
 * Provides functions for generating meta tags, Open Graph, and Twitter Card data
 * 
 * @module lib/seo/metadata
 */

import type { Metadata } from 'next';
import { siteConfig } from '@/config/site';
import { type Locale, localeConfig, locales } from '@/lib/i18n/config';
import type { Tool, ToolContent } from '@/types/tool';

/**
 * Base metadata configuration
 */
export interface BaseMetadataOptions {
  locale: Locale;
  path?: string;
}

/**
 * Page-specific metadata options
 */
export interface PageMetadataOptions extends BaseMetadataOptions {
  title: string;
  description: string;
  keywords?: string[];
  image?: string;
  noIndex?: boolean;
}

/**
 * Tool page metadata options
 */
export interface ToolMetadataOptions extends BaseMetadataOptions {
  tool: Tool;
  content: ToolContent;
}

/**
 * Generate the canonical URL for a page
 */
export function getCanonicalUrl(locale: Locale, path: string = ''): string {
  const cleanPath = path.startsWith('/') ? path : `/${path}`;
  return `${siteConfig.url}/${locale}${cleanPath}`;
}

/**
 * Generate alternate language URLs for hreflang tags
 */
export function getAlternateUrls(path: string = ''): Record<string, string> {
  const cleanPath = path.startsWith('/') ? path : `/${path}`;
  const alternates: Record<string, string> = {};

  for (const locale of locales) {
    alternates[locale] = `${siteConfig.url}/${locale}${cleanPath}`;
  }

  // Add x-default pointing to English
  alternates['x-default'] = `${siteConfig.url}/en${cleanPath}`;

  return alternates;
}

/**
 * Generate base metadata for any page
 */
export function generateBaseMetadata(options: PageMetadataOptions): Metadata {
  const { locale, path = '', title, description, keywords = [], image, noIndex = false } = options;

  const fullTitle = title.includes(siteConfig.name)
    ? title
    : `${title} | ${siteConfig.name}`;

  const canonicalUrl = getCanonicalUrl(locale, path);
  const ogImage = image || siteConfig.ogImage;
  const ogLocale = getOpenGraphLocale(locale);

  // Ensure description is optimal length (150-160 characters)
  const optimizedDescription = description.length > 160
    ? description.substring(0, 157) + '...'
    : description;

  return {
    title: fullTitle,
    description: optimizedDescription,
    keywords: [...new Set([...keywords, 'PDF', 'PDF tools', 'free', 'online', siteConfig.name])],
    authors: [{ name: siteConfig.creator }],
    creator: siteConfig.creator,
    publisher: siteConfig.name,
    robots: noIndex
      ? { index: false, follow: false }
      : {
        index: true,
        follow: true,
        'max-snippet': -1,
        'max-image-preview': 'large',
        'max-video-preview': -1,
      },
    icons: {
      icon: '/favicon.svg',
      shortcut: '/favicon.svg',
      apple: '/favicon.svg',
    },
    alternates: {
      canonical: canonicalUrl,
      languages: getAlternateUrls(path),
    },
    openGraph: {
      type: 'website',
      locale: ogLocale,
      url: canonicalUrl,
      title: fullTitle,
      description: optimizedDescription,
      siteName: siteConfig.name,
      images: [
        {
          url: ogImage.startsWith('http') ? ogImage : `${siteConfig.url}${ogImage}`,
          width: 1200,
          height: 630,
          alt: fullTitle,
          type: 'image/png',
        },
      ],
    },
    twitter: {
      card: 'summary_large_image',
      title: fullTitle,
      description: optimizedDescription,
      images: [ogImage.startsWith('http') ? ogImage : `${siteConfig.url}${ogImage}`],
      creator: siteConfig.creator,
    },
    verification: {
      // Add verification tags if needed
      // google: 'google-site-verification-code',
      // yandex: 'yandex-verification-code',
    },
    category: 'technology',
  };
}

/**
 * Generate metadata for tool pages
 */
export function generateToolMetadata(options: ToolMetadataOptions): Metadata {
  const { locale, tool, content } = options;
  const path = `/tools/${tool.slug}`;

  // Enhance keywords with common PDF-related terms
  const enhancedKeywords = [
